    fireEvent.click(screen.getByRole("button", { name: /Finalizar Compra/i }));

    await waitFor(() => {
      expect(H.toast).toHaveBeenCalledWith("Faça login para continuar.");
      expect(H.router.push).toHaveBeenCalledWith("/login");
    });
  });

  it("handleCheckout: logado navega para /checkout", async () => {
    setCartItems([{ id: 1, name: "Produto A", quantity: 1, price: 10 }]);
    setAuth({ user: { id: 1 }, isAuthenticated: true });

    await renderCartAndReady();

    fireEvent.click(screen.getByRole("button", { name: /Finalizar Compra/i }));

    await waitFor(() => {
      expect(H.router.push).toHaveBeenCalledWith("/checkout");
    });
  });

  it("limpa estado de cupom quando carrinho muda: após rerender, total reflete novo subtotal", async () => {
    setCartItems([{ id: 1, name: "Produto A", quantity: 2, price: 50 }]); // 100
    setAuth({ user: { id: 1 }, isAuthenticated: true });

    H.axios.post.mockResolvedValueOnce({
      data: { success: true, desconto: 10, message: "OK" },
    });

    const closeCart = vi.fn();
    const { rerender } = render(
      <CartCar isCartOpen={true} closeCart={closeCart} />,
    );

    await waitFor(() => {
      expect(
        screen.getByRole("dialog", { name: "Carrinho de compras" }),
      ).toBeInTheDocument();
    });

    fireEvent.change(screen.getByPlaceholderText("Cupom de desconto"), {
      target: { value: "OFF10" },
    });
    fireEvent.click(screen.getByRole("button", { name: "Aplicar" }));

    await waitFor(() => {
      expect(H.axios.post).toHaveBeenCalledTimes(1);
      expect(H.toast.success).toHaveBeenCalled();
    });

    // muda carrinho -> componente recalcula subtotal/total
    setCartItems([{ id: 1, name: "Produto A", quantity: 1, price: 50 }]); // 50
    rerender(<CartCar isCartOpen={true} closeCart={closeCart} />);

    await waitFor(() => {
      expect(
        screen.getAllByText(moneyRegex("R$ 50,00")).length,
      ).toBeGreaterThanOrEqual(1);
    });
  });
});

import React from "react";
import { describe, it, expect, vi, beforeEach } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";

import CategoryPage from "../../components/products/CategoryPage";
import type { Product } from "@/types/product";

// ---------- Mocks ----------
const mockUseFetchProducts = vi.fn();

vi.mock("@/hooks/useFetchProducts", () => ({
  useFetchProducts: (args: any) => mockUseFetchProducts(args),
}));

vi.mock("@/components/products/ProductCard", () => ({
  __esModule: true,
  default: ({ product }: { product: any }) => (
    <article
      data-testid="product-card"
      aria-label={`product-${String(product?.id ?? "unknown")}`}
    >
      <span>
        {String(
          product?.name ?? product?.title ?? `Produto ${product?.id ?? ""}`,
        )}
      </span>
      <span data-testid="third-category">
        {String(product?.third_category ?? "")}
      </span>
    </article>
  ),
}));

// ---------- Helpers ----------
function makeProduct(partial: Partial<Product> & { id: number }): Product {
  return {
    id: partial.id,
    name: (partial as any).name ?? `Produto ${partial.id}`,
    third_category: (partial as any).third_category ?? null,
    ...(partial as any),
  } as Product;
}

function setFetchReturn(opts: {
  data?: unknown;
  loading?: boolean;
  error?: unknown;
}) {
  mockUseFetchProducts.mockImplementation((_args: any) => ({
    data: opts.data,
    loading: opts.loading ?? false,
    error: opts.error ?? null,
  }));
}

beforeEach(() => {
  vi.clearAllMocks();
});

// ---------- Tests ----------
describe("CategoryPage", () => {
  it("chama useFetchProducts com categorySlug=categoria (contrato)", () => {
    setFetchReturn({ data: [], loading: false, error: null });

    render(<CategoryPage categoria="medicamentos" title="Medicamentos" />);

    expect(mockUseFetchProducts).toHaveBeenCalledTimes(1);
    expect(mockUseFetchProducts).toHaveBeenCalledWith({
      categorySlug: "medicamentos",
    });
  });

  it("renderiza estado de loading (positivo)", () => {
    setFetchReturn({ loading: true });

    render(<CategoryPage categoria="pets" title="Pets" />);

    expect(screen.getByText(/Carregando produtos/i)).toBeInTheDocument();
    expect(screen.queryByTestId("product-card")).not.toBeInTheDocument();
    expect(
      screen.queryByText(/Nenhum item encontrado/i),
    ).not.toBeInTheDocument();
  });

  it("renderiza estado de erro com mensagem e detalhes (negativo)", () => {
    setFetchReturn({ loading: false, error: "Falha 500" });

    render(<CategoryPage categoria="pragas" title="Pragas" />);

    expect(screen.getByText(/Erro ao carregar produtos/i)).toBeInTheDocument();
    expect(screen.getByText("Falha 500")).toBeInTheDocument();
    expect(screen.queryByTestId("product-card")).not.toBeInTheDocument();
  });

  it("renderiza título preferindo `title` quando fornecido (positivo)", () => {
    setFetchReturn({ data: [] });

    render(<CategoryPage categoria="fertilizantes" title="Fertilizantes" />);

    const h1 = screen.getByRole("heading", { level: 1 });
    expect(h1).toHaveTextContent("Fertilizantes");
  });

  it("renderiza o fallback do título para `categoria` quando `title` não existe (positivo)", () => {
    setFetchReturn({ data: [] });

    render(<CategoryPage categoria="outros" />);

    const h1 = screen.getByRole("heading", { level: 1 });
    expect(h1).toHaveTextContent("outros");
  });

  it("quando não há produtos, mostra empty-state (negativo)", () => {
    setFetchReturn({ data: [] });

    render(<CategoryPage categoria="servicos" title="Serviços" />);

    expect(screen.getByText(/Nenhum item encontrado/i)).toBeInTheDocument();
    expect(screen.queryByTestId("product-card")).not.toBeInTheDocument();
  });

  it("aceita data no formato array e renderiza ProductCard para cada item (positivo)", () => {
    const products = [
      makeProduct({ id: 1, third_category: "Suplemento" }),
      makeProduct({ id: 2, third_category: "Hormônio" }),
    ];
    setFetchReturn({ data: products });

    render(<CategoryPage categoria="medicamentos" />);

    const cards = screen.getAllByTestId("product-card");
    expect(cards).toHaveLength(2);
    expect(
      screen.queryByText(/Nenhum item encontrado/i),
    ).not.toBeInTheDocument();
  });

  it("aceita data no formato { data: [] } e renderiza corretamente (positivo)", () => {
    const products = [
      makeProduct({ id: 10, third_category: "Café" }),
      makeProduct({ id: 11, third_category: "Milho" }),
    ];
    setFetchReturn({ data: { data: products } });

    render(<CategoryPage categoria="agricultura" title="Agricultura" />);

    const cards = screen.getAllByTestId("product-card");
    expect(cards).toHaveLength(2);
  });

  it("não renderiza select quando não existem subcategorias (third_category vazio/nulo) (negativo)", () => {
    const products = [
      makeProduct({ id: 1, third_category: null }),
      makeProduct({ id: 2, third_category: "" as any }),
    ];
    setFetchReturn({ data: products });

    render(<CategoryPage categoria="pets" />);

    expect(screen.queryByRole("combobox")).not.toBeInTheDocument();
    expect(screen.getAllByTestId("product-card")).toHaveLength(2);
  });

  it("renderiza select quando há subcategorias e inclui opção 'Todas as Subcategorias' (positivo)", () => {
    const products = [
      makeProduct({ id: 1, third_category: "Bovinos" }),
      makeProduct({ id: 2, third_category: "Bovinos" }),
      makeProduct({ id: 3, third_category: "Equino" }),
    ];
    setFetchReturn({ data: products });

    render(<CategoryPage categoria="medicamentos" title="Medicamentos" />);

    const select = screen.getByRole("combobox");
    expect(select).toBeInTheDocument();

    expect(
      screen.getByRole("option", { name: /Todas as Subcategorias/i }),
    ).toBeInTheDocument();

    expect(screen.getByRole("option", { name: "Bovinos" })).toBeInTheDocument();
    expect(screen.getByRole("option", { name: "Equino" })).toBeInTheDocument();
  });

  it("filtra produtos ao selecionar uma subcategoria (positivo) e retorna todos ao limpar", async () => {
    const user = userEvent.setup();

    const products = [
      makeProduct({ id: 1, third_category: "Bovinos" }),
      makeProduct({ id: 2, third_category: "Equino" }),
      makeProduct({ id: 3, third_category: "Bovinos" }),
    ];
    setFetchReturn({ data: products });

    render(<CategoryPage categoria="medicamentos" />);

    expect(screen.getAllByTestId("product-card")).toHaveLength(3);

    const select = screen.getByRole("combobox");
    await user.selectOptions(select, "Bovinos");

    expect(screen.getAllByTestId("product-card")).toHaveLength(2);

    const categories = screen
      .getAllByTestId("third-category")
      .map((el) => el.textContent);

    expect(categories.every((c) => c === "Bovinos")).toBe(true);

    await user.selectOptions(select, "");
    expect(screen.getAllByTestId("product-card")).toHaveLength(3);
  });

  it("quando os dados mudam e a subcategoria selecionada deixa de existir, a opção some do select e o componente pode cair em empty-state pois o filtro persiste (negativo/consistência)", async () => {
    const user = userEvent.setup();

    // Dataset inicial com Bovinos e Equino
    setFetchReturn({
      data: [
        makeProduct({ id: 1, third_category: "Bovinos" }),
        makeProduct({ id: 2, third_category: "Equino" }),
      ],
    });

    const { rerender } = render(<CategoryPage categoria="medicamentos" />);

    const select = screen.getByRole("combobox");
    await user.selectOptions(select, "Bovinos");

    // Confirma que filtrou para 1 item
    expect(screen.getAllByTestId("product-card")).toHaveLength(1);
    expect(screen.getByText("Produto 1")).toBeInTheDocument();

    // Backend muda e agora só existe Equino
    setFetchReturn({
      data: [makeProduct({ id: 9, third_category: "Equino" })],
    });

    rerender(<CategoryPage categoria="medicamentos" />);

    // A opção antiga ("Bovinos") some porque subcategorias deriva de products atuais
    expect(
      screen.queryByRole("option", { name: "Bovinos" }),
    ).not.toBeInTheDocument();

    // Como o state `selected` permanece "Bovinos", o filtro fica sem resultados => empty-state
    expect(screen.getByText(/Nenhum item encontrado/i)).toBeInTheDocument();
    expect(screen.queryByTestId("product-card")).not.toBeInTheDocument();
  });
});

import React from "react";
import { describe, it, expect, vi, beforeEach } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";

import CustomButton from "@/components/buttons/CustomButton";

// Mock do next/link para não navegar de verdade
vi.mock("next/link", () => ({
  default: ({ href, children, ...rest }: any) => (
    <a href={href} {...rest}>
      {children}
    </a>
  ),
}));

describe("CustomButton", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("renderiza botão padrão com label (positivo)", () => {
    render(
      <CustomButton
        label="Salvar"
        variant="primary"
        size="medium"
        isLoading={false}
      />,
    );

    expect(screen.getByRole("button", { name: /salvar/i })).toBeInTheDocument();
  });

  it("chama onClick quando clicado e não está em loading (positivo)", async () => {
    const user = userEvent.setup();
    const onClickMock = vi.fn();

    render(
      <CustomButton
        label="Enviar"
        variant="primary"
        size="medium"
        isLoading={false}
        onClick={onClickMock}
      />,
    );

    await user.click(screen.getByRole("button", { name: /enviar/i }));

    expect(onClickMock).toHaveBeenCalledTimes(1);
  });

  it("não chama onClick quando está em loading (negativo)", async () => {
    const user = userEvent.setup();
    const onClickMock = vi.fn();

    render(
      <CustomButton
        label="Enviar"
        variant="primary"
        size="medium"
        isLoading={true}
        onClick={onClickMock}
      />,
    );

    const button = screen.getByRole("button");

    expect(button).toBeDisabled();

    await user.click(button);

    expect(onClickMock).not.toHaveBeenCalled();
  });

  it("exibe spinner e texto 'Carregando...' quando isLoading=true (positivo)", () => {
    render(
      <CustomButton
        label="Salvar"
        variant="primary"
        size="medium"
        isLoading={true}
      />,
    );

    expect(screen.getByText(/carregando/i)).toBeInTheDocument();
    expect(screen.queryByText("Salvar")).not.toBeInTheDocument();
  });

  it("renderiza como link quando href é fornecido (positivo)", () => {
    render(
      <CustomButton
        label="Ir para página"
        href="/teste"
        variant="secondary"
        size="small"
        isLoading={false}
      />,
    );

    const link = screen.getByRole("link", { name: /ir para página/i });

    expect(link).toBeInTheDocument();
    expect(link).toHaveAttribute("href", "/teste");
  });

  it("aplica aria-disabled e tabIndex quando link está em loading (a11y)", () => {
    render(
      <CustomButton
        label="Ir"
        href="/teste"
        variant="secondary"
        size="small"
        isLoading={true}
      />,
    );

    const link = screen.getByRole("link");

    expect(link).toHaveAttribute("aria-disabled", "true");
    expect(link).toHaveAttribute("tabIndex", "-1");
  });

  it("renderiza mensagem de erro quando message é fornecida e não está carregando (positivo)", () => {
    render(
      <CustomButton
        label="Salvar"
        variant="primary"
        size="medium"
        isLoading={false}
        message="Erro ao salvar"
      />,
    );

    expect(screen.getByText("Erro ao salvar")).toBeInTheDocument();
  });

  it("não renderiza message quando está em loading (negativo)", () => {
    render(
      <CustomButton
        label="Salvar"
        variant="primary"
        size="medium"
        isLoading={true}
        message="Erro ao salvar"
      />,
    );

    expect(screen.queryByText("Erro ao salvar")).not.toBeInTheDocument();
  });

  it("aplica corretamente variant, size e className customizada (positivo/controle)", () => {
    render(
      <CustomButton
        label="Custom"
        variant="secondary"
        size="large"
        isLoading={false}
        className="extra-class"
      />,
    );

    const button = screen.getByRole("button", { name: /custom/i });

    expect(button.className).toContain("extra-class");
    expect(button.className).toContain("w-full"); // size large
    expect(button.className).toContain("bg-[#EC5B20]"); // secondary
  });

  it("define type corretamente quando passado via props (controle)", () => {
    render(
      <CustomButton
        label="Submit"
        variant="primary"
        size="medium"
        isLoading={false}
        type="submit"
      />,
    );

    const button = screen.getByRole("button", { name: /submit/i });
    expect(button).toHaveAttribute("type", "submit");
  });

  it("define aria-busy quando isLoading=true (a11y)", () => {
    render(
      <CustomButton
        label="Salvar"
        variant="primary"
        size="medium"
        isLoading={true}
      />,
    );

    const button = screen.getByRole("button");
    expect(button).toHaveAttribute("aria-busy", "true");
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { render, screen, act, fireEvent } from "@testing-library/react";
import PromocoesHero from "@/components/products/DestaquesSection";

// ---------- Mocks padrão ----------
vi.mock("next/link", () => ({
  __esModule: true,
  default: ({ href, children, ...rest }: any) => (
    <a href={href} {...rest}>
      {children}
    </a>
  ),
}));

/**
 * Mock de next/image:
 * remove props inválidas para DOM (ex: fill boolean),
 * evitando warnings do React.
 */
vi.mock("next/image", () => ({
  __esModule: true,
  default: ({ alt, fill: _fill, ...props }: any) => (
    <img alt={alt} {...props} />
  ),
}));

const apiMock = vi.fn();

vi.mock("@/lib/api", () => ({
  api: (...args: any[]) => apiMock(...args),
}));

// ---------- Helpers ----------
const baseProduct = {
  id: 1,
  name: "Produto Teste",
  description: "Descrição do produto",
  original_price: 150,
  final_price: 100,
  discount_percent: 33,
  image: "uploads/produto.jpg",
  // meio-dia UTC evita “voltar um dia” no -03:00
  ends_at: "2025-12-31T12:00:00Z",
};

async function flushEffects() {
  // garante que o useEffect async que chama api() rode e aplique setState
  await act(async () => {
    await Promise.resolve();
  });
  await act(async () => {
    await Promise.resolve();
  });
}

beforeEach(() => {
  vi.clearAllMocks();
  // IMPORTANTE: timers reais por padrão, para findBy/waitFor não travarem
  vi.useRealTimers();
});

afterEach(() => {
  vi.useRealTimers();
});

describe("PromocoesHero (DestaquesSection)", () => {
  it("não renderiza nada quando API retorna lista vazia (negativo)", async () => {
    apiMock.mockResolvedValueOnce([]);

    const { container } = render(<PromocoesHero />);
    await flushEffects();

    expect(container.firstChild).toBeNull();
  });

  it("busca promoções na API correta (contrato)", async () => {
    apiMock.mockResolvedValueOnce([baseProduct]);

    render(<PromocoesHero />);

    // com timers reais, findByText é estável
    await screen.findByText("Produtos em Promoção");

    expect(apiMock).toHaveBeenCalledTimes(1);
    expect(apiMock).toHaveBeenCalledWith("/api/public/promocoes");
  });

  it("renderiza produto em promoção com nome, preço e desconto (positivo)", async () => {
    apiMock.mockResolvedValueOnce([baseProduct]);

    render(<PromocoesHero />);
    await screen.findByText("Produtos em Promoção");

    // nome aparece em mais de um lugar
    expect(screen.getAllByText("Produto Teste").length).toBeGreaterThan(0);

    expect(screen.getByText("R$ 100.00")).toBeInTheDocument();
    expect(screen.getByText("-33% OFF")).toBeInTheDocument();
  });

  it("exibe preço original riscado quando há desconto (positivo)", async () => {
    apiMock.mockResolvedValueOnce([baseProduct]);

    render(<PromocoesHero />);
    await screen.findByText("Produtos em Promoção");

    expect(screen.getByText("R$ 150.00")).toBeInTheDocument();
  });

  it("renderiza data de validade formatada (positivo)", async () => {
    apiMock.mockResolvedValueOnce([baseProduct]);

    render(<PromocoesHero />);
    await screen.findByText("Produtos em Promoção");

    const line = screen.getByText(/Válido até/i);
    expect(line.textContent).toMatch(/\b\d{2}\/\d{2}\b/);
    expect(line.textContent).toContain("31/12");
  });

  it("renderiza link correto para o produto (positivo)", async () => {
    apiMock.mockResolvedValueOnce([baseProduct]);

    render(<PromocoesHero />);
    await screen.findByText("Produtos em Promoção");

    const link = screen.getByRole("link", { name: /Ver oferta/i });
    expect(link).toHaveAttribute("href", "/produtos/1");
  });

  it("usa placeholder quando produto não possui imagem (negativo)", async () => {
    apiMock.mockResolvedValueOnce([{ ...baseProduct, image: null }]);

    render(<PromocoesHero />);
    await screen.findByText("Produtos em Promoção");

    const img = screen.getByAltText("Produto Teste") as HTMLImageElement;
    expect(img.src).toContain("via.placeholder.com");
  });

  it("renderiza bolinhas de navegação quando há mais de uma promoção (positivo)", async () => {
    apiMock.mockResolvedValueOnce([
      baseProduct,
      { ...baseProduct, id: 2, name: "Produto 2", image: "uploads/p2.jpg" },
    ]);

    render(<PromocoesHero />);
    await screen.findByText("Produtos em Promoção");

    const dots = screen.getAllByRole("button", { name: /Ir para promoção/i });
    expect(dots).toHaveLength(2);
  });

  it("permite navegar manualmente clicando nas bolinhas (positivo)", async () => {
    apiMock.mockResolvedValueOnce([
      baseProduct,
      { ...baseProduct, id: 2, name: "Produto 2", image: "uploads/p2.jpg" },
    ]);

    render(<PromocoesHero />);
    await screen.findByText("Produtos em Promoção");

    const dot2 = screen.getByRole("button", { name: "Ir para promoção 2" });

    act(() => {
      fireEvent.click(dot2);
    });

    expect(screen.getAllByText("Produto 2").length).toBeGreaterThan(0);
  });

  it("faz autoplay das promoções após o intervalo (positivo)", async () => {
    // fake timers SOMENTE aqui
    vi.useFakeTimers();

    apiMock.mockResolvedValueOnce([
      baseProduct,
      { ...baseProduct, id: 2, name: "Produto 2", image: "uploads/p2.jpg" },
    ]);

    render(<PromocoesHero />);
    await flushEffects();

    // agora já renderizou
    expect(screen.getAllByText("Produto Teste").length).toBeGreaterThan(0);

    act(() => {
      vi.advanceTimersByTime(6000);
    });

    expect(screen.getAllByText("Produto 2").length).toBeGreaterThan(0);

    vi.useRealTimers();
  });

  it("não inicia autoplay quando há apenas uma promoção (negativo)", async () => {
    // fake timers SOMENTE aqui
