    } as unknown as Response);
  }) as unknown as typeof fetch;
}

function mockFetchFail(text: string, status = 500) {
  globalThis.fetch = vi.fn(() => {
    return Promise.resolve({
      ok: false,
      status,
      statusText: "ERR",
      text: () => Promise.resolve(text),
    } as unknown as Response);
  }) as unknown as typeof fetch;
}

