    Object.defineProperty(scroller!, "scrollWidth", {
      value: 700,
      configurable: true,
    });

    // dispara ResizeObserver check
    expect(lastROTrigger).toBeTruthy();
    lastROTrigger?.();

    const btnPrev = await screen.findByRole("button", {
