      return new Promise<Response>(() => {});
    }) as unknown as typeof fetch;

    // Act
    const { unmount } = render(<ServicosSection />);
    unmount();

    // Assert
    expect(abortSpy).toHaveBeenCalledTimes(1);
  });
});

