        syncingId={null}
      />,
    );

    const syncButtons = screen.getAllByRole("button", { name: "Sync" });
    await user.click(syncButtons[0]);
    expect(onSync).toHaveBeenCalledTimes(1);
    expect(onSync).toHaveBeenCalledWith(99);

    rerender(
      <ClimaTable
        rows={rows}
        loading={false}
        errorMsg={null}
        onReload={vi.fn()}
        onEdit={vi.fn()}
        onDelete={vi.fn()}
