}

describe("CotacaoCard", () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it("deve renderizar link com href e aria-label corretos (positivo)", () => {
