    fireEvent.click(screen.getByText("logout"));

    // Assert
    await waitFor(() => expect(apiMock).toHaveBeenCalledTimes(2));
    expect(apiMock).toHaveBeenNthCalledWith(2, "/api/logout", {
      method: "POST",
    });

    expect(screen.getByTestId("userId").textContent).toBe("");
