type AnyChangeEvent = {
  target: {
    name?: string;
    value?: any;
    type?: string;
    checked?: boolean;
  };
};

function makeEvent(
  name?: string,
  value?: any,
  opts?: { type?: string; checked?: boolean },
): AnyChangeEvent {
  return {
    target: {
      name,
      value,
      type: opts?.type,
      checked: opts?.checked,
    },
  };
}

