/**
 * Helper local para mockar Response (evita depender de util compartilhado).
 */
function makeRes(opts: { ok: boolean; status: number; text?: string }) {
  return {
    ok: opts.ok,
    status: opts.status,
    async text() {
      return opts.text ?? "";
    },
  } as unknown as Response;
}

