        </div>

        <header className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
          <div className="min-w-0">
            <h1 className="text-lg font-semibold text-slate-50 sm:text-xl">
              Carrinhos abandonados
            </h1>
            <p className="mt-1 text-sm text-slate-400">
              Visualize carrinhos não concluídos e envie lembretes para
              recuperação.
            </p>
          </div>

          <div className="flex flex-wrap items-center gap-2 self-start sm:self-auto">
            <button
              type="button"
              onClick={carregar}
              className="inline-flex items-center rounded-xl border border-slate-800 bg-slate-950 px-3 py-2 text-xs font-medium text-slate-200 hover:bg-slate-900"
