"use client";

import { useEffect, useState, ChangeEvent } from "react";
import apiClient from "@/lib/apiClient";
import { useParams, useRouter } from "next/navigation";
import toast from "react-hot-toast";
import CustomButton from "@/components/buttons/CustomButton";
import DeleteButton from "@/components/buttons/DeleteButton";

type StatusConta = "ativo" | "bloqueado" | null;

type AdminUserDetail = {
  id: number;
  nome: string;
  email: string;
  telefone?: string | null;
  cpf?: string | null;
  endereco?: string | null;
  cidade?: string | null;
  estado?: string | null;
  cep?: string | null;
  pais?: string | null;
  ponto_referencia?: string | null;
  status_conta?: StatusConta;
};

export default function AdminClienteEditPage() {
  const params = useParams<{ id: string }>();
  const router = useRouter();
  const userId = Number(params.id);

  const [user, setUser] = useState<AdminUserDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [blocking, setBlocking] = useState(false);

  useEffect(() => {
    if (!userId) return;

    const load = async () => {
      try {
        setLoading(true);

        const res = await apiClient.get<AdminUserDetail>(
          `/api/users/admin/${userId}`,
        );

        setUser(res);
      } catch (err: any) {
        console.error(err);

        if (err?.status === 401 || err?.status === 403) {
          toast.error("Sessão expirada. Faça login novamente.");
          router.push("/admin/login");
          return;
        }

        toast.error("Não foi possível carregar os dados do cliente.");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [userId, router]);

  const handleChange =
    (field: keyof AdminUserDetail) =>
    (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      if (!user) return;
      setUser({ ...user, [field]: e.target.value });
    };

  const handleSave = async () => {
    if (!user) return;
    setSaving(true);

    try {
      const { id, email, status_conta, ...body } = user;

      await apiClient.put(`/api/users/admin/${userId}`, body);

      toast.success("Dados do cliente atualizados com sucesso.");
    } catch (err: any) {
      console.error(err);

      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        router.push("/admin/login");
        return;
      }

      const msg = err?.message || "Erro ao salvar dados do cliente.";
      toast.error(msg);
    } finally {
      setSaving(false);
    }
  };

  const handleToggleBlock = async () => {
    if (!user) return;
    setBlocking(true);

    try {
      const novoStatus: StatusConta =
        user.status_conta === "bloqueado" ? "ativo" : "bloqueado";

      await apiClient.put(`/api/admin/users/${userId}/block`, {
        status_conta: novoStatus,
      });

      setUser((prev) => (prev ? { ...prev, status_conta: novoStatus } : prev));

      toast.success(
        novoStatus === "bloqueado"
          ? "Cliente bloqueado para compras."
          : "Conta ativada com sucesso.",
      );
    } catch (err: any) {
      console.error(err);

      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        router.push("/admin/login");
        return;
      }

      const msg = err?.message || "Erro ao atualizar status da conta.";
      toast.error(msg);
    } finally {
      setBlocking(false);
    }
  };

  const handleDelete = async () => {
    try {
      await apiClient.del(`/api/admin/users/${userId}`);

      toast.success("Cliente removido com sucesso.");
      router.push("/admin/clientes");
    } catch (err: any) {
      console.error(err);

      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        router.push("/admin/login");
        return;
      }

      toast.error("Não foi possível excluir o cliente.");
    }
  };

  if (loading) {
    return (
      <div className="p-6">
        <p className="text-sm text-gray-500">Carregando dados do cliente…</p>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="p-6">
        <p className="text-sm text-red-500">Cliente não encontrado.</p>
      </div>
    );
  }

  const isBlocked = user.status_conta === "bloqueado";

  return (
    <div className="px-4 py-6 sm:px-6 lg:px-8">
      <div className="max-w-5xl mx-auto space-y-5">
        {/* Cabeçalho */}
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h1 className="text-xl sm:text-2xl font-semibold text-white">
              Editar Cliente
            </h1>
            <p className="text-xs sm:text-sm text-gray-500">
              Ajuste os dados cadastrais e o status da conta.
            </p>
          </div>

          <button
            type="button"
            onClick={() => router.back()}
            className="inline-flex items-center justify-center rounded-full border border-gray-300 px-4 py-1.5 text-xs sm:text-sm text-gray-700 bg-white hover:bg-gray-50"
          >
            ← Voltar
          </button>
        </div>

        {/* Card principal */}
        <div className="rounded-2xl bg-[#020617] text-white px-4 py-5 sm:px-6 sm:py-6 shadow-sm border border-[#0f172a] space-y-5">
          {/* Cabeçalho do card + status */}
          <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h2 className="text-sm sm:text-base font-semibold">
                {user.nome}
              </h2>
              <p className="text-[11px] text-gray-400">
                ID #{String(user.id).padStart(4, "0")}
              </p>
            </div>

            <div className="flex flex-wrap gap-2 justify-start sm:justify-end">
              <span
                className={`inline-flex items-center rounded-full border px-3 py-1 text-[11px] font-semibold ${
                  isBlocked
                    ? "border-red-500/60 bg-red-500/10 text-red-300"
                    : "border-emerald-500/60 bg-emerald-500/10 text-emerald-200"
                }`}
              >
                {isBlocked ? "Conta bloqueada" : "Conta ativa"}
              </span>

              <button
                type="button"
                onClick={handleToggleBlock}
                disabled={blocking}
                className={`inline-flex items-center rounded-full px-3 py-1 text-[11px] font-semibold ${
                  isBlocked
                    ? "bg-emerald-600 hover:bg-emerald-700"
                    : "bg-red-600 hover:bg-red-700"
                } text-white disabled:opacity-60 disabled:cursor-not-allowed`}
              >
                {blocking
                  ? "Atualizando..."
                  : isBlocked
                    ? "Ativar conta"
                    : "Bloquear cliente"}
              </button>
            </div>
          </div>

          {/* Aviso quando bloqueado */}
          {isBlocked && (
            <div className="rounded-xl border border-red-500/50 bg-red-500/10 px-4 py-3 text-xs text-red-100 flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
              <p>
                Este cliente está{" "}
                <span className="font-semibold">bloqueado</span> e não poderá
                finalizar compras até a conta ser ativada.
              </p>
              <button
                type="button"
                onClick={handleToggleBlock}
                disabled={blocking}
                className="inline-flex items-center justify-center rounded-full bg-emerald-600 px-3 py-1.5 text-[11px] font-semibold text-white hover:bg-emerald-700 disabled:opacity-60 disabled:cursor-not-allowed"
              >
                {blocking ? "Atualizando..." : "Ativar conta agora"}
              </button>
            </div>
          )}

          {/* Form */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-[13px]">
            <div className="space-y-1.5">
              <label className="text-xs text-gray-300">Nome</label>
              <input
                value={user.nome}
                onChange={handleChange("nome")}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-xs text-gray-300">Email</label>
              <input
                value={user.email}
                disabled
                className="w-full rounded-xl border border-slate-800 bg-slate-900/40 px-3 py-2 text-sm text-gray-400"
              />
              <p className="text-[10px] text-gray-400">
                Email não é editável por aqui (evita conflitos de login).
              </p>
            </div>

            <div className="space-y-1.5">
              <label className="text-xs text-gray-300">Telefone</label>
              <input
                value={user.telefone ?? ""}
                onChange={handleChange("telefone")}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-xs text-gray-300">CPF</label>
              <input
                value={user.cpf ?? ""}
                onChange={handleChange("cpf")}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>

            <div className="space-y-1.5 sm:col-span-2">
              <label className="text-xs text-gray-300">Endereço</label>
              <input
                value={user.endereco ?? ""}
                onChange={handleChange("endereco")}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-xs text-gray-300">Cidade</label>
              <input
                value={user.cidade ?? ""}
                onChange={handleChange("cidade")}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-xs text-gray-300">Estado</label>
              <input
                value={user.estado ?? ""}
                onChange={handleChange("estado")}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-xs text-gray-300">CEP</label>
              <input
                value={user.cep ?? ""}
                onChange={handleChange("cep")}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-xs text-gray-300">País</label>
              <input
                value={user.pais ?? ""}
                onChange={handleChange("pais")}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>

            <div className="space-y-1.5 sm:col-span-2">
              <label className="text-xs text-gray-300">
                Ponto de referência
              </label>
              <textarea
                value={user.ponto_referencia ?? ""}
                onChange={handleChange("ponto_referencia")}
                rows={2}
                className="w-full rounded-xl border border-slate-700 bg-slate-900/60 px-3 py-2 text-sm outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500"
              />
            </div>
          </div>

          {/* Ações */}
          <div className="flex flex-col gap-3 pt-2 sm:flex-row sm:items-center sm:justify-between">
            <div className="flex flex-wrap gap-2">
              <CustomButton
                label="Ver pedidos desse cliente"
                href={`/admin/pedidos?clienteId=${userId}`}
                variant="secondary"
                size="small"
                isLoading={false}
              />
            </div>

            <div className="flex flex-wrap gap-2 justify-end">
              <DeleteButton label="Excluir cliente" onConfirm={handleDelete} />
              <CustomButton
                label="Salvar alterações"
                onClick={handleSave}
                variant="primary"
                size="small"
                isLoading={saving}
              />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import apiClient from "@/lib/apiClient";
import CustomButton from "@/components/buttons/CustomButton";
import DeleteButton from "@/components/buttons/DeleteButton";
import toast from "react-hot-toast";
import { useRouter } from "next/navigation";

type AdminUser = {
  id: number;
  nome: string;
  email: string;
  telefone?: string | null;
  cpf?: string | null;
  cidade?: string | null;
  estado?: string | null;
  status_conta?: "ativo" | "bloqueado" | null;
};

function padId(id: number) {
  return `#${String(id).padStart(4, "0")}`;
}

function onlyDigits(v?: string | null) {
  if (!v) return "";
  return v.replace(/\D/g, "");
}

function formatTelefone(v?: string | null) {
  const digits = onlyDigits(v);
  if (!digits) return "-";
  const d = digits.slice(0, 11);
  if (d.length <= 2) return `(${d}`;
  if (d.length <= 7) return `(${d.slice(0, 2)}) ${d.slice(2)}`;
  return `(${d.slice(0, 2)}) ${d.slice(2, 7)}-${d.slice(7)}`;
}

function formatCpf(v?: string | null) {
  const digits = onlyDigits(v).slice(0, 11);
  if (!digits) return "-";
  if (digits.length <= 3) return digits;
  if (digits.length <= 6) return digits.replace(/(\d{3})(\d{0,3})/, "$1.$2");
  if (digits.length <= 9)
    return digits.replace(/(\d{3})(\d{3})(\d{0,3})/, "$1.$2.$3");
  return digits.replace(/(\d{3})(\d{3})(\d{3})(\d{0,2})/, "$1.$2.$3-$4");
}

export default function AdminClientesPage() {
  const router = useRouter();
  const [list, setList] = useState<AdminUser[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  useEffect(() => {
    async function load() {
      try {
        const data = await apiClient.get<AdminUser[]>("/api/admin/users");

        setList(data ?? []);
      } catch (err: any) {
        console.error(err);

        if (err?.status === 401 || err?.status === 403) {
          toast.error("Sessão expirada. Faça login novamente.");
          router.push("/admin/login");
          return;
        }

        toast.error("Não foi possível carregar os clientes.");
      } finally {
        setLoading(false);
      }
    }

    load();
  }, [router]);

  const filtered = useMemo(() => {
    if (!search.trim()) return list;

    const q = search.toLowerCase();
    return list.filter((u) => {
      return (
        u.nome.toLowerCase().includes(q) || u.email.toLowerCase().includes(q)
      );
    });
  }, [list, search]);

  const total = list.length;

  const handleDelete = async (id: number) => {
    try {
      await apiClient.del(`/api/admin/users/${id}`);

      setList((prev) => prev.filter((u) => u.id !== id));
      toast.success("Cliente removido com sucesso.");
    } catch (err: any) {
      console.error(err);

      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        router.push("/admin/login");
        return;
      }

      toast.error("Não foi possível excluir o cliente.");
    }
  };

  if (loading) {
    return (
      <div className="p-6">
        <p className="text-sm text-gray-500">Carregando clientes…</p>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-4">
      {/* Cabeçalho */}
      <div className="flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h1 className="text-xl  sm:text-2xl font-semibold text-[#359293]">
            Clientes
          </h1>
          <p className="text-xs sm:text-sm text-gray-500">
            {total === 0
              ? "Nenhum cliente cadastrado ainda."
              : `${total} cliente(s) cadastrados no sistema.`}
          </p>
        </div>

        <div className="w-full sm:w-72">
          <input
            type="text"
            placeholder="Buscar por nome ou email..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full rounded-full border border-gray-300 bg-white text-black px-4 py-2 text-sm outline-none transition focus:border-[#359293] focus:ring-2 focus:ring-[#359293]/20"
          />
        </div>
      </div>

      {/* Lista de clientes */}
      {filtered.length === 0 ? (
        <div className="mt-4 rounded-2xl border border-dashed border-gray-300 bg-gray-50 px-4 py-8 text-center text-sm text-gray-500">
          Nenhum cliente encontrado para essa busca.
        </div>
      ) : (
        <div className="mt-4 space-y-4">
          {filtered.map((u) => {
            const telFormatted = formatTelefone(u.telefone);
            const cpfFormatted = formatCpf(u.cpf);
            const telDigits = onlyDigits(u.telefone);

            const waLink = telDigits
              ? `https://wa.me/55${telDigits}?text=${encodeURIComponent(
                  `Olá ${u.nome}, tudo bem?`,
                )}`
              : null;

            const isBlocked = u.status_conta === "bloqueado";

            return (
              <div
                key={u.id}
                className="rounded-2xl bg-[#020617] text-white px-4 py-4 sm:px-6 sm:py-5 shadow-sm border border-[#0f172a]"
              >
                {/* Linha principal */}
                <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="text-[11px] font-mono text-gray-400">
                        {padId(u.id)}
                      </span>
                      <h2 className="text-sm sm:text-base font-semibold">
                        {u.nome}
                      </h2>

                      {isBlocked && (
                        <span className="ml-2 inline-flex items-center rounded-full border border-red-500/60 bg-red-500/10 px-2 py-0.5 text-[10px] font-semibold text-red-300">
                          Cliente bloqueado
                        </span>
                      )}
                    </div>

                    <div className="mt-1 flex flex-wrap gap-x-4 gap-y-1 text-xs sm:text-sm text-gray-300">
                      <span>
                        Telefone:{" "}
                        <span className="font-medium">{telFormatted}</span>
                      </span>
                      <span>
                        CPF: <span className="font-medium">{cpfFormatted}</span>
                      </span>
                      {(u.cidade || u.estado) && (
                        <span>
                          Local:{" "}
                          <span className="font-medium">
                            {u.cidade || "-"} {u.estado ? `/ ${u.estado}` : ""}
                          </span>
                        </span>
                      )}
                    </div>
                  </div>

                  <div className="flex flex-col items-start sm:items-end gap-2">
                    {u.email && (
                      <a
                        href={`mailto:${u.email}`}
                        className="text-xs sm:text-sm text-[#22c55e] hover:underline break-all"
                      >
                        {u.email}
                      </a>
                    )}

                    {waLink && (
                      <a
                        href={waLink}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="inline-flex items-center justify-center rounded-full border border-[#22c55e] px-3 py-1 text-[11px] sm:text-xs font-medium text-[#22c55e] hover:bg-[#22c55e]/10 transition"
                      >
                        WhatsApp
                      </a>
                    )}
                  </div>
                </div>

                {/* Linha de ações */}
                <div className="mt-4 flex flex-wrap items-center justify-end gap-2 sm:gap-3">
                  <CustomButton
                    label="Ver pedidos desse cliente"
                    href={`/admin/pedidos?clienteId=${u.id}`}
                    variant="secondary"
                    size="small"
                    isLoading={false}
                    className="text-xs sm:text-sm"
                  />

                  <CustomButton
                    label="Editar cliente"
                    href={`/admin/clientes/${u.id}`}
                    variant="primary"
                    size="small"
                    isLoading={false}
                    className="text-xs sm:text-sm"
                  />

                  <DeleteButton
                    label="Excluir cliente"
                    onConfirm={() => handleDelete(u.id)}
                  />
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import apiClient from "@/lib/apiClient";
import CloseButton from "@/components/buttons/CloseButton";
import CustomButton from "@/components/buttons/CustomButton";
import toast from "react-hot-toast";
import { useRouter } from "next/navigation";

type Categoria = {
  id: number;
  name: string;
  slug: string;
  is_active: 0 | 1 | boolean;
  sort_order: number;
};

export default function AdminCategoriasPage() {
  const router = useRouter();
  const [categorias, setCategorias] = useState<Categoria[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [editingId, setEditingId] = useState<number | null>(null);
  const [form, setForm] = useState({
    name: "",
    slug: "",
    sort_order: 0,
  });

  function resetForm() {
    setEditingId(null);
    setForm({ name: "", slug: "", sort_order: 0 });
  }

  async function loadCategorias() {
    try {
      setLoading(true);
      const res = await apiClient.get<Categoria[]>("/api/admin/categorias");
      setCategorias(res);
    } catch (err: any) {
      console.error(err);

      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login no painel admin.");
        router.push("/admin/login");
        return;
      }

      toast.error("Erro ao carregar categorias.");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    loadCategorias();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  function handleChange<K extends keyof typeof form>(
    field: K,
    value: (typeof form)[K],
  ) {
    setForm((prev) => ({ ...prev, [field]: value }));
  }

  function handleEdit(cat: Categoria) {
    setEditingId(cat.id);
    setForm({
      name: cat.name,
      slug: cat.slug,
      sort_order: cat.sort_order ?? 0,
    });
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();

    if (!form.name.trim()) {
      toast.error("Nome é obrigatório.");
      return;
    }

    try {
      setSaving(true);

      if (editingId) {
        await apiClient.put(`/api/admin/categorias/${editingId}`, {
          name: form.name.trim(),
          slug: form.slug.trim() || undefined,
          sort_order: Number(form.sort_order) || 0,
        });
        toast.success("Categoria atualizada.");
      } else {
        await apiClient.post("/api/admin/categorias", {
          name: form.name.trim(),
          slug: form.slug.trim() || undefined,
          sort_order: Number(form.sort_order) || 0,
        });
        toast.success("Categoria criada.");
      }

      resetForm();
      await loadCategorias();
    } catch (err: any) {
      console.error(err);

      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login no painel admin.");
        router.push("/admin/login");
        return;
      }

      const msg = err?.message || "Erro ao salvar categoria.";
      toast.error(msg);
    } finally {
      setSaving(false);
    }
  }

  async function toggleAtivo(cat: Categoria) {
    try {
      await apiClient.patch(`/api/admin/categorias/${cat.id}/status`, {
        is_active: !cat.is_active,
      });
      toast.success(
        !cat.is_active ? "Categoria ativada." : "Categoria desativada.",
      );
      await loadCategorias();
    } catch (err: any) {
      console.error(err);

      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login no painel admin.");
        router.push("/admin/login");
        return;
      }

      toast.error("Erro ao atualizar status.");
    }
  }

  async function handleDelete(cat: Categoria) {
    if (!window.confirm(`Remover categoria "${cat.name}"?`)) return;

    try {
      await apiClient.del(`/api/admin/categorias/${cat.id}`);
      toast.success("Categoria removida.");
      await loadCategorias();
    } catch (err: any) {
      console.error(err);

      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login no painel admin.");
        router.push("/admin/login");
        return;
      }

      const msg = err?.message || "Erro ao remover categoria.";
      toast.error(msg);
    }
