/* ------------------------------------------------------------------ */
/* Toggle padrão                                                       */
/* ------------------------------------------------------------------ */

type ToggleItemProps = {
  label: string;
  description?: string;
  checked: boolean;
  onChange: (value: boolean) => void;
};

function ToggleItem({
  label,
  description,
  checked,
  onChange,
}: ToggleItemProps) {
  return (
    <button
      type="button"
      onClick={() => onChange(!checked)}
      className="flex w-full items-center justify-between gap-3 rounded-xl border border-slate-800/80 bg-slate-900/70 px-3.5 py-3 text-left shadow-sm transition hover:border-emerald-400 hover:bg-slate-900/90 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald-500"
    >
      <div className="min-w-0">
        <p className="text-sm font-medium text-slate-50">{label}</p>
        {description && (
          <p className="mt-0.5 text-xs text-slate-400">{description}</p>
        )}
      </div>
      <span
        className={`inline-flex h-6 w-11 items-center rounded-full border shadow-inner transition ${
          checked
            ? "border-emerald-400 bg-emerald-500/80"
            : "border-slate-500 bg-slate-700"
        }`}
      >
        <span
          className={`ml-[2px] inline-block h-5 w-5 rounded-full bg-white shadow transition ${
            checked ? "translate-x-4" : "translate-x-0"
          }`}
        />
      </span>
    </button>
  );
}

/* ------------------------------------------------------------------ */
/* Toggle compacto (pill)                                              */
/* ------------------------------------------------------------------ */

function TogglePill({
  checked,
  onChange,
}: {
  checked: boolean;
  onChange: (value: boolean) => void;
}) {
  return (
    <button
      type="button"
      onClick={() => onChange(!checked)}
      className={`inline-flex h-7 w-12 items-center rounded-full border shadow-inner transition ${
        checked
          ? "border-emerald-400 bg-emerald-500/80"
          : "border-slate-500 bg-slate-700"
      }`}
      aria-pressed={checked}
    >
      <span
        className={`ml-[2px] inline-block h-6 w-6 rounded-full bg-white shadow transition ${
          checked ? "translate-x-5" : "translate-x-0"
        }`}
      />
    </button>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { toast } from "react-hot-toast";

import { useAdminAuth } from "@/context/AdminAuthContext";
import { useAdminRouteGuard } from "@/hooks/useAdminRouteGuard";
import CloseButton from "@/components/buttons/CloseButton";
import apiClient from "@/lib/apiClient";

// Gera um slug bonitinho a partir do nome do papel
function slugify(value: string) {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

type Permission = {
  id: number;
  chave: string;
  grupo: string;
  descricao: string | null;
};

type Role = {
  id: number;
  name: string;
  description?: string | null;
  slug?: string;
  permissions: string[]; // lista de chaves (ex: ["products_manage", "logs_view"])
};

export default function AdminUserPermissionsConfigPage() {
  const router = useRouter();
  const { logout, hasPermission } = useAdminAuth();

  // 🔐 Proteção de rota — exige as duas permissões
  const { allowed, checking } = useAdminRouteGuard({
    permission: ["roles_manage", "permissions_manage"],
    redirectTo: "/admin",
  });

  const canManagePermissions = hasPermission("permissions_manage");

  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // novo papel
  const [newRoleName, setNewRoleName] = useState("");
  const [newRoleDescription, setNewRoleDescription] = useState("");
  const [creatingRole, setCreatingRole] = useState(false);

  // nova permissão
  const [newPermKey, setNewPermKey] = useState("");
  const [newPermGroup, setNewPermGroup] = useState("");
  const [newPermDescription, setNewPermDescription] = useState("");
  const [creatingPerm, setCreatingPerm] = useState(false);

  // 🔍 filtros da matriz
  const [filterGroup, setFilterGroup] = useState<string>("all");
  const [searchTerm, setSearchTerm] = useState<string>("");

  // 🔄 Carrega dados só depois que o hook liberar o acesso
  useEffect(() => {
    if (checking || !allowed) return;

    async function loadData() {
      setLoading(true);
      setErrorMsg(null);

      try {
        const [rolesData, permsData] = await Promise.all([
          apiClient.get<any>("/api/admin/roles"),
          apiClient.get<Permission[]>("/api/admin/permissions"),
        ]);

        const mappedRoles: Role[] = Array.isArray(rolesData)
          ? rolesData.map((r: any) => ({
              id: r.id,
              name: r.name ?? r.nome ?? "",
              description: r.description ?? r.descricao ?? "",
              slug: r.slug,
              permissions: Array.isArray(r.permissions)
                ? r.permissions
                    .map((p: any) => {
                      if (typeof p === "string") return p;
                      if (p.key) return p.key;
                      if (p.chave) return p.chave;
                      return "";
                    })
                    .filter(Boolean)
                : [],
            }))
          : [];

        setRoles(mappedRoles);
        setPermissions(permsData);
      } catch (err: any) {
        console.error(err);
        if (err?.status === 401 || err?.status === 403) {
          toast.error("Sessão expirada. Faça login novamente.");
          logout();
          router.replace("/admin/login");
          return;
        }
        setErrorMsg(
          err?.message ||
            "Não foi possível carregar papéis e permissões no momento.",
        );
      } finally {
        setLoading(false);
      }
    }

    loadData();
  }, [allowed, checking, logout, router]);

  // grupos únicos para o select do filtro
  const permissionGroups = useMemo(() => {
    const set = new Set<string>();
    permissions.forEach((p) => {
      if (p.grupo) set.add(p.grupo);
    });
    return Array.from(set).sort();
  }, [permissions]);

  // aplica filtros (grupo + busca)
  const filteredPermissions = useMemo(() => {
    const term = searchTerm.trim().toLowerCase();

    return permissions.filter((p) => {
      const matchGroup = filterGroup === "all" ? true : p.grupo === filterGroup;
      if (!matchGroup) return false;

      if (!term) return true;

      const inKey = p.chave.toLowerCase().includes(term);
      const inDesc = (p.descricao ?? "").toLowerCase().includes(term);

      return inKey || inDesc;
    });
  }, [permissions, filterGroup, searchTerm]);

  // Enquanto o hook está checando, exibimos um skeleton simples
  if (checking) {
    return (
      <main className="mx-auto w-full max-w-6xl px-4 py-6 text-slate-50 sm:px-8">
        <header className="flex items-start justify-between gap-3">
          <div className="space-y-1">
            <p className="inline-flex items-center rounded-full border border-emerald-500/40 bg-emerald-500/10 px-2 py-[2px] text-[10px] font-medium uppercase tracking-[0.16em] text-emerald-300">
              Configurações • Usuários & Permissões
            </p>
            <div className="mt-2 h-5 w-48 animate-pulse rounded bg-slate-800" />
          </div>
          <div className="sm:hidden">
            <CloseButton className="text-slate-400 hover:text-slate-100 text-3xl" />
          </div>
        </header>
        <section className="mt-4 h-40 animate-pulse rounded-2xl border border-slate-800 bg-slate-950/80" />
      </main>
    );
  }

  if (!allowed) return null;

  async function handleCreateRole() {
    if (!newRoleName.trim()) return;

    const nome = newRoleName.trim();
    const descricao = newRoleDescription.trim();
    const slug = slugify(nome);

    setCreatingRole(true);
    try {
      const created = await apiClient.post<any>("/api/admin/roles", {
        name: nome,
        nome,
        slug,
        description: descricao || undefined,
        descricao: descricao || undefined,
      });

      const newRole: Role = {
        id: created.id,
        name: created.name ?? created.nome ?? nome,
        description:
          created.description ?? created.descricao ?? (descricao || ""),
        slug: created.slug ?? slug,
        permissions: Array.isArray(created.permissions)
          ? created.permissions
              .map((p: any) => {
                if (typeof p === "string") return p;
                if (p.key) return p.key;
                if (p.chave) return p.chave;
                return "";
              })
              .filter(Boolean)
          : [],
      };

      setRoles((prev) => [...prev, newRole]);
      setNewRoleName("");
      setNewRoleDescription("");
      toast.success("Papel criado com sucesso.");
    } catch (err: any) {
      console.error(err);
      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        logout();
        router.replace("/admin/login");
        return;
      }
      toast.error(err?.message || "Erro ao criar papel.");
    } finally {
      setCreatingRole(false);
    }
  }

  async function handleCreatePermission() {
    if (!newPermKey.trim() || !newPermGroup.trim()) return;

    const chave = newPermKey.trim().toLowerCase();
    const grupo = newPermGroup.trim();
    const descricao = newPermDescription.trim();

    setCreatingPerm(true);
    try {
      const created: Permission = await apiClient.post<Permission>(
        "/api/admin/permissions",
        {
          chave,
          grupo,
          descricao: descricao || undefined,
        },
      );

      setPermissions((prev) => [...prev, created]);
      setNewPermKey("");
      setNewPermGroup("");
      setNewPermDescription("");
      toast.success("Permissão criada com sucesso.");
    } catch (err: any) {
      console.error(err);
      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        logout();
        router.replace("/admin/login");
        return;
      }
      toast.error(err?.message || "Erro ao criar permissão.");
    } finally {
      setCreatingPerm(false);
    }
  }

  async function handleToggleRolePermission(
    roleId: number,
    permKey: string,
    checked: boolean,
  ) {
    const previousRoles = roles;

    const updatedRoles = roles.map((role) => {
      if (role.id !== roleId) return role;
      const alreadyHas = role.permissions.includes(permKey);

      if (checked && !alreadyHas) {
        return { ...role, permissions: [...role.permissions, permKey] };
      }
      if (!checked && alreadyHas) {
        return {
          ...role,
          permissions: role.permissions.filter((p) => p !== permKey),
        };
      }
      return role;
    });

    setRoles(updatedRoles);

    try {
      const roleToUpdate = updatedRoles.find((r) => r.id === roleId);
      if (!roleToUpdate) return;

      await apiClient.put(`/api/admin/roles/${roleId}`, {
        permissions: roleToUpdate.permissions,
      });

      toast.success("Permissões do papel atualizadas.");
    } catch (err: any) {
      console.error(err);
      setRoles(previousRoles);
      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        logout();
        router.replace("/admin/login");
        return;
      }
      toast.error(err?.message || "Erro ao atualizar permissões.");
    }
  }

  async function handleDeletePermission(perm: Permission) {
    if (!canManagePermissions) {
      toast.error("Você não tem permissão para excluir permissões.");
      return;
    }

    const ok = confirm(
      `Tem certeza que deseja excluir esta permissão?\n\n${perm.chave}\nGrupo: ${perm.grupo}\n\nIsso pode afetar o acesso de usuários no admin.`,
    );
    if (!ok) return;

    const prevPerms = permissions;
    const prevRoles = roles;

    // otimista: remove permissão da lista e remove de todos os roles
    setPermissions((p) => p.filter((x) => x.id !== perm.id));
    setRoles((rs) =>
      rs.map((r) => ({
        ...r,
        permissions: r.permissions.filter((k) => k !== perm.chave),
      })),
    );

    try {
      await apiClient.del(`/api/admin/permissions/${perm.id}`);

      toast.success("Permissão excluída com sucesso.");
    } catch (err: any) {
      console.error(err);
      // rollback
      setPermissions(prevPerms);
      setRoles(prevRoles);
      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        logout();
        router.replace("/admin/login");
        return;
      }
      toast.error(err?.message || "Erro ao excluir permissão.");
    }
  }

  const DeletePermButton = ({ perm }: { perm: Permission }) => {
    if (!canManagePermissions) return null;
    return (
      <button
        type="button"
        onClick={() => handleDeletePermission(perm)}
        title="Excluir permissão"
        aria-label={`Excluir permissão ${perm.chave}`}
        className="inline-flex h-8 w-8 items-center justify-center rounded-lg border border-slate-800 bg-slate-900/70 text-base text-slate-200 hover:bg-rose-950/40 hover:text-rose-200 hover:border-rose-900/60 transition-colors"
      >
        🗑️
      </button>
    );
  };

  return (
    <main className="mx-auto flex w-full max-w-6xl flex-col gap-5 px-4 py-6 text-slate-50 sm:px-8">
      {/* Header */}
      <header className="flex items-start justify-between gap-3">
        <div className="space-y-1">
          <p className="inline-flex items-center rounded-full border border-emerald-500/40 bg-emerald-500/10 px-2 py-[2px] text-[10px] font-medium uppercase tracking-[0.16em] text-emerald-300">
            Configurações • Usuários & Permissões
          </p>
          <h1 className="mt-1 text-2xl font-bold sm:text-3xl">
            Papéis e permissões
          </h1>
          <p className="max-w-2xl text-sm text-slate-400">
            Defina os papéis administrativos (master, gerente, suporte, leitura,
            etc.) e quais permissões cada um deles possui dentro do painel.
          </p>
        </div>

        <div className="flex flex-col items-end gap-2">
          <div className="sm:hidden">
            <CloseButton className="text-slate-400 hover:text-slate-100 text-3xl" />
          </div>
        </div>
      </header>

      {loading ? (
        <section className="rounded-2xl border border-slate-800 bg-slate-950/80 p-4 text-sm text-slate-200">
          Carregando papéis e permissões...
        </section>
      ) : errorMsg ? (
        <section className="rounded-2xl border border-rose-900/60 bg-rose-950/40 p-4 text-sm text-rose-100">
          {errorMsg}
        </section>
      ) : (
        <>
          {/* Seção de criação */}
          <section className="grid gap-4 lg:grid-cols-2">
            {/* Novo papel */}
            <div className="rounded-2xl border border-slate-800 bg-slate-950/80 p-4 sm:p-5">
              <div className="mb-3 flex items-center justify-between gap-2">
                <h2 className="text-sm font-semibold">Criar novo papel</h2>
                <span className="text-[11px] text-slate-400">
                  Ex: master, gerente_marketing, suporte_financeiro
                </span>
              </div>

              <div className="space-y-3">
                <div className="space-y-2">
                  <label className="block text-xs font-medium text-slate-300">
                    Nome do papel
                  </label>
                  <input
                    className="h-9 w-full rounded-lg border border-slate-700 bg-slate-900 px-3 text-sm text-slate-100"
                    placeholder="Ex: master, gerente_marketing"
                    value={newRoleName}
                    onChange={(e) => setNewRoleName(e.target.value)}
                  />
                  {newRoleName.trim() && (
                    <p className="mt-1 text-[11px] text-slate-500">
                      Slug gerado:{" "}
                      <span className="font-mono">
                        {slugify(newRoleName.trim())}
                      </span>
                    </p>
                  )}
                </div>

                <div className="space-y-2">
                  <label className="block text-xs font-medium text-slate-300">
                    Descrição (opcional)
                  </label>
                  <textarea
                    className="min-h-[60px] w-full rounded-lg border border-slate-700 bg-slate-900 px-3 py-2 text-sm text-slate-100"
                    placeholder="Ex: Acesso total a todos os módulos do painel."
                    value={newRoleDescription}
                    onChange={(e) => setNewRoleDescription(e.target.value)}
                  />
                </div>

                <div className="flex justify-end">
                  <button
                    type="button"
                    disabled={creatingRole || !newRoleName.trim()}
                    onClick={handleCreateRole}
                    className="inline-flex items-center rounded-lg bg-emerald-600 px-4 py-2 text-xs font-semibold text-white disabled:opacity-60"
                  >
                    {creatingRole ? "Salvando..." : "Criar papel"}
                  </button>
                </div>
              </div>
            </div>

            {/* Nova permissão */}
            <div className="rounded-2xl border border-slate-800 bg-slate-950/80 p-4 sm:p-5">
              <div className="mb-3 flex items-center justify-between gap-2">
                <h2 className="text-sm font-semibold">Criar nova permissão</h2>
                <span className="text-[11px] text-slate-400">
                  Disponível apenas para quem tem permissions_manage
                </span>
              </div>

              {!canManagePermissions ? (
                <p className="text-xs text-slate-500">
                  Seu usuário não possui a permissão{" "}
                  <span className="font-semibold">permissions_manage</span>.
                </p>
              ) : (
                <div className="space-y-3">
                  <div className="space-y-2">
                    <label className="block text-xs font-medium text-slate-300">
                      Chave da permissão (key)
                    </label>
                    <input
                      className="h-9 w-full rounded-lg border border-slate-700 bg-slate-900 px-3 text-sm text-slate-100"
                      placeholder="Ex: products_manage, orders_view"
                      value={newPermKey}
                      onChange={(e) => setNewPermKey(e.target.value)}
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="block text-xs font-medium text-slate-300">
                      Grupo
                    </label>
                    <input
                      className="h-9 w-full rounded-lg border border-slate-700 bg-slate-900 px-3 text-sm text-slate-100"
                      placeholder="Ex: produtos, pedidos, relatorios, marketing..."
                      value={newPermGroup}
                      onChange={(e) => setNewPermGroup(e.target.value)}
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="block text-xs font-medium text-slate-300">
                      Descrição (opcional)
                    </label>
                    <textarea
                      className="min-h-[60px] w-full rounded-lg border border-slate-700 bg-slate-900 px-3 py-2 text-sm text-slate-100"
                      placeholder="Explique onde essa permissão será usada dentro do painel."
                      value={newPermDescription}
                      onChange={(e) => setNewPermDescription(e.target.value)}
                    />
                  </div>

                  <div className="flex justify-end">
                    <button
                      type="button"
                      disabled={
                        creatingPerm ||
                        !newPermKey.trim() ||
                        !newPermGroup.trim()
                      }
                      onClick={handleCreatePermission}
                      className="inline-flex items-center rounded-lg bg-sky-600 px-4 py-2 text-xs font-semibold text-white disabled:opacity-60"
                    >
                      {creatingPerm ? "Salvando..." : "Criar permissão"}
                    </button>
                  </div>
                </div>
              )}
            </div>
          </section>

          {/* Matriz */}
          <section className="rounded-2xl border border-slate-800 bg-slate-950/90">
            <div className="border-b border-slate-800 px-4 py-3">
              <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
                <div>
                  <h2 className="text-sm font-semibold">
                    Matriz de papéis x permissões
                  </h2>
                  <p className="text-[11px] text-slate-400">
                    Marque quais permissões cada papel administrativo possui.
                  </p>
                </div>
                <div className="text-[11px] text-slate-400">
                  {roles.length} papel(is) • {permissions.length} permissão(ões)
                </div>
              </div>

              <div className="mt-3 flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                <div className="flex gap-2">
                  <select
                    className="h-9 rounded-lg border border-slate-700 bg-slate-900 px-3 text-xs text-slate-100"
                    value={filterGroup}
                    onChange={(e) => setFilterGroup(e.target.value)}
                  >
                    <option value="all">Todos os grupos</option>
                    {permissionGroups.map((g) => (
                      <option key={g} value={g}>
                        {g}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="flex flex-1 gap-2 sm:justify-end">
                  <input
                    className="h-9 w-full rounded-lg border border-slate-700 bg-slate-900 px-3 text-xs text-slate-100 sm:max-w-xs"
                    placeholder="Buscar permissão por chave ou descrição..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
              </div>
            </div>

            {roles.length === 0 || permissions.length === 0 ? (
              <div className="p-4 text-sm text-slate-300">
                Cadastre ao menos um papel e uma permissão para começar a
                configurar a matriz.
              </div>
            ) : filteredPermissions.length === 0 ? (
              <div className="p-4 text-sm text-slate-300">
                Nenhuma permissão encontrada com os filtros atuais.
              </div>
            ) : (
              <>
                {/* Mobile */}
                <div className="md:hidden divide-y divide-slate-900/80">
                  {filteredPermissions.map((perm) => (
                    <div
                      key={perm.id}
                      className="px-4 py-3 hover:bg-slate-950/80 transition-colors"
                    >
                      <div className="flex items-start justify-between gap-3">
                        <div className="flex flex-col gap-1">
                          <span className="text-sm font-semibold text-slate-50">
                            {perm.chave}
                          </span>
                          <span className="text-[11px] text-emerald-300">
                            Grupo: {perm.grupo}
                          </span>
                          {perm.descricao && (
                            <span className="text-[11px] text-slate-400">
                              {perm.descricao}
                            </span>
                          )}
                        </div>

                        <DeletePermButton perm={perm} />
                      </div>

                      <div className="mt-3 grid grid-cols-2 gap-2">
                        {roles.map((role) => {
                          const checked = role.permissions.includes(perm.chave);
                          return (
                            <label
                              key={role.id}
                              className="flex items-center gap-2 rounded-lg border border-slate-800 bg-slate-900/80 px-2 py-2 text-[11px]"
                            >
                              <input
                                type="checkbox"
                                className="h-4 w-4 accent-emerald-500"
                                checked={checked}
                                onChange={(e) =>
                                  handleToggleRolePermission(
                                    role.id,
                                    perm.chave,
                                    e.target.checked,
                                  )
                                }
                              />
                              <span className="text-slate-100">
                                {role.name}
                              </span>
                            </label>
                          );
                        })}
                      </div>
                    </div>
                  ))}
                </div>

                {/* Desktop */}
                <div className="hidden md:block overflow-x-auto">
                  <table className="min-w-full border-separate border-spacing-0 text-xs">
                    <thead>
                      <tr className="bg-slate-900/80 text-[11px] uppercase tracking-wide text-slate-400">
                        <th className="border-b border-slate-800 px-3 py-2 text-left">
                          Permissão
                        </th>
                        {roles.map((role) => (
                          <th
                            key={role.id}
                            className="border-b border-slate-800 px-3 py-2 text-center"
                          >
                            {role.name}
                          </th>
                        ))}
                      </tr>
                    </thead>

                    <tbody>
                      {filteredPermissions.map((perm, index) => (
                        <tr
                          key={perm.id}
                          className={
                            index % 2 === 0
                              ? "bg-slate-950/60"
                              : "bg-slate-900/40"
                          }
                        >
                          <td className="border-b border-slate-900/80 px-3 py-2 align-top">
                            <div className="flex items-start justify-between gap-3">
                              <div className="flex flex-col gap-1">
                                <span className="font-medium text-slate-50">
                                  {perm.chave}
                                </span>
                                <span className="text-[11px] text-emerald-300">
                                  Grupo: {perm.grupo}
                                </span>
                                {perm.descricao && (
                                  <span className="text-[11px] text-slate-500">
                                    {perm.descricao}
                                  </span>
                                )}
                              </div>

                              <DeletePermButton perm={perm} />
                            </div>
                          </td>

                          {roles.map((role) => {
                            const checked = role.permissions.includes(
                              perm.chave,
                            );
                            return (
                              <td
                                key={role.id}
                                className="border-b border-slate-900/80 px-3 py-2 text-center align-middle"
                              >
                                <input
                                  type="checkbox"
                                  className="h-4 w-4 accent-emerald-500"
                                  checked={checked}
                                  onChange={(e) =>
                                    handleToggleRolePermission(
                                      role.id,
                                      perm.chave,
                                      e.target.checked,
                                    )
                                  }
                                />
                              </td>
                            );
                          })}
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </>
            )}
          </section>
        </>
      )}
    </main>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import Link from "next/link";
import { toast } from "react-hot-toast";
import apiClient from "@/lib/apiClient";
import CustomButton from "@/components/buttons/CustomButton";
import CloseButton from "@/components/buttons/CloseButton";
import type { Coupon } from "@/types/coupon";
import { emptyCoupon } from "@/types/coupon";

export default function CuponsPage() {
  const [cupons, setCupons] = useState<Coupon[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [editing, setEditing] = useState<Coupon | null>(null);
  const [form, setForm] = useState<Coupon>(emptyCoupon);

  const formRef = useRef<HTMLDivElement | null>(null);

  // ========= helpers =========

  function scrollToForm() {
    if (formRef.current) {
      formRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }

  function handleChange(
    field: keyof Coupon,
    value: string | number | boolean | null,
  ) {
    setForm((prev) => ({
      ...prev,
      [field]: value,
    }));
  }

  function handleNovoCupom() {
    setEditing(null);
    setForm(emptyCoupon);
    scrollToForm();
  }

  function handleEditarCupom(cupom: Coupon) {
    setEditing(cupom);
    setForm({
      ...cupom,
      expiracao: cupom.expiracao ? cupom.expiracao.slice(0, 16) : "",
    });
    scrollToForm();
  }

  // ========= requests =========

  async function carregarCupons() {
    setLoading(true);
    setError(null);

    try {
      const data = await apiClient.get<Coupon[]>("/api/admin/cupons");
      setCupons(data);
    } catch (err: any) {
      console.error(err);
      if (err?.status === 401 || err?.status === 403) {
        const msg = "Sessão expirada ou sem permissão. Faça login no admin.";
        setError(msg);
        toast.error(msg);
        setCupons([]);
        return;
      }
      const msg = err?.message || "Erro ao carregar cupons.";
      setError(msg);
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    carregarCupons();
  }, []);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    setError(null);

    try {
      const payload = {
        codigo: form.codigo.trim(),
        tipo: form.tipo,
        valor: Number(form.valor),
        minimo: Number(form.minimo) || 0,
        expiracao: form.expiracao || null,
        max_usos:
          form.max_usos === null || (form.max_usos as any) === ""
            ? null
            : Number(form.max_usos),
        ativo: !!form.ativo,
      };

      if (editing) {
        await apiClient.put(`/api/admin/cupons/${editing.id}`, payload);
      } else {
        await apiClient.post("/api/admin/cupons", payload);
      }

      await carregarCupons();
      setEditing(null);
      setForm(emptyCoupon);
      toast.success(
        editing ? "Cupom atualizado com sucesso." : "Cupom criado com sucesso.",
      );
    } catch (err: any) {
      console.error(err);
      if (err?.status === 401 || err?.status === 403) {
        const msg = "Sessão expirada ou sem permissão. Faça login no admin.";
        setError(msg);
        toast.error(msg);
        return;
      }
      const msg = err?.message || "Erro ao salvar o cupom.";
      setError(msg);
      toast.error(msg);
    } finally {
      setSaving(false);
    }
  }

  async function handleRemoverCupom(id: number) {
    if (!confirm("Deseja realmente remover este cupom?")) return;

    try {
      await apiClient.del(`/api/admin/cupons/${id}`);

      setCupons((prev) => prev.filter((c) => c.id !== id));
      toast.success("Cupom removido com sucesso.");
    } catch (err: any) {
      console.error(err);
      if (err?.status === 401 || err?.status === 403) {
        toast.error("Sessão expirada ou sem permissão. Faça login no admin.");
        return;
      }
      const msg = err?.message || "Erro ao remover o cupom.";
      setError(msg);
      toast.error(msg);
    }
  }

  // ========= UI =========

  return (
    <div className="min-h-screen bg-[#050816] text-gray-100">
      <div className="mx-auto flex max-w-6xl flex-col gap-6 px-4 py-6 sm:px-6 lg:px-8">
        {/* Header */}
        <header className="relative flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <p className="text-xs uppercase tracking-[0.2em] text-[#38bdf8]/80">
              Marketing interno
            </p>
            <h1 className="mt-1 text-2xl font-extrabold tracking-tight text-[#359293] sm:text-3xl">
              Cupons e Promoções
            </h1>
            <p className="mt-1 text-sm text-gray-300">
              Crie cupons de desconto para campanhas internas do Kavita.
            </p>
          </div>

          {/* Botões de navegação:
              - CloseButton: só no mobile (X que volta)
              - Voltar: só no desktop */}
          <div className="absolute right-0 top-0 flex items-center gap-2 sm:static">
            <div className="block sm:hidden">
              <CloseButton className="text-3xl text-gray-100 hover:text-[#38bdf8]" />
            </div>

            <Link href="/admin" className="hidden sm:block">
              <CustomButton
                label="Voltar"
                variant="secondary"
                size="small"
                isLoading={false}
              />
            </Link>
          </div>
        </header>

        {error && (
          <div className="rounded-md border border-red-500 bg-red-500/10 px-4 py-2 text-sm text-red-200">
            {error}
          </div>
        )}

        {/* Layout: Form + Lista */}
        <div className="grid gap-6 lg:grid-cols-[minmax(0,1.3fr)_minmax(0,2fr)]">
          {/* Formulário */}
          <section
            ref={formRef}
            className="rounded-2xl border border-white/5 bg-[#0b1120] p-4 shadow-xl shadow-black/40 sm:p-6"
          >
            <div className="mb-4 flex items-center justify-between gap-2">
              <div>
                <h2 className="text-lg font-semibold text-white">
                  {editing ? "Editar cupom" : "Novo cupom"}
                </h2>
                <p className="mt-1 text-xs text-gray-400">
                  Defina código, tipo de desconto e regras de uso.
                </p>
              </div>

              {editing && (
                <button
                  type="button"
                  onClick={handleNovoCupom}
                  className="text-xs font-medium text-[#38bdf8] hover:underline"
                >
                  + Criar novo
                </button>
              )}
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-1">
                <label className="text-sm font-medium text-gray-200">
                  Código
                </label>
                <input
                  type="text"
                  value={form.codigo}
                  onChange={(e) => handleChange("codigo", e.target.value)}
                  className="w-full rounded-lg border border-white/10 bg-[#020617] px-3 py-2 text-sm text-white outline-none ring-0 focus:border-[#38bdf8]"
                  placeholder="PROMO10"
                  required
                />
                <p className="text-[11px] text-gray-400">
                  Esse é o código que o cliente vai digitar no checkout.
                </p>
              </div>

              <div className="grid gap-3 sm:grid-cols-2">
                <div className="space-y-1">
                  <label className="text-sm font-medium text-gray-200">
                    Tipo
                  </label>
                  <select
                    value={form.tipo}
                    onChange={(e) =>
                      handleChange("tipo", e.target.value as Coupon["tipo"])
                    }
                    className="w-full rounded-lg border border-white/10 bg-[#020617] px-3 py-2 text-sm text-white outline-none focus:border-[#38bdf8]"
                  >
                    <option value="percentual">% (percentual)</option>
                    <option value="valor">R$ (valor fixo)</option>
                  </select>
                </div>

                <div className="space-y-1">
                  <label className="text-sm font-medium text-gray-200">
                    Valor
                  </label>
                  <input
                    type="number"
                    step="0.01"
                    min={0}
                    value={form.valor}
                    onChange={(e) =>
                      handleChange("valor", Number(e.target.value))
                    }
                    className="w-full rounded-lg border border-white/10 bg-[#020617] px-3 py-2 text-sm text-white outline-none focus:border-[#38bdf8]"
                    placeholder="10"
                    required
                  />
                </div>
              </div>

              <div className="grid gap-3 sm:grid-cols-2">
                <div className="space-y-1">
                  <label className="text-sm font-medium text-gray-200">
                    Mínimo de compra (R$)
                  </label>
                  <input
                    type="number"
                    step="0.01"
                    min={0}
                    value={form.minimo}
                    onChange={(e) =>
                      handleChange("minimo", Number(e.target.value))
                    }
                    className="w-full rounded-lg border border-white/10 bg-[#020617] px-3 py-2 text-sm text-white outline-none focus:border-[#38bdf8]"
                    placeholder="0"
                  />
                  <p className="text-[11px] text-gray-400">
                    Valor mínimo do pedido para o cupom ser aceito.
                  </p>
                </div>

                <div className="space-y-1">
                  <label className="text-sm font-medium text-gray-200">
                    Máx. de usos
                  </label>
                  <input
                    type="number"
                    min={0}
                    value={form.max_usos ?? ""}
                    onChange={(e) =>
                      handleChange(
                        "max_usos",
                        e.target.value === "" ? null : Number(e.target.value),
                      )
                    }
                    className="w-full rounded-lg border border-white/10 bg-[#020617] px-3 py-2 text-sm text-white outline-none focus:border-[#38bdf8]"
                    placeholder="Ilimitado"
                  />
                  <p className="text-[11px] text-gray-400">
                    Deixe em branco para uso ilimitado.
                  </p>
                </div>
              </div>

              <div className="grid gap-3 sm:grid-cols-2">
                <div className="space-y-1">
                  <label className="text-sm font-medium text-gray-200">
                    Expiração
                  </label>
                  <input
                    type="datetime-local"
                    value={form.expiracao || ""}
                    onChange={(e) => handleChange("expiracao", e.target.value)}
                    className="w-full rounded-lg border border-white/10 bg-[#020617] px-3 py-2 text-sm text-white outline-none focus:border-[#38bdf8]"
                  />
                  <p className="text-[11px] text-gray-400">
                    Deixe em branco para não expirar.
                  </p>
                </div>

                <div className="flex items-center gap-3 pt-6">
                  <input
                    id="ativo"
                    type="checkbox"
                    checked={!!form.ativo}
                    onChange={(e) => handleChange("ativo", e.target.checked)}
                    className="h-4 w-4 rounded border-white/30 bg-[#020617] text-[#38bdf8] focus:ring-0"
                  />
                  <label htmlFor="ativo" className="text-sm text-gray-200">
                    Cupom ativo
                  </label>
                </div>
              </div>

              <div className="pt-2">
                <button
                  type="submit"
                  disabled={saving}
                  className="inline-flex items-center justify-center rounded-lg bg-[#38bdf8] px-4 py-2 text-sm font-semibold text-[#020617] shadow-md shadow-cyan-500/30 transition hover:bg-[#0ea5e9] disabled:opacity-60"
                >
                  {saving
                    ? "Salvando..."
                    : editing
                      ? "Salvar alterações"
                      : "Criar cupom"}
                </button>
              </div>
            </form>
          </section>

          {/* Lista de cupons */}
          <section className="space-y-3">
            <div className="flex items-center justify-between gap-2">
              <h2 className="text-lg font-semibold text-white">
                Cupons cadastrados
              </h2>
              <button
                type="button"
                onClick={handleNovoCupom}
                className="text-xs font-medium text-[#38bdf8] hover:underline"
              >
                + Novo cupom
              </button>
            </div>

            {loading ? (
              <p className="text-sm text-gray-300">Carregando cupons...</p>
            ) : cupons.length === 0 ? (
              <p className="text-sm text-gray-300">
                Nenhum cupom cadastrado ainda.
              </p>
            ) : (
              <div className="space-y-3">
                {cupons.map((c) => (
                  <div
                    key={c.id}
                    className="flex flex-col gap-3 rounded-2xl border border-white/5 bg-[#020617] p-4 text-sm text-gray-100 shadow-md shadow-black/40 sm:flex-row sm:items-center sm:justify-between"
                  >
                    <div className="space-y-1">
                      <div className="flex flex-wrap items-center gap-2">
                        <span className="rounded-full bg-[#38bdf8]/10 px-3 py-1 text-xs font-semibold text-[#38bdf8]">
                          {c.codigo}
                        </span>
                        {!c.ativo && (
                          <span className="rounded-full bg-red-500/10 px-2 py-0.5 text-[11px] font-medium text-red-300">
                            Inativo
                          </span>
                        )}
                      </div>
                      <div className="text-xs text-gray-300">
                        {(() => {
                          const valor = Number(c.valor) || 0;
                          const minimo = Number(c.minimo) || 0;

                          return (
                            <>
                              {c.tipo === "percentual"
                                ? `Desconto de ${valor}%`
                                : `Desconto de R$ ${valor.toFixed(2)}`}
                              {minimo > 0 && (
                                <> · Mínimo R$ {minimo.toFixed(2)}</>
                              )}
                            </>
                          );
                        })()}
                      </div>
                      <div className="text-[11px] text-gray-400">
                        Usos: {c.usos}
                        {c.max_usos != null && ` / ${c.max_usos}`}
                        {c.expiracao && (
                          <>
                            {" "}
                            · expira em{" "}
                            {new Date(c.expiracao).toLocaleString("pt-BR")}
                          </>
                        )}
                      </div>
                    </div>

                    <div className="flex gap-2 pt-2 sm:pt-0">
                      <button
                        type="button"
                        onClick={() => handleEditarCupom(c)}
                        className="rounded-lg border border-white/10 px-3 py-1.5 text-xs font-medium text-gray-100 hover:border-[#38bdf8] hover:text-[#38bdf8]"
                      >
                        Editar
                      </button>
                      <button
                        type="button"
                        onClick={() => handleRemoverCupom(c.id)}
                        className="rounded-lg border border-red-500/40 px-3 py-1.5 text-xs font-medium text-red-300 hover:bg-red-500/10"
                      >
                        Remover
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </section>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import Image from "next/image";
import { useRouter } from "next/navigation";
import toast from "react-hot-toast";
import DeleteButton from "@/components/buttons/DeleteButton";
import SearchInputProdutos from "@/components/products/SearchInput";
import CloseButton from "@/components/buttons/CloseButton";
import apiClient from "@/lib/apiClient";

type Promocao = {
  id: number;
  product_id: number;
  name: string;
  image: string | null;

  original_price: number | string;
  final_price: number | string;
  discount_percent: number | null;
  promo_price: number | null;

  title: string | null;
  type: "PROMOCAO" | "FLASH" | string;
  start_at?: string | null;
  end_at?: string | null;
  is_active?: 0 | 1;
  status?: string; // ATIVA / INATIVA
};

type FormMode = "idle" | "create" | "edit";

const API_BASE = process.env.NEXT_PUBLIC_API_BASE ?? "http://localhost:5000";
const PLACEHOLDER = "https://via.placeholder.com/400x240?text=Sem+imagem";

function toImageUrl(raw?: string | null) {
  if (!raw) return PLACEHOLDER;
  const p = String(raw).trim().replace(/\\/g, "/");
  if (/^https?:\/\//i.test(p)) return p;
  const clean = p.replace(/^\/+/, "");
  if (clean.startsWith("uploads/")) return `${API_BASE}/${clean}`;
  if (clean.startsWith("public/")) return `${API_BASE}/${clean}`;
  return `${API_BASE}/uploads/${clean}`;
}

function toArray(json: any): any[] {
  if (Array.isArray(json)) return json;
  if (json && Array.isArray(json.data)) return json.data;
  if (json && Array.isArray(json.rows)) return json.rows;
  if (json && Array.isArray(json.products)) return json.products;
  if (json && Array.isArray(json.items)) return json.items;
  return [];
}

function toInputDateTime(value?: string | null) {
  if (!value) return "";
  const s = value.replace(" ", "T");
  return s.slice(0, 16);
}

export default function MarketingPromocoesPage() {
  const router = useRouter();

  const [promocoes, setPromocoes] = useState<Promocao[]>([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState<string | null>(null);

  // ----- estado do formulário -----
  const [mode, setMode] = useState<FormMode>("idle");
  const [formPromoId, setFormPromoId] = useState<number | null>(null);
  const [formProductId, setFormProductId] = useState<number | null>(null);
  const [formProductName, setFormProductName] = useState<string>("");
  const [formBasePrice, setFormBasePrice] = useState<number | null>(null);
  const [formTitle, setFormTitle] = useState<string>("");
  const [formType, setFormType] = useState<"PROMOCAO" | "FLASH">("PROMOCAO");
  const [formDiscountPercent, setFormDiscountPercent] = useState<string>("10");
  const [formPromoPrice, setFormPromoPrice] = useState<string>("");
  const [formStartAt, setFormStartAt] = useState<string>("");
  const [formEndAt, setFormEndAt] = useState<string>("");
  const [formActive, setFormActive] = useState<boolean>(true);
  const [saving, setSaving] = useState<boolean>(false);

  useEffect(() => {
    buscarPromocoes();
  }, []);

  async function buscarPromocoes() {
    try {
      setLoading(true);
      setErr(null);

      const json = await apiClient.get<any>("/api/admin/marketing/promocoes");
      const list = toArray(json) as Promocao[];

      setPromocoes(
        list.map((d) => ({
          ...d,
          original_price: Number(d.original_price ?? d.final_price ?? 0),
          final_price: Number(d.final_price ?? d.original_price ?? 0),
          discount_percent:
            d.discount_percent !== null && d.discount_percent !== undefined
              ? Number(d.discount_percent)
              : null,
          promo_price:
            d.promo_price !== null && d.promo_price !== undefined
              ? Number(d.promo_price)
              : null,
          image: toImageUrl(d.image),
        })),
      );
    } catch (e: any) {
      console.error(e);
      const msg = e?.message || "Falha ao carregar promoções.";
      setErr(msg);
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }

  // --------- FORM: abrir para criação ---------
  function abrirCriarPromocao(produto: any) {
    const id = Number(produto.id);
    if (!id) {
      toast.error("Produto inválido.");
      return;
    }

    if (promocoes.some((d) => d.product_id === id)) {
      toast.error("Este produto já possui uma promoção ativa.");
      return;
    }

    setMode("create");
    setFormPromoId(null);
    setFormProductId(id);
    setFormProductName(produto.name || produto.nome || `Produto #${id}`);
    setFormBasePrice(produto.price ?? produto.preco ?? null);
    setFormTitle("");
    setFormType("PROMOCAO");
    setFormDiscountPercent("10");
    setFormPromoPrice("");
    setFormStartAt("");
    setFormEndAt("");
    setFormActive(true);
  }

  // --------- FORM: abrir para edição ---------
  function abrirEditarPromocao(promo: Promocao) {
    setMode("edit");
    setFormPromoId(promo.id);
    setFormProductId(promo.product_id);
    setFormProductName(promo.name);
    setFormBasePrice(Number(promo.original_price));
    setFormTitle(promo.title || "");
    setFormType(promo.type === "FLASH" ? "FLASH" : "PROMOCAO");
    setFormDiscountPercent(
      promo.discount_percent != null ? String(promo.discount_percent) : "",
    );
    setFormPromoPrice(
      promo.promo_price != null ? String(promo.promo_price) : "",
    );
    setFormStartAt(toInputDateTime((promo as any).start_at));
    setFormEndAt(toInputDateTime((promo as any).end_at));
    setFormActive(promo.is_active === 1 || promo.status === "ATIVA");
  }

  function limparFormulario() {
    setMode("idle");
    setFormPromoId(null);
    setFormProductId(null);
    setFormProductName("");
    setFormBasePrice(null);
    setFormTitle("");
    setFormType("PROMOCAO");
    setFormDiscountPercent("10");
    setFormPromoPrice("");
    setFormStartAt("");
    setFormEndAt("");
    setFormActive(true);
  }

  // --------- FORM: submit (criar/editar) ---------
  async function handleSubmitForm(e: React.FormEvent) {
    e.preventDefault();
    if (!formProductId) {
      toast.error("Selecione um produto para a promoção.");
      return;
    }

    const discount =
      formDiscountPercent.trim() !== "" ? Number(formDiscountPercent) : null;
    const promoPrice =
      formPromoPrice.trim() !== "" ? Number(formPromoPrice) : null;

    if (!discount && !promoPrice) {
      toast.error("Informe desconto em % ou preço promocional.");
      return;
    }

    if (discount != null && (Number.isNaN(discount) || discount <= 0)) {
      toast.error("Desconto em % inválido.");
      return;
    }

    if (promoPrice != null && (Number.isNaN(promoPrice) || promoPrice <= 0)) {
      toast.error("Preço promocional inválido.");
      return;
    }

    const payload: any = {
      title: formTitle || null,
      type: formType,
      discount_percent: discount,
      promo_price: promoPrice,
      start_at: formStartAt || null,
      end_at: formEndAt || null,
      is_active: formActive ? 1 : 0,
    };

    try {
      setSaving(true);

      if (mode === "create") {
        await apiClient.post("/api/admin/marketing/promocoes", {
          product_id: formProductId,
          ...payload,
        });
        toast.success("Promoção criada com sucesso.");
      } else if (mode === "edit" && formPromoId != null) {
        await apiClient.put(
          `/api/admin/marketing/promocoes/${formPromoId}`,
          payload,
        );
        toast.success("Promoção atualizada com sucesso.");
      }

      await buscarPromocoes();
      limparFormulario();
    } catch (error: any) {
      console.error(error);
      if (error?.status === 401 || error?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente no admin.");
        return;
      }
      toast.error(error?.message || "Erro ao salvar promoção.");
    } finally {
      setSaving(false);
    }
  }

  async function removerPromocao(id: number) {
    try {
      await apiClient.del(`/api/admin/marketing/promocoes/${id}`);

      toast.success("Promoção removida com sucesso.");
      await buscarPromocoes();
    } catch (e: any) {
      console.error(e);
      if (e?.status === 401 || e?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente no admin.");
        return;
      }
      toast.error(e?.message || "Erro ao remover promoção.");
    }
  }

  const temItens = useMemo(() => promocoes.length > 0, [promocoes]);

  return (
    <div className="w-full px-3 py-5 sm:px-4 lg:px-6">
      <div className="relative mx-auto w-full max-w-6xl">
        {/* Botão voltar (mobile) */}
        <CloseButton className="absolute right-3 -top-2 z-10 block text-2xl sm:hidden" />

        {/* Header */}
        <div className="mb-4 flex flex-col gap-3 sm:mb-6 sm:flex-row sm:items-start sm:justify-between">
          <div className="flex flex-1 flex-col gap-1">
            <h1 className="text-2xl font-extrabold tracking-tight text-[#359293] sm:text-3xl">
              Marketing & Promoções
            </h1>

            <p className="text-xs text-gray-300 sm:text-sm">
              Busque um produto e transforme em promoção. Use descontos em
              porcentagem ou preços especiais para criar campanhas como os
              grandes ecommerces.
            </p>

            <div className="mt-3 w-full sm:w-80 md:w-96">
              <SearchInputProdutos
                className="w-full"
                placeholder="Buscar produto para criar promoção..."
                onPick={(produto: any) => abrirCriarPromocao(produto)}
              />
            </div>

            {/* ✅ Botão do Hero (agora aparece SEMPRE, logo abaixo da busca) */}
            <div className="mt-3">
              <button
                type="button"
                onClick={() => router.push("/admin/destaques/site-hero")}
                className="inline-flex items-center justify-center rounded-xl border border-[#359293] bg-transparent px-4 py-2 text-xs font-semibold text-white transition hover:bg-[#359293]"
              >
                Configurar Hero Section
              </button>
            </div>
          </div>
        </div>

        {/* FORMULÁRIO DE CRIAÇÃO/EDIÇÃO */}
        {mode !== "idle" && formProductId && (
          <div className="mb-6 rounded-2xl border border-emerald-600/40 bg-slate-950/70 p-4 shadow-xl sm:p-5">
            <div className="mb-3 flex items-center justify-between gap-3">
              <div>
                <h2 className="text-base font-semibold text-emerald-100 sm:text-lg">
                  {mode === "create" ? "Criar promoção" : "Editar promoção"}
                </h2>
                <p className="text-[11px] text-slate-300 sm:text-xs">
                  {formProductName}{" "}
                  {formBasePrice != null && (
                    <span className="ml-1 text-[11px] text-slate-400">
                      (Preço cheio: R$ {formBasePrice.toFixed(2)})
                    </span>
                  )}
                </p>
              </div>

              <button
                type="button"
                onClick={limparFormulario}
                className="rounded-full bg-slate-800 px-3 py-1 text-xs font-medium text-slate-100 hover:bg-slate-700"
              >
                Cancelar
              </button>
            </div>

            <form
              className="grid gap-3 sm:grid-cols-2 sm:gap-4"
              onSubmit={handleSubmitForm}
            >
              <div className="sm:col-span-2">
                <label className="mb-1 block text-xs font-medium uppercase tracking-wide text-slate-300">
                  Título da promoção (opcional)
                </label>
                <input
                  type="text"
                  value={formTitle}
                  onChange={(e) => setFormTitle(e.target.value)}
                  className="w-full rounded-xl border border-slate-700 bg-slate-900/80 px-3 py-2 text-sm text-slate-100 placeholder:text-slate-500 focus:border-emerald-500 focus:outline-none focus:ring-1 focus:ring-emerald-500"
                  placeholder="Ex.: Semana Bovinos, Oferta do Campo..."
                />
              </div>

              <div>
                <label className="mb-1 block text-xs font-medium uppercase tracking-wide text-slate-300">
                  Tipo
                </label>
                <select
                  value={formType}
                  onChange={(e) =>
                    setFormType(
                      e.target.value === "FLASH" ? "FLASH" : "PROMOCAO",
                    )
                  }
                  className="w-full rounded-xl border border-slate-700 bg-slate-900/80 px-3 py-2 text-sm text-slate-100 focus:border-emerald-500 focus:outline-none focus:ring-1 focus:ring-emerald-500"
                >
                  <option value="PROMOCAO">Promoção normal</option>
                  <option value="FLASH">Oferta relâmpago</option>
                </select>
              </div>

              <div>
                <label className="mb-1 block text-xs font-medium uppercase tracking-wide text-slate-300">
                  Desconto (%)
                </label>
                <div className="flex items-center gap-2">
                  <input
                    type="number"
                    min={0}
                    step={0.01}
                    value={formDiscountPercent}
                    onChange={(e) => setFormDiscountPercent(e.target.value)}
                    className="w-full rounded-xl border border-slate-700 bg-slate-900/80 px-3 py-2 text-sm text-slate-100 placeholder:text-slate-500 focus:border-emerald-500 focus:outline-none focus:ring-1 focus:ring-emerald-500"
                    placeholder="Ex.: 10"
                  />
                  <span className="text-xs text-slate-400">%</span>
                </div>
                <p className="mt-1 text-[10px] text-slate-400">
                  Se você preencher preço promocional abaixo, ele será
                  prioridade.
                </p>
              </div>

              <div>
                <label className="mb-1 block text-xs font-medium uppercase tracking-wide text-slate-300">
                  Preço promocional (opcional)
                </label>
                <div className="flex items-center gap-2">
                  <span className="text-xs text-slate-400">R$</span>
                  <input
                    type="number"
                    min={0}
                    step={0.01}
                    value={formPromoPrice}
                    onChange={(e) => setFormPromoPrice(e.target.value)}
                    className="w-full rounded-xl border border-slate-700 bg-slate-900/80 px-3 py-2 text-sm text-slate-100 placeholder:text-slate-500 focus:border-emerald-500 focus:outline-none focus:ring-1 focus:ring-emerald-500"
                    placeholder="Deixe em branco para usar apenas %"
                  />
                </div>
              </div>

              <div>
                <label className="mb-1 block text-xs font-medium uppercase tracking-wide text-slate-300">
                  Início (opcional)
                </label>
                <input
                  type="datetime-local"
                  value={formStartAt}
                  onChange={(e) => setFormStartAt(e.target.value)}
                  className="w-full rounded-xl border border-slate-700 bg-slate-900/80 px-3 py-2 text-sm text-slate-100 focus:border-emerald-500 focus:outline-none focus:ring-1 focus:ring-emerald-500"
                />
              </div>

              <div>
                <label className="mb-1 block text-xs font-medium uppercase tracking-wide text-slate-300">
                  Fim (opcional)
                </label>
                <input
                  type="datetime-local"
                  value={formEndAt}
                  onChange={(e) => setFormEndAt(e.target.value)}
                  className="w-full rounded-xl border border-slate-700 bg-slate-900/80 px-3 py-2 text-sm text-slate-100 focus:border-emerald-500 focus:outline-none focus:ring-1 focus:ring-emerald-500"
                />
              </div>

              <div className="flex items-center gap-2 sm:col-span-2">
                <input
                  id="promo-active"
                  type="checkbox"
                  checked={formActive}
                  onChange={(e) => setFormActive(e.target.checked)}
                  className="h-4 w-4 rounded border-slate-600 bg-slate-900 text-emerald-500 focus:ring-emerald-500"
                />
                <label
                  htmlFor="promo-active"
                  className="text-xs text-slate-200"
                >
                  Promoção ativa (aparece para os clientes enquanto estiver
                  dentro do período configurado)
                </label>
              </div>

              <div className="mt-2 flex flex-col gap-2 sm:col-span-2 sm:flex-row sm:justify-end">
                <button
                  type="button"
                  onClick={limparFormulario}
                  className="inline-flex items-center justify-center rounded-xl border border-slate-700 px-4 py-2 text-xs font-semibold text-slate-200 hover:bg-slate-800"
                >
                  Cancelar
                </button>

                <button
                  type="submit"
                  disabled={saving}
                  className="inline-flex items-center justify-center rounded-xl bg-emerald-600 px-4 py-2 text-xs font-semibold text-white shadow-md transition hover:bg-emerald-500 disabled:cursor-not-allowed disabled:opacity-70"
                >
                  {saving
                    ? "Salvando..."
                    : mode === "create"
                      ? "Criar promoção"
                      : "Salvar alterações"}
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Estados */}
        {loading && (
          <div className="mt-6 rounded-2xl bg-white p-4 text-sm text-gray-600 shadow-sm sm:p-5">
            Carregando promoções…
          </div>
        )}
        {err && !loading && (
          <div className="mt-6 rounded-2xl border border-red-300 bg-red-50 p-4 text-sm text-red-700 sm:p-5">
            {err}
          </div>
        )}
        {!loading && !err && !temItens && (
          <div className="mt-6 rounded-2xl bg-white p-4 text-sm text-gray-600 shadow-sm sm:p-5">
            Nenhuma promoção cadastrada ainda. Use a busca acima para criar a
            primeira oferta.
          </div>
        )}

        {/* Grid de promoções */}
        {temItens && (
          <div className="mt-6 grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
            {promocoes.map((promo) => {
              const original = Number(promo.original_price);
              const final = Number(promo.final_price);
              const desconto =
                promo.discount_percent ??
                (original > 0 ? ((original - final) / original) * 100 : 0);

              const isFlash = promo.type === "FLASH";
              const status = promo.status || "INATIVA";

              return (
                <article
                  key={promo.id}
                  className="flex h-full flex-col overflow-hidden rounded-xl border border-gray-100 bg-white shadow-sm transition-shadow hover:shadow-md"
                >
                  <div className="relative w-full bg-gray-100/80 pb-[56.25%]">
                    <Image
                      src={toImageUrl(promo.image)}
                      alt={String(promo.name)}
                      fill
                      className="object-cover"
                      sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 25vw"
                      onError={(e) =>
                        ((e.currentTarget as any).src = PLACEHOLDER)
                      }
                    />

                    <div className="absolute left-2 top-2 flex items-center gap-2">
                      {desconto && desconto > 0 && (
                        <span className="rounded-full bg-red-500 px-2 py-0.5 text-xs font-semibold text-white">
                          -{desconto.toFixed(0)}%
                        </span>
                      )}
                      {isFlash && (
                        <span className="rounded-full bg-amber-500 px-2 py-0.5 text-[11px] font-semibold text-white">
                          Oferta relâmpago
                        </span>
                      )}
                    </div>
                  </div>

                  <div className="flex flex-1 flex-col p-4">
                    <h2 className="truncate text-sm font-semibold text-gray-900 sm:text-base">
                      {promo.name}
                    </h2>

                    {promo.title && (
                      <p className="mt-0.5 line-clamp-2 text-xs font-medium uppercase tracking-wide text-emerald-700">
                        {promo.title}
                      </p>
                    )}

                    <div className="mt-2 flex flex-col gap-1 text-sm">
                      {original > final && (
                        <span className="text-xs text-gray-400 line-through">
                          R$ {original.toFixed(2)}
                        </span>
                      )}
                      <span className="text-base font-bold text-emerald-700">
                        R$ {final.toFixed(2)}
                      </span>
                    </div>

                    <div className="mt-2 flex items-center justify-between text-xs">
                      <span
                        className={`rounded-full px-2 py-0.5 font-semibold ${
                          status === "ATIVA"
                            ? "bg-emerald-100 text-emerald-700"
                            : "bg-gray-100 text-gray-500"
                        }`}
                      >
                        {status === "ATIVA" ? "Ativa" : "Inativa"}
                      </span>
                      <span className="text-[11px] uppercase tracking-wide text-gray-400">
                        {promo.type === "FLASH" ? "Flash" : "Promoção"}
                      </span>
                    </div>

                    <div className="mt-3 flex gap-2">
                      <button
                        type="button"
                        onClick={() => abrirEditarPromocao(promo)}
                        className="flex-1 rounded-xl border border-emerald-600 bg-emerald-50 px-3 py-1.5 text-xs font-semibold text-emerald-700 hover:bg-emerald-100"
                      >
                        Editar
                      </button>

                      <DeleteButton
                        onConfirm={() => removerPromocao(promo.id)}
                        label="Remover promoção"
                      />
                    </div>
                  </div>
                </article>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import toast from "react-hot-toast";
import apiClient from "@/lib/apiClient";

type HeroConfig = {
  hero_video_url: string;
  hero_image_url: string;

  // ✅ NOVO (opcionais)
  title?: string;
  subtitle?: string;

  button_label: string;
  button_href: string;
};

export default function SiteHeroAdminPage() {
  const router = useRouter();

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [config, setConfig] = useState<HeroConfig>({
    hero_video_url: "",
    hero_image_url: "",
    title: "",
    subtitle: "",
    button_label: "Saiba Mais",
    button_href: "/drones",
  });

  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);

  const videoPreview = useMemo(
    () => (videoFile ? URL.createObjectURL(videoFile) : config.hero_video_url),
    [videoFile, config.hero_video_url],
  );

  const imagePreview = useMemo(
    () => (imageFile ? URL.createObjectURL(imageFile) : config.hero_image_url),
    [imageFile, config.hero_image_url],
  );

  useEffect(() => {
    return () => {
      if (videoFile) URL.revokeObjectURL(videoPreview);
      if (imageFile) URL.revokeObjectURL(imagePreview);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    async function load() {
      try {
        setLoading(true);
        const data = await apiClient.get<Partial<HeroConfig>>(
          "/api/admin/site-hero",
        );

        setConfig({
          hero_video_url: data.hero_video_url || "",
          hero_image_url: data.hero_image_url || "",

          // ✅ NOVO (opcionais)
          title: data.title || "",
          subtitle: data.subtitle || "",

          button_label: data.button_label || "Saiba Mais",
          button_href: data.button_href || "/drones",
        });
      } catch (e: any) {
        console.error(e);
        if (e?.status === 401 || e?.status === 403) {
          toast.error("Sessão expirada. Faça login novamente.");
          router.push("/admin/login");
          return;
        }
        toast.error("Não foi possível carregar as configurações do Hero.");
      } finally {
        setLoading(false);
      }
    }
    load();
  }, [router]);

  async function handleSave() {
    try {
      setSaving(true);

      const fd = new FormData();
      if (videoFile) fd.append("heroVideo", videoFile);
      if (imageFile) fd.append("heroImage", imageFile);

      // ✅ NOVO (não obrigatório)
      fd.append("title", String(config.title || ""));
      fd.append("subtitle", String(config.subtitle || ""));

      fd.append("button_label", config.button_label || "");
      fd.append("button_href", config.button_href || "");

      const payload = await apiClient.put<any>("/api/admin/site-hero", fd, {
        skipContentType: true,
      });

      toast.success("Hero atualizado com sucesso!");
      setVideoFile(null);
      setImageFile(null);

      const hero = payload?.hero as HeroConfig | undefined;
      if (hero) {
        // garante que title/subtitle existam no state mesmo se vierem null
        setConfig({
          hero_video_url: hero.hero_video_url || "",
          hero_image_url: hero.hero_image_url || "",
          title: hero.title || "",
          subtitle: hero.subtitle || "",
          button_label: hero.button_label || "Saiba Mais",
          button_href: hero.button_href || "/drones",
        });
      }
    } catch (e: any) {
      console.error(e);
      if (e?.status === 401 || e?.status === 403) {
        toast.error("Sessão expirada. Faça login novamente.");
        router.push("/admin/login");
        return;
      }
      toast.error(e?.message || "Falha ao salvar Hero.");
    } finally {
      setSaving(false);
    }
  }

  function handleBack() {
    // Volta no histórico. Se não tiver histórico (ou der ruim), cai no fallback.
    try {
      router.back();
      // fallback “seguro” (executa logo depois; se back funcionar, o usuário sai antes de notar)
      setTimeout(() => {
        // ✅ FIX lint: ban-ts-comment -> usar ts-expect-error (e não ts-ignore)
        if (
          typeof window !== "undefined" &&
          window.location.pathname.includes("/admin/destaques/site-hero")
        ) {
          router.push("/admin/destaques");
        }
      }, 200);
    } catch {
      router.push("/admin/destaques");
    }
  }

  if (loading) {
    return (
      <div className="min-h-[60vh] p-4 sm:p-6 text-white">
        <div className="mx-auto w-full max-w-6xl">
          <div className="animate-pulse space-y-4">
            <div className="h-8 w-48 rounded bg-white/10" />
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 sm:gap-6">
              <div className="h-[340px] rounded-2xl bg-white/5 border border-white/10" />
              <div className="h-[340px] rounded-2xl bg-white/5 border border-white/10" />
            </div>
          </div>
        </div>
      </div>
    );
  }

  const hasAnyMedia = Boolean(videoPreview || imagePreview);

  return (
    <div className="min-h-[70vh] p-4 sm:p-6 text-white">
      <div className="mx-auto w-full max-w-6xl">
        {/* Header */}
        <div className="mb-4 sm:mb-6 flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
          <div className="flex items-start gap-3">
            {/* ✅ Botão voltar (mobile) */}
            <button
              type="button"
              onClick={handleBack}
              className="sm:hidden inline-flex h-10 w-10 items-center justify-center rounded-xl border border-white/10 bg-white/[0.04] hover:bg-white/[0.08] transition"
              aria-label="Voltar"
              title="Voltar"
            >
              <span className="text-lg leading-none">←</span>
            </button>

            <div>
              <h1 className="text-xl sm:text-2xl font-bold tracking-tight">
                Hero do Site
              </h1>
              <p className="text-sm text-white/60">
                Atualize vídeo/imagem do Hero e personalize o CTA.
              </p>
            </div>
          </div>

          <button
            disabled={saving}
            onClick={handleSave}
            className="inline-flex w-full sm:w-auto items-center justify-center gap-2 rounded-xl bg-[#359293] px-5 py-3 text-sm font-semibold text-white shadow-lg shadow-black/20 hover:opacity-90 disabled:opacity-50"
          >
            {saving ? "Salvando..." : "Salvar alterações"}
          </button>
        </div>

        {/* Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-4 sm:gap-6">
          {/* Preview */}
          <div className="lg:col-span-3 order-1">
            <div className="rounded-2xl border border-white/10 bg-white/[0.04] p-3 sm:p-4">
              <div className="flex items-center justify-between gap-3 mb-3">
                <p className="font-semibold">Preview</p>

                <div className="hidden sm:flex items-center gap-2 text-xs text-white/60">
                  <span className="rounded-full border border-white/10 bg-black/30 px-2 py-1">
                    {videoPreview ? "Vídeo" : imagePreview ? "Imagem" : "Vazio"}
                  </span>
                  <span className="rounded-full border border-white/10 bg-black/30 px-2 py-1">
                    Responsivo
                  </span>
                </div>
              </div>

              <div className="relative overflow-hidden rounded-2xl border border-white/10 bg-black/40">
                <div className="aspect-[16/9] w-full">
                  {videoPreview ? (
                    <video
                      className="absolute inset-0 h-full w-full object-cover"
                      src={videoPreview}
                      autoPlay
                      loop
                      muted
                      playsInline
                    />
                  ) : imagePreview ? (
                    <div
                      className="absolute inset-0 bg-cover bg-center"
                      style={{ backgroundImage: `url('${imagePreview}')` }}
                    />
                  ) : (
                    <div className="absolute inset-0 grid place-items-center text-white/70">
                      <div className="text-center px-6">
                        <p className="font-semibold">Sem mídia definida</p>
                        <p className="text-sm text-white/50 mt-1">
                          Envie um vídeo ou imagem para ver o Hero aqui.
                        </p>
                      </div>
                    </div>
                  )}

                  <div className="absolute inset-0 bg-gradient-to-t from-black/75 via-black/35 to-black/10" />
                  <div className="absolute inset-0 bg-gradient-to-r from-black/55 via-black/10 to-transparent" />

                  <div className="relative z-10 flex h-full items-end p-4 sm:p-6">
                    <div className="max-w-xl">
                      <h2 className="text-lg sm:text-2xl font-bold leading-tight">
                        {config.title?.trim()
                          ? config.title
                          : "Seu título aqui"}
                      </h2>
                      <p className="mt-1 sm:mt-2 text-sm sm:text-base text-white/80">
                        {config.subtitle?.trim()
                          ? config.subtitle
                          : "Seu subtítulo aqui"}
                      </p>

                      <div className="mt-4 sm:mt-5 flex flex-col xs:flex-row gap-2 xs:items-center">
                        <a
                          href={config.button_href || "#"}
                          className="inline-flex w-full xs:w-auto items-center justify-center rounded-xl border border-[#359293] bg-black/20 px-5 py-3 text-sm font-semibold text-white backdrop-blur hover:bg-[#359293]/25 transition"
                        >
                          {config.button_label || "Saiba Mais"}
                        </a>

                        <div className="text-xs text-white/55">
                          {hasAnyMedia
                            ? "Preview do CTA ativo"
                            : "Defina uma mídia"}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <p className="mt-3 text-xs text-white/50">
                *Se enviar vídeo, ele tem prioridade sobre a imagem (fallback).
              </p>
            </div>
          </div>

          {/* Form */}
          <div className="lg:col-span-2 order-2">
            <div className="rounded-2xl border border-white/10 bg-white/[0.04] p-3 sm:p-4">
              <p className="font-semibold mb-3">Configurações</p>

              <div className="space-y-4">
                {/* ✅ NOVO: Título/Subtítulo (opcional) */}
                <div className="rounded-2xl border border-white/10 bg-black/20 p-3 sm:p-4 space-y-3">
                  <div>
                    <label
                      htmlFor="heroTitleInput"
                      className="block text-sm text-white/80 mb-2"
                    >
                      Título (opcional)
                    </label>
                    <input
                      id="heroTitleInput"
                      name="heroTitleInput"
                      value={config.title || ""}
                      onChange={(e) =>
                        setConfig((p) => ({ ...p, title: e.target.value }))
                      }
                      className="w-full rounded-xl bg-black/30 border border-white/10 px-3 py-3 text-sm outline-none focus:border-[#359293]/70 focus:ring-2 focus:ring-[#359293]/20"
                      placeholder="Ex: Tecnologia que transforma o campo"
                    />
                  </div>

                  <div>
                    <label
                      htmlFor="heroSubtitleInput"
                      className="block text-sm text-white/80 mb-2"
                    >
                      Subtítulo (opcional)
                    </label>
                    <textarea
                      id="heroSubtitleInput"
                      name="heroSubtitleInput"
                      value={config.subtitle || ""}
                      onChange={(e) =>
                        setConfig((p) => ({ ...p, subtitle: e.target.value }))
                      }
                      rows={3}
                      className="w-full resize-none rounded-xl bg-black/30 border border-white/10 px-3 py-3 text-sm outline-none focus:border-[#359293]/70 focus:ring-2 focus:ring-[#359293]/20"
                      placeholder="Ex: Os drones agrícolas mais avançados do mercado"
