                        Vídeo do Hero
                      </label>
                      <p className="text-xs text-white/55 mt-1">
                        Recomendo mp4 (leve e rápido).
                      </p>
                    </div>
                    {videoFile ? (
                      <span className="shrink-0 rounded-full border border-white/10 bg-white/5 px-2 py-1 text-xs text-white/70">
