                        </p>
                      </div>

                      <span className="ml-3 shrink-0 rounded-lg bg-[#359293]/15 px-3 py-2 text-xs font-semibold text-white border border-[#359293]/30 group-hover:bg-[#359293]/25 transition">
                        Escolher arquivo
                      </span>

                      <input
                        id="heroVideoInput"
                        name="heroVideoInput"
                        type="file"
                        accept="video/*"
