                      </span>
                    ) : null}
                  </div>

                  <div className="mt-3">
                    <label
                      htmlFor="heroImageInput"
                      className="group relative flex cursor-pointer items-center justify-between rounded-xl border border-dashed border-white/15 bg-white/[0.03] px-4 py-4 hover:bg-white/[0.05] transition"
