export default function AdminDashboardPage() {
  const { logout, role, nome, hasPermission } = useAdminAuth();
  const router = useRouter();

  const [resumo, setResumo] = useState<AdminResumo | null>(null);
  const [vendas, setVendas] = useState<VendaPoint[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const [logs, setLogs] = useState<AdminLog[]>([]);
  const [logsLoading, setLogsLoading] = useState(false);
  const [logsError, setLogsError] = useState<string | null>(null);

  const [topClientes, setTopClientes] = useState<TopCliente[]>([]);
  const [topProdutos, setTopProdutos] = useState<TopProduto[]>([]);
  const [topServicos, setTopServicos] = useState<TopServico[]>([]);
  const [topsLoading, setTopsLoading] = useState(false);
  const [topsError, setTopsError] = useState<string | null>(null);

  const [alertas, setAlertas] = useState<AlertItem[]>([]);
  const [alertasLoading, setAlertasLoading] = useState(false);
  const [alertasError, setAlertasError] = useState<string | null>(null);

  const canViewLogs = role === "master" || role === "gerente";

  const handleUnauthorized = useCallback(() => {
    logout();
    router.replace("/admin/login");
  }, [logout, router]);

  const handleLogout = useCallback(() => {
    logout();
    router.replace("/admin/login");
  }, [logout, router]);

  // === Resumo + gráfico ===
  useEffect(() => {
    let cancelado = false;

    async function loadDashboard() {
      setLoading(true);
      setErrorMsg(null);

      try {
        const [resumoJson, vendasJson] = await Promise.all([
          apiClient.get<AdminResumo>("/api/admin/stats/resumo"),
          apiClient.get<{ rangeDays: number; points: VendaPoint[] }>(
            "/api/admin/stats/vendas?range=7",
          ),
        ]);

        if (cancelado) return;

        setResumo(resumoJson ?? null);
        setVendas(Array.isArray(vendasJson.points) ? vendasJson.points : []);
      } catch (err: any) {
        if (cancelado) return;
        if (err?.status === 401 || err?.status === 403) {
          handleUnauthorized();
          return;
        }
        console.error("Erro ao carregar dashboard:", err);
        const msg =
          err?.message ||
          "Não foi possível carregar o painel. Tente novamente.";
        setErrorMsg(msg);
        toast.error(msg);
      } finally {
        if (!cancelado) setLoading(false);
      }
    }

    loadDashboard();
    return () => {
      cancelado = true;
    };
  }, [handleUnauthorized]);

  // === Logs (atividade recente) ===
  useEffect(() => {
    if (!canViewLogs) return;

    let cancelado = false;

    async function loadLogs() {
      setLogsLoading(true);
      setLogsError(null);

      try {
        const data = await apiClient.get<any[]>("/api/admin/logs?limit=20");
        if (cancelado) return;

        const parsed: AdminLog[] = data.map((log) => ({
          id: log.id,
          admin_nome: log.admin_nome,
          acao: log.acao,
          detalhes: log.detalhes ?? null,
          criado_em: log.criado_em,
        }));

        setLogs(parsed ?? []);
      } catch (err: any) {
        if (cancelado) return;
        if (err?.status === 401 || err?.status === 403) {
          handleUnauthorized();
          return;
        }
        console.warn("Erro ao carregar logs de auditoria:", err);
        setLogsError(
          "Não foi possível carregar a atividade recente. Tente novamente mais tarde.",
        );
      } finally {
        if (!cancelado) setLogsLoading(false);
      }
    }

    loadLogs();
    return () => {
      cancelado = true;
    };
  }, [canViewLogs, handleUnauthorized]);

  // === Mini-rankings (top clientes / produtos / serviços) ===
  useEffect(() => {
    let cancelado = false;

    async function loadTops() {
      setTopsLoading(true);
      setTopsError(null);

      try {
        const [resCli, resProd, resServ] = await Promise.allSettled([
          apiClient.get<{ rows: any[] }>("/api/admin/relatorios/clientes-top"),
          apiClient.get<any[]>(
            "/api/admin/stats/produtos-mais-vendidos?limit=5",
          ),
          apiClient.get<{ rows: any[] }>(
            "/api/admin/relatorios/servicos-ranking",
          ),
        ]);

        if (cancelado) return;

        for (const result of [resCli, resProd, resServ]) {
          if (
            result.status === "rejected" &&
            (result.reason?.status === 401 || result.reason?.status === 403)
          ) {
            handleUnauthorized();
            return;
          }
        }

        let algumaCoisaOk = false;

        if (resCli.status === "fulfilled") {
          const data = resCli.value;
          const rows = Array.isArray(data.rows) ? data.rows : [];
          const mapped: TopCliente[] = rows.slice(0, 5).map((c) => ({
            id: c.id,
            nome: c.nome,
            total_pedidos: Number(c.pedidos || 0),
            total_gasto: Number(c.total_gasto || 0),
          }));
          setTopClientes(mapped);
          algumaCoisaOk = true;
        }

        if (resProd.status === "fulfilled") {
          const data = resProd.value;
          const mapped: TopProduto[] = (Array.isArray(data) ? data : []).map(
            (p) => ({
              id: p.id,
              nome: p.name,
              total_vendido: Number(p.quantidadeVendida || 0),
              receita_total: Number(p.totalVendido || 0),
            }),
          );
          setTopProdutos(mapped);
          algumaCoisaOk = true;
        }

        if (resServ.status === "fulfilled") {
          const data = resServ.value;
          const rows = Array.isArray(data.rows) ? data.rows : [];
          const mapped: TopServico[] = rows.slice(0, 5).map((s) => ({
            id: s.id,
            titulo: s.nome,
            total_contratos: Number(s.total_servicos || 0),
            receita_total: 0,
            nota_media: typeof s.rating_avg === "number" ? s.rating_avg : null,
          }));
          setTopServicos(mapped);
          algumaCoisaOk = true;
        }

        if (!algumaCoisaOk) {
          setTopsError(
            "Não foi possível carregar os rankings. Verifique se as rotas de relatórios estão ativas.",
          );
        }
      } catch (err) {
        if (cancelado) return;
        console.warn("Erro ao carregar tops:", err);
        setTopsError(
          "Erro ao carregar rankings de clientes/produtos/serviços.",
        );
      } finally {
        if (!cancelado) setTopsLoading(false);
      }
    }

    loadTops();
    return () => {
      cancelado = true;
    };
  }, [handleUnauthorized]);

