"use client";

import { JSX, useEffect, useRef, useState } from "react";
import Link from "next/link";
import CustomButton from "@/components/buttons/CustomButton";
import apiClient from "@/lib/apiClient";

import ProdutoForm from "@/components/admin/produtos/produtoform";
import ProdutoCard from "@/components/admin/produtos/produtocard";
import type { Product } from "@/components/admin/produtos/produtocard";

const ProdutoFormAny = ProdutoForm as unknown as (props: any) => JSX.Element;

// IMPORTANTE:
// API_BASE = host do backend (sem /api), porque seus endpoints já usam `${API_BASE}/api/...`
const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

export default function ProdutosPage() {
  const [produtos, setProdutos] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [erro, setErro] = useState<string | null>(null);
  const [produtoEditado, setProdutoEditado] = useState<Product | null>(null);
  const formRef = useRef<HTMLDivElement>(null);

  async function carregarProdutos() {
    setLoading(true);
    setErro(null);

    try {
      const data = await apiClient.get<Product[]>("/api/admin/produtos");
      const arr = Array.isArray(data) ? data : [];

      const parsed: Product[] = arr.map((p: any) => ({
        ...p,
        price: Number(p.price),
        quantity: Number(p.quantity),
      }));

      setProdutos(parsed);
    } catch (e: any) {
      console.error("carregarProdutos:", e);
      if (e?.status === 401 || e?.status === 403) {
        setErro("Sessão expirada. Faça login novamente.");
        return;
      }
      setErro(e?.message || "Erro ao carregar produtos.");
      setProdutos([]);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    carregarProdutos();
  }, []);

  function handleEditarProduto(produto: Product) {
    setProdutoEditado(produto);
    formRef.current?.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  async function removerProduto(id: number) {
    if (!confirm("Tem certeza que deseja remover este produto?")) return;

    try {
      await apiClient.del(`/api/admin/produtos/${id}`);
      await carregarProdutos();
    } catch (e: any) {
      console.error("removerProduto:", e);
      if (e?.status === 401 || e?.status === 403) {
        alert("Sessão expirada. Faça login novamente.");
        return;
      }
      alert(e?.message || "Erro ao remover produto.");
    }
  }

  return (
    <div className="w-full px-3 py-5 sm:px-4 lg:px-6">
      <div className="mx-auto w-full max-w-6xl space-y-6 sm:space-y-8">
        <header className="relative flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h1 className="text-2xl font-extrabold tracking-tight text-[#359293] sm:text-3xl">
              Produtos
            </h1>
            <p className="mt-1 text-sm text-gray-300">
              Adicione, edite ou remova produtos do catálogo.
            </p>
          </div>

          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:gap-3">
            <Link href="/admin/frete" className="w-full sm:w-auto">
              <CustomButton
                label="Editar frete (regiões)"
                variant="secondary"
                size="small"
                isLoading={false}
              />
            </Link>

            <Link href="/admin" className="hidden sm:block">
              <CustomButton
                label="Voltar"
                variant="secondary"
                size="small"
                isLoading={false}
              />
            </Link>
          </div>

          <Link
            href="/admin"
            className="absolute -right-1 -top-3 z-10 block sm:hidden"
          >
            <CustomButton
              label="Voltar"
              variant="secondary"
              size="small"
              isLoading={false}
            />
          </Link>
        </header>

        <section ref={formRef} aria-label="Formulário de produto">
          <ProdutoFormAny
            API_BASE={API_BASE} // ✅ ESSENCIAL: sem isso vira "undefined/api/..." e cai no Next (3000)
            produtoEditado={produtoEditado}
            onLimparEdicao={() => setProdutoEditado(null)}
            onProdutoAdicionado={carregarProdutos}
          />
        </section>

        {loading && (
          <div className="rounded-2xl bg-white/95 p-4 text-gray-700 shadow-sm sm:p-6">
            Carregando produtos…
          </div>
        )}

        {!loading && erro && (
          <div className="rounded-2xl border border-red-300 bg-red-50 p-4 text-red-700 sm:p-5">
            {erro}
          </div>
        )}

        {!loading && !erro && produtos.length === 0 && (
          <div className="rounded-2xl bg-white/95 p-4 text-gray-700 shadow-sm sm:p-6">
            Nenhum produto cadastrado.
          </div>
        )}

        {!loading && !erro && produtos.length > 0 && (
          <section className="space-y-3 sm:space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-lg font-semibold text-gray-50">
                Lista de produtos
              </h3>
              <span className="text-sm text-gray-300">
                {produtos.length} itens
              </span>
            </div>

            <div className="grid grid-cols-1 gap-4 sm:gap-5 md:grid-cols-2 xl:grid-cols-3">
              {produtos.map((p) => (
                <ProdutoCard
                  key={p.id}
                  produto={p}
                  className="mt-0"
                  onEditar={handleEditarProduto}
                  onRemover={removerProduto}
                />
              ))}
            </div>
          </section>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import apiClient from "@/lib/apiClient";
import toast from "react-hot-toast";

import CustomButton from "@/components/buttons/CustomButton";
import CloseButton from "@/components/buttons/CloseButton";
import { KpiCard } from "@/components/admin/KpiCard";
import { formatCurrency } from "@/utils/formatters";

type ClienteTop = {
  id: number;
  nome: string;
  email: string;
  pedidos: number;
  total_gasto: number;
};

type ClientesResponse = {
  rows: ClienteTop[];
};

type LimitOption = 10 | 25 | 50 | 100 | "all";
type SortMode = "valor" | "pedidos";

export default function RelatorioClientesPage() {
  const [data, setData] = useState<ClienteTop[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // 🔍 filtros
  const [searchTerm, setSearchTerm] = useState("");
  const [limit, setLimit] = useState<LimitOption>(25);
  const [sortMode, setSortMode] = useState<SortMode>("valor");

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);

        const res = await apiClient.get<ClientesResponse>(
          "/api/admin/relatorios/clientes-top",
        );

        setData(res.rows ?? []);
      } catch (err: any) {
        console.error(err);

        let msg = "Não foi possível carregar o relatório de clientes.";
        if (err?.status === 401 || err?.status === 403) {
          msg =
            "Sessão expirada ou sem permissão. Faça login novamente no admin.";
        }

        setError(msg);
        toast.error(msg);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  const totalClientes = useMemo(() => data.length, [data]);

  const totalGastoGeral = useMemo(
    () => data.reduce((acc, c) => acc + Number(c.total_gasto || 0), 0),
    [data],
  );

  const totalPedidosGeral = useMemo(
    () => data.reduce((acc, c) => acc + Number(c.pedidos || 0), 0),
    [data],
  );

  const ticketMedioPorCliente = useMemo(
    () => (totalClientes ? totalGastoGeral / totalClientes : 0),
    [totalClientes, totalGastoGeral],
  );

  const melhorCliente = useMemo(() => {
    if (!data.length) return null;
    return data.reduce((prev, curr) =>
      Number(curr.total_gasto) > Number(prev.total_gasto) ? curr : prev,
    );
  }, [data]);

  const hasData = !loading && !error && data.length > 0;

  // 🎯 aplica ordenação + busca + top N
  const filteredData = useMemo(() => {
    let result = [...data];

    // ordenação
    result.sort((a, b) => {
      if (sortMode === "valor") {
        return Number(b.total_gasto || 0) - Number(a.total_gasto || 0);
      }
      return Number(b.pedidos || 0) - Number(a.pedidos || 0);
    });

    // busca
    if (searchTerm.trim()) {
      const term = searchTerm.toLowerCase();
      result = result.filter(
        (c) =>
          c.nome.toLowerCase().includes(term) ||
          c.email.toLowerCase().includes(term),
      );
    }

    // limite top N
    if (limit !== "all") {
      result = result.slice(0, limit);
    }

    return result;
  }, [data, searchTerm, limit, sortMode]);

  const visibleTotalPedidos = useMemo(
    () => filteredData.reduce((acc, c) => acc + Number(c.pedidos || 0), 0),
    [filteredData],
  );

  const visibleTotalGasto = useMemo(
    () => filteredData.reduce((acc, c) => acc + Number(c.total_gasto || 0), 0),
    [filteredData],
  );

  const visibleClientes = filteredData.length;

  const resetFilters = () => {
    setSearchTerm("");
    setLimit("all");
    setSortMode("valor");
  };

  // 📤 Exportar CSV com o resultado filtrado
  const handleExportCsv = () => {
    if (!filteredData.length) {
      toast.error("Não há dados para exportar.");
      return;
    }

    const header = [
      "posicao",
      "cliente",
      "email",
      "pedidos",
      "total_gasto_numero",
    ];

    const rows = filteredData.map((c, index) => {
      const safeNome = c.nome.replace(/"/g, '""');
      const safeEmail = c.email.replace(/"/g, '""');
      return [
        String(index + 1),
        safeNome,
        safeEmail,
        String(c.pedidos),
        String(c.total_gasto),
      ];
    });

    const csvLines = [
      header.join(";"),
      ...rows.map((r) => r.map((field) => `"${field}"`).join(";")),
    ];

    const csv = csvLines.join("\n");
    const blob = new Blob([csv], {
      type: "text/csv;charset=utf-8;",
    });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "relatorio_clientes.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);

    toast.success("CSV exportado com sucesso!");
  };

  return (
    <main className="min-h-screen bg-[#050816] text-gray-100">
      <div className="mx-auto flex max-w-6xl flex-col gap-6 px-4 py-6 sm:px-6 lg:px-8">
        {/* HEADER */}
        <header className="relative flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div className="pr-10 sm:pr-0">
            <p className="text-[11px] uppercase tracking-[0.25em] text-teal-400/80">
              Inteligência de clientes
            </p>
            <h1 className="mt-1 text-2xl font-extrabold tracking-tight text-[#35c2c4] sm:text-3xl">
              Relatório de Clientes
            </h1>
            <p className="mt-1 max-w-xl text-xs text-slate-300 sm:text-sm">
              Ranking dos clientes que mais compram. Ideal para definir
              campanhas VIP, cupons exclusivos e ações de fidelização dignas de
              um marketplace gigante.
            </p>

            {hasData && (
              <p className="mt-2 text-xs font-semibold text-slate-100 sm:text-sm">
                Total gasto pelo ranking:{" "}
                <span className="text-[#35c2c4]">
                  {formatCurrency(totalGastoGeral)}
                </span>
              </p>
            )}
          </div>

          {/* Navegação (X no mobile / Voltar no desktop) */}
          <div className="absolute right-0 top-0 flex items-center gap-2 sm:static">
            <div className="block sm:hidden">
              <CloseButton className="text-3xl text-slate-200 hover:text-[#35c2c4]" />
            </div>

            <div className="hidden sm:block">
              <CustomButton
                label="← Voltar para relatórios"
                href="/admin/relatorios"
                variant="secondary"
                size="small"
                isLoading={false}
              />
            </div>
          </div>
        </header>

        {/* ESTADOS GLOBAIS */}
        {loading && (
          <section className="flex min-h-[40vh] items-center justify-center">
            <div className="rounded-2xl border border-slate-700 bg-slate-950/60 px-5 py-4 text-sm text-slate-200">
