"use client";

import { useEffect, useMemo, useState } from "react";
import apiClient from "@/lib/apiClient";
import {
  ResponsiveContainer,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
} from "recharts";
import toast from "react-hot-toast";
import CustomButton from "@/components/buttons/CustomButton";
import CloseButton from "@/components/buttons/CloseButton";
import { KpiCard } from "@/components/admin/KpiCard";
import {
  formatCurrency,
  formatShortDate,
  formatFullDate,
  formatFullDateShortYear,
} from "@/utils/formatters";

interface DailySale {
  date: string;
  total: number;
}

interface VendasAPIResponse {
  rows: {
    dia: string;
    total: number;
  }[];
}

export default function RelatorioVendasPage() {
  const [sales, setSales] = useState<DailySale[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchSales = async () => {
      try {
        setLoading(true);
        setError(null);

        const response = await apiClient.get<VendasAPIResponse>(
          "/api/admin/relatorios/vendas",
        );

        const mapped: DailySale[] =
          response.rows?.map((row) => ({
            date: row.dia,
            total: Number(row.total || 0),
          })) ?? [];

        setSales(mapped);
      } catch (err: any) {
        console.error(err);

        let msg = "Não foi possível carregar o relatório de vendas.";

        if (err?.status === 401 || err?.status === 403) {
          msg =
            "Sessão expirada ou sem permissão. Faça login novamente no admin.";
        }

        setError(msg);
        toast.error(msg);
      } finally {
        setLoading(false);
      }
    };

    fetchSales();
  }, []);

  const totalFaturado = useMemo(
    () => sales.reduce((sum, sale) => sum + (sale.total || 0), 0),
    [sales],
  );

  const chartData = useMemo(
    () =>
      sales.map((sale) => ({
        label: formatShortDate(sale.date),
        total: sale.total,
      })),
    [sales],
  );

  return (
    <main className="w-full px-3 pb-6 pt-4 sm:px-6 lg:px-8">
      <section className="relative mx-auto flex w-full max-w-6xl flex-col gap-6">
        {/* Cabeçalho */}
        <header className="relative space-y-3">
          <div className="flex items-center justify-between gap-3">
            <h1 className="text-2xl font-extrabold tracking-tight text-[#35c2c4] sm:text-3xl">
              Relatório de Vendas
            </h1>

            {/* Voltar só em telas médias pra cima */}
            <CustomButton
              label="← Voltar para relatórios"
              href="/admin/relatorios"
              variant="secondary"
              size="small"
              isLoading={false}
              className="hidden md:inline-flex shrink-0 justify-center"
            />
          </div>

          <p className="max-w-xl text-xs text-slate-300 sm:text-sm">
            Total de vendas por dia. Ideal para entender sazonalidade e
            desempenho do faturamento.
          </p>

          <p className="text-sm font-semibold text-slate-100 sm:text-base">
            Total faturado:{" "}
            <span className="text-[#35c2c4]">
              {formatCurrency(totalFaturado)}
            </span>
          </p>

          {/* Close só no mobile, funciona como "voltar" */}
          <div className="absolute right-0 top-0 translate-y-1 md:hidden">
            <CloseButton className="text-2xl text-slate-400 hover:text-slate-100" />
          </div>
        </header>

        {/* Card principal */}
        <div
          className="
            rounded-3xl border border-slate-800 bg-slate-950/70 
            p-4 shadow-[0_18px_45px_rgba(0,0,0,0.65)] backdrop-blur
            sm:p-6
          "
        >
          {loading ? (
            <div className="flex h-40 items-center justify-center text-sm text-slate-400">
              Carregando relatório de vendas...
            </div>
          ) : error ? (
            <div className="flex h-40 items-center justify-center">
              <div className="w-full max-w-md rounded-2xl border border-red-500/40 bg-red-950/10 px-4 py-3 text-center text-sm text-red-400">
                {error}
              </div>
            </div>
          ) : sales.length === 0 ? (
            <div className="flex h-40 flex-col items-center justify-center gap-2 text-sm text-slate-400">
              <span>Nenhuma venda encontrada para o período selecionado.</span>
            </div>
          ) : (
            <>
              {/* Gráfico + KPIs */}
              <div className="grid gap-6 lg:grid-cols-3">
                {/* Gráfico ocupa 2 colunas no desktop */}
                <div className="space-y-3 lg:col-span-2">
                  <h2 className="text-sm font-semibold text-slate-100 sm:text-base">
                    Faturamento diário
                  </h2>
                  <div className="h-64 rounded-2xl border border-slate-800 bg-slate-950/80 p-3 sm:p-4">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart
                        data={chartData}
                        margin={{ top: 10, right: 10, left: -20, bottom: 0 }}
                      >
                        <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" />
                        <XAxis
                          dataKey="label"
                          tick={{ fill: "#9ca3af", fontSize: 11 }}
                          tickLine={false}
                          axisLine={{ stroke: "#1f2937" }}
                        />
                        <YAxis
                          tick={{ fill: "#9ca3af", fontSize: 11 }}
                          tickLine={false}
                          axisLine={{ stroke: "#1f2937" }}
                        />
                        <Tooltip
                          formatter={(value: number | undefined) =>
                            value !== undefined ? formatCurrency(value) : "-"
                          }
                          labelFormatter={(label) =>
                            label ? `Dia ${label}` : "-"
                          }
                          contentStyle={{
                            backgroundColor: "#ffffff",
                            border: "1px solid #e5e7eb",
                            borderRadius: "0.75rem",
                            color: "#020617",
                            fontSize: 12,
                            boxShadow: "0 15px 35px rgba(15,23,42,0,0.22)",
                          }}
                        />
                        <Bar
                          dataKey="total"
                          radius={[10, 10, 0, 0]}
                          fill="#35c2c4"
                        />
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                {/* KPIs rápidos */}
                <div className="space-y-3 lg:col-span-1">
                  <h2 className="text-sm font-semibold text-slate-100 sm:text-base">
                    Visão rápida
                  </h2>
                  <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-1">
                    <KpiCard
                      label="Dias com vendas"
                      value={sales.length}
                      helper="Quantidade de dias com faturamento registrado."
                      icon={<span>📅</span>}
                      variant="default"
                    />
                    <KpiCard
                      label="Ticket médio (por dia)"
                      value={formatCurrency(
                        totalFaturado / (sales.length || 1),
                      )}
                      helper="Faturamento médio diário."
                      icon={<span>💳</span>}
                      variant="success"
                    />
                    <KpiCard
                      label="Maior dia de vendas"
                      value={getBestDayLabel(sales)}
                      helper="Dia com maior faturamento."
                      icon={<span>📈</span>}
                      variant="warning"
                    />
                  </div>
                </div>
              </div>

              {/* Tabela de vendas por dia */}
              <div className="mt-8 space-y-3">
                <h2 className="text-sm font-semibold text-slate-100 sm:text-base">
                  Detalhamento por dia
                </h2>
                <div className="overflow-hidden rounded-2xl border border-slate-800 bg-slate-950/80">
                  <div className="overflow-x-auto">
                    <table className="min-w-full text-left text-xs text-slate-200 sm:text-sm">
                      <thead>
                        <tr className="border-b border-slate-800 bg-slate-900/80">
                          <th className="px-4 py-3 font-semibold">Dia</th>
                          <th className="px-4 py-3 text-right font-semibold">
                            Total (R$)
                          </th>
                        </tr>
                      </thead>
                      <tbody>
                        {sales.map((sale) => (
                          <tr
                            key={sale.date}
                            className="border-b border-slate-900/80 last:border-none"
                          >
                            <td className="px-4 py-2.5 align-middle">
                              <span className="block text-[11px] text-slate-400 sm:hidden">
                                {formatShortDate(sale.date)}
                              </span>
                              <span className="hidden sm:inline">
                                {formatFullDate(sale.date)}
                              </span>
                              <span className="inline sm:hidden">
                                {formatFullDateShortYear(sale.date)}
                              </span>
                            </td>
                            <td className="px-4 py-2.5 text-right align-middle">
                              {formatCurrency(sale.total)}
                            </td>
                          </tr>
                        ))}
                        <tr className="bg-slate-900/80">
                          <td className="px-4 py-3 font-semibold">Total</td>
                          <td className="px-4 py-3 text-right font-semibold text-[#35c2c4]">
                            {formatCurrency(totalFaturado)}
                          </td>
                        </tr>
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>
            </>
          )}
        </div>
      </section>
    </main>
  );
}

/* ---------- HELPERS ---------- */

function getBestDayLabel(sales: DailySale[]): string {
  if (!sales.length) return "-";
  const best = sales.reduce((prev, curr) =>
    curr.total > prev.total ? curr : prev,
  );
  return `${formatShortDate(best.date)} · ${formatCurrency(best.total)}`;
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { toast } from "react-hot-toast";
import CustomButton from "@/components/buttons/CustomButton";

const BACKEND_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";
const API_BASE = `${BACKEND_BASE}/api/admin/colaboradores`;

type ColaboradorPendente = {
  id: number;
  nome: string;
  cargo: string | null;
  whatsapp: string;
  email?: string | null;
  imagem?: string | null;
  descricao: string | null;
  especialidade_id: number;
  verificado: number | boolean;
  created_at: string;
};

function getInitials(name: string) {
  if (!name) return "?";
  const parts = name.trim().split(" ");
  if (parts.length === 1) return parts[0][0]?.toUpperCase() ?? "?";
  return `${parts[0][0]}${parts[parts.length - 1][0]}`.toUpperCase();
}

export default function ColaboradoresPendentesPage() {
  const [items, setItems] = useState<ColaboradorPendente[]>([]);
  const [loading, setLoading] = useState(true);

  async function carregar() {
    setLoading(true);
    try {
      const res = await fetch(`${API_BASE}/pending`, {
        cache: "no-store",
        credentials: "include", // ✅ cookie HttpOnly
      });

      if (!res.ok) {
        console.error("Erro ao buscar pendentes:", res.status);
        if (res.status === 401 || res.status === 403) {
          toast.error(
            "Você não tem permissão para ver colaboradores pendentes. Faça login novamente.",
          );
        } else {
          toast.error("Erro ao carregar colaboradores pendentes.");
        }
        setItems([]);
        return;
      }

      const data = await res.json();
      setItems(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Erro ao carregar colaboradores pendentes:", err);
      toast.error("Erro de conexão ao carregar colaboradores.");
      setItems([]);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    carregar();
  }, []);

  async function aprovar(id: number) {
    if (!confirm("Confirmar verificação deste profissional?")) return;

    try {
      const res = await fetch(`${API_BASE}/${id}/verify`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
        },
        credentials: "include", // ✅ cookie HttpOnly
      });

      if (!res.ok) {
        console.error("Erro ao verificar colaborador:", res.status);
        if (res.status === 401 || res.status === 403) {
          toast.error(
            "Você não tem permissão para aprovar colaboradores. Faça login novamente.",
          );
        } else {
          toast.error("Erro ao verificar colaborador.");
        }
        return;
      }

      toast.success("Colaborador aprovado e liberado com sucesso!");
      await carregar();
    } catch (err) {
      console.error("Erro ao verificar colaborador:", err);
      toast.error("Erro interno ao verificar colaborador.");
    }
  }

  async function remover(id: number) {
    if (!confirm("Deseja remover este cadastro pendente?")) return;

    try {
      const res = await fetch(`${API_BASE}/${id}`, {
        method: "DELETE",
        credentials: "include", // ✅ cookie HttpOnly
      });

      if (!res.ok) {
        console.error("Erro ao remover colaborador:", res.status);
        if (res.status === 401 || res.status === 403) {
          toast.error(
            "Você não tem permissão para remover colaboradores. Faça login novamente.",
          );
        } else {
          toast.error("Erro ao remover colaborador.");
        }
        return;
      }

      toast.success("Colaborador removido com sucesso.");
      await carregar();
    } catch (err) {
      console.error("Erro ao remover colaborador:", err);
      toast.error("Erro interno ao remover colaborador.");
    }
  }

  return (
    <div className="w-full px-3 py-4 sm:px-4 lg:px-6">
      <div className="mx-auto w-full max-w-5xl lg:max-w-6xl">
        {/* Header */}
        <div className="mb-4 flex flex-col gap-3 sm:mb-6 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h1 className="text-xl font-extrabold text-[#359293] sm:text-2xl md:text-3xl">
              Colaboradores pendentes
            </h1>
            <p className="mt-1 max-w-xl text-xs text-gray-300 sm:text-sm">
              Cadastros enviados via <strong>Trabalhe com a Kavita</strong>.
              Aprove ou remova antes de liberar o profissional para aparecer na
              lista de serviços.
            </p>
            {!loading && (
              <p className="mt-1 text-[11px] text-gray-400 sm:text-xs">
                {items.length === 0
                  ? "Nenhum cadastro aguardando análise."
                  : `${items.length} colaborador${
                      items.length > 1 ? "es" : ""
                    } aguardando análise.`}
              </p>
            )}
          </div>

          {/* Botão responsivo: full width no mobile, compacto no desktop */}
          <div className="w-full sm:w-auto">
            <Link href="/admin/servicos">
              <CustomButton
                label="Voltar para serviços"
                variant="secondary"
                size="small"
                isLoading={false}
              />
            </Link>
          </div>
        </div>

        {/* Estados */}
        {loading ? (
          <div className="rounded-2xl bg-white/90 p-4 text-sm text-gray-700 shadow-sm sm:text-base">
            Carregando...
          </div>
        ) : items.length === 0 ? (
          <div className="rounded-2xl bg-white/90 p-4 text-sm text-gray-700 shadow-sm sm:text-base">
            Nenhum colaborador pendente no momento.
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 2xl:grid-cols-3">
            {items.map((c) => {
              const phoneDigits = c.whatsapp.replace(/\D/g, "");
              const hasPhone = phoneDigits.length >= 10;
              const waLink = hasPhone
                ? `https://wa.me/55${phoneDigits}`
                : undefined;

              const avatarUrl =
                c.imagem && c.imagem.startsWith("http")
                  ? c.imagem
                  : c.imagem
                    ? `${BACKEND_BASE}${c.imagem}`
                    : null;

              return (
                <article
                  key={c.id}
                  className="flex h-full flex-col rounded-2xl bg-white p-4 shadow-sm ring-1 ring-black/5"
                >
                  <div className="mb-2 flex flex-1 flex-col">
                    {/* Topo: avatar + dados básicos */}
                    <div className="mb-2 flex items-start gap-3">
                      <div className="h-10 w-10 flex-shrink-0 overflow-hidden rounded-full bg-emerald-100 ring-1 ring-emerald-200">
                        {avatarUrl ? (
                          <img
                            src={avatarUrl}
                            alt={c.nome}
                            className="h-full w-full object-cover"
                          />
                        ) : (
                          <div className="flex h-full w-full items-center justify-center text-xs font-semibold text-emerald-900">
                            {getInitials(c.nome)}
                          </div>
                        )}
                      </div>

                      <div className="min-w-0">
                        <h2 className="truncate text-base font-semibold text-gray-900">
                          {c.nome}
                        </h2>
                        {c.cargo && (
                          <p className="text-xs text-gray-600">
                            Cargo: {c.cargo}
                          </p>
                        )}
                        {c.email && (
                          <p className="mt-0.5 truncate text-xs text-gray-500">
                            E-mail:{" "}
                            <a
                              href={`mailto:${c.email}`}
                              className="font-medium text-emerald-700 hover:underline"
                            >
                              {c.email}
                            </a>
                          </p>
                        )}
                      </div>
                    </div>

                    {/* Contatos / descrição */}
                    <div className="mt-1">
                      <p className="text-xs text-gray-500">
                        WhatsApp:{" "}
                        {waLink ? (
                          <a
                            href={waLink}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="inline-flex items-center gap-1 font-semibold text-emerald-700 hover:underline"
                          >
                            {c.whatsapp}
                            <span aria-hidden>↗</span>
                          </a>
                        ) : (
                          c.whatsapp
                        )}
                      </p>

                      {c.descricao && (
                        <p className="mt-2 whitespace-pre-line text-xs text-gray-700">
                          {c.descricao}
                        </p>
                      )}

                      <p className="mt-2 text-[11px] text-gray-400">
                        Criado em:{" "}
                        {new Date(c.created_at).toLocaleString("pt-BR")}
                      </p>
                    </div>
                  </div>

                  {/* Ações */}
                  <div className="mt-3 flex flex-wrap gap-2">
                    <button
                      onClick={() => aprovar(c.id)}
                      className="flex-1 rounded-full bg-emerald-100 px-3 py-1 text-center text-xs font-semibold text-emerald-800 hover:bg-emerald-200 sm:flex-none sm:px-4"
                    >
                      Aprovar e liberar
                    </button>
                    <button
                      onClick={() => remover(c.id)}
                      className="flex-1 rounded-full bg-red-100 px-3 py-1 text-center text-xs font-semibold text-red-800 hover:bg-red-200 sm:flex-none sm:px-4"
                    >
                      Remover
                    </button>
                  </div>
                </article>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import Link from "next/link";
import { useEffect, useMemo, useRef, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { SlidersHorizontal } from "lucide-react";

import {
  FiltersPanel,
  type FiltersState,
} from "../../components/search/FiltersPanel";
import { SortSelect, type SortKey } from "../../components/search/SortSelect";
import { Pagination } from "../../components/search/Pagination";
import ProductCard from "../../components/products/ProductCard";

import type { Product } from "@/types/product";
import CloseButton from "../../components/buttons/CloseButton";
import LoadingButton from "../../components/buttons/LoadingButton";

import type { Category, ProductsResponse } from "@/types/search";
import { absUrl } from "@/utils/absUrl";
import {
  buildQueryString,
  clamp,
  parseIntList,
  toNum,
  toNumberParam,
} from "@/utils/search";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";
const PLACEHOLDER = "/placeholder.png";

type Params = {
  q: string;
  categories: number[];
  minPrice: number | null;
  maxPrice: number | null;
  promo: boolean;
  sort: string;
  page: number;
  limit: number;
};

function safeJsonParse(text: string) {
  try {
    return text ? JSON.parse(text) : null;
  } catch {
    return null;
  }
}

function normalizeCategories(payload: any): Category[] {
  const arr: any[] = Array.isArray(payload)
    ? payload
    : Array.isArray(payload?.data)
      ? payload.data
      : Array.isArray(payload?.categories)
        ? payload.categories
        : [];

  return arr
    .map((c: any) => ({
      id: Number(c?.id),
      name: String(c?.name ?? c?.nome ?? ""),
      slug: c?.slug ? String(c.slug) : undefined,
      total_products:
        typeof c?.total_products === "number"
          ? c.total_products
          : typeof c?.totalProducts === "number"
            ? c.totalProducts
            : undefined,
      active: c?.active ?? c?.is_active ?? c?.isActive ?? undefined,
    }))
    .filter((c) => Number.isFinite(c.id) && Boolean(c.name))
    .filter((c: any) => (c.active === undefined ? true : Boolean(c.active)))
    .sort((a, b) => a.name.localeCompare(b.name, "pt-BR"));
}

function readCategoriesFromSearchParams(
  sp: ReturnType<typeof useSearchParams>,
) {
  // 1) prioridade: categories=1,2,3
  const fromList = parseIntList(sp.get("categories"));
  if (fromList.length) return fromList;

  // 2) fallback: category_id=7
  const cid = sp.get("category_id");
  if (cid) {
    const n = Number(cid);
    if (Number.isFinite(n) && n > 0) return [n];
  }

  // 3) fallback: category=7 (ou outro backend)
  const c = sp.get("category");
  if (c) {
    const n = Number(c);
    if (Number.isFinite(n) && n > 0) return [n];
  }

  return [];
}

export default function BuscaClient() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const abortRef = useRef<AbortController | null>(null);

  const params: Params = useMemo(() => {
    const q = searchParams.get("q") || "";
    const categories = readCategoriesFromSearchParams(searchParams);
    const minPrice = toNumberParam(searchParams.get("minPrice"));
    const maxPrice = toNumberParam(searchParams.get("maxPrice"));
    const promo = (searchParams.get("promo") || "").toLowerCase() === "true";
    const sort = searchParams.get("sort") || "relevance";
    const page = clamp(Number(searchParams.get("page") || 1), 1, 10_000);
    const limit = clamp(Number(searchParams.get("limit") || 12), 1, 60);

    return { q, categories, minPrice, maxPrice, promo, sort, page, limit };
  }, [searchParams]);

  const [debouncedQ, setDebouncedQ] = useState(params.q);
  useEffect(() => {
    const t = setTimeout(() => setDebouncedQ(params.q), 350);
    return () => clearTimeout(t);
  }, [params.q]);

  const effectiveParams: Params = useMemo(
    () => ({ ...params, q: debouncedQ }),
    [params, debouncedQ],
  );

  const [cats, setCats] = useState<Category[]>([]);
  const [catsLoading, setCatsLoading] = useState(false);

  const [productsData, setProductsData] = useState<ProductsResponse | null>(
    null,
  );
  const [loadingProducts, setLoadingProducts] = useState(false);
  const [errorProducts, setErrorProducts] = useState<string | null>(null);

  const [filtersOpen, setFiltersOpen] = useState(false);

  const pushParams = (patch: Partial<Params>) => {
    const merged: Params = { ...params, ...patch };

    const filterKeys: (keyof Params)[] = [
      "q",
      "categories",
      "minPrice",
      "maxPrice",
      "promo",
      "sort",
      "limit",
    ];
    const shouldResetPage =
      filterKeys.some((k) => k in patch) && !("page" in patch);
    if (shouldResetPage) merged.page = 1;

    const sp = new URLSearchParams();

    if (merged.q?.trim()) sp.set("q", merged.q.trim());

    // ✅ compat total: categories + category_id + category
    if (merged.categories?.length) {
      sp.set("categories", merged.categories.join(","));

      if (merged.categories.length === 1) {
        const id = merged.categories[0];
        sp.set("category_id", String(id));
        sp.set("category", String(id));
      } else {
        sp.delete("category_id");
        sp.delete("category");
      }
    } else {
      sp.delete("categories");
      sp.delete("category_id");
      sp.delete("category");
    }

    if (typeof merged.minPrice === "number")
      sp.set("minPrice", String(merged.minPrice));
    if (typeof merged.maxPrice === "number")
      sp.set("maxPrice", String(merged.maxPrice));
    if (merged.promo) sp.set("promo", "true");
    if (merged.sort) sp.set("sort", merged.sort);
    sp.set("page", String(merged.page || 1));
    sp.set("limit", String(merged.limit || 12));

    router.push(`/busca?${sp.toString()}`, { scroll: false });
  };

  const clearAll = () =>
    pushParams({
      q: "",
      categories: [],
      minPrice: null,
      maxPrice: null,
      promo: false,
      sort: "relevance",
      page: 1,
    });

  useEffect(() => {
    let mounted = true;

    (async () => {
      setCatsLoading(true);
      try {
        const res = await fetch(`${API_BASE}/api/public/categorias`, {
          method: "GET",
          credentials: "include",
          cache: "no-store",
          headers: {
            "Content-Type": "application/json",
          },
        });

        const text = await res.text();
        if (!res.ok) throw new Error(text || res.statusText);

        const json = safeJsonParse(text) ?? [];
        const normalized = normalizeCategories(json);

        if (!mounted) return;
        setCats(normalized);
      } catch (e) {
        if (!mounted) return;
        console.warn("Categorias (BuscaClient):", e);
        setCats([]);
      } finally {
        if (mounted) setCatsLoading(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, []);

  useEffect(() => {
    abortRef.current?.abort();
    const ctrl = new AbortController();
    abortRef.current = ctrl;

    (async () => {
      setLoadingProducts(true);
      setErrorProducts(null);

      try {
        const qs = buildQueryString({
          ...effectiveParams,
          page: params.page,
        });

        const res = await fetch(`${API_BASE}/api/products/search?${qs}`, {
          method: "GET",
          credentials: "include",
          signal: ctrl.signal,
          headers: { "Content-Type": "application/json" },
        });

        if (!res.ok) {
          let msg = `HTTP ${res.status}`;
          try {
            const j = await res.json();
            msg = j?.message || j?.mensagem || msg;
          } catch {}
          throw new Error(msg);
        }

        const json = (await res.json()) as ProductsResponse;
        setProductsData(json);
      } catch (e: any) {
        if (e?.name === "AbortError") return;
        setProductsData(null);
        setErrorProducts(e?.message || "Erro ao buscar produtos");
      } finally {
        setLoadingProducts(false);
      }
    })();

    return () => ctrl.abort();
  }, [
    effectiveParams.q,
    effectiveParams.categories.join(","),
    effectiveParams.minPrice,
    effectiveParams.maxPrice,
    effectiveParams.promo,
    effectiveParams.sort,
    params.page,
    effectiveParams.limit,
  ]);

  const list = productsData?.products || [];
  const pag = productsData?.pagination || {
    page: params.page,
    limit: params.limit,
    total: 0,
    totalPages: 1,
  };

  const filtersState: FiltersState = {
    q: params.q,
    categories: params.categories,
    minPrice: params.minPrice,
    maxPrice: params.maxPrice,
    promo: params.promo,
  };

  const catIdToName = useMemo(() => {
    const m = new Map<number, string>();
    for (const c of cats) m.set(c.id, c.name);
    return m;
  }, [cats]);

  const hasAnyFilter =
    Boolean(params.q?.trim()) ||
    params.categories.length > 0 ||
    params.minPrice != null ||
    params.maxPrice != null ||
    params.promo;

  const activeFiltersCount = useMemo(() => {
    let c = 0;
    if (params.q?.trim()) c++;
    if (params.categories?.length) c++;
    if (params.minPrice != null || params.maxPrice != null) c++;
    if (params.promo) c++;
    return c;
  }, [
    params.q,
    params.categories,
    params.minPrice,
    params.maxPrice,
    params.promo,
  ]);

  const DesktopFilters = (
    <div className="rounded-2xl border border-zinc-200 bg-white p-4 shadow-sm">
      <FiltersPanel
        categories={cats}
        categoriesLoading={catsLoading}
        value={filtersState}
        onChange={(patch) => pushParams(patch as any)}
        onClear={clearAll}
      />

      <div className="mt-4 border-t border-zinc-200 pt-4">
        <Link
          href="/"
          className="text-sm font-medium text-emerald-700 hover:text-emerald-800"
        >
          Voltar para Home
        </Link>
      </div>
    </div>
  );

  return (
    <section className="min-h-screen bg-white">
      <div className="mx-auto w-full max-w-7xl px-4 py-6 md:py-8">
        <div className="flex flex-col gap-3">
          <div className="flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between">
            <div className="min-w-0">
              <h1 className="text-2xl font-bold text-zinc-900">Busca</h1>
              <p className="text-sm text-zinc-600">
                {loadingProducts
                  ? "Buscando..."
                  : `${pag.total} produto${pag.total === 1 ? "" : "s"} encontrado${pag.total === 1 ? "" : "s"}`}
              </p>
            </div>

            <div className="flex items-center gap-2">
              <button
                type="button"
                onClick={() => setFiltersOpen(true)}
                className="
                  relative inline-flex items-center justify-center gap-2
                  rounded-xl border border-zinc-200 bg-white
                  px-3 py-2 text-sm font-semibold text-zinc-800
                  shadow-sm hover:bg-zinc-50
                  transition
                  lg:hidden
                "
              >
                <SlidersHorizontal className="h-4 w-4" />
                <span>Filtros</span>

                {activeFiltersCount > 0 && (
                  <span
                    className="
                      ml-1 inline-flex h-5 min-w-[20px] items-center justify-center
                      rounded-full bg-emerald-600 px-1.5
                      text-[11px] font-bold text-white
                    "
                    aria-label={`${activeFiltersCount} filtros ativos`}
                  >
                    {activeFiltersCount}
                  </span>
                )}
              </button>

              <SortSelect
                value={params.sort as SortKey}
                onChange={(v) => pushParams({ sort: v })}
              />
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            {hasAnyFilter && (
              <button
                type="button"
                onClick={clearAll}
                className="rounded-full border border-zinc-200 bg-white px-3 py-1 text-xs font-medium text-zinc-700 hover:bg-zinc-50"
              >
                Limpar tudo
              </button>
            )}

            {params.categories.map((id) => (
              <span
                key={id}
                className="rounded-full bg-zinc-50 px-3 py-1 text-xs font-medium text-zinc-700 ring-1 ring-zinc-200"
              >
                {catIdToName.get(id) || `Categoria ${id}`}
              </span>
            ))}
          </div>
        </div>

        <div className="mt-5 grid grid-cols-1 gap-6 lg:grid-cols-[320px_1fr] lg:items-start">
          <aside className="hidden lg:block lg:sticky lg:top-24">
            {DesktopFilters}
          </aside>

          <main>
            {errorProducts ? (
              <div className="rounded-2xl border border-red-200 bg-red-50 p-4 text-sm text-red-700">
                {errorProducts}
              </div>
            ) : null}

            <div className="mt-3">
              {loadingProducts ? (
                <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
                  {Array.from({ length: Math.min(12, params.limit) }).map(
                    (_, i) => (
                      <div
                        key={i}
                        className="h-72 rounded-2xl border border-zinc-200 bg-white shadow-sm"
                      >
                        <div className="h-40 w-full animate-pulse rounded-t-2xl bg-zinc-100" />
                        <div className="space-y-2 p-3">
                          <div className="h-4 w-3/4 animate-pulse rounded bg-zinc-100" />
                          <div className="h-4 w-1/2 animate-pulse rounded bg-zinc-100" />
                          <div className="h-4 w-2/5 animate-pulse rounded bg-zinc-100" />
                        </div>
                      </div>
                    ),
                  )}
                </div>
              ) : list.length === 0 ? (
                <div className="rounded-2xl border border-zinc-200 bg-white p-8 text-center">
                  <h3 className="text-lg font-semibold text-zinc-900">
                    Nenhum produto encontrado
                  </h3>
                  <p className="mt-1 text-sm text-zinc-600">
                    Tente ajustar os filtros.
                  </p>
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
                  {list.map((p) => {
                    const allImgsRaw = [
                      p.image ?? null,
                      ...(Array.isArray(p.images) ? p.images : []),
                    ].filter(Boolean) as string[];
                    const allImgs = Array.from(new Set(allImgsRaw))
                      .map(absUrl)
                      .filter(Boolean);
                    const cover = allImgs[0] ?? PLACEHOLDER;

                    const finalPrice = toNum(p.final_price);
                    const basePrice = toNum(p.price);
                    const originalPrice = toNum(p.original_price);
                    const priceCandidate =
                      finalPrice ?? basePrice ?? originalPrice ?? 0;

                    const productForCard = {
                      id: p.id,
                      name: p.name,
                      description: p.description || "",
                      image: cover,
                      images: allImgs,
                      price: priceCandidate,
                    } as unknown as Product;

                    return (
                      <ProductCard
                        key={p.id}
                        product={productForCard}
                        images={allImgs.length ? allImgs : [cover]}
                      />
                    );
                  })}
                </div>
              )}
            </div>

            <div className="mt-6 flex items-center justify-center">
              <Pagination
                page={pag.page}
                totalPages={pag.totalPages}
                onPageChange={(nextPage) => pushParams({ page: nextPage })}
              />
            </div>
          </main>
        </div>
      </div>

      {filtersOpen && (
        <div className="fixed inset-0 z-50 lg:hidden">
          <button
            type="button"
            aria-label="Fechar filtros"
            className="absolute inset-0 bg-black/40"
            onClick={() => setFiltersOpen(false)}
          />

          <div className="absolute right-0 top-0 h-full w-[92%] max-w-md overflow-auto bg-white shadow-2xl">
            <div className="flex items-center justify-between border-b border-zinc-200 px-4 py-4">
              <div className="min-w-0">
                <h2 className="text-base font-semibold text-zinc-900">
                  Filtros
                </h2>
                {activeFiltersCount > 0 ? (
                  <p className="mt-0.5 text-xs text-zinc-500">
                    {activeFiltersCount} ativo(s)
                  </p>
                ) : (
                  <p className="mt-0.5 text-xs text-zinc-500">
                    Nenhum filtro ativo
                  </p>
                )}
              </div>

              <CloseButton
                onClose={() => setFiltersOpen(false)}
                className="text-3xl"
              />
            </div>

            <div className="px-4 py-4">
              <FiltersPanel
                categories={cats}
                categoriesLoading={catsLoading}
                value={filtersState}
                onChange={(patch) => pushParams(patch as any)}
                onClear={clearAll}
                onApply={() => setFiltersOpen(false)}
                stickyActions
                applyLabel="Ver resultados"
              />

              <div className="mt-4 border-t border-zinc-200 pt-4">
                <Link
                  href="/"
                  className="text-sm font-medium text-emerald-700 hover:text-emerald-800"
                >
                  Voltar para Home
                </Link>
              </div>
            </div>

            <div className="sticky bottom-0 border-t border-zinc-200 bg-white px-4 py-4">
              <LoadingButton
                isLoading={false}
                onClick={() => setFiltersOpen(false)}
                className="w-full"
              >
                Ver resultados
              </LoadingButton>
            </div>
          </div>
        </div>
      )}
    </section>
  );
}

