function ModelsCarouselSection({
  models,
  onOpenModel,
  onTalkToRep,
}: {
  models: DroneModel[];
  onOpenModel: (key: string) => void;
  onTalkToRep: () => void;
}) {
  const scrollerRef = useRef<HTMLDivElement | null>(null);

  function scrollByCards(dir: -1 | 1) {
    const el = scrollerRef.current;
    if (!el) return;

    const amount = Math.round(el.clientWidth * 0.85) * dir;
    el.scrollBy({ left: amount, behavior: "smooth" });
  }

  return (
    <section className="py-10 sm:py-14">
      <style jsx global>{`
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
      `}</style>

      <div className="max-w-6xl mx-auto px-5">
        <div className="flex items-end justify-between gap-4">
          <div>
            <h2 className="text-xl sm:text-3xl font-extrabold tracking-tight">
              Modelos disponíveis
            </h2>
            <p className="mt-2 text-sm text-slate-300 max-w-2xl">
              Escolha um modelo para ver <b>especificações</b>,{" "}
              <b>funcionalidades</b>, <b>benefícios</b> e a <b>galeria</b>{" "}
              completa.
            </p>
          </div>

          <div className="hidden sm:flex items-center gap-2">
            <button
              onClick={() => scrollByCards(-1)}
              className="rounded-2xl border border-white/10 bg-white/5 px-4 py-2 text-sm font-extrabold text-slate-200 hover:bg-white/10"
              aria-label="Anterior"
            >
              ←
            </button>
            <button
              onClick={() => scrollByCards(1)}
              className="rounded-2xl border border-white/10 bg-white/5 px-4 py-2 text-sm font-extrabold text-slate-200 hover:bg-white/10"
              aria-label="Próximo"
            >
              →
            </button>
          </div>
        </div>

        <div className="relative mt-6 overflow-hidden rounded-[34px] border border-white/10 bg-white/[0.03] p-4 sm:p-6">
          <div className="pointer-events-none absolute inset-0 opacity-80">
            <div className="absolute -top-24 -right-24 h-64 w-64 rounded-full bg-emerald-500/10 blur-3xl" />
            <div className="absolute -bottom-28 -left-20 h-72 w-72 rounded-full bg-blue-500/10 blur-3xl" />
          </div>

          <div className="pointer-events-none absolute inset-y-0 left-0 w-12 bg-gradient-to-r from-[#070A0E] to-transparent opacity-80" />
          <div className="pointer-events-none absolute inset-y-0 right-0 w-12 bg-gradient-to-l from-[#070A0E] to-transparent opacity-80" />

          <div
            ref={scrollerRef}
            className="relative flex gap-4 overflow-x-auto overscroll-x-contain snap-x snap-mandatory scroll-smooth no-scrollbar"
          >
            {models.map((m) => (
              <ModelCard key={m.key} model={m} onOpen={onOpenModel} />
            ))}
          </div>

          <div className="relative mt-4 flex flex-col sm:flex-row gap-3 sm:items-center sm:justify-between">
            <div className="text-xs text-slate-400">
              No celular, arraste para o lado. No desktop, use as setas.
            </div>

            <button
              onClick={onTalkToRep}
              className="inline-flex items-center justify-center rounded-2xl border border-emerald-400/30 bg-emerald-500/10 px-4 py-3 text-sm font-extrabold text-emerald-200 hover:bg-emerald-500/15"
            >
              Fale com um representante
            </button>
          </div>
        </div>
      </div>
    </section>
  );
}

export default function DronesPublicPage() {
  const router = useRouter();
  const search = useSearchParams();

  const [models, setModels] = useState<DroneModel[]>([]);
  const [selectedModel, setSelectedModel] = useState<string>("");

  const [landing, setLanding] = useState<any>(null);
  const [modelData, setModelData] = useState<any>(null);
  const [comments, setComments] = useState<any[]>([]);
  const [representatives, setRepresentatives] = useState<any[]>([]);

  const [loading, setLoading] = useState(true);

  const fetchModels = useCallback(async (): Promise<DroneModel[]> => {
    const res = await fetch(`${API_BASE}/api/public/drones/models`, {
      cache: "no-store",
    });
    if (!res.ok) return fallbackModels();

    const json = await res.json();
    const raw = extractArray(json);

    const normalized = raw
      .map((m: any) => {
        const key = String(m.key || m.model_key || "")
          .trim()
          .toLowerCase();
        const label = String(m.label || m.name || "").trim();

        // ✅ backend ideal: já manda a mídia do card resolvida pela seleção (models_json)
        const cardMediaUrl = m.card_media_url || "";
        const cardMediaPath = m.card_media_path || m.card_media || ""; // tolerante
        const cardMediaType =
          m.card_media_type || m.card_media_kind || m.media_type || undefined;

        // fallback compat antigo (se ainda existir)
        const legacyUrl =
          m.media_url ||
          m.file_url ||
          m.src ||
          m.media_path ||
          m.mediaPath ||
          m.path ||
          m.video_url ||
          m.image_url ||
          m.image ||
          m.video ||
          m.cover_url ||
          m.thumb_url ||
          "";

        const chosenUrl = cardMediaUrl || cardMediaPath || legacyUrl;

        return {
          key,
          label,
          is_active: Number(m.is_active ?? 1),
          sort_order: Number(m.sort_order ?? 0),

          // ✅ preferir os campos novos de card
          card_media_url: chosenUrl ? absUrl(chosenUrl) : undefined,
          card_media_path: cardMediaPath ? String(cardMediaPath) : undefined,
          card_media_type: cardMediaType,

          // ✅ ids (opcionais)
          current_card_media_id:
            m.current_card_media_id != null
              ? Number(m.current_card_media_id)
              : null,
          current_hero_media_id:
            m.current_hero_media_id != null
              ? Number(m.current_hero_media_id)
              : null,

          _raw: m,
        } as DroneModel;
      })
      .filter((m: DroneModel) => m.key && m.label);

    return sortModels(normalized.length ? normalized : fallbackModels());
  }, []);

  const fetchPage = useCallback(async (modelKey?: string) => {
    const url = modelKey
      ? `${API_BASE}/api/public/drones?model=${modelKey}`
      : `${API_BASE}/api/public/drones`;

    const res = await fetch(url, { cache: "no-store" });
    if (!res.ok) return null;
    return (await res.json()) as RootResponse;
  }, []);

  const fetchRepresentatives = useCallback(async () => {
    const res = await fetch(`${API_BASE}/api/public/drones/representantes`, {
      cache: "no-store",
    });
    if (!res.ok) return [];
    const json = await res.json();
    return extractArray(json);
  }, []);

  useEffect(() => {
    (async () => {
      setLoading(true);

      const [modelsDb, reps] = await Promise.all([
        fetchModels(),
        fetchRepresentatives(),
      ]);
      setModels(modelsDb);
      setRepresentatives(reps);

      const urlModel = search.get("model") || "";
      const initial = pickInitialModel(modelsDb, urlModel);

      setSelectedModel(initial);

      const root = await fetchPage(initial);
      setLanding(root?.landing || null);
      setModelData(root?.model_data || null);
      setComments(extractArray(root?.comments));

      setLoading(false);
    })();
  }, [fetchModels, fetchPage, fetchRepresentatives, search]);

  async function changeModel(key: string) {
    if (!key || key === selectedModel) return;

    setSelectedModel(key);
    router.replace(`/drones?model=${key}`);

    setLoading(true);
    const root = await fetchPage(key);

    setLanding(root?.landing || null);
    setModelData(root?.model_data || null);
    setComments(extractArray(root?.comments));
    setLoading(false);
  }

  const mergedPage = useMemo(
    () => ({ ...(landing || {}), ...(modelData || {}) }),
    [landing, modelData],
  );

  const sectionsOrder = useMemo(() => {
    const raw = mergedPage?.sections_order_json || [
      "hero",
      "specs",
      "features",
      "benefits",
      "gallery",
      "representatives",
      "comments",
    ];

    const filtered = raw.filter(
      (k: any) =>
        !["specs", "features", "benefits", "gallery"].includes(String(k)),
    );

    if (!filtered.includes("models")) {
      const heroIndex = filtered.indexOf("hero");
      if (heroIndex >= 0) filtered.splice(heroIndex + 1, 0, "models");
      else filtered.unshift("models");
    }

    return filtered;
  }, [mergedPage]);

  const sections: Record<string, JSX.Element> = {
    hero: <HeroSection page={mergedPage} representatives={representatives} />,

    models: (
      <ModelsCarouselSection
        models={models.filter((m) => String(m.is_active ?? 1) === "1")}
        onOpenModel={(key) => router.push(`/drones/${key}`)}
        onTalkToRep={() => {
          const el = document.getElementById("drones-representatives");
          if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
        }}
      />
    ),

    representatives: (
      <div id="drones-representatives">
        <RepresentativesSection
          page={mergedPage}
          representatives={representatives}
        />
      </div>
    ),

    comments: (
      <CommentsSection
        comments={comments}
        modelKey={selectedModel}
        onCreated={() => changeModel(selectedModel)}
      />
    ),
  };

  if (loading && !landing) {
    return (
      <div className="min-h-svh bg-[#070A0E] flex items-center justify-center">
        <div className="h-10 w-10 rounded-full border-2 border-white/20 border-t-white animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-svh bg-[#070A0E] text-slate-100">
      <div className="sticky top-0 z-40 bg-black/60 backdrop-blur border-b border-white/10">
        <div className="max-w-6xl mx-auto px-5 py-3 flex gap-3 items-center">
          <span className="text-xs font-semibold text-slate-300 shrink-0">
            Modelo:
          </span>

          <select
            className="sm:hidden w-full rounded-xl bg-white/5 border border-white/10 px-3 py-2 text-sm"
            value={selectedModel}
            onChange={(e) => changeModel(e.target.value)}
          >
            {models.map((m) => (
              <option key={m.key} value={m.key}>
                {m.label}
              </option>
            ))}
          </select>

          <div className="hidden sm:flex gap-2 overflow-x-auto no-scrollbar">
            {models.map((m) => (
              <button key={m.key} onClick={() => changeModel(m.key)}>
                <ModelTab active={m.key === selectedModel} label={m.label} />
              </button>
            ))}
          </div>
        </div>
      </div>

      {sectionsOrder.map((key: Key | null | undefined, idx: number) => {
        const sectionKey = String(key);
        return (
          <div key={sectionKey}>
            {sections[sectionKey]}
            {idx < sectionsOrder.length - 1 && (
              <div className="max-w-6xl mx-auto px-5">
                <div className="h-px bg-gradient-to-r from-transparent via-white/10 to-transparent" />
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import type { Product } from "@/types/product";
import ProductCard from "@/components/products/ProductCard";
import { useAuth } from "@/context/AuthContext";
import { apiClient } from "@/lib/apiClient";
import { ENDPOINTS } from "@/services/api/endpoints";

export default function FavoritosPage() {
  const { user, loading: authLoading } = useAuth();

  const [loading, setLoading] = useState(true);
  const [favoritos, setFavoritos] = useState<Product[]>([]);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // se ainda está carregando o auth, espera
    if (authLoading) return;

    // se não tem usuário logado, não tenta buscar nada
    if (!user) {
      setLoading(false);
      return;
    }

    async function fetchFavorites() {
      try {
        const json = await apiClient.get<Product[] | { data: Product[] }>(
          ENDPOINTS.FAVORITES.LIST,
        );

        // aceita { data: [...] } ou [...]
        const data: Product[] = Array.isArray(json)
          ? (json as Product[])
          : ((json as any)?.data ?? []);

        setFavoritos(data ?? []);
      } catch (err: any) {
        console.error("Erro ao buscar favoritos:", err);
        if (err?.status === 401) {
          setError("Faça login novamente para ver seus favoritos.");
        } else {
          setError("Erro ao carregar seus favoritos.");
        }
      } finally {
        setLoading(false);
      }
    }

    fetchFavorites();
  }, [user, authLoading]);

  // ======================
  // RENDER
  // ======================

  if (!user) {
    return (
      <main className="min-h-svh max-w-5xl mx-auto px-4 py-8">
        <h1 className="text-2xl font-semibold mb-4">Meus Favoritos</h1>
        <p className="text-gray-700 mb-4">
          Você precisa estar logado para ver seus favoritos.
        </p>
        <Link
          href="/login"
          className="inline-flex items-center justify-center rounded-lg bg-[#2F7E7F] text-white px-4 py-2 text-sm font-semibold hover:bg-[#2a6f70]"
        >
          Fazer login
        </Link>
      </main>
    );
  }

  return (
    <main className="min-h-svh max-w-6xl mx-auto px-4 py-8">
      <div className="flex items-center justify-between gap-2 mb-6 flex-wrap">
        <h1 className="text-2xl font-semibold">Meus Favoritos</h1>

        <Link href="/" className="text-sm text-[#2F7E7F] hover:underline">
          Voltar para a loja
        </Link>
      </div>

      {loading && <p className="text-gray-600">Carregando favoritos...</p>}

      {!loading && error && <p className="text-red-600">{error}</p>}

      {!loading && !error && favoritos.length === 0 && (
        <div className="border border-dashed border-gray-300 rounded-xl p-6 text-center">
          <p className="text-gray-700 mb-3">
            Você ainda não adicionou nenhum produto aos favoritos.
          </p>
          <Link
            href="/"
            className="inline-flex items-center justify-center rounded-lg bg-[#2F7E7F] text-white px-4 py-2 text-sm font-semibold hover:bg-[#2a6f70]"
          >
            Começar a comprar
          </Link>
        </div>
      )}

      {!loading && !error && favoritos.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6">
          {favoritos.map((product) => (
            <ProductCard
              key={product.id}
              product={product}
              images={(product as any).images}
              initialIsFavorite
            />
          ))}
        </div>
      )}
    </main>
  );
}

"use client";

import { useState } from "react";
import { api } from "@/lib/api";
import CustomButton from "@/components/buttons/CustomButton";
import CloseButton from "@/components/buttons/CloseButton";

type Toast = { type: "success" | "error"; message: string };

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState("");
  const [toast, setToast] = useState<Toast | null>(null);
  const [loading, setLoading] = useState(false);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!email) {
      setToast({ type: "error", message: "Informe um e-mail válido." });
      return;
    }

    setLoading(true);
    setToast(null);

    try {
      await api("/api/users/forgot-password", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email }),
      });

      setToast({
        type: "success",
        message:
          "Se este e-mail existir em nossa base, você receberá um link para redefinir a senha.",
      });
      setEmail("");
    } catch (err: any) {
      setToast({
        type: "error",
        message:
          err?.message ?? "Não foi possível enviar o e-mail de recuperação.",
      });
    } finally {
      setLoading(false);
      setTimeout(() => setToast(null), 5500);
    }
  }

  return (
    <main
      className="relative min-h-screen flex items-center justify-center bg-cover bg-center"
      style={{
        backgroundImage: "url('/images/cafe.png')",
      }}
    >
      {/* camada escura por cima da imagem */}
      <div className="absolute inset-0 bg-black/50 backdrop-blur-sm"></div>

      <section className="relative z-10 w-full max-w-md rounded-2xl border border-white/20 bg-white/10 backdrop-blur-md shadow-xl text-center text-white p-8">
        <div className="absolute left-4 top-4">
          <CloseButton className="text-white/70 hover:text-white" />
        </div>

        {/* ícone de cadeado */}
        <div className="mx-auto mb-5 flex h-14 w-14 items-center justify-center rounded-full bg-white/20 backdrop-blur-sm">
          <svg
            viewBox="0 0 24 24"
            className="h-7 w-7 text-white"
            fill="currentColor"
          >
            <path d="M12 1a5 5 0 0 0-5 5v3H6a2 2 0 0 0-2 2v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8a2 2 0 0 0-2-2h-1V6a5 5 0 0 0-5-5Zm-3 8V6a3 3 0 0 1 6 0v3H9Zm3 4a1.5 1.5 0 0 1 .75 2.8V18a.75.75 0 1 1-1.5 0v-2.2A1.5 1.5 0 0 1 12 13Z" />
          </svg>
        </div>

        <h1 className="text-2xl font-semibold mb-2">Esqueci minha senha</h1>
        <p className="text-sm text-white/80 mb-6">
          Informe seu e-mail para enviarmos um link de redefinição.
        </p>

        <form onSubmit={onSubmit} className="space-y-5">
          <div className="text-left">
            <label htmlFor="email" className="block text-sm mb-1 text-white/90">
              E-mail
            </label>
            <input
              id="email"
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="seu@email.com"
              className="w-full rounded-md border border-white/30 bg-white/20 placeholder-white/60 text-white px-3 py-2 outline-none focus:ring-2 focus:ring-[#359293]"
            />
          </div>

          <CustomButton
            label={loading ? "Enviando..." : "Enviar link de redefinição"}
            variant="primary"
            size="large"
            isLoading={loading}
            type="submit"
            className="w-full"
          />
        </form>

        {toast && (
          <div
            className={`mt-5 rounded-lg px-4 py-3 text-sm ${
              toast.type === "success"
                ? "bg-green-500/20 text-green-100"
                : "bg-red-500/20 text-red-100"
            }`}
            role="status"
          >
            {toast.message}
          </div>
        )}
      </section>
    </main>
  );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { z } from "zod";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";

const schema = z.object({
  email: z.string().email("Informe um e-mail válido"),
  senha: z.string().min(6, "A senha deve ter pelo menos 6 caracteres"),
});

type FormData = z.infer<typeof schema>;

export default function LoginPage() {
  const router = useRouter();
  const { login } = useAuth();
  const [serverMsg, setServerMsg] = useState<string | null>(null);
  const [showPw, setShowPw] = useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
    setError,
  } = useForm<FormData>({ resolver: zodResolver(schema) });

  const onSubmit = async (data: FormData) => {
    setServerMsg(null);

    try {
      const r = await login(data.email, data.senha);

      if (!r.ok) {
        // Consistência: SEMPRE a mesma frase
        setServerMsg("Credenciais inválidas.");
        // Opcional: marcar campos como inválidos sem mensagem técnica
        setError("email", { message: undefined });
        setError("senha", { message: undefined });
        return; // fica na tela de login
      }

      router.push("/");
    } catch {
      // Blindagem final: nunca deixar erro estourar overlay
      setServerMsg("Credenciais inválidas.");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center relative">
      {/* Fundo */}
      <div
        className="absolute inset-0 bg-cover bg-center filter blur-sm"
        style={{ backgroundImage: "url('/images/cafe.png')" }}
        aria-hidden
      />
      <div className="absolute inset-0 bg-black/50" aria-hidden />

      {/* Card */}
      <div className="relative w-full max-w-md rounded-2xl shadow-2xl overflow-hidden backdrop-blur-xl bg-white/10 border border-white/20">
        <div className="px-8 pt-8 text-center">
          <h1 className="text-3xl font-extrabold tracking-tight text-white drop-shadow-sm">
            Login
          </h1>
          <p className="mt-2 text-white/80 text-sm">
            Entre para acompanhar pedidos e ofertas.
          </p>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="p-8 grid gap-5">
          {/* Aviso de erro do servidor */}
          {serverMsg && (
            <div
              className="text-center text-sm px-3 py-2 rounded-md bg-red-500/20 text-red-100"
              role="alert"
              aria-live="assertive"
            >
              {serverMsg}
            </div>
          )}

          {/* Email */}
          <div>
            <label className="block text-sm font-medium text-white/90 mb-1">
              Email
            </label>
            <input
              type="email"
              {...register("email")}
              placeholder="seu@email.com"
              className="w-full rounded-lg bg-white/90 focus:bg-white px-4 py-2.5 outline-none ring-2 ring-transparent focus:ring-[#EC5B20] transition"
              autoComplete="email"
            />
            {errors.email && (
              <p className="mt-1 text-xs text-red-200">
                {errors.email.message}
              </p>
            )}
          </div>

          {/* Senha */}
          <div>
            <label className="block text-sm font-medium text-white/90 mb-1">
              Senha
            </label>
            <div className="relative">
              <input
                type={showPw ? "text" : "password"}
                {...register("senha")}
                placeholder="••••••••"
                className="w-full rounded-lg bg-white/90 focus:bg-white px-4 py-2.5 pr-11 outline-none ring-2 ring-transparent focus:ring-[#EC5B20] transition"
                autoComplete="current-password"
              />
              <button
                type="button"
                onClick={() => setShowPw((v) => !v)}
                className="absolute inset-y-0 right-0 px-3 text-[#0f5e63] hover:text-[#EC5B20]"
                aria-label={showPw ? "Ocultar senha" : "Mostrar senha"}
                title={showPw ? "Ocultar senha" : "Mostrar senha"}
              >
                {showPw ? "🙈" : "👁️"}
              </button>
            </div>
            {errors.senha && (
              <p className="mt-1 text-xs text-red-200">
                {errors.senha.message}
              </p>
            )}
          </div>

          {/* Botão */}
          <button
            disabled={isSubmitting}
            className="w-full mt-2 inline-flex items-center justify-center gap-2 rounded-lg bg-[#359293] hover:bg-[#2e7f81] active:bg-[#2a7476] text-white font-semibold py-3 shadow-lg transition"
          >
            {isSubmitting ? "Entrando…" : "Entrar"}
          </button>

          {/* Links */}
          <p className="text-center text-white/90 text-sm">
            Esqueceu a senha?{" "}
            <Link
              href="/forgot-password"
              className="underline text-[#EC5B20] hover:text-white transition"
            >
              Recuperar
            </Link>
          </p>
          <p className="text-center text-white/90 text-sm">
            Ainda não tem conta?{" "}
            <Link
              href="/register"
              className="underline text-[#EC5B20] hover:text-white transition"
            >
              Cadastre-se
            </Link>
          </p>
        </form>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useUserAddresses, UserAddressPayload } from "@/hooks/useUserAddresses";
import { ESTADOS_BR } from "@/utils/brasil";

export default function NovoEnderecoPage() {
  const router = useRouter();
  const { createAddress } = useUserAddresses();

  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState<UserAddressPayload>({
    apelido: "",
    cep: "",
    endereco: "",
    numero: "",
    bairro: "",
    cidade: "",
    estado: "",
    complemento: "",
    ponto_referencia: "",
    telefone: "",
    is_default: true,
  });

  const [cepLoading, setCepLoading] = useState(false);
  const [cities, setCities] = useState<string[]>([]);

  const set =
    (field: keyof UserAddressPayload) =>
    (e: React.ChangeEvent<HTMLInputElement>) =>
      setForm((prev) => ({ ...prev, [field]: e.target.value }));

  const handleCepChange: React.ChangeEventHandler<HTMLInputElement> = (e) => {
    const digits = e.target.value.replace(/\D/g, "").slice(0, 8);
    const masked =
      digits.length > 5 ? `${digits.slice(0, 5)}-${digits.slice(5)}` : digits;
    setForm((prev) => ({ ...prev, cep: masked }));
  };

  useEffect(() => {
    const digits = form.cep.replace(/\D/g, "");
    if (digits.length !== 8) return;

    let aborted = false;

    (async () => {
      try {
        setCepLoading(true);
        const res = await fetch(`https://viacep.com.br/ws/${digits}/json/`);
        if (!res.ok) return;
        const data = await res.json();
        if (aborted || data.erro) return;

        setForm((prev) => ({
          ...prev,
          endereco: data.logradouro || prev.endereco,
          bairro: data.bairro || prev.bairro,
          cidade: data.localidade || prev.cidade,
          estado: data.uf || prev.estado,
        }));
      } catch {
      } finally {
        if (!aborted) setCepLoading(false);
      }
    })();

    return () => {
      aborted = true;
    };
  }, [form.cep]);

  useEffect(() => {
    const uf = (form.estado || "").toUpperCase();
    if (!uf) {
      setCities([]);
      return;
    }

    let aborted = false;

    (async () => {
      try {
        const res = await fetch(
          `https://servicodados.ibge.gov.br/api/v1/localidades/estados/${uf}/municipios`,
        );
        if (!res.ok) return;
        const data = await res.json();
        if (aborted || !Array.isArray(data)) return;
        const names = data.map((m: any) => m.nome).sort();
        setCities(names);
      } catch {}
    })();

    return () => {
      aborted = true;
    };
  }, [form.estado]);

  const handleEstadoChange: React.ChangeEventHandler<HTMLSelectElement> = (
    e,
  ) => {
    const uf = e.target.value;
    setForm((prev) => ({ ...prev, estado: uf, cidade: "" }));
  };

  const handleCidadeChange: React.ChangeEventHandler<HTMLInputElement> = (
    e,
  ) => {
    const value = e.target.value;
    setForm((prev) => ({ ...prev, cidade: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.endereco || !form.cep || !form.cidade || !form.estado) {
      // validação simples
      return;
    }

    try {
      setSaving(true);
      await createAddress(form);
      router.push("/meus-dados/enderecos");
    } finally {
      setSaving(false);
    }
  };

  const ui = {
    wrap: "pt-20 sm:pt-24 md:pt-28 px-4 sm:px-6 lg:px-10",
    container: "mx-auto w-full max-w-3xl sm:max-w-4xl lg:max-w-5xl",
    card: "rounded-2xl border border-gray-200 bg-white shadow-sm overflow-hidden",
    header: "mb-4 sm:mb-6",
    title: "text-lg sm:text-xl font-semibold tracking-tight",
    subtitle: "mt-1 text-xs sm:text-sm text-gray-500",
    form: "p-5 sm:p-6 lg:p-8 space-y-4 sm:space-y-5",
    grid: "grid grid-cols-1 md:grid-cols-2 gap-4 sm:gap-5",
    input:
      "w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 sm:py-3 text-sm " +
      "outline-none transition min-h-[44px] " +
      "focus:border-[#359293] focus:ring-2 focus:ring-[#359293]/20 placeholder:text-gray-400",
    footerButtons:
      "mt-6 flex flex-col-reverse sm:flex-row sm:justify-end gap-3",
    cancelBtn:
      "inline-flex items-center justify-center rounded-lg border border-gray-300 px-4 py-2.5 " +
      "text-sm font-medium text-gray-700 hover:bg-gray-50",
    saveBtn:
      "inline-flex items-center justify-center rounded-lg bg-[#359293] px-5 py-2.5 text-sm font-semibold " +
      "text-white shadow-sm hover:bg-[#2b7778] disabled:opacity-60",
  };

  return (
    <div className={ui.wrap}>
      <div className={ui.container}>
        <div className={ui.header}>
          <h1 className={ui.title}>Novo endereço</h1>
          <p className={ui.subtitle}>
            Cadastre um endereço para facilitar seus próximos pedidos.
          </p>
        </div>

        <div className={ui.card}>
          <form onSubmit={handleSubmit} className={ui.form}>
            <div className={ui.grid}>
              <Field label="Apelido (Casa, Trabalho...)" full>
                <input
                  className={`${ui.input} input-kavita`}
                  value={form.apelido || ""}
                  onChange={set("apelido")}
                  placeholder="Casa, Fazenda, Escritório..."
                />
              </Field>

              <Field label="CEP">
                <div className="flex items-center gap-2">
                  <input
                    className={`${ui.input} input-kavita`}
                    value={form.cep || ""}
                    onChange={handleCepChange}
                    inputMode="numeric"
                    placeholder="00000-000"
                  />
                  {cepLoading && (
                    <span className="text-[11px] text-gray-500">
                      Buscando...
                    </span>
                  )}
                </div>
              </Field>

              <Field label="Endereço" full>
                <input
                  className={`${ui.input} input-kavita`}
                  value={form.endereco || ""}
                  onChange={set("endereco")}
                  autoComplete="street-address"
                  placeholder="Rua / Avenida"
                />
              </Field>

              <Field label="Número">
                <input
                  className={`${ui.input} input-kavita`}
                  value={form.numero || ""}
                  onChange={set("numero")}
                  placeholder="Número"
                />
              </Field>

              <Field label="Bairro">
                <input
                  className={`${ui.input} input-kavita`}
                  value={form.bairro || ""}
                  onChange={set("bairro")}
                />
              </Field>

              <Field label="Cidade">
                <input
                  className={`${ui.input} input-kavita`}
                  list="novo-endereco-cidades"
                  value={form.cidade || ""}
                  onChange={handleCidadeChange}
                  placeholder="Cidade"
                />
                <datalist id="novo-endereco-cidades">
                  {cities.map((city) => (
                    <option key={city} value={city} />
                  ))}
                </datalist>
              </Field>

              <Field label="Estado">
                <select
                  className={`${ui.input} input-kavita`}
                  value={(form.estado || "").toUpperCase()}
                  onChange={handleEstadoChange}
                >
                  <option value="">Selecione o estado</option>
                  {ESTADOS_BR.map((uf) => (
                    <option key={uf.sigla} value={uf.sigla}>
                      {uf.sigla} - {uf.nome}
                    </option>
                  ))}
                </select>
              </Field>

              <Field label="Complemento" full>
                <input
                  className={`${ui.input} input-kavita`}
                  value={form.complemento || ""}
                  onChange={set("complemento")}
                  placeholder="Apartamento, bloco, etc."
                />
              </Field>

              <Field label="Ponto de referência" full>
                <input
                  className={`${ui.input} input-kavita`}
                  value={form.ponto_referencia || ""}
                  onChange={set("ponto_referencia")}
                  placeholder="Perto de..."
                />
              </Field>

              <Field label="Telefone para entrega">
                <input
                  className={`${ui.input} input-kavita`}
                  value={form.telefone || ""}
                  onChange={set("telefone")}
                  inputMode="tel"
                  placeholder="(DD) 99999-9999"
                />
              </Field>
            </div>

            <div className="mt-2 flex items-center gap-2">
              <input
                id="addr-default"
                type="checkbox"
                checked={!!form.is_default}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    is_default: e.target.checked,
                  }))
                }
              />
              <label htmlFor="addr-default" className="text-sm text-gray-700">
                Definir como endereço padrão
              </label>
            </div>

            <div className={ui.footerButtons}>
              <button
                type="button"
                onClick={() => router.back()}
                className={ui.cancelBtn}
              >
                Cancelar
              </button>
              <button type="submit" disabled={saving} className={ui.saveBtn}>
                {saving ? "Salvando..." : "Salvar endereço"}
              </button>
            </div>
          </form>
        </div>

        <div className="h-8 sm:h-10" />
      </div>
    </div>
  );
}

function Field({
  label,
  children,
  full,
}: {
  label: string;
  children: React.ReactNode;
  full?: boolean;
}) {
  return (
    <div
      className={
        full ? "md:col-span-2 flex flex-col gap-1.5" : "flex flex-col gap-1.5"
      }
    >
      <span className="text-sm text-gray-700">{label}</span>
      {children}
    </div>
  );
}

