  quantidade: number;

  // possíveis nomes para a imagem
  imagem?: string | null;
  image?: string | null;
  product_image?: string | null;
};

type PedidoDetalhe = {
  id: number;
  usuario_id: number;
  forma_pagamento: string;
  status: string;
  data_pedido: string;
  endereco: any;
  total: number;
  itens: PedidoItem[];
};

const money = (v: number) =>
  `R$ ${Number(v || 0)
    .toFixed(2)
    .replace(".", ",")}`;

export default function PedidoPage() {
  const router = useRouter();
  const params = useParams<{ id: string }>();
  const pedidoId = params?.id;

  const { user } = useAuth();

  // Ajuste mínimo: evita erro de tipo se AuthUser não tiver "token" tipado
  const token = (user as any)?.token as string | undefined;

  const isLoggedIn = !!user?.id;

  const [pedido, setPedido] = useState<PedidoDetalhe | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Redireciona se não estiver logado
  useEffect(() => {
    if (!isLoggedIn) {
      setError("Você precisa estar logado para ver o detalhe da compra.");
      router.push("/login");
    }
  }, [isLoggedIn, router]);

  // Busca os dados do pedido
  useEffect(() => {
    if (!pedidoId || !isLoggedIn) return;

    const fetchPedido = async () => {
      try {
        setLoading(true);
        setError(null);

        const headers: Record<string, string> = {};
        // Ajuste: usa token real (quando existir)
        if (token) headers.Authorization = `Bearer ${token}`;

        const { data } = await axios.get<PedidoDetalhe>(
          `${API_BASE}/api/pedidos/${pedidoId}`,
          {
            headers,
          },
        );

        setPedido(data);
      } catch (err: any) {
        const status = err?.response?.status;
        if (status === 404) {
          setError("Pedido não encontrado.");
        } else if (status === 401 || status === 403) {
          setError(
            "Você não tem permissão para ver este pedido. Faça login novamente.",
          );
          router.push("/login");
        } else {
          setError(
            err?.response?.data?.message ||
              "Não foi possível carregar esta compra.",
          );
        }
      } finally {
        setLoading(false);
      }
    };

    fetchPedido();
  }, [pedidoId, token, isLoggedIn, router]);

  if (loading) {
    return (
      <main className="max-w-4xl mx-auto px-4 py-10">
        <h1 className="text-2xl font-bold mb-4">Detalhe da compra</h1>
        <p className="text-gray-600">Carregando informações do pedido...</p>
      </main>
    );
  }

  if (error || !pedido) {
    return (
      <main className="max-w-4xl mx-auto px-4 py-10">
        <h1 className="text-2xl font-bold mb-4">Detalhe da compra</h1>
        <p className="text-red-600">
          {error || "Não foi possível carregar esta compra."}
        </p>
      </main>
    );
  }

  // endereço vem como JSON string ou objeto
  const endereco = (() => {
    if (!pedido.endereco) return null;
    if (typeof pedido.endereco === "string") {
      try {
        return JSON.parse(pedido.endereco);
      } catch {
        return pedido.endereco;
      }
    }
    return pedido.endereco;
  })();

  return (
    <main className="max-w-4xl mx-auto px-4 py-10">
      {/* Título */}
      <div className="flex items-center justify-between gap-3 mb-6">
        <h1 className="text-2xl font-bold">Detalhe da compra</h1>

        <button
          type="button"
          onClick={() => router.push("/pedidos")}
          className="hidden sm:inline-flex px-4 py-2 rounded-lg border border-gray-300 text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors"
        >
          Voltar para minhas compras
        </button>
      </div>

      {/* Dados gerais */}
      <section className="mb-6 space-y-2 text-sm text-gray-800">
        <p>
          <span className="font-semibold">Pedido:</span> #{pedido.id}
        </p>
        <p>
          <span className="font-semibold">Status:</span> {pedido.status}
        </p>
        <p>
          <span className="font-semibold">Forma de pagamento:</span>{" "}
          {pedido.forma_pagamento}
        </p>
        <p>
          <span className="font-semibold">Data:</span>{" "}
          {new Date(pedido.data_pedido).toLocaleString("pt-BR")}
        </p>
      </section>

      {/* Endereço */}
      {endereco && (
        <section className="mb-6">
          <h2 className="font-semibold mb-2">Endereço de entrega</h2>
          <div className="text-sm text-gray-800 space-y-0.5">
            <p>
              {endereco.rua}, {endereco.numero}
            </p>
            <p>
              {endereco.bairro} - {endereco.cidade}/{endereco.estado}
            </p>
            {endereco.complemento && <p>{endereco.complemento}</p>}
            {endereco.cep && <p>CEP: {endereco.cep}</p>}
          </div>
        </section>
      )}

      {/* Itens */}
      <section className="mb-6">
        <h2 className="font-semibold mb-2">Itens do pedido</h2>
        <div className="border rounded-lg divide-y bg-white">
          {pedido.itens.map((item) => {
            // tenta pegar o id do produto; se não tiver, cai pro id do item (fallback)
            const productId =
              item.produto_id ?? item.product_id ?? item.id_produto ?? item.id;

            const rawImage =
              item.imagem ?? item.image ?? item.product_image ?? null;

            return (
              <div
                key={item.id}
                className="flex flex-col sm:flex-row items-center justify-between gap-3 px-4 py-3 text-sm"
              >
                {/* Imagem */}
                <div className="w-20 h-20 flex-shrink-0 rounded-lg bg-gray-100 overflow-hidden">
                  <img
                    src={rawImage ? absUrl(rawImage) : "/placeholder.png"}
                    alt={item.nome}
                    className="w-full h-full object-cover"
                    onError={(e) => {
                      (e.target as HTMLImageElement).src = "/placeholder.png";
                    }}
                  />
                </div>

                {/* Infos */}
                <div className="flex-1 min-w-0 self-stretch flex flex-col justify-center">
                  <p className="font-medium truncate">{item.nome}</p>
                  <p className="text-gray-500">
                    {item.quantidade} x {money(item.preco)}
                  </p>
                </div>

                {/* Total + botão */}
                <div className="flex flex-col items-end gap-2">
                  <span className="font-semibold">
                    {money(item.preco * item.quantidade)}
                  </span>

                  <button
                    type="button"
                    onClick={() => router.push(`/produtos/${productId}`)}
                    className="px-4 py-2 rounded-lg bg-[#359293] text-white font-semibold text-xs sm:text-sm hover:bg-[#2b7778] transition-colors"
                  >
                    Comprar novamente
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {/* Total geral */}
      <section className="flex items-center justify-between mt-4 text-lg font-bold">
        <span>Total</span>
        <span className="text-[#EC5B20]">{money(pedido.total)}</span>
      </section>

      {/* Botão voltar em mobile */}
      <button
        type="button"
        onClick={() => router.push("/pedidos")}
        className="mt-6 w-full sm:hidden px-4 py-3 rounded-lg border border-gray-300 text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors"
      >
        Voltar para minhas compras
      </button>
    </main>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import axios from "axios";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import CustomButton from "@/components/buttons/CustomButton";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

// ----- Tipos -----
type PedidoResumo = {
  id: number;
  usuario_id: number;
  forma_pagamento: string;
  status: string;
  data_pedido: string;
  total: number;
};

export default function PedidosClientePage() {
  const router = useRouter();
  const { user } = useAuth();

  const isLoggedIn = !!user?.id;

  const [pedidos, setPedidos] = useState<PedidoResumo[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Se não estiver logado, manda para login
  useEffect(() => {
    if (!isLoggedIn) {
      setError("Você precisa estar logado para ver suas compras.");
      router.push("/login");
    }
  }, [isLoggedIn, router]);

  // Buscar pedidos do cliente (via cookie HttpOnly)
  useEffect(() => {
    if (!isLoggedIn) return;

    const fetchPedidos = async () => {
      try {
        setLoading(true);
        setError(null);

        const { data } = await axios.get<PedidoResumo[]>(
          `${API_BASE}/api/pedidos`,
          {
            withCredentials: true,
          },
        );

        setPedidos(Array.isArray(data) ? data : []);
      } catch (err: any) {
        const status = err?.response?.status;
        if (status === 401 || status === 403) {
          setError("Sessão expirada. Faça login novamente.");
          router.push("/login");
        } else {
          setError(
            err?.response?.data?.message ||
              "Não foi possível carregar seus pedidos.",
          );
        }
      } finally {
        setLoading(false);
      }
    };

    fetchPedidos();
  }, [isLoggedIn, router]);

  // --------- RENDER ---------

  if (loading) {
    return (
      <main className="max-w-5xl mx-auto px-4 py-10">
        <h1 className="text-2xl font-bold mb-4">Painel de pedidos</h1>
        <p className="text-gray-600">Carregando seus pedidos.</p>
      </main>
    );
  }

  if (error) {
    return (
      <main className="max-w-5xl mx-auto px-4 py-10">
        <h1 className="text-2xl font-bold mb-4">Painel de pedidos</h1>
        <p className="text-red-600 mb-4">{error}</p>
        <Link href="/">
          <CustomButton
            label="Voltar para a página inicial"
            variant="primary"
            size="medium"
            isLoading={false}
          />
        </Link>
      </main>
    );
  }

  return (
    <main className="max-w-5xl mx-auto px-4 py-10">
      {/* Cabeçalho */}
      <div className="flex items-center justify-between gap-3 mb-6">
        <h1 className="text-2xl font-bold">Painel de pedidos</h1>

        <button
          type="button"
          onClick={() => router.push("/")}
          className="text-sm text-gray-600 hover:text-gray-900"
        >
          Voltar
        </button>
      </div>

      {pedidos.length === 0 ? (
        <p className="text-gray-600">Você ainda não fez nenhuma compra.</p>
      ) : (
        <div className="grid gap-4">
          {pedidos.map((p) => (
            <Link
              key={p.id}
              href={`/pedidos/${p.id}`}
              className="block rounded-lg border border-gray-200 p-4 hover:bg-gray-50 transition"
            >
              <div className="flex items-start justify-between gap-3">
                <div>
                  <p className="font-semibold">Pedido #{p.id}</p>
                  <p className="text-sm text-gray-600">
                    {new Date(p.data_pedido).toLocaleString("pt-BR")}
                  </p>
                  <p className="text-sm text-gray-600">Status: {p.status}</p>
                </div>

                <div className="text-right">
                  <p className="font-semibold">
                    R${" "}
                    {Number(p.total || 0)
                      .toFixed(2)
                      .replace(".", ",")}
                  </p>
                  <p className="text-sm text-gray-600">{p.forma_pagamento}</p>
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </main>
  );
}

import { useEffect, useState } from "react";
import type { Product } from "@/types/product";
import Gallery from "@/components/ui/Gallery";
import ProductBuyBox from "@/components/products/ProductBuyBox";
import CustomButton from "@/components/buttons/CustomButton";
import { toast } from "react-hot-toast";

interface Props {
  produto: Product;
}

interface ProductReview {
  nota: number;
  comentario: string | null;
  created_at: string;
}

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

/** Normaliza qualquer caminho vindo do backend para uma URL válida do <Image> */
function absUrl(raw?: string | null): string | null {
  if (!raw) return null;
  const s = String(raw).trim().replace(/\\/g, "/");
  if (/^https?:\/\//i.test(s)) return s;
  if (s.startsWith("/uploads")) return `${API_BASE}${s}`;
  if (s.startsWith("uploads")) return `${API_BASE}/${s}`;
  if (!s.startsWith("/")) return `${API_BASE}/uploads/${s}`;
  return `${API_BASE}${s}`;
}

// MESMO TIPO DE PROMOÇÃO QUE USAMOS NA PAGE SERVER
type ProductPromotion = {
  id: number;
  product_id: number;
  title?: string;
  price?: number | string | null;
  original_price?: number | string | null;
  final_price?: number | string | null;
  discount_percent?: number | string | null;
  promo_price?: number | string | null;
  start_at?: string | null;
  end_at?: string | null;
  ends_at?: string | null;
  is_active?: number | boolean;
};

export default function ProdutoContent({ produto }: Props) {
  // ===== IMAGENS =====
  const extras = Array.isArray(produto.images)
    ? (produto.images as unknown as string[])
    : [];
  const images = Array.from(
    new Set(
      [produto.image, ...extras]
        .filter(Boolean)
        .map((img) => absUrl(img as string | null))
        .filter(Boolean) as string[],
    ),
  );

  const estoque = Number(
    (produto as any).estoque ?? (produto as any).quantity ?? 0,
  );
  const disponivel = estoque > 0;

  // ===== PROMOÇÃO / DESCONTO =====
  const [promocao, setPromocao] = useState<ProductPromotion | null>(null);

  useEffect(() => {
    async function carregarPromocao() {
      try {
        if (!produto?.id) return;

        // espera-se rota GET /api/public/promocoes/:productId
        const res = await fetch(
          `${API_BASE}/api/public/promocoes/${produto.id}`,
        );

        if (!res.ok) {
          // se não tiver promo para esse produto, só ignora
          return;
        }

        const data = await res.json();
        const promo = Array.isArray(data)
          ? ((data[0] as ProductPromotion) ?? null)
          : (data as ProductPromotion);

        setPromocao(promo);
      } catch (err) {
        console.error("Erro ao carregar promoção do produto:", err);
      }
    }

    carregarPromocao();
  }, [produto?.id]);

  // ===== LÓGICA DE PREÇO / DESCONTO (mesma da page.tsx) =====
  const precoBase = Number(produto.price ?? 0);

  const originalFromPromo = promocao?.original_price ?? promocao?.price ?? null;
  const finalFromPromo =
    promocao?.final_price ?? promocao?.promo_price ?? promocao?.price ?? null;

  const originalPrice =
    originalFromPromo != null ? Number(originalFromPromo) : precoBase || 0;

  let finalPrice =
    finalFromPromo != null ? Number(finalFromPromo) : originalPrice;

  let discountPercent: number | null = null;

  if (promocao) {
    const explicitDiscount =
      promocao.discount_percent != null
        ? Number(promocao.discount_percent)
        : NaN;

    if (
      !finalFromPromo &&
      !Number.isNaN(explicitDiscount) &&
      explicitDiscount > 0 &&
      originalPrice > 0
    ) {
      finalPrice = originalPrice * (1 - explicitDiscount / 100);
    }

    if (originalPrice > 0 && finalPrice < originalPrice) {
      discountPercent = ((originalPrice - finalPrice) / originalPrice) * 100;
    } else if (!Number.isNaN(explicitDiscount) && explicitDiscount > 0) {
      discountPercent = explicitDiscount;
    }
  }

  const priceBRL = finalPrice.toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL",
  });

  const originalPriceBRL = originalPrice.toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL",
  });

  const promoEndsAt =
    (promocao?.ends_at as string | null) ??
    (promocao?.end_at as string | null) ??
    null;

  // Esse é o produto que vai para o carrinho já com o preço final
  const produtoComPrecoFinal: Product = {
    ...produto,
    price: finalPrice,
  };

  // ===== AVALIAÇÕES (igual antes) =====
  const [reviews, setReviews] = useState<ProductReview[]>([]);
  const [loadingReviews, setLoadingReviews] = useState(true);
  const [nota, setNota] = useState<number>(0);
  const [comentario, setComentario] = useState("");

  useEffect(() => {
    async function carregarAvaliacoes() {
      try {
        setLoadingReviews(true);
        const res = await fetch(
          `${API_BASE}/api/public/produtos/${produto.id}/avaliacoes`,
        );
        if (!res.ok) {
          console.error("Erro ao buscar avaliações:", res.status);
          return;
        }
        const data = await res.json();
        setReviews(Array.isArray(data) ? data : []);
      } catch (err) {
        console.error("Erro ao carregar avaliações:", err);
      } finally {
        setLoadingReviews(false);
      }
    }

    if (produto?.id) {
      carregarAvaliacoes();
    }
  }, [produto?.id]);

  async function enviarAvaliacao() {
    if (!nota || nota < 1 || nota > 5) {
      toast.error("Selecione uma nota de 1 a 5.");
      return;
    }

    try {
      const res = await fetch(`${API_BASE}/api/public/produtos/avaliacoes`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          produto_id: produto.id,
          nota,
          comentario: comentario.trim() || null,
        }),
      });

      if (!res.ok) {
        const txt = await res.text();
        console.error("Erro ao enviar avaliação:", txt);
        toast.error("Erro ao enviar sua avaliação.");
        return;
      }

      toast.success("Avaliação enviada com sucesso!");
      setNota(0);
      setComentario("");

      const resList = await fetch(
        `${API_BASE}/api/public/produtos/${produto.id}/avaliacoes`,
      );
      const data = await resList.json();
      setReviews(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Erro ao enviar avaliação:", err);
      toast.error("Erro ao enviar sua avaliação.");
    }
  }

  const ratingAvgBackend: number | undefined = (produto as any)?.rating_avg;
  const ratingCountBackend: number | undefined = (produto as any)?.rating_count;

  const media =
    ratingAvgBackend && ratingAvgBackend > 0
      ? Number(ratingAvgBackend)
      : reviews.length
        ? reviews.reduce((acc, r) => acc + Number(r.nota || 0), 0) /
          reviews.length
        : 0;

  const totalAval = ratingCountBackend ?? reviews.length;

  const totalComentarios = reviews.filter(
    (r) => r.comentario && r.comentario.trim() !== "",
  ).length;

  const dist = [5, 4, 3, 2, 1].map((star) => {
    const count = reviews.filter((r) => Number(r.nota) === star).length;
    const percent = totalAval ? (count / totalAval) * 100 : 0;
    return { star, count, percent };
  });

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 md:py-12 space-y-10">
      {/* ===== BLOCO PRINCIPAL: GALERIA + INFO + COMPRA ===== */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        {/* Galeria (lado esquerdo) */}
        <div className="md:sticky md:top-24 h-fit">
          <Gallery images={images} alt={produto.name} />
        </div>

        {/* Conteúdo + caixa de compra (lado direito) */}
        <div className="flex flex-col gap-6">
          <header className="space-y-2">
            <h1 className="text-3xl md:text-4xl font-bold tracking-tight text-gray-900">
              {produto.name}
            </h1>

            <div className="flex items-center gap-3 flex-wrap">
              <span
                className={`inline-flex items-center rounded-full px-3 py-1 text-xs font-medium ${
                  disponivel
                    ? "bg-emerald-50 text-emerald-700 ring-1 ring-emerald-200"
                    : "bg-red-50 text-red-700 ring-1 ring-red-200"
                }`}
              >
                {disponivel ? "Em estoque" : "Esgotado"}
              </span>
              <span className="text-xs text-gray-500">ID #{produto.id}</span>

              {discountPercent && discountPercent > 0 && (
                <span className="inline-flex items-center rounded-full bg-red-500 px-2 py-0.5 text-[11px] font-bold text-white shadow-sm">
                  -{discountPercent.toFixed(0)}% OFF
                </span>
              )}
            </div>

            {/* Resumo de avaliação (estrelinhas + média) */}
            <div className="flex items-center gap-3 pt-1">
              <div className="flex items-center gap-1 text-yellow-500 text-lg">
                {Array.from({ length: 5 }).map((_, i) => (
                  <span key={i}>
                    {media >= i + 1
                      ? "★"
                      : media > i && media < i + 1
                        ? "★"
                        : "☆"}
                  </span>
                ))}
              </div>
              <div className="text-sm text-gray-700">
                {media ? (
                  <>
                    <span className="font-semibold">
                      {media.toFixed(1)} / 5
                    </span>{" "}
                    <span className="text-gray-400">
                      ({totalAval || 0} avaliação
                      {totalAval === 1 ? "" : "es"})
                    </span>
                  </>
                ) : (
                  <span className="text-gray-400">
                    Ainda não avaliado pelos clientes
                  </span>
                )}
              </div>
            </div>
          </header>

          {/* PREÇO + DESCONTO (mesma lógica da page.tsx) */}
          <div className="space-y-1">
            {discountPercent &&
              discountPercent > 0 &&
              originalPrice > finalPrice && (
                <div className="flex flex-wrap items-baseline gap-2 text-sm">
                  <span className="text-sm text-gray-400 line-through">
                    {originalPriceBRL}
                  </span>
                  <span className="text-xs font-semibold text-emerald-700">
                    economia de {discountPercent.toFixed(0)}%
                  </span>
                </div>
              )}

            <p className="text-3xl font-extrabold text-emerald-600">
              {priceBRL}
            </p>

            {promoEndsAt && (
              <p className="text-xs text-amber-700">
                Promoção válida até{" "}
                {new Date(promoEndsAt).toLocaleDateString("pt-BR", {
                  day: "2-digit",
                  month: "2-digit",
                })}
                , ou enquanto durarem os estoques.
              </p>
            )}
          </div>

          {/* Descrição */}
          <div className="prose max-w-none text-gray-700">
            <p>{produto.description || "Sem descrição disponível."}</p>
          </div>

          {/* Caixa de compra usando PREÇO FINAL */}
          <ProductBuyBox product={produtoComPrecoFinal} stock={estoque} />
        </div>
      </div>

      {/* ===== BLOCO DE AVALIAÇÕES DOS CLIENTES ===== */}
      <section className="rounded-2xl border border-gray-200 bg-white/90 p-4 sm:p-6 space-y-6">
        {/* Resumo tipo Magalu/Shein */}
        <div className="grid gap-6 md:grid-cols-[minmax(0,0.9fr)_minmax(0,1.1fr)] items-center">
