import { notFound } from "next/navigation";
import type { Product } from "@/types/product";
import Gallery from "@/components/ui/Gallery";
import ProductBuyBox from "@/components/products/ProductBuyBox";
import ProductReviews from "./ProductReviews";

export const dynamic = "force-dynamic";

const API = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

/** Normaliza qualquer caminho vindo do backend para uma URL válida */
function absUrl(raw?: string | null): string {
  if (!raw) return "/placeholder.png";
  const s = String(raw).trim().replace(/\\/g, "/");
  if (/^https?:\/\//i.test(s)) return s;
  if (s.startsWith("/uploads")) return `${API}${s}`;
  if (s.startsWith("uploads")) return `${API}/${s}`;
  if (!s.startsWith("/")) return `${API}/uploads/${s}`;
  return `${API}${s}`;
}

async function getProduto(id: string): Promise<Product | null> {
  try {
    const res = await fetch(`${API}/api/products/${id}`, {
      cache: "no-store",
    });
    if (!res.ok) return null;
    return (await res.json()) as Product;
  } catch {
    return null;
  }
}

type ProductPromotion = {
  id: number;
  product_id: number;
  price?: number | string | null;
  original_price?: number | string | null;
  final_price?: number | string | null;
  discount_percent?: number | string | null;
  promo_price?: number | string | null;
  start_at?: string | null;
  end_at?: string | null;
  ends_at?: string | null;
  is_active?: number | boolean;
};

async function getPromocaoProduto(
  id: string,
): Promise<ProductPromotion | null> {
  try {
    const res = await fetch(`${API}/api/public/promocoes/${id}`, {
      cache: "no-store",
    });
    if (!res.ok) return null;
    const data = await res.json();
    return Array.isArray(data)
      ? ((data[0] as ProductPromotion) ?? null)
      : (data as ProductPromotion);
  } catch {
    return null;
  }
}

type ProductPageProps = {
  params: Promise<{ id: string }>;
};

export default async function Page({ params }: ProductPageProps) {
  const { id } = await params;

  const [produto, promocao] = await Promise.all([
    getProduto(id),
    getPromocaoProduto(id),
  ]);

  if (!produto) return notFound();

  // ===== FRETE GRÁTIS =====
  const shippingFree = Boolean((produto as any).shipping_free);
  const shippingFreeFromQty =
    (produto as any).shipping_free_from_qty != null
      ? Number((produto as any).shipping_free_from_qty)
      : null;

  // ===== PREÇO / DESCONTO =====
  const precoBase = Number(produto.price ?? 0);

  const originalFromPromo = promocao?.original_price ?? promocao?.price ?? null;
  const finalFromPromo =
    promocao?.final_price ?? promocao?.promo_price ?? promocao?.price ?? null;

  const originalPrice =
    originalFromPromo != null ? Number(originalFromPromo) : precoBase;

  let finalPrice =
    finalFromPromo != null ? Number(finalFromPromo) : originalPrice;

  let discountPercent: number | null = null;

  if (promocao) {
    const explicit =
      promocao.discount_percent != null
        ? Number(promocao.discount_percent)
        : NaN;

    if (!finalFromPromo && !Number.isNaN(explicit) && explicit > 0) {
      finalPrice = originalPrice * (1 - explicit / 100);
    }

    if (originalPrice > 0 && finalPrice < originalPrice) {
      discountPercent = ((originalPrice - finalPrice) / originalPrice) * 100;
    } else if (!Number.isNaN(explicit) && explicit > 0) {
      discountPercent = explicit;
    }
  }

  const priceBRL = finalPrice.toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL",
  });

  const originalPriceBRL = originalPrice.toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL",
  });

  const promoEndsAt =
    (promocao?.ends_at as string | null) ??
    (promocao?.end_at as string | null) ??
    null;

  // ===== ESTOQUE =====
  const estoque = Number(
    (produto as any).estoque ?? (produto as any).quantity ?? 0,
  );
  const disponivel = estoque > 0;

  // ===== IMAGENS =====
  const extras = Array.isArray(produto.images)
    ? (produto.images as unknown as string[])
    : [];
  const images = Array.from(
    new Set([produto.image, ...extras].filter(Boolean) as string[]),
  ).map(absUrl);

  const produtoComPrecoFinal: Product = {
    ...produto,
    price: finalPrice,
  };

  return (
    <>
      <section className="max-w-6xl mx-auto px-4 py-8 md:py-12">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="md:sticky md:top-24 h-fit">
            <Gallery images={images} alt={produto.name} />
          </div>

          <div className="flex flex-col gap-6">
            <header className="space-y-2">
              <h1 className="text-3xl md:text-4xl font-bold tracking-tight text-gray-900">
                {produto.name}
              </h1>

              <div className="flex items-center gap-3 flex-wrap">
                <span
                  className={`inline-flex items-center rounded-full px-3 py-1 text-xs font-medium ${
                    disponivel
                      ? "bg-emerald-50 text-emerald-700 ring-1 ring-emerald-200"
                      : "bg-red-50 text-red-700 ring-1 ring-red-200"
                  }`}
                >
                  {disponivel ? "Em estoque" : "Esgotado"}
                </span>

                {discountPercent && discountPercent > 0 && (
                  <span className="inline-flex items-center rounded-full bg-red-500 px-2 py-0.5 text-[11px] font-bold text-white shadow-sm">
                    -{discountPercent.toFixed(0)}% OFF
                  </span>
                )}

                {shippingFree && (
                  <span className="inline-flex items-center rounded-full bg-emerald-100 px-2.5 py-1 text-[11px] font-semibold text-emerald-700 ring-1 ring-emerald-200">
                    {shippingFreeFromQty
                      ? `Frete grátis a partir de ${shippingFreeFromQty} un.`
                      : "Frete grátis"}
                  </span>
                )}
              </div>
            </header>

            <div className="space-y-1">
              {discountPercent && discountPercent > 0 && (
                <div className="flex flex-wrap items-baseline gap-2 text-sm">
                  <span className="text-sm text-gray-400 line-through">
                    {originalPriceBRL}
                  </span>
                  <span className="text-xs font-semibold text-emerald-700">
                    economia de {discountPercent.toFixed(0)}%
                  </span>
                </div>
              )}

              <p className="text-3xl font-extrabold text-emerald-600">
                {priceBRL}
              </p>

              {promoEndsAt && (
                <p className="text-xs text-amber-700">
                  Promoção válida até{" "}
                  {new Date(promoEndsAt).toLocaleDateString("pt-BR", {
                    day: "2-digit",
                    month: "2-digit",
                  })}
                  , ou enquanto durarem os estoques.
                </p>
              )}
            </div>

            <div className="prose max-w-none text-gray-700">
              <p>{produto.description || "Sem descrição disponível."}</p>
            </div>

            <ProductBuyBox product={produtoComPrecoFinal} stock={estoque} />
          </div>
        </div>
      </section>

      <ProductReviews
        produtoId={produto.id}
        ratingAvg={produto.rating_avg ?? undefined}
        ratingCount={produto.rating_count ?? undefined}
      />
    </>
  );
}

"use client";

import { useMemo, useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { z } from "zod";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";

import { useAuth } from "@/context/AuthContext";
import CloseButton from "@/components/buttons/CloseButton";
import LoadingButton from "@/components/buttons/LoadingButton";

// helper: formata CPF enquanto o usuário digita
function formatCpfMask(value: string): string {
  const digits = value.replace(/\D/g, "").slice(0, 11);

  if (digits.length <= 3) return digits;
  if (digits.length <= 6) return digits.replace(/(\d{3})(\d{0,3})/, "$1.$2");
  if (digits.length <= 9)
    return digits.replace(/(\d{3})(\d{3})(\d{0,3})/, "$1.$2.$3");

  return digits.replace(/(\d{3})(\d{3})(\d{3})(\d{0,2})/, "$1.$2.$3-$4");
}

function onlyDigits(v: string) {
  return (v || "").replace(/\D/g, "");
}

function normalizeEmail(v: string) {
  return (v || "").trim().toLowerCase();
}

/**
 * Segurança (front): não vazar “email já cadastrado” (evita enumeração).
 * Mantém mensagens úteis para validações não sensíveis (ex.: CPF inválido, senha fraca).
 */
function safeServerMessage(raw?: string | null): string | null {
  if (!raw) return null;

  const msg = raw.trim();
  const lowered = msg.toLowerCase();

  // padrões comuns que indicam enumeração de conta
  const looksLikeEmailExists =
    lowered.includes("e-mail já está cadastrado") ||
    lowered.includes("email já está cadastrado") ||
    lowered.includes("já existe") ||
    lowered.includes("já cadastrado");

  if (looksLikeEmailExists) {
    return "Não foi possível concluir o cadastro. Verifique seus dados e tente novamente.";
  }

  return msg;
}

// senha mais forte (mínimo viável)
const passwordSchema = z
  .string()
  .min(8, "Mínimo de 8 caracteres")
  .regex(/[A-Z]/, "Inclua pelo menos 1 letra maiúscula")
  .regex(/[a-z]/, "Inclua pelo menos 1 letra minúscula")
  .regex(/\d/, "Inclua pelo menos 1 número");

const schema = z
  .object({
    // Honeypot anti-bot (campo invisível no form)
    website: z.string().optional(),

    nome: z
      .string()
      .min(2, "Informe seu nome")
      .transform((v) => v.trim()),
    email: z
      .string()
      .email("Email inválido")
      .transform((v) => normalizeEmail(v)),
    cpf: z
      .string()
      .min(11, "Informe seu CPF")
      .refine(
        (value) => onlyDigits(value).length === 11,
        "CPF deve ter 11 dígitos",
      ),
    senha: passwordSchema,
    confirmSenha: z.string().min(8, "Confirme sua senha"),
  })
  .refine((v) => v.senha === v.confirmSenha, {
    path: ["confirmSenha"],
    message: "As senhas não conferem",
  });

type FormData = z.infer<typeof schema>;

export default function RegisterPage() {
  const router = useRouter();
  const { register: registerUser, login } = useAuth();

  const [serverMsg, setServerMsg] = useState<string | null>(null);
  const [showPw, setShowPw] = useState(false);
  const [showPw2, setShowPw2] = useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting, isValid },
    reset,
    setValue,
  } = useForm<FormData>({
    resolver: zodResolver(schema),
    mode: "onChange",
    defaultValues: {
      website: "",
    },
  });

  const canSubmit = useMemo(() => {
    // isValid só funciona bem com mode onChange e resolver
    return isValid && !isSubmitting;
  }, [isValid, isSubmitting]);

  const onSubmit = async (data: FormData) => {
    setServerMsg(null);

    // Honeypot anti-bot: se preenchido, “finge sucesso” e não chama API
    if (data.website && data.website.trim().length > 0) {
      reset();
      router.push("/");
      return;
    }

    // Normalizações finais (defensivo)
    const payload = {
      nome: data.nome.trim(),
      email: normalizeEmail(data.email),
      senha: data.senha,
      cpf: onlyDigits(data.cpf), // envia apenas dígitos para evitar divergência no backend
    };

    const { ok, message } = await registerUser(payload);

    if (!ok) {
      setServerMsg(
        safeServerMessage(message) ||
          "Não foi possível concluir o cadastro. Verifique seus dados e tente novamente.",
      );
      return;
    }

    // Auto-login (mantido). Se falhar, vai para login (fluxo mais previsível que jogar pra Home).
    const r = await login(payload.email, payload.senha);
    reset();

    if (!r.ok) {
      router.push("/login");
      return;
    }

    router.push("/");
  };

  return (
    <div className="min-h-screen relative overflow-hidden">
      <div className="absolute inset-0 bg-gradient-to-br from-[#083E46] via-[#0f5e63] to-[#359293]" />
      <div
        className="absolute inset-0 opacity-20"
        style={{
          backgroundImage: "radial-gradient(#ffffff33 1px, transparent 1px)",
          backgroundSize: "14px 14px",
        }}
      />

      <div className="relative z-10 flex items-center justify-center min-h-screen px-4 py-10">
        <div className="w-full max-w-xl">
          <div className="relative backdrop-blur-xl bg-white/10 border border-white/20 rounded-2xl shadow-2xl overflow-hidden">
            {/* Botão voltar/fechar */}
            <div className="absolute top-4 left-4 z-20">
              <CloseButton
                className="
                    text-[#0f5e63]
                    bg-white/90
                    hover:bg-white
                    hover:text-[#EC5B20]
                    rounded-full
                    p-2
                    shadow-md
                    text-2xl
                    transition
                  "
              />
            </div>

            <div className="px-8 pt-10 text-center">
              <h1 className="text-3xl font-extrabold tracking-tight text-white drop-shadow-sm">
                Cadastro
              </h1>
              <p className="mt-2 text-white/80 text-sm">
                Crie sua conta para acompanhar pedidos e ofertas.
              </p>
            </div>

            <form
              onSubmit={handleSubmit(onSubmit)}
              className="p-8 grid grid-cols-1 gap-5"
            >
              {/* Mensagem do servidor (aria-live para acessibilidade) */}
              {serverMsg && (
                <div
                  className="text-center text-sm px-3 py-2 rounded-md bg-white/20 text-white"
                  role="status"
                  aria-live="polite"
                >
                  {serverMsg}
                </div>
              )}

              {/* Honeypot invisível */}
              <input
                type="text"
                tabIndex={-1}
                autoComplete="off"
                className="hidden"
                aria-hidden="true"
                {...register("website")}
              />

              {/* Nome */}
              <div>
                <label className="block text-sm font-medium text-white/90 mb-1">
                  Nome
                </label>
                <input
                  {...register("nome")}
                  placeholder="Seu nome"
                  autoComplete="name"
                  className="w-full rounded-lg bg-white/90 focus:bg-white px-4 py-2.5 outline-none ring-2 ring-transparent focus:ring-[#EC5B20] transition"
                />
                {errors.nome && (
                  <p className="mt-1 text-xs text-red-200">
                    {errors.nome.message}
                  </p>
                )}
              </div>

              {/* Email */}
              <div>
                <label className="block text-sm font-medium text-white/90 mb-1">
                  Email
                </label>
                <input
                  type="email"
                  {...register("email")}
                  placeholder="seu@email.com"
                  autoComplete="email"
                  inputMode="email"
                  className="w-full rounded-lg bg-white/90 focus:bg-white px-4 py-2.5 outline-none ring-2 ring-transparent focus:ring-[#EC5B20] transition"
                />
                {errors.email && (
                  <p className="mt-1 text-xs text-red-200">
                    {errors.email.message}
                  </p>
                )}
              </div>

              {/* CPF */}
              <div>
                <label className="block text-sm font-medium text-white/90 mb-1">
                  CPF
                </label>
                <input
                  {...register("cpf", {
                    onChange: (e) => {
                      const formatado = formatCpfMask(e.target.value);
                      setValue("cpf", formatado, { shouldValidate: true });
                    },
                  })}
                  placeholder="000.000.000-00"
                  inputMode="numeric"
                  autoComplete="off"
                  maxLength={14}
                  className="w-full rounded-lg bg-white/90 focus:bg-white px-4 py-2.5 outline-none ring-2 ring-transparent focus:ring-[#EC5B20] transition"
                />
                {errors.cpf && (
                  <p className="mt-1 text-xs text-red-200">
                    {errors.cpf.message}
                  </p>
                )}
              </div>

              {/* Senha */}
              <div>
                <label className="block text-sm font-medium text-white/90 mb-1">
                  Senha
                </label>
                <div className="relative">
                  <input
                    type={showPw ? "text" : "password"}
                    {...register("senha")}
                    placeholder="••••••••"
                    autoComplete="new-password"
                    className="w-full rounded-lg bg-white/90 focus:bg-white px-4 py-2.5 pr-11 outline-none ring-2 ring-transparent focus:ring-[#EC5B20] transition"
