                  type="submit"
                  isLoading={isSubmitting}
                  disabled={!canSubmit}
                  className="w-full justify-center rounded-lg bg-[#359293] hover:bg-[#2e7f81] active:bg-[#2a7476]"
                >
                  Cadastrar
                </LoadingButton>
                <p className="mt-2 text-[11px] text-white/60 text-center">
                  Dica: use uma senha com letras maiúsculas, minúsculas e
                  números.
                </p>
              </div>

              <p className="text-center text-white/90 text-sm">
                Já tem conta?{" "}
                <Link
                  className="underline text-[#EC5B20] hover:text-white transition"
                  href="/login"
                >
                  Entrar
                </Link>
              </p>
            </form>
          </div>

          <p className="mt-4 text-center text-white/60 text-xs">
            Ao continuar, você concorda com nossos Termos e Política de
            Privacidade.
          </p>
        </div>
      </div>
    </div>
  );
}

"use client";

import { Suspense, useMemo, useState, useEffect } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { api } from "@/lib/api";
import CustomButton from "@/components/buttons/CustomButton";
import CloseButton from "@/components/buttons/CloseButton";

type Toast = { type: "success" | "error"; message: string };

export default function ResetPasswordPage() {
  return (
    <Suspense fallback={<ResetPasswordFallback />}>
      <ResetPasswordContent />
    </Suspense>
  );
}

function ResetPasswordContent() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const token = useMemo(() => searchParams.get("token") || "", [searchParams]);

  const [password, setPassword] = useState("");
  const [confirm, setConfirm] = useState("");
  const [toast, setToast] = useState<Toast | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!token) {
      setToast({
        type: "error",
        message:
          "Token ausente ou inválido. Verifique o link enviado ao seu e-mail.",
      });
    }
  }, [token]);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!token) return;

    if (!password || password.length < 6) {
      setToast({
        type: "error",
        message: "A nova senha deve ter pelo menos 6 caracteres.",
      });
      return;
    }
    if (password !== confirm) {
      setToast({ type: "error", message: "As senhas não conferem." });
      return;
    }

    setLoading(true);
    setToast(null);

    try {
      await api("/api/users/reset-password", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ token, novaSenha: password }),
      });

      setToast({
        type: "success",
        message: "Senha redefinida com sucesso! Você já pode fazer login.",
      });
      setPassword("");
      setConfirm("");
      setTimeout(() => router.push("/login"), 2000);
    } catch (err: any) {
      setToast({
        type: "error",
        message: err?.message ?? "Falha ao redefinir a senha.",
      });
    } finally {
      setLoading(false);
      setTimeout(() => setToast(null), 5500);
    }
  }

  return (
    <main
      className="relative min-h-screen flex items-center justify-center bg-cover bg-center"
      style={{
        backgroundImage: "url('/images/cafe.png')", // mesma imagem do forgot
      }}
    >
      {/* camada escura por cima da imagem */}
      <div className="absolute inset-0 bg-black/50 backdrop-blur-sm"></div>

      <section className="relative z-10 w-full max-w-md rounded-2xl border border-white/20 bg-white/10 backdrop-blur-md shadow-xl text-center text-white p-8">
        <div className="absolute left-4 top-4">
          <CloseButton className="text-white/70 hover:text-white" />
        </div>

        {/* ícone de chave */}
        <div className="mx-auto mb-5 flex h-14 w-14 items-center justify-center rounded-full bg-white/20 backdrop-blur-sm">
          <svg
            viewBox="0 0 24 24"
            className="h-7 w-7 text-white"
            fill="currentColor"
          >
            <path d="M17 8V6a5 5 0 1 0-10 0v2H6a2 2 0 0 0-2 2v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8a2 2 0 0 0-2-2h-1Zm-8 0V6a3 3 0 1 1 6 0v2H9Zm3 4a1.5 1.5 0 0 1 .75 2.8V18a.75.75 0 1 1-1.5 0v-2.2A1.5 1.5 0 0 1 12 13Z" />
          </svg>
        </div>

        <h1 className="text-2xl font-semibold mb-2">Redefinir senha</h1>
        <p className="text-sm text-white/80 mb-6">
          Digite sua nova senha para concluir a redefinição.
        </p>

        <form onSubmit={onSubmit} className="space-y-5">
          <div className="text-left">
            <label
              htmlFor="password"
              className="block text-sm mb-1 text-white/90"
            >
              Nova senha
            </label>
            <input
              id="password"
              type="password"
              required
              minLength={6}
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full rounded-md border border-white/30 bg-white/20 placeholder-white/60 text-white px-3 py-2 outline-none focus:ring-2 focus:ring-[#359293]"
            />
          </div>

          <div className="text-left">
            <label
              htmlFor="confirm"
              className="block text-sm mb-1 text-white/90"
            >
              Confirmar nova senha
            </label>
            <input
              id="confirm"
              type="password"
              required
              placeholder="••••••••"
              value={confirm}
              onChange={(e) => setConfirm(e.target.value)}
              className="w-full rounded-md border border-white/30 bg-white/20 placeholder-white/60 text-white px-3 py-2 outline-none focus:ring-2 focus:ring-[#359293]"
            />
          </div>

          <CustomButton
            label={loading ? "Salvando..." : "Redefinir senha"}
            variant="primary"
            size="large"
            isLoading={loading}
            type="submit"
            className="w-full"
          />
        </form>

        {toast && (
          <div
            className={`mt-5 rounded-lg px-4 py-3 text-sm ${
              toast.type === "success"
                ? "bg-green-500/20 text-green-100"
                : "bg-red-500/20 text-red-100"
            }`}
            role="status"
          >
            {toast.message}
          </div>
        )}
      </section>
    </main>
  );
}

function ResetPasswordFallback() {
  return (
    <main className="min-h-screen flex items-center justify-center bg-slate-900 text-white">
      <p className="text-sm opacity-80">
        Carregando formulário de redefinição...
      </p>
    </main>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { absUrl } from "@/utils/absUrl";
import type { Service } from "@/types/service";
import { toast } from "react-hot-toast";
import { useAuth } from "@/context/AuthContext";

const PLACEHOLDER = "/placeholder.png";
const API = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

function parseMaybeJson(x: unknown): any {
  if (typeof x !== "string") return x;
  try {
    return JSON.parse(x);
  } catch {
    return x;
  }
}

function coerceImages(imagem?: unknown, images?: unknown): string[] {
  const capa = imagem ? [String(imagem)] : [];

  let extras: string[] = [];
  const parsed = parseMaybeJson(images);

  if (Array.isArray(parsed)) {
    extras = parsed.filter(Boolean).map(String);
  } else if (typeof parsed === "string") {
    extras = parsed
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean);
  }

  const all = [...capa, ...extras]
    .map((s) => absUrl(s))
    .filter(Boolean) as string[];

  return Array.from(new Set(all));
}

const onlyDigits = (s?: string | null) => (s ?? "").replace(/\D/g, "");

// Tipo das avaliações com nome do autor
type Avaliacao = {
  id: number;
  colaborador_id: number;
  nota: number;
  comentario: string | null;
  autor_nome: string | null;
  created_at: string;
};

export default function ServicoContent({ servico }: { servico: Service }) {
  const { user } = useAuth();
  const autorNome = user?.nome || user?.email || "Cliente Kavita";

  const titulo = servico.nome || "Serviço";

  const imagens = useMemo(() => {
    const arr = coerceImages(servico.imagem as any, servico.images as any);
    return arr.length ? arr : [PLACEHOLDER];
  }, [servico.imagem, servico.images]);

  const [idx, setIdx] = useState(0);
  const atual = imagens[Math.min(idx, imagens.length - 1)];

  const whatsappHref = useMemo(() => {
    const phone = onlyDigits(servico.whatsapp);
    if (!phone) return undefined;

    const text = `Olá! Encontrei seu serviço na Kavita e gostaria de saber mais.\nServiço: ${titulo}\nCódigo: ${servico.id}`;
    return `https://wa.me/${phone}?text=${encodeURIComponent(text)}`;
  }, [servico.whatsapp, servico.id, titulo]);

  const ratingAvg = (servico as any).rating_avg as number | null | undefined;
  const ratingCount = (servico as any).rating_count as
    | number
    | null
    | undefined;

  const [nota, setNota] = useState<number>(5);
  const [comentario, setComentario] = useState("");
  const [sendingRating, setSendingRating] = useState(false);

  const [nomeContato, setNomeContato] = useState("");
  const [whatsContato, setWhatsContato] = useState("");
  const [descPedido, setDescPedido] = useState("");
  const [sendingLead, setSendingLead] = useState(false);

  const [avaliacoes, setAvaliacoes] = useState<Avaliacao[]>([]);
  const [loadingAval, setLoadingAval] = useState(true);

  // registra visualização
  useEffect(() => {
    fetch(`${API}/api/public/servicos/${servico.id}/view`, {
      method: "POST",
    }).catch(() => {});
  }, [servico.id]);

  const handleWhatsAppClick = () => {
    if (!whatsappHref) return;
    fetch(`${API}/api/public/servicos/${servico.id}/whatsapp-click`, {
      method: "POST",
    }).catch(() => {});
    window.open(whatsappHref, "_blank");
  };

  // carrega avaliações
  async function carregarAvaliacoes() {
    try {
      setLoadingAval(true);
      const res = await fetch(
        `${API}/api/public/servicos/${servico.id}/avaliacoes`,
      );
      if (!res.ok) {
        throw new Error(await res.text());
      }
      const data = (await res.json()) as Avaliacao[];
      setAvaliacoes(data);
    } catch (err) {
      console.error("Erro ao carregar avaliações:", err);
    } finally {
      setLoadingAval(false);
    }
  }

  useEffect(() => {
    carregarAvaliacoes();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [servico.id]);

  async function enviarAvaliacao() {
    if (!nota || nota < 1 || nota > 5) {
      toast.error("Selecione uma nota válida entre 1 e 5.");
      return;
    }

    setSendingRating(true);
    try {
      await fetch(`${API}/api/public/servicos/avaliacoes`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          colaborador_id: servico.id,
          nota,
          comentario,
          autor_nome: autorNome,
        }),
      });
      toast.success("Obrigado pela avaliação!");
      setComentario("");
      await carregarAvaliacoes();
    } catch (err) {
      console.error(err);
      toast.error("Erro ao enviar avaliação, tente novamente.");
    } finally {
      setSendingRating(false);
    }
  }

  async function enviarSolicitacao() {
    if (!nomeContato || !whatsContato || !descPedido) {
      toast.error("Preencha nome, WhatsApp e descrição.");
      return;
    }
    setSendingLead(true);
    try {
      await fetch(`${API}/api/public/servicos/solicitacoes`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          colaborador_id: servico.id,
          nome_contato: nomeContato,
          whatsapp: whatsContato,
          descricao: descPedido,
          origem: "pagina_servico",
        }),
      });
      toast.success("Pedido enviado! O profissional irá entrar em contato.");
      setNomeContato("");
      setWhatsContato("");
      setDescPedido("");
    } catch (err) {
      console.error(err);
      toast.error("Erro ao enviar pedido, tente novamente.");
    } finally {
      setSendingLead(false);
    }
  }

  return (
    <section className="mx-auto max-w-6xl">
      <div className="rounded-3xl bg-white p-5 text-slate-900 shadow-2xl sm:p-6 lg:p-8">
        <div className="grid grid-cols-1 gap-8 lg:grid-cols-[minmax(0,1.1fr)_minmax(0,1fr)] lg:items-start">
          {/* Coluna esquerda: imagens + comentários */}
          <div className="flex w-full flex-col items-center gap-4">
            <div className="w-full overflow-hidden rounded-2xl bg-gray-50 shadow-md">
              <img
                key={atual}
                src={atual}
                alt={titulo}
                className="h-auto max-h-[320px] w-full object-cover sm:max-h-[380px] lg:max-h-[420px]"
                onError={(e) => {
                  (e.currentTarget as HTMLImageElement).src = PLACEHOLDER;
                }}
              />
            </div>

            {imagens.length > 1 && (
              <div className="flex w-full justify-center gap-3 overflow-x-auto">
                {imagens.map((src, i) => (
                  <button
                    key={`${src}-${i}`}
                    onClick={() => setIdx(i)}
                    aria-label={`Ver imagem ${i + 1}`}
                    className={`overflow-hidden rounded-xl border-2 transition ${
                      i === idx
                        ? "border-emerald-600"
                        : "border-transparent hover:border-emerald-200"
                    }`}
                  >
                    <img
                      src={src}
                      alt={`thumb-${i + 1}`}
                      className="h-20 w-20 object-cover sm:h-22 sm:w-22"
                      width={88}
                      height={88}
                      onError={(e) => {
                        (e.currentTarget as HTMLImageElement).src = PLACEHOLDER;
                      }}
                    />
                  </button>
                ))}
              </div>
            )}

            {/* Lista de avaliações embaixo da imagem */}
            <div className="mt-4 w-full space-y-3">
              <h2 className="text-sm font-semibold text-slate-900">
                O que outros clientes dizem
              </h2>

              {loadingAval ? (
                <p className="text-xs text-slate-500">Carregando avaliações…</p>
              ) : avaliacoes.length === 0 ? (
                <p className="text-xs text-slate-500">
                  Ainda não há comentários para este profissional. Seja o
                  primeiro a avaliar!
                </p>
              ) : (
                <div className="max-h-80 space-y-3 overflow-y-auto pr-1">
                  {avaliacoes.map((av) => (
                    <div
                      key={av.id}
                      className="rounded-2xl border border-slate-200 bg-slate-50 px-3 py-2 text-xs text-slate-800"
                    >
                      <div className="mb-1 flex items-center justify-between gap-2">
                        <div className="flex flex-col">
                          <span className="text-[11px] font-semibold text-slate-900">
                            {Array.from({ length: av.nota }).map(
                              (_, i) => "⭐",
                            )}
                          </span>
                          {av.autor_nome && (
                            <span className="text-[11px] text-slate-700">
                              {av.autor_nome}
                            </span>
                          )}
                        </div>
                        <span className="text-[10px] text-slate-400">
                          {new Date(av.created_at).toLocaleDateString("pt-BR")}
                        </span>
                      </div>
                      {av.comentario && (
                        <p className="text-[11px] leading-relaxed text-slate-700">
                          {av.comentario}
                        </p>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Coluna direita: texto, botões, forms */}
          <div className="flex h-full flex-col">
            <div className="space-y-4">
              <div className="flex flex-wrap items-center gap-2">
                <h1 className="text-2xl font-bold text-slate-900 sm:text-3xl">
                  {titulo}
                </h1>

                <span className="inline-flex items-center rounded-full bg-emerald-50 px-3 py-1 text-xs font-semibold text-emerald-700 ring-1 ring-emerald-200">
                  ✓ Profissional verificado
                </span>
              </div>

              {/* nota média */}
              <div className="flex flex-wrap items-center gap-2 text-sm">
                {typeof ratingAvg === "number" && (ratingCount ?? 0) > 0 ? (
                  <span className="inline-flex items-center gap-1 rounded-full bg-amber-50 px-3 py-1 text-xs font-semibold text-amber-700 ring-1 ring-amber-200">
                    ⭐ {ratingAvg.toFixed(1)}{" "}
                    <span className="text-[11px] font-normal text-amber-800/80">
                      ({ratingCount} avaliação
                      {ratingCount && ratingCount > 1 ? "s" : ""})
                    </span>
                  </span>
                ) : (
                  <span className="text-sm text-slate-600">
                    Ainda sem avaliações
                  </span>
                )}
              </div>

              <div className="space-y-1 text-sm text-slate-700">
                {servico.especialidade_nome && (
                  <p>
                    <span className="font-semibold text-slate-900">
                      Especialidade:
                    </span>{" "}
                    {servico.especialidade_nome}
                  </p>
                )}
                {servico.cargo && (
                  <p>
                    <span className="font-semibold text-slate-900">Cargo:</span>{" "}
                    {servico.cargo}
                  </p>
                )}
                {servico.whatsapp && (
                  <p>
                    <span className="font-semibold text-slate-900">
                      WhatsApp:
                    </span>{" "}
                    {servico.whatsapp}
                  </p>
                )}
              </div>

              <p className="text-sm leading-relaxed text-slate-800 sm:text-base">
                {servico.descricao?.trim() || "Sem descrição disponível."}
              </p>
            </div>

            {/* ações + formulários */}
            <div className="mt-6 space-y-6">
              <div className="flex flex-col gap-3 sm:flex-row">
                {whatsappHref ? (
                  <button
                    type="button"
                    onClick={handleWhatsAppClick}
                    className="inline-flex w-full items-center justify-center rounded-full bg-[#2F7E7F] px-6 py-3 text-sm font-semibold text-white shadow-md transition hover:bg-[#277273] sm:w-auto"
                  >
                    Falar no WhatsApp
                  </button>
                ) : (
                  <a
                    href={`/contatos?servico=${encodeURIComponent(
                      titulo,
                    )}&id=${servico.id}`}
                    className="inline-flex w-full items-center justify-center rounded-full bg-[#2F7E7F] px-6 py-3 text-sm font-semibold text-white shadow-md transition hover:bg-[#277273] sm:w-auto"
                  >
                    Solicitar orçamento
                  </a>
                )}
              </div>

              {/* avaliação */}
              <div className="space-y-2 rounded-2xl border border-slate-200 bg-slate-50 p-4">
                <p className="text-sm font-semibold text-slate-900">
                  Avalie este profissional
                </p>
                <div className="flex flex-wrap items-center gap-2 text-sm">
                  <span className="text-slate-700">Nota:</span>
                  <select
                    value={nota}
                    onChange={(e) => setNota(Number(e.target.value))}
                    className="rounded-full border border-slate-300 px-3 py-1 text-sm text-slate-800"
                  >
                    {[5, 4, 3, 2, 1].map((n) => (
                      <option key={n} value={n}>
                        {n} estrela{n > 1 ? "s" : ""}
                      </option>
                    ))}
                  </select>
                </div>
                <textarea
                  value={comentario}
                  onChange={(e) => setComentario(e.target.value)}
                  placeholder="Deixe seu comentário (opcional)…"
                  className="w-full rounded-2xl border border-slate-300 px-3 py-2 text-sm text-slate-800"
                  rows={2}
                />
                <button
                  type="button"
                  onClick={enviarAvaliacao}
                  disabled={sendingRating}
                  className="rounded-full bg-[#2F7E7F] px-5 py-2 text-sm font-medium text-white shadow-sm transition hover:bg-[#277273] disabled:opacity-60"
                >
                  {sendingRating ? "Enviando..." : "Enviar avaliação"}
                </button>
              </div>

              {/* formulário de lead */}
              <div className="space-y-3 rounded-2xl border border-emerald-100 bg-emerald-50/70 p-4">
                <h2 className="text-sm font-semibold text-slate-900 sm:text-base">
                  Pedir orçamento rápido
                </h2>
                <p className="text-xs text-slate-700">
                  Seus dados serão enviados diretamente para este profissional.
                </p>

                <input
                  className="w-full rounded-full border border-slate-300 px-3 py-2 text-sm text-slate-800"
                  placeholder="Seu nome"
                  value={nomeContato}
                  onChange={(e) => setNomeContato(e.target.value)}
                />
                <input
                  className="w-full rounded-full border border-slate-300 px-3 py-2 text-sm text-slate-800"
                  placeholder="Seu WhatsApp"
                  value={whatsContato}
                  onChange={(e) => setWhatsContato(e.target.value)}
                />
                <textarea
                  className="w-full rounded-2xl border border-slate-300 px-3 py-2 text-sm text-slate-800"
                  rows={3}
                  placeholder="Descreva o serviço que você precisa…"
                  value={descPedido}
                  onChange={(e) => setDescPedido(e.target.value)}
                />
                <button
                  type="button"
                  onClick={enviarSolicitacao}
                  disabled={sendingLead}
                  className="mt-1 w-full rounded-full bg-[#2F7E7F] px-4 py-2 text-sm font-semibold text-white shadow-sm transition hover:bg-[#277273] disabled:opacity-60"
                >
                  {sendingLead ? "Enviando..." : "Enviar pedido"}
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

import { notFound } from "next/navigation";
import type { Service } from "@/types/service";
import ServicoContent from "./ServicoContent";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

type PageProps = {
  params: Promise<{ id: string }>;
};

// 🔍 Busca um serviço público pelo ID
async function fetchService(id: string): Promise<Service | null> {
  if (!id) return null;

  try {
    const res = await fetch(`${API_BASE}/api/public/servicos/${id}`, {
      cache: "no-store",
    });

    if (res.status === 404) return null;
    if (!res.ok) {
      console.error("Erro ao buscar serviço:", await res.text());
      return null;
    }

    const data = await res.json();

    const normalizado: Service = {
      ...data,
      images: Array.isArray(data.images)
        ? data.images
        : typeof data.images === "string" && data.images
          ? [data.images]
          : [],
    };

    return normalizado;
  } catch (err) {
    console.error("Erro inesperado ao buscar serviço:", err);
    return null;
  }
}

export default async function ServicoPage({ params }: PageProps) {
  const { id } = await params;

  const servico = await fetchService(id);

  if (!servico) {
    notFound();
  }

  return (
    <main className="min-h-screen bg-gradient-to-b from-[#041a24] via-[#053a3f] to-[#021117] text-white">
      <section className="container mx-auto px-4 pt-6 pb-10 lg:pt-8 lg:pb-16">
        <div className="mb-4 lg:mb-6">
          <a
            href="/servicos"
            className="inline-flex items-center gap-1 text-sm font-medium text-emerald-200 hover:text-emerald-100"
          >
            <span aria-hidden>←</span>
            <span>Voltar para lista de serviços</span>
          </a>
        </div>

        <ServicoContent servico={servico} />
      </section>
    </main>
  );
}

// src/app/servicos/page.tsx
"use client";

import { useMemo, useState } from "react";
import Link from "next/link";

import ServiceCard from "@/components/layout/ServiceCard";
import type { Service } from "@/types/service";
import { useFetchServicos } from "@/hooks/useFetchServicos";

export default function ServicosPage() {
  const [q, setQ] = useState("");
  // aqui guardamos o ID da especialidade (string) vindo do <select>
  const [especialidade, setEspecialidade] = useState<string>("");
  const [page, setPage] = useState(1);
  const [isInputFocused, setIsInputFocused] = useState(false);

  const { data, meta, loading, error } = useFetchServicos({
    q,
    especialidade, // agora é ID, o hook converte para número na query ?especialidade=ID
    page,
    limit: 12,
    sort: "id",
    order: "desc",
  });

  const services: Service[] = data ?? [];

  // lista de especialidades únicas (id + nome)
  const especialidades = useMemo(() => {
    const map = new Map<number, string>();

    services.forEach((s) => {
      // força para number com segurança
      const espId = Number(s.especialidade_id);

      if (!Number.isNaN(espId) && espId > 0 && s.especialidade_nome) {
        map.set(espId, s.especialidade_nome);
      }
    });

    return Array.from(map, ([id, nome]) => ({ id, nome }));
  }, [services]);

  // nome da especialidade selecionada (para mostrar no header)
  const selectedEspecialidadeNome = useMemo(() => {
    if (!especialidade) return "";
    const idNum = Number(especialidade);
    if (Number.isNaN(idNum)) return "";
    return especialidades.find((e) => e.id === idNum)?.nome ?? "";
  }, [especialidade, especialidades]);

  // filtro extra no cliente (além do backend)
  const filtered = useMemo(() => {
    const term = q.trim().toLowerCase();
    const espId = especialidade ? Number(especialidade) : null;

    return services.filter((s) => {
      const okSpec =
        !espId || (s.especialidade_id && s.especialidade_id === espId);

      const okTerm =
        !term ||
        s.nome?.toLowerCase().includes(term) ||
        s.descricao?.toLowerCase().includes(term) ||
        s.cargo?.toLowerCase().includes(term);

      return okSpec && okTerm;
    });
  }, [services, q, especialidade]);

  const suggestions = useMemo(() => filtered.slice(0, 5), [filtered]);

  const totalPages = meta?.totalPages ?? 1;
  const totalServicos = meta?.total ?? services.length;

  return (
    <main className="min-h-screen bg-gradient-to-b from-[#041a24] via-[#053a3f] to-[#021117] text-white">
      {/* HERO / CABEÇALHO */}
      <section className="container mx-auto px-4 pt-10 pb-10 lg:pt-16 lg:pb-14">
        <div className="flex flex-col lg:flex-row gap-10 lg:items-center">
          {/* LADO ESQUERDO – TEXTO */}
          <div className="flex-1">
            <span className="inline-flex items-center rounded-full bg-emerald-900/40 border border-emerald-500/40 px-3 py-1 text-xs md:text-sm font-medium text-emerald-100">
              Rede de serviços do campo • Kavita
            </span>

            <h1 className="mt-4 text-3xl md:text-4xl lg:text-5xl font-extrabold leading-tight">
              Encontre{" "}
              <span className="text-emerald-300">profissionais do agro</span>{" "}
              prontos para atender a sua região.
            </h1>

            <p className="mt-4 text-sm md:text-base text-emerald-50/80 max-w-xl">
              Veterinários, agrônomos, mecânicos e prestadores de serviço
              especializados no campo. A Kavita conecta quem precisa de ajuda
              com quem sabe fazer.
            </p>

            {/* FILTROS PRINCIPAIS – versão hero */}
            <div className="mt-6 flex flex-col gap-3 md:flex-row">
              {/* INPUT COM SUGESTÕES */}
              <div className="relative flex-1">
                <input
                  value={q}
                  onChange={(e) => {
                    setQ(e.target.value);
                    setPage(1);
                  }}
                  onFocus={() => setIsInputFocused(true)}
                  onBlur={() => {
                    // pequeno delay para permitir clique na sugestão
                    setTimeout(() => setIsInputFocused(false), 150);
                  }}
                  placeholder="Buscar por nome, descrição ou cargo..."
                  className="w-full rounded-full bg-white/95 px-4 py-3 pr-10 text-sm md:text-base text-gray-800 shadow-md outline-none ring-2 ring-transparent focus:ring-emerald-400"
                />
                <span className="pointer-events-none absolute right-4 top-1/2 -translate-y-1/2 text-sm text-emerald-700">
                  🔍
                </span>

                {/* SUGESTÕES (AUTOCOMPLETE) */}
                {q.trim().length >= 2 && isInputFocused && (
                  <div className="absolute left-0 right-0 top-full z-30 mt-2 rounded-2xl bg-white text-gray-900 shadow-xl border border-gray-200 overflow-hidden">
                    {suggestions.length === 0 ? (
                      <div className="px-4 py-3 text-sm text-gray-500">
                        Nenhum profissional encontrado para{" "}
                        <span className="font-semibold">
                          &quot;{q.trim()}&quot;
                        </span>
                        .
                      </div>
                    ) : (
                      suggestions.map((s) => (
                        <Link
                          key={s.id}
                          href={`/servicos/${s.id}`}
                          className="flex items-center gap-3 px-4 py-3 text-sm hover:bg-emerald-50 transition-colors"
                        >
                          <div className="flex h-10 w-10 items-center justify-center rounded-full bg-emerald-100 text-xs font-semibold text-emerald-700">
                            {s.nome?.charAt(0)?.toUpperCase() ?? "S"}
                          </div>
                          <div className="flex flex-col">
                            <span className="font-semibold text-gray-900">
                              {s.nome}
                            </span>
                            <span className="text-xs text-gray-500">
                              Serviço • {s.cargo || s.especialidade_nome}
                            </span>
                          </div>
                        </Link>
                      ))
                    )}
                  </div>
                )}
              </div>

              {/* SELECT DE ESPECIALIDADE (AGORA COM ID) */}
              <select
                value={especialidade}
                onChange={(e) => {
                  setEspecialidade(e.target.value);
                  setPage(1);
                }}
                className="w-full md:w-60 rounded-full bg-white/95 px-4 py-3 text-sm md:text-base text-gray-800 shadow-md outline-none ring-2 ring-transparent focus:ring-emerald-400"
              >
                <option value="">Todas as especialidades</option>
                {especialidades.map((esp) => (
                  <option key={esp.id} value={esp.id}>
                    {esp.nome}
                  </option>
                ))}
              </select>
            </div>

            <div className="mt-3 flex flex-wrap gap-2 text-[11px] md:text-xs text-emerald-50/80">
              <span className="inline-flex items-center rounded-full bg-black/20 px-3 py-1">
                ✅ Profissionais verificados
              </span>
              <span className="inline-flex items-center rounded-full bg-black/20 px-3 py-1">
                📍 Foco em produtores rurais
              </span>
              <span className="inline-flex items-center rounded-full bg-black/20 px-3 py-1">
                ⚙️ Serviços técnicos e consultorias
              </span>
            </div>
          </div>

          {/* LADO DIREITO – CARD INFORMATIVO */}
          <aside className="flex-1">
            <div className="rounded-3xl bg-black/25 border border-emerald-500/40 px-6 py-5 md:px-8 md:py-7 shadow-xl backdrop-blur-sm">
              <p className="text-xs uppercase tracking-wide text-emerald-200/90 mb-2">
                Visão geral
              </p>
              <h2 className="text-xl md:text-2xl font-semibold mb-4">
                Como a Kavita te ajuda na hora de contratar?
              </h2>

              <div className="grid grid-cols-2 gap-4 mb-5 text-sm">
                <div className="rounded-2xl bg-emerald-900/40 px-4 py-3 flex flex-col">
                  <span className="text-xs text-emerald-100/70">
                    Profissionais cadastrados
                  </span>
                  <strong className="text-2xl font-bold">
                    {totalServicos || "—"}
                  </strong>
                </div>
                <div className="rounded-2xl bg-emerald-900/40 px-4 py-3 flex flex-col">
                  <span className="text-xs text-emerald-100/70">
                    Especialidades
                  </span>
                  <strong className="text-2xl font-bold">
                    {especialidades.length || "—"}
                  </strong>
                </div>
              </div>

              <ul className="space-y-2 text-sm text-emerald-50/85">
                <li>• Encontre quem atende sua cidade ou região.</li>
                <li>• Veja cargo, especialidade e WhatsApp direto no card.</li>
                <li>• Profissionais verificados pela equipe Kavita.</li>
                <li>• Ideal para produtores rurais, fazendas e empresas.</li>
              </ul>

              <p className="mt-4 text-[11px] text-emerald-100/60">
                Cadastro sujeito à análise simples para manter a qualidade da
                rede de serviços.
              </p>
            </div>
          </aside>
        </div>
      </section>

      {/* CONTEÚDO / LISTA DE SERVIÇOS */}
      <section className="bg-white rounded-t-3xl shadow-[0_-12px_40px_rgba(0,0,0,0.35)]">
        <div className="container mx-auto px-4 py-8 md:py-10">
          {/* Header da lista */}
          <header className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between mb-4">
            <div>
              <h2 className="text-lg md:text-xl font-semibold text-gray-900">
                Profissionais disponíveis
              </h2>
              <p className="text-xs md:text-sm text-gray-500">
                {filtered.length} resultado(s) encontrado(s)
                {selectedEspecialidadeNome && (
                  <>
                    {" "}
                    • especialidade:{" "}
                    <span className="font-medium">
                      {selectedEspecialidadeNome}
                    </span>
                  </>
                )}
              </p>
            </div>

            <button
              type="button"
              onClick={() => {
                setQ("");
                setEspecialidade("");
                setPage(1);
              }}
              className="self-start inline-flex items-center justify-center rounded-full border border-emerald-600 px-4 py-2 text-xs md:text-sm font-medium text-emerald-700 hover:bg-emerald-600 hover:text-white transition-colors"
            >
              Limpar filtros
            </button>
          </header>

          {/* Estados */}
          {loading && (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {Array.from({ length: 6 }).map((_, i) => (
                <div
                  key={i}
                  className="animate-pulse bg-white rounded-2xl shadow-sm p-4 h-64 border border-gray-100"
                >
                  <div className="h-32 bg-gray-200 rounded-xl mb-3" />
                  <div className="h-4 bg-gray-200 rounded w-2/3 mb-2" />
                  <div className="h-3 bg-gray-200 rounded w-1/2" />
                </div>
              ))}
            </div>
          )}

          {error && !loading && (
            <p className="text-red-600">
              Ocorreu um erro ao carregar os serviços. Tente novamente.
            </p>
          )}

          {/* Lista */}
          {!loading && !error && (
            <>
              {filtered.length === 0 ? (
                <p className="text-gray-600">
                  Nenhum serviço encontrado com os filtros atuais.
                </p>
              ) : (
                <section className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-4">
                  {filtered.map((service) => (
                    <ServiceCard
                      key={service.id}
                      servico={service}
                      readOnly
                      href={`/servicos/${service.id}`}
                      className="h-full cursor-pointer"
                    />
                  ))}
                </section>
              )}

              {/* Paginação */}
              {totalPages > 1 && (
                <div className="flex items-center justify-center gap-3 mt-8">
                  <button
                    className="px-4 py-2 rounded-full border border-gray-300 text-sm text-gray-700 hover:border-emerald-500 hover:text-emerald-700 disabled:opacity-40 disabled:hover:border-gray-300 disabled:hover:text-gray-700 transition-colors"
                    disabled={page <= 1}
                    onClick={() => setPage((p) => Math.max(1, p - 1))}
                  >
                    Anterior
                  </button>
                  <span className="text-xs md:text-sm text-gray-600">
                    Página {meta?.page ?? 1} de {totalPages}
                  </span>
                  <button
                    className="px-4 py-2 rounded-full border border-gray-300 text-sm text-gray-700 hover:border-emerald-500 hover:text-emerald-700 disabled:opacity-40 disabled:hover:border-gray-300 disabled:hover:text-gray-700 transition-colors"
                    disabled={page >= totalPages}
                    onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                  >
                    Próxima
                  </button>
                </div>
              )}

              {/* CTA TRABALHE CONOSCO */}
              <section className="mt-10 rounded-3xl border border-emerald-100 bg-emerald-50 px-5 py-6 md:px-8 md:py-8 flex flex-col md:flex-row md:items-center md:justify-between gap-4">
                <div>
                  <h3 className="text-base md:text-lg font-semibold text-emerald-900">
                    É profissional do agro? Trabalhe com a Kavita.
                  </h3>
                  <p className="mt-1 text-xs md:text-sm text-emerald-800 max-w-xl">
                    Se você é veterinário, agrônomo, mecânico ou presta qualquer
                    serviço voltado para o campo, faça parte da nossa rede de
                    profissionais e apareça aqui na página de serviços.
                  </p>
                </div>
                <div className="flex flex-wrap gap-2">
                  <Link
                    href="/trabalhe-conosco"
                    className="inline-flex items-center justify-center rounded-full bg-emerald-600 px-5 py-2 text-xs md:text-sm font-semibold text-white shadow-md hover:bg-emerald-500"
                  >
                    Quero me cadastrar
                  </Link>
                  <Link
                    href="/trabalhe-conosco#como-funciona"
                    className="inline-flex items-center justify-center rounded-full border border-emerald-400 px-5 py-2 text-xs md:text-sm font-semibold text-emerald-700 hover:bg-emerald-100"
                  >
                    Entender como funciona
                  </Link>
                </div>
              </section>
            </>
          )}
        </div>
      </section>
    </main>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { toast } from "react-hot-toast";
import { FormattedInput } from "@/components/layout/FormattedInput";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

type Especialidade = {
  id: number;
  nome: string;
};

type FormState = {
  nome: string;
  cargo: string;
  whatsapp: string;
  email: string;
  especialidade_id: string;
  descricao: string;
};

export default function CadastroColaboradorPage() {
  const [form, setForm] = useState<FormState>({
    nome: "",
    cargo: "",
    whatsapp: "",
    email: "",
    especialidade_id: "",
    descricao: "",
  });

  const [imagemFile, setImagemFile] = useState<File | null>(null);
  const [imagemPreview, setImagemPreview] = useState<string | null>(null);

  const [especialidades, setEspecialidades] = useState<Especialidade[]>([]);
  const [loadingEspecialidades, setLoadingEspecialidades] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [successMessage, setSuccessMessage] = useState("");
  const [errorMessage, setErrorMessage] = useState("");

  // Carrega especialidades pela rota pública
  useEffect(() => {
    async function loadEspecialidades() {
      try {
        const res = await fetch(`${API_URL}/api/admin/especialidades/public`);

        if (!res.ok) {
          throw new Error("Erro ao buscar especialidades");
        }

        const data = await res.json();
        setEspecialidades(Array.isArray(data) ? data : []);
      } catch (err) {
        console.error(err);
        setErrorMessage(
          "Não foi possível carregar a lista de especialidades. Tente novamente mais tarde.",
        );
        toast.error(
          "Erro ao carregar especialidades. Tente novamente mais tarde.",
        );
      } finally {
        setLoadingEspecialidades(false);
      }
    }

    loadEspecialidades();
  }, []);

  function handleChange(
    e: React.ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >,
  ) {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  }

  function handleImagemChange(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0] || null;
    setImagemFile(file);

    if (file) {
      const url = URL.createObjectURL(file);
      setImagemPreview(url);
    } else {
      setImagemPreview(null);
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setErrorMessage("");
    setSuccessMessage("");

    if (!form.nome || !form.whatsapp || !form.email || !form.especialidade_id) {
      const msg =
        "Preencha pelo menos nome, WhatsApp, e-mail e especialidade para enviar o cadastro.";
      setErrorMessage(msg);
      toast.error(msg);
      return;
    }

    setSubmitting(true);

    try {
      const formData = new FormData();
      formData.append("nome", form.nome.trim());
      formData.append("cargo", form.cargo.trim());
      formData.append("whatsapp", form.whatsapp.trim());
      formData.append("email", form.email.trim());
      formData.append("descricao", form.descricao.trim());
      formData.append("especialidade_id", form.especialidade_id);

      if (imagemFile) {
        formData.append("imagem", imagemFile);
      }

      const res = await fetch(`${API_URL}/api/admin/colaboradores/public`, {
        method: "POST",
        body: formData,
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data.message || "Erro ao enviar cadastro.");
      }

      const okMsg =
        "Cadastro enviado com sucesso! A equipe da Kavita vai analisar seus dados e, se aprovado, você receberá um e-mail de confirmação.";
      setSuccessMessage(okMsg);
      toast.success("Cadastro enviado para análise com sucesso!");

      setForm({
        nome: "",
        cargo: "",
        whatsapp: "",
        email: "",
        especialidade_id: "",
        descricao: "",
      });
      setImagemFile(null);
      setImagemPreview(null);
    } catch (err: any) {
      console.error(err);
      const msg = err.message || "Erro ao enviar cadastro. Tente novamente.";
      setErrorMessage(msg);
      toast.error(msg);
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <main className="min-h-screen bg-slate-950 text-white">
      <section className="bg-gradient-to-b from-[#083E46] via-[#0b4f56] to-slate-950">
        {/* AGORA TUDO USA A MESMA LARGURA DO CARD (max-w-3xl) */}
        <div className="mx-auto flex w-full max-w-3xl flex-col items-center gap-6 px-4 pb-14 pt-10 sm:px-6 sm:pb-20 sm:pt-14 lg:px-8">
          {/* Header + breadcrumb centralizado dentro de max-w-2xl */}
          <header className="w-full">
            <div className="mx-auto max-w-2xl text-center">
              <p className="mb-2 text-xs text-emerald-100/80 sm:text-sm">
                <Link
                  href="/trabalhe-conosco"
                  className="font-medium hover:underline"
                >
                  Trabalhe com a Kavita
                </Link>{" "}
                <span className="text-emerald-100/60">
                  / Cadastro de prestador
                </span>
              </p>
              <h1 className="text-2xl font-extrabold leading-tight sm:text-3xl md:text-4xl">
                Cadastro de prestador de serviços
              </h1>
              <p className="mt-3 text-sm text-emerald-50/90 sm:text-base">
                Preencha seus dados para entrar na fila de análise. Depois de
                aprovado, seu perfil passa a aparecer na página de serviços da
                Kavita e produtores poderão encontrar você com facilidade.
              </p>
            </div>
          </header>

          {/* Card do formulário (mesma largura do container) */}
          <div className="w-full rounded-2xl bg-white/95 p-4 text-slate-900 shadow-xl sm:p-6 lg:p-7">
            {successMessage && (
              <div className="mb-4 rounded-xl border border-emerald-500 bg-emerald-50 px-3 py-2 text-sm text-emerald-800">
                {successMessage}
              </div>
            )}

            {errorMessage && (
              <div className="mb-4 rounded-xl border border-red-500 bg-red-50 px-3 py-2 text-sm text-red-800">
                {errorMessage}
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-5 sm:space-y-6">
              {/* Nome + Cargo */}
              <div className="grid gap-4 sm:grid-cols-2">
                <FormattedInput
                  label="Nome completo*"
                  name="nome"
                  value={form.nome}
                  onChange={handleChange as any}
                  placeholder="Ex: João da Silva"
                  required
                />

                <FormattedInput
                  label="Função / Cargo"
                  name="cargo"
                  value={form.cargo}
                  onChange={handleChange as any}
                  placeholder="Ex: Médico veterinário, Agrônomo, Mecânico..."
                />
              </div>

              {/* E-mail + WhatsApp */}
              <div className="grid gap-4 sm:grid-cols-2">
                <FormattedInput
                  label="E-mail profissional*"
                  name="email"
                  type="email"
                  value={form.email}
                  onChange={handleChange as any}
                  placeholder="seuemail@exemplo.com"
                  required
                  helperText="Usaremos esse e-mail para avisar quando seu cadastro for aprovado."
                />

                <FormattedInput
                  label="WhatsApp para contato*"
                  name="whatsapp"
                  value={form.whatsapp}
                  onChange={handleChange as any}
                  mask="telefone"
                  placeholder="(00) 00000-0000"
                  required
                  helperText="Esse número será usado para contato dos produtores."
                />
              </div>

              {/* Upload de foto de perfil */}
              <div className="flex flex-col gap-1.5">
                <label className="text-sm font-medium text-gray-700">
                  Foto de perfil
                </label>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleImagemChange}
                  className="block w-full text-sm text-gray-700 file:mr-3 file:rounded-full file:border-0 file:bg-emerald-600 file:px-4 file:py-2 file:text-sm file:font-semibold file:text-white hover:file:bg-emerald-700"
                />
                <span className="text-xs text-gray-500">
                  Use uma foto nítida, de preferência com fundo simples.
                </span>

                {imagemPreview && (
                  <div className="mt-2 flex items-center gap-3">
                    <div className="h-12 w-12 overflow-hidden rounded-full bg-gray-100 ring-1 ring-gray-200">
                      {/* eslint-disable-next-line @next/next/no-img-element */}
                      <img
                        src={imagemPreview}
                        alt="Pré-visualização da foto de perfil"
                        className="h-full w-full object-cover"
                      />
                    </div>
                    <p className="text-xs text-gray-500">
                      Pré-visualização da foto que será enviada.
                    </p>
                  </div>
                )}
              </div>

              {/* Especialidade */}
