    try {
      const data = await adminFetchJson<any>(
        "/api/admin/drones/models?includeInactive=1",
      );
      const items = extractItemsArray<DroneModelRow>(data);

      const sorted = [...items].sort(
        (a, b) =>
          (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0) ||
          a.label.localeCompare(b.label),
      );

      setModels(sorted);

      const keep = opts?.keepSelection ?? true;
      if (!keep || !selectedKey || !sorted.some((x) => x.key === selectedKey)) {
        const firstActive =
          sorted.find((x) => String(x.is_active ?? 1) === "1") || sorted[0];
        if (firstActive?.key) setSelectedKey(firstActive.key);
      }
    } catch (e: any) {
      if (e?.message === "AUTH") return;
      setMsg(e?.message || "Falha ao carregar modelos.");
    } finally {
      setLoadingModels(false);
    }
  }

  async function loadSelectedModel() {
    if (!selectedKey) return;

    setLoadingModel(true);
    setMsg(null);

    try {
      const agg = await adminFetchJson<AdminModelAggregateResponse>(
        `/api/admin/drones/models/${selectedKey}`,
      );

      const label =
        agg?.model?.label || selected?.label || selectedKey.toUpperCase();
      setModelLabel(label);

      setModelData((agg?.data ?? null) as any);
    } catch (e: any) {
      if (e?.message === "AUTH") return;
      setMsg(e?.message || "Falha ao carregar dados do modelo.");
      setModelData(null);
      setModelLabel("");
    } finally {
      setLoadingModel(false);
    }
  }

  /**
   * ✅ Salva seleção (CARD/HERO) no admin (do jeito mais seguro)
   * - Optimistic update em modelData (não em selectedKey!)
   * - Persiste via endpoint
   * - Recarrega aggregate como fonte da verdade
   */
  async function savePick(
    modelKey: string,
    target: "HERO" | "CARD",
    mediaId: number,
  ) {
    setMsg(null);

    // optimistic update (UI responde na hora)
    setModelData((prev) => {
      const base = prev || {};
      if (target === "HERO") return { ...base, current_hero_media_id: mediaId };
      return { ...base, current_card_media_id: mediaId };
    });

    try {
      const resp = await adminFetchJson<any>(
        `/api/admin/drones/models/${modelKey}/media-selection`,
        {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ target, media_id: mediaId }),
        },
      );

      // se o backend devolver algo útil, aplica também (tolerante)
      const nextHero =
        resp?.current_hero_media_id ??
        resp?.data?.current_hero_media_id ??
        resp?.model?.current_hero_media_id;

      const nextCard =
        resp?.current_card_media_id ??
        resp?.data?.current_card_media_id ??
        resp?.model?.current_card_media_id;

      if (nextHero !== undefined || nextCard !== undefined) {
        setModelData((prev) => {
          const base = prev || {};
          return {
            ...base,
            ...(nextHero !== undefined
              ? { current_hero_media_id: Number(nextHero) }
              : null),
            ...(nextCard !== undefined
              ? { current_card_media_id: Number(nextCard) }
              : null),
          };
        });
      }

      // fonte da verdade
      await loadSelectedModel();
    } catch (e: any) {
      setMsg(e?.message || "Falha ao salvar seleção.");
      // garante consistência
      await loadSelectedModel().catch(() => {});
      throw e;
    }
  }

  useEffect(() => {
    loadModels({ keepSelection: false });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    loadSelectedModel();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedKey]);

  return (
    <div className="space-y-5">
      <div className="relative overflow-hidden rounded-3xl border border-white/10 bg-gradient-to-b from-[#0b1220] via-[#0b1220] to-[#070b13] p-5 shadow-[0_18px_50px_-30px_rgba(0,0,0,0.8)]">
        <div className="absolute inset-0 opacity-60">
          <div className="absolute -left-40 -top-40 h-96 w-96 rounded-full bg-white/10 blur-3xl" />
          <div className="absolute -right-40 -bottom-40 h-96 w-96 rounded-full bg-white/10 blur-3xl" />
        </div>

        <div className="relative">
          <div className="flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
            <div className="min-w-0">
              <div className="text-xs text-white/50">
                Admin <span className="mx-1">/</span> Kavita Drones
              </div>

              <h1 className="mt-1 truncate text-2xl font-semibold tracking-tight text-white">
                Modelos de Drones
              </h1>

              <p className="mt-1 max-w-2xl text-sm text-white/60">
                Configure por modelo:{" "}
                <span className="text-white/80">especificações</span>,{" "}
                <span className="text-white/80">funcionalidades</span>,{" "}
                <span className="text-white/80">benefícios</span> e{" "}
                <span className="text-white/80">galeria</span>.
              </p>
            </div>

            <div className="flex flex-col gap-2 md:flex-row md:items-center">
              <button
                type="button"
                onClick={() => loadModels({ keepSelection: true })}
                disabled={loadingModels}
                className={[
                  "inline-flex items-center justify-center rounded-xl px-4 py-2 text-sm font-medium",
                  "border border-white/15 bg-white/5 text-white",
                  "hover:bg-white/10 active:scale-[0.99] transition",
                  "disabled:opacity-60 disabled:hover:bg-white/5",
                ].join(" ")}
              >
                {loadingModels ? "Atualizando..." : "Recarregar"}
              </button>

              <div className="flex items-center gap-2 rounded-2xl border border-white/10 bg-white/[0.04] p-2 backdrop-blur">
                <select
                  value={selectedKey}
                  onChange={(e) => setSelectedKey(e.target.value)}
                  className={[
                    "min-w-[260px] rounded-xl border border-white/10 bg-white/5 px-3 py-2 text-sm text-white",
                    "outline-none focus:ring-2 focus:ring-white/20",
                  ].join(" ")}
                >
                  {models.map((m) => (
                    <option key={m.key} value={m.key} className="text-zinc-900">
                      {m.label} ({m.key})
                    </option>
                  ))}
                </select>

                {selected ? <StatusPill active={selectedIsActive} /> : null}
              </div>
            </div>
          </div>

          <div className="mt-4">
            {msg ? (
              <div className="rounded-2xl border border-amber-200/20 bg-amber-500/10 px-4 py-3 text-sm text-amber-100">
                {msg}
              </div>
            ) : null}

            {loadingModel ? (
              <div className="mt-3 rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm text-white/70">
                Carregando dados do modelo...
              </div>
            ) : selectedKey ? (
              <div className="mt-3 flex flex-col gap-2 md:flex-row md:items-center md:justify-between">
                <div className="text-sm text-white/70">
                  Editando:{" "}
                  <b className="text-white">
                    {modelLabel || selectedKey.toUpperCase()}
                  </b>
                </div>
                {lastUpdate ? (
                  <div className="text-xs text-white/45">
                    Última atualização: {lastUpdate}
                  </div>
                ) : null}
              </div>
            ) : null}
          </div>
        </div>
      </div>

      {selectedKey ? (
        <div className="flex flex-col gap-5">
          <SectionShell
            title="Especificações"
            subtitle={`Por modelo: ${selectedKey.toUpperCase()}`}
          >
            <DroneModelSpecsEditor
              modelKey={selectedKey}
              initialTitle={modelData?.specs_title ?? "Especificações"}
              initialGroups={modelData?.specs_items_json ?? []}
              onSaved={(p) =>
                setModelData((prev) => ({ ...(prev || {}), ...p }))
              }
            />
          </SectionShell>

          <SectionShell
            title="Funcionalidades"
            subtitle={`Por modelo: ${selectedKey.toUpperCase()}`}
          >
            <DroneModelFeaturesEditor
              modelKey={selectedKey}
              initialTitle={modelData?.features_title ?? "Funcionalidades"}
              initialItems={modelData?.features_items_json ?? []}
              onSaved={(p) =>
                setModelData((prev) => ({ ...(prev || {}), ...p }))
              }
            />
          </SectionShell>

          <SectionShell
            title="Benefícios"
            subtitle={`Por modelo: ${selectedKey.toUpperCase()}`}
          >
            <DroneModelBenefitsEditor
              modelKey={selectedKey}
              initialTitle={modelData?.benefits_title ?? "Benefícios"}
              initialItems={modelData?.benefits_items_json ?? []}
              onSaved={(p) =>
                setModelData((prev) => ({ ...(prev || {}), ...p }))
              }
            />
          </SectionShell>

          <SectionShell
            title="Galeria"
            subtitle={`Por modelo: ${selectedKey.toUpperCase()}`}
          >
            <GalleryForm
              modelKey={selectedKey}
              currentCardMediaId={modelData?.current_card_media_id ?? null}
              currentHeroMediaId={modelData?.current_hero_media_id ?? null}
              onPickForCard={async (item) => {
                await savePick(selectedKey, "CARD", item.id);
              }}
              onPickForHero={async (item) => {
                await savePick(selectedKey, "HERO", item.id);
              }}
            />
          </SectionShell>
        </div>
      ) : (
        <div className="rounded-2xl border border-zinc-200 bg-white p-5 text-sm text-zinc-600">
          Selecione um modelo para editar.
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useMemo, useState } from "react";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

type TextItem = { title?: string; text?: string };

type Toast = { type: "success" | "error" | "info"; text: string } | null;

function cx(...classes: Array<string | false | null | undefined>) {
  return classes.filter(Boolean).join(" ");
}

function isAuthError(res: Response) {
  return res.status === 401 || res.status === 403;
}

function redirectToLogin() {
  if (typeof window !== "undefined") window.location.assign("/admin/login");
}

async function readSafe(res: Response) {
  const txt = await res.text();
  try {
    return { txt, data: JSON.parse(txt) };
  } catch {
    return { txt, data: null as any };
  }
}

function normalizeItems(v: any): TextItem[] {
  if (!Array.isArray(v)) return [];
  const out: TextItem[] = [];
  for (const x of v) {
    if (!x) continue;
    const title = typeof x?.title === "string" ? x.title : "";
    const text = typeof x?.text === "string" ? x.text : "";
    if (title.trim() || text.trim()) out.push({ title, text });
  }
  return out;
}

function ModelPill({ modelKey }: { modelKey: string }) {
  return (
    <span className="inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/5 px-3 py-1 text-xs text-white/70">
      <span className="h-1.5 w-1.5 rounded-full bg-white/50" />
      Modelo: <b className="text-white">{modelKey.toUpperCase()}</b>
    </span>
  );
}

function ToastView({ toast }: { toast: Toast }) {
  if (!toast) return null;

  const cls =
    toast.type === "success"
      ? "border-emerald-200/20 bg-emerald-500/10 text-emerald-100"
      : toast.type === "error"
        ? "border-amber-200/20 bg-amber-500/10 text-amber-100"
        : "border-white/10 bg-white/5 text-white/80";

  return (
    <div className={cx("rounded-2xl border px-4 py-3 text-sm", cls)}>
      {toast.text}
    </div>
  );
}

type Props = {
  modelKey: string;
  initialTitle?: string | null;
  initialItems?: TextItem[] | null;
  onSaved?: (payload: {
    features_title: string | null;
    features_items_json: TextItem[];
  }) => void;
};

export default function DroneModelFeaturesEditor({
  modelKey,
  initialTitle,
  initialItems,
  onSaved,
}: Props) {
  const [toast, setToast] = useState<Toast>(null);
  const [saving, setSaving] = useState(false);

  const [title, setTitle] = useState<string>(
    initialTitle?.trim() || "Funcionalidades",
  );
  const [items, setItems] = useState<TextItem[]>(normalizeItems(initialItems));

  useEffect(() => {
    setTitle(initialTitle?.trim() || "Funcionalidades");
    setItems(normalizeItems(initialItems));
    setToast(null);
  }, [initialTitle, initialItems, modelKey]);

  const canSave = useMemo(() => Boolean(modelKey), [modelKey]);

  function addItem() {
    setItems((prev) => [...prev, { title: "", text: "" }]);
  }

  function removeItem(idx: number) {
    setItems((prev) => prev.filter((_, i) => i !== idx));
  }

  function updateItem(idx: number, patch: Partial<TextItem>) {
    setItems((prev) =>
      prev.map((it, i) => (i === idx ? { ...it, ...patch } : it)),
    );
  }

  function sanitizePayload() {
    const cleanTitle = title.trim() ? title.trim() : null;

    const cleanItems: TextItem[] = items
      .map((it) => ({
        title: (it.title || "").trim() || undefined,
        text: (it.text || "").trim() || undefined,
      }))
      .filter(
        (it) => (it.title && it.title.trim()) || (it.text && it.text.trim()),
      );

    return { features_title: cleanTitle, features_items_json: cleanItems };
  }

  async function save() {
    if (!canSave) return;

    setSaving(true);
    setToast(null);

    try {
      const payload = sanitizePayload();

      const res = await fetch(
        `${API_BASE}/api/admin/drones/models/${modelKey}`,
        {
          method: "PUT",
          credentials: "include",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        },
      );

      if (isAuthError(res)) return redirectToLogin();

      const { data } = await readSafe(res);
      if (!res.ok) {
        throw new Error(data?.message || "Erro ao salvar funcionalidades.");
      }

      setToast({
        type: "success",
        text: "Funcionalidades salvas com sucesso.",
      });
      onSaved?.(payload);
    } catch (e: any) {
      setToast({ type: "error", text: e?.message || "Falha ao salvar." });
    } finally {
      setSaving(false);
    }
  }

  return (
    <div className="space-y-4">
      <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
        <div className="flex items-center gap-2">
          <ModelPill modelKey={modelKey} />
          <span className="hidden text-xs text-white/40 md:inline">
            Cards curtos (título opcional + descrição).
          </span>
        </div>

        <div className="flex items-center gap-2">
          <button
            type="button"
            onClick={addItem}
            className="rounded-xl border border-white/10 bg-white/5 px-3 py-2 text-sm text-white hover:bg-white/10 active:scale-[0.99] transition"
          >
            + Item
          </button>

          <button
            type="button"
            onClick={save}
            disabled={saving || !canSave}
            className={cx(
              "rounded-xl px-4 py-2 text-sm font-medium text-white transition active:scale-[0.99]",
              saving || !canSave
                ? "bg-white/10 text-white/50"
                : "bg-emerald-500 hover:bg-emerald-400",
            )}
          >
            {saving ? "Salvando..." : "Salvar"}
          </button>
        </div>
      </div>

      <ToastView toast={toast} />

      <div className="space-y-1">
        <label className="text-xs font-medium text-white/60">
          Título da seção
        </label>
        <input
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className="w-full rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm text-white placeholder:text-white/30 outline-none focus:ring-2 focus:ring-white/20"
          placeholder="Ex: Funcionalidades"
        />
      </div>

      <div className="space-y-3">
        {items.length === 0 ? (
          <div className="rounded-2xl border border-dashed border-white/15 bg-white/[0.03] p-5 text-sm text-white/60">
            Nenhum item ainda. Clique em <b className="text-white">+ Item</b>.
          </div>
        ) : (
          items.map((it, idx) => (
            <div
              key={idx}
              className="rounded-2xl border border-white/10 bg-white/[0.04] p-4 shadow-[0_10px_30px_-25px_rgba(0,0,0,0.9)]"
            >
              <div className="mb-3 flex items-center justify-between gap-2">
                <span className="rounded-full border border-white/10 bg-white/5 px-2.5 py-1 text-[11px] text-white/70">
                  Item {idx + 1}
                </span>

                <button
                  type="button"
                  onClick={() => removeItem(idx)}
                  className="rounded-xl border border-white/10 bg-white/5 px-3 py-2 text-sm text-white hover:bg-white/10 transition"
                >
                  Remover
                </button>
              </div>

              <div className="grid grid-cols-1 gap-3 lg:grid-cols-2">
                <div className="space-y-1">
                  <label className="text-xs font-medium text-white/60">
                    Título (opcional)
                  </label>
                  <input
                    value={it.title || ""}
                    onChange={(e) => updateItem(idx, { title: e.target.value })}
                    className="w-full rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm text-white placeholder:text-white/30 outline-none focus:ring-2 focus:ring-white/20"
                    placeholder="Ex: Radar inteligente"
                  />
                </div>

                <div className="space-y-1 lg:col-span-2">
                  <label className="text-xs font-medium text-white/60">
                    Descrição
                  </label>
                  <textarea
                    value={it.text || ""}
                    onChange={(e) => updateItem(idx, { text: e.target.value })}
                    className="min-h-[110px] w-full rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm text-white placeholder:text-white/30 outline-none focus:ring-2 focus:ring-white/20"
                    placeholder="Escreva o texto do item... (curto e objetivo)"
                  />
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

