export default function PageSettingsForm() {
  const router = useRouter();

  const defaultSections = useMemo(
    () => ["hero", "gallery", "representatives", "comments"],
    [],
  );

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<string | null>(null);

  const [heroTitle, setHeroTitle] = useState("");
  const [heroSubtitle, setHeroSubtitle] = useState("");

  const [ctaTitle, setCtaTitle] = useState("");
  const [ctaButtonLabel, setCtaButtonLabel] = useState("");
  const [ctaTemplate, setCtaTemplate] = useState("");

  const [sectionsOrder, setSectionsOrder] = useState<string[]>(defaultSections);

  const [heroVideo, setHeroVideo] = useState<File | null>(null);
  const [heroImageFallback, setHeroImageFallback] = useState<File | null>(null);

  const [currentHeroVideoPath, setCurrentHeroVideoPath] = useState<
    string | null
  >(null);
  const [currentHeroImagePath, setCurrentHeroImagePath] = useState<
    string | null
  >(null);

  async function fetchWithFallback(paths: string[]) {
    let lastError: any = null;
    for (const p of paths) {
      try {
        return await apiClient.get(p);
      } catch (err: any) {
        lastError = err;
        if (err?.status !== 404) throw err;
      }
    }
    throw lastError;
  }

  useEffect(() => {
    (async () => {
      setMsg(null);
      setLoading(true);
      try {
        // compat: /page-settings (novo) e /page (legado)
        const json = await fetchWithFallback([
          "/api/admin/drones/page-settings",
          "/api/admin/drones/page",
        ]);

        const data = (
          json && typeof json === "object" && "page" in json
            ? (json as any).page
            : json
        ) as Partial<PageSettingsDTO>;

        setHeroTitle(sanitizeString(data.hero_title, ""));
        setHeroSubtitle(sanitizeString(data.hero_subtitle, ""));

        setCtaTitle(sanitizeString(data.cta_title, ""));
        setCtaButtonLabel(sanitizeString(data.cta_button_label, ""));
        setCtaTemplate(sanitizeString(data.cta_message_template, ""));

        setCurrentHeroVideoPath(
          sanitizeString(data.hero_video_path, "") || null,
        );
        setCurrentHeroImagePath(
          sanitizeString(data.hero_image_fallback_path, "") || null,
        );

        setSectionsOrder(
          uniqOrder(
            ensureArray<string>(data.sections_order_json, defaultSections),
          ),
        );
      } catch {
        setMsg("Erro de rede ao carregar Config Landing.");
      } finally {
        setLoading(false);
      }
    })();
  }, [defaultSections]);

  function validate(): string | null {
    if (!heroTitle.trim()) return "hero_title é obrigatório.";
    if (!Array.isArray(sectionsOrder) || sectionsOrder.length === 0)
      return "sections_order_json inválido.";
    return null;
  }

  async function save() {
    setMsg(null);

    const err = validate();
    if (err) {
      setMsg(err);
      return;
    }

    setSaving(true);
    try {
      const fd = new FormData();

      // campos do DTO (landing)
      fd.append("hero_title", heroTitle.trim());

      const hs = normalizeNullableString(heroSubtitle);
      if (hs) fd.append("hero_subtitle", hs);

      const ct = normalizeNullableString(ctaTitle);
      if (ct) fd.append("cta_title", ct);

      const cbl = normalizeNullableString(ctaButtonLabel);
      if (cbl) fd.append("cta_button_label", cbl);

      const ctmp = normalizeNullableString(ctaTemplate);
      if (ctmp) fd.append("cta_message_template", ctmp);

      fd.append(
        "sections_order_json",
        JSON.stringify(uniqOrder(sectionsOrder)),
      );

      // mídia (nomes devem bater com seu controller)
      if (heroVideo) fd.append("heroVideo", heroVideo);
      if (heroImageFallback) fd.append("heroImageFallback", heroImageFallback);

      // compat PUT:
      // - tenta page-settings
      // - se 404, tenta /page
      let targetPath = "/api/admin/drones/page";
      try {
        await apiClient.request("/api/admin/drones/page-settings", {
          method: "OPTIONS",
        });
        targetPath = "/api/admin/drones/page-settings";
      } catch {
        // use legacy endpoint
      }

      const json = await apiClient.put(targetPath, fd, {
        skipContentType: true,
      });

      const page = (
        json && typeof json === "object" && "page" in json
          ? (json as any).page
          : json
      ) as Partial<PageSettingsDTO>;

      setCurrentHeroVideoPath(sanitizeString(page.hero_video_path, "") || null);
      setCurrentHeroImagePath(
        sanitizeString(page.hero_image_fallback_path, "") || null,
      );

      setHeroVideo(null);
      setHeroImageFallback(null);

      setMsg("Config Landing salva com sucesso.");
    } catch {
      setMsg("Erro de rede ao salvar Config Landing.");
    } finally {
      setSaving(false);
    }
  }

  function updateSectionAt(idx: number, value: string) {
    setSectionsOrder((prev) => prev.map((s, i) => (i === idx ? value : s)));
  }
  function addSection(value = "") {
    setSectionsOrder((prev) => [...prev, value]);
  }
  function removeSection(idx: number) {
    setSectionsOrder((prev) => prev.filter((_, i) => i !== idx));
  }

  if (loading) return <div className="text-slate-300">Carregando...</div>;

  return (
    <div className="relative grid gap-6">
      {/* Mobile header */}
      <div className="sticky top-0 z-30 -mx-4 border-b border-white/10 bg-black/60 px-4 py-3 backdrop-blur sm:hidden">
        <div className="flex items-center justify-between gap-3">
          <button
            type="button"
            onClick={() => router.back()}
            className="inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/10 px-3 py-2 text-xs font-bold text-white hover:bg-white/15"
            aria-label="Voltar"
          >
            ← Voltar
          </button>
          <div className="min-w-0 text-right">
            <p className="truncate text-xs font-extrabold text-slate-100">
              Config Landing
            </p>
            <p className="truncate text-[11px] text-slate-400">Kavita Drones</p>
          </div>
        </div>
      </div>

      {/* Desktop header */}
      <div className="hidden sm:flex sm:items-start sm:justify-between sm:gap-4">
        <div>
          <h1 className="text-lg font-extrabold text-white">
            Config Landing (Drones)
          </h1>
          <p className="mt-1 text-sm text-slate-300">
            Ajuste título, CTA, mídias e a ordem das seções.
          </p>
        </div>

        <div className="flex items-center gap-2">
          <button
            type="button"
            onClick={() => router.back()}
            className="rounded-full border border-white/10 bg-white/5 px-4 py-2 text-sm font-bold text-white hover:bg-white/10"
          >
            Voltar
          </button>

          <LoadingButton
            isLoading={saving}
            onClick={save}
            className="rounded-full px-5"
          >
            Salvar
          </LoadingButton>
        </div>
      </div>

      {msg ? (
        <div className="rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-sm text-slate-100">
          {msg}
        </div>
      ) : null}

      <SectionCard title="Hero" subtitle="Título, subtítulo e mídias do hero.">
        <div className="grid gap-4 sm:grid-cols-2">
          <Field label="Título (hero_title)" hint="Obrigatório">
            <input
              value={heroTitle}
              onChange={(e) => setHeroTitle(e.target.value)}
              className={cx(inputBase, inputFocus)}
              placeholder="Ex: DJI Agras — Drones Agrícolas"
            />
          </Field>

          <Field label="Subtítulo (hero_subtitle)" hint="Opcional">
            <input
              value={heroSubtitle}
              onChange={(e) => setHeroSubtitle(e.target.value)}
              className={cx(inputBase, inputFocus)}
              placeholder="Ex: Alto desempenho, precisão e suporte local"
            />
          </Field>

          <div className="sm:col-span-2 grid gap-3 sm:grid-cols-2">
            <Field
              label="Vídeo do Hero (upload)"
              hint={
                currentHeroVideoPath
                  ? `Atual: ${currentHeroVideoPath}`
                  : undefined
              }
            >
              <input
                type="file"
                accept="video/mp4"
                onChange={(e) => setHeroVideo(e.target.files?.[0] || null)}
              />
            </Field>

            <Field
              label="Imagem fallback (upload)"
              hint={
                currentHeroImagePath
                  ? `Atual: ${currentHeroImagePath}`
                  : undefined
              }
            >
              <input
                type="file"
                accept="image/jpeg,image/png,image/webp"
                onChange={(e) =>
                  setHeroImageFallback(e.target.files?.[0] || null)
                }
              />
            </Field>
          </div>
        </div>
      </SectionCard>

      <SectionCard title="CTA" subtitle="Mensagem e botão de contato.">
        <div className="grid gap-4 sm:grid-cols-2">
          <Field label="Título do CTA (cta_title)" hint="Opcional">
            <input
              value={ctaTitle}
              onChange={(e) => setCtaTitle(e.target.value)}
              className={cx(inputBase, inputFocus)}
            />
          </Field>

          <Field label="Label do botão (cta_button_label)" hint="Opcional">
            <input
              value={ctaButtonLabel}
              onChange={(e) => setCtaButtonLabel(e.target.value)}
              className={cx(inputBase, inputFocus)}
            />
          </Field>

          <div className="sm:col-span-2">
            <Field
              label="Template da mensagem (cta_message_template)"
              hint="Opcional"
            >
              <textarea
                value={ctaTemplate}
                onChange={(e) => setCtaTemplate(e.target.value)}
                className="w-full min-h-[120px] rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm text-slate-100 outline-none focus:border-white/20 focus:ring-2 focus:ring-white/10"
                placeholder="Ex: Olá! Tenho interesse em um drone agrícola. Quero falar com um representante."
              />
            </Field>
          </div>
        </div>
      </SectionCard>

      <SectionCard
        title="Ordem das seções"
        subtitle="Define a ordem de renderização na landing pública."
        actions={
          <button
            type="button"
            onClick={() => addSection("")}
            className="rounded-full border border-white/10 bg-white/5 px-4 py-2 text-xs font-extrabold text-white hover:bg-white/10"
          >
            + Adicionar
          </button>
        }
      >
        <div className="grid gap-2">
          {sectionsOrder.map((s, idx) => (
            <div
              key={`${s}-${idx}`}
              className="grid gap-2 sm:grid-cols-[1fr_auto] sm:items-center"
            >
              <input
                value={s}
                onChange={(e) => updateSectionAt(idx, e.target.value)}
                className={cx(inputBase, inputFocus, "font-mono")}
                placeholder="hero | gallery | representatives | comments"
              />
              <button
                type="button"
                onClick={() => removeSection(idx)}
                className="rounded-full bg-red-500/80 px-4 py-2 text-xs font-extrabold text-white hover:bg-red-500"
              >
                Remover
              </button>
            </div>
          ))}
        </div>
      </SectionCard>

      <div className="sm:hidden">
        <LoadingButton
          isLoading={saving}
          onClick={save}
          className="w-full rounded-full px-5 py-3"
        >
          Salvar
        </LoadingButton>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import {
  onlyDigits,
  formatCnpjMask,
  formatCepMask,
  formatPhoneMask,
} from "@/utils/formatters";
import { ESTADOS_BR } from "@/utils/brasil";
import apiClient from "@/lib/apiClient";

type Rep = {
  id: number;
  name: string;
  whatsapp: string;
  cnpj: string;
  instagram_url: string | null;

  address_street: string;
  address_number: string;
  address_complement: string | null;
  address_neighborhood: string | null;
  address_city: string | null;
  address_uf: string | null;
  address_cep: string | null;

  notes: string | null;
  sort_order: number;
  is_active: 0 | 1;

  created_at: string;
  updated_at: string;
};

function normalizeUF(value: string) {
  return (value || "")
    .toUpperCase()
    .replace(/[^A-Z]/g, "")
    .slice(0, 2);
}

function isValidUF(uf: string) {
  const v = normalizeUF(uf);
  if (!v) return true; // opcional
  return ESTADOS_BR.some((e) => e.sigla === v);
}

export default function RepresentativeForm() {
  const [loading, setLoading] = useState(true);
  const [msg, setMsg] = useState<string | null>(null);

  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);

  const [data, setData] = useState<{
    items: Rep[];
    total: number;
    totalPages: number;
  } | null>(null);

  const [saving, setSaving] = useState(false);
  const [deletingId, setDeletingId] = useState<number | null>(null);

  const [editing, setEditing] = useState<Rep | null>(null);

  // form state (create/edit)
  const [name, setName] = useState("");
  const [whatsapp, setWhatsapp] = useState("");
  const [cnpj, setCnpj] = useState("");
  const [instagramUrl, setInstagramUrl] = useState("");

  const [street, setStreet] = useState("");
  const [number, setNumber] = useState("");
  const [complement, setComplement] = useState("");
  const [neighborhood, setNeighborhood] = useState("");
  const [city, setCity] = useState("");
  const [uf, setUf] = useState("");
  const [cep, setCep] = useState("");

  const [notes, setNotes] = useState("");
  const [sortOrder, setSortOrder] = useState(0);
  const [isActive, setIsActive] = useState(true);

  const items = useMemo(() => data?.items || [], [data]);

  function resetForm() {
    setName("");
    setWhatsapp("");
    setCnpj("");
    setInstagramUrl("");
    setStreet("");
    setNumber("");
    setComplement("");
    setNeighborhood("");
    setCity("");
    setUf("");
    setCep("");
    setNotes("");
    setSortOrder(0);
    setIsActive(true);
    setEditing(null);
  }

  function startEdit(rep: Rep) {
    setEditing(rep);
    setName(rep.name || "");
    setWhatsapp(formatPhoneMask(rep.whatsapp || ""));
    setCnpj(formatCnpjMask(rep.cnpj || ""));
    setInstagramUrl(rep.instagram_url || "");
    setStreet(rep.address_street || "");
    setNumber(rep.address_number || "");
    setComplement(rep.address_complement || "");
    setNeighborhood(rep.address_neighborhood || "");
    setCity(rep.address_city || "");
    setUf(normalizeUF(rep.address_uf || ""));
    setCep(formatCepMask(rep.address_cep || ""));
    setNotes(rep.notes || "");
    setSortOrder(rep.sort_order || 0);
    setIsActive(Boolean(rep.is_active));
    setMsg(null);
  }

  async function load(p = page) {
    setMsg(null);
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.set("page", String(p));
      params.set("limit", "20");
      if (search.trim()) params.set("busca", search.trim());
      params.set("orderBy", "sort_order");
      params.set("orderDir", "asc");

      const data = await apiClient.get<any>(
        `/api/admin/drones/representantes?${params.toString()}`,
      );

      setData({
        items: Array.isArray(data?.items) ? data.items : [],
        total: Number(data?.total || 0),
        totalPages: Number(data?.totalPages || 1),
      });
      setPage(Number(data?.page || p));
    } catch (err: any) {
      if (err?.status === 401 || err?.status === 403) {
        if (typeof window !== "undefined")
          window.location.assign("/admin/login");
        return;
      }
      setMsg(err?.message || "Erro de rede ao carregar representantes.");
      setData(null);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    load(1);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  async function applySearch() {
    setPage(1);
    await load(1);
  }

  function validate() {
    if (!name.trim()) return "name é obrigatório.";

    const w = onlyDigits(whatsapp);
    if (!w) return "whatsapp é obrigatório.";
    if (!(w.length === 10 || w.length === 11))
      return "whatsapp inválido (DDD + número).";

    const c = onlyDigits(cnpj);
    if (!c) return "cnpj é obrigatório.";
    if (c.length !== 14) return "cnpj inválido (14 dígitos).";

    if (!street.trim()) return "address_street é obrigatório.";
    if (!number.trim()) return "address_number é obrigatório.";

    const cepDigits = onlyDigits(cep);
    if (cepDigits && cepDigits.length !== 8) return "cep inválido (8 dígitos).";

    if (!isValidUF(uf))
      return "UF inválida. Use uma sigla válida (ex: SP, MG).";

    return null;
  }

  async function save() {
    setMsg(null);
    const err = validate();
    if (err) {
      setMsg(err);
      return;
    }

    setSaving(true);
    try {
      const payload = {
        name: name.trim(),
        whatsapp: onlyDigits(whatsapp),
        cnpj: onlyDigits(cnpj),
        instagram_url: instagramUrl.trim() || null,

        address_street: street.trim(),
        address_number: number.trim(),
        address_complement: complement.trim() || null,
        address_neighborhood: neighborhood.trim() || null,
        address_city: city.trim() || null,
        address_uf: normalizeUF(uf) || null,
        address_cep: onlyDigits(cep) || null,

        notes: notes.trim() || null,
        sort_order: Number(sortOrder) || 0,
        is_active: isActive ? 1 : 0,
      };

      if (editing) {
        await apiClient.put(
          `/api/admin/drones/representantes/${editing.id}`,
          payload,
        );
      } else {
        await apiClient.post("/api/admin/drones/representantes", payload);
      }

      setMsg(editing ? "Representante atualizado." : "Representante criado.");
      resetForm();
      await load(1);
    } catch (err: any) {
      if (err?.status === 401 || err?.status === 403) {
        if (typeof window !== "undefined")
          window.location.assign("/admin/login");
        return;
      }
      setMsg(err?.message || "Erro de rede ao salvar representante.");
    } finally {
      setSaving(false);
    }
  }

  async function remove(id: number) {
    setMsg(null);
    setDeletingId(id);
    try {
      await apiClient.del(`/api/admin/drones/representantes/${id}`);
      setMsg("Representante removido.");
      await load(1);
    } catch (err: any) {
      if (err?.status === 401 || err?.status === 403) {
        if (typeof window !== "undefined")
          window.location.assign("/admin/login");
        return;
      }
      setMsg(err?.message || "Erro de rede ao remover representante.");
    } finally {
      setDeletingId(null);
    }
  }

  return (
    <div className="grid gap-6">
      <div className="rounded-2xl border border-white/10 bg-white/5 p-5">
        <h2 className="text-sm font-extrabold">
          Representantes/Lojas (CRUD + busca + ordenação)
        </h2>

        <div className="mt-4 grid gap-3 sm:grid-cols-[1fr_auto]">
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Buscar por nome, cidade, UF, CNPJ..."
            className="rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
          />
          <button
            onClick={applySearch}
            className="rounded-full bg-white/10 px-6 py-2 text-sm font-bold text-white border border-white/10 hover:bg-white/15"
          >
            Buscar
          </button>
        </div>

        {msg ? <p className="mt-3 text-sm text-slate-200">{msg}</p> : null}
      </div>

      <div className="rounded-2xl border border-white/10 bg-white/5 p-5">
        <h3 className="text-sm font-extrabold">
          {editing ? "Editar representante" : "Adicionar representante"}
        </h3>

        <div className="mt-4 grid gap-3 sm:grid-cols-2">
          <div>
            <label className="text-xs text-slate-300">Nome (obrigatório)</label>
            <input
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">WhatsApp</label>
            <input
              value={whatsapp}
              onChange={(e) => setWhatsapp(formatPhoneMask(e.target.value))}
              inputMode="tel"
              placeholder="(00) 00000-0000"
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">CNPJ</label>
            <input
              value={cnpj}
              onChange={(e) => setCnpj(formatCnpjMask(e.target.value))}
              inputMode="numeric"
              placeholder="00.000.000/0000-00"
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">Instagram (URL)</label>
            <input
              value={instagramUrl}
              onChange={(e) => setInstagramUrl(e.target.value)}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">Rua (obrigatório)</label>
            <input
              value={street}
              onChange={(e) => setStreet(e.target.value)}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">
              Número (obrigatório)
            </label>
            <input
              value={number}
              onChange={(e) => setNumber(e.target.value)}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">Complemento</label>
            <input
              value={complement}
              onChange={(e) => setComplement(e.target.value)}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">Bairro</label>
            <input
              value={neighborhood}
              onChange={(e) => setNeighborhood(e.target.value)}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">Cidade</label>
            <input
              value={city}
              onChange={(e) => setCity(e.target.value)}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">UF</label>
            <input
              value={uf}
              onChange={(e) => setUf(normalizeUF(e.target.value))}
              maxLength={2}
              placeholder="SP"
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm uppercase"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">CEP</label>
            <input
              value={cep}
              onChange={(e) => setCep(formatCepMask(e.target.value))}
              inputMode="numeric"
              placeholder="00000-000"
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div>
            <label className="text-xs text-slate-300">Ordem (sort_order)</label>
            <input
              type="number"
              value={sortOrder}
              onChange={(e) => setSortOrder(Number(e.target.value))}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div className="sm:col-span-2">
            <label className="text-xs text-slate-300">Observações</label>
            <input
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="mt-1 w-full rounded-xl bg-black/50 border border-white/10 px-3 py-2 text-sm"
            />
          </div>

          <div className="sm:col-span-2 flex items-center gap-2">
            <input
              id="rep-active"
              type="checkbox"
              checked={isActive}
              onChange={(e) => setIsActive(e.target.checked)}
            />
            <label htmlFor="rep-active" className="text-sm text-slate-200">
              Ativo (aparece na página pública)
            </label>
          </div>

          <div className="sm:col-span-2 flex flex-wrap gap-2">
            <button
              onClick={save}
              disabled={saving}
              className="rounded-full bg-emerald-500 px-6 py-2 text-sm font-bold text-white disabled:opacity-60"
            >
              {saving
                ? "Salvando..."
                : editing
                  ? "Salvar alterações"
                  : "Adicionar"}
            </button>

            <button
              onClick={resetForm}
              className="rounded-full bg-white/10 px-6 py-2 text-sm font-bold text-white border border-white/10"
            >
              Limpar
            </button>
          </div>
        </div>
      </div>

      <div className="rounded-2xl border border-white/10 bg-white/5 p-5">
        <h3 className="text-sm font-extrabold">Lista</h3>

        {loading ? <p className="mt-3 text-slate-300">Carregando...</p> : null}

        <div className="mt-4 grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
          {items.map((r) => (
            <div
              key={r.id}
              className="rounded-2xl border border-white/10 bg-black/30 p-4"
            >
              <div className="flex items-center justify-between gap-3">
                <p className="text-sm font-bold text-white">{r.name}</p>
                <span className="text-xs text-slate-300">
                  {r.is_active ? "ATIVO" : "INATIVO"}
                </span>
              </div>

              <p className="mt-1 text-xs text-slate-300">
                {r.address_city || "Cidade"}{" "}
                {r.address_uf ? `- ${normalizeUF(r.address_uf)}` : ""} • ordem{" "}
                {r.sort_order}
              </p>

              <p className="mt-2 text-xs text-slate-300">
                WhatsApp: {formatPhoneMask(r.whatsapp)} • CNPJ:{" "}
                {formatCnpjMask(r.cnpj)}
              </p>

              <p className="mt-2 text-xs text-slate-400">
                {r.address_street}, {r.address_number}
                {r.address_neighborhood ? ` - ${r.address_neighborhood}` : ""}
                {r.address_cep ? ` • CEP ${formatCepMask(r.address_cep)}` : ""}
              </p>

              <div className="mt-3 flex flex-wrap gap-2">
                <button
                  onClick={() => startEdit(r)}
                  className="rounded-full bg-white/10 px-4 py-2 text-xs font-bold text-white border border-white/10"
                >
                  Editar
                </button>
                <button
                  onClick={() => remove(r.id)}
                  disabled={deletingId === r.id}
                  className="rounded-full bg-red-500/80 px-4 py-2 text-xs font-bold text-white disabled:opacity-60"
                >
                  {deletingId === r.id ? "Excluindo..." : "Excluir"}
                </button>
              </div>
            </div>
          ))}
        </div>

        {data?.totalPages && data.totalPages > 1 ? (
          <div className="mt-5 flex items-center gap-2">
            <button
              disabled={page <= 1}
              onClick={() => load(page - 1)}
              className="rounded-full bg-white/10 px-4 py-2 text-xs font-bold text-white border border-white/10 disabled:opacity-50"
            >
              Anterior
            </button>
            <p className="text-xs text-slate-300">
              Página {page} de {data.totalPages}
            </p>
            <button
              disabled={page >= data.totalPages}
              onClick={() => load(page + 1)}
              className="rounded-full bg-white/10 px-4 py-2 text-xs font-bold text-white border border-white/10 disabled:opacity-50"
            >
              Próxima
            </button>
          </div>
        ) : null}

        {!items.length && !loading ? (
          <p className="mt-3 text-sm text-slate-300">
            Nenhum representante encontrado.
          </p>
        ) : null}
      </div>
    </div>
  );
}

"use client";

import type { Dispatch, SetStateAction } from "react";
import { useEffect, useMemo, useRef, useState } from "react";
import type {
  ClimaEditMode,
  ClimaFormState,
  ClimaItem,
} from "@/types/kavita-news";
import LoadingButton from "@/components/buttons/LoadingButton";
import { normalizeSlug } from "@/utils/kavita-news/clima";

type IbgeMunicipioNivelado = {
  "municipio-id": string | number;
  "municipio-nome": string;
  "UF-sigla": string;
};

type IbgeMunicipioCompleto = {
  id: number;
  nome: string;
  microrregiao?: any;
  "regiao-imediata"?: any;
};

type GeoSuggestion = {
  code?: string;
  name: string;
  uf: string;
  status?: string;
  lat?: string | number | null;
  lon?: string | number | null;
  country?: string;
  admin1?: string;
  admin2?: string;
  timezone?: string;
};

function isAbortError(e: any) {
  const msg = String(e?.message || e || "").toLowerCase();
  return (
    e?.name === "AbortError" || msg.includes("aborted") || msg.includes("abort")
  );
}

function stripAccents(s: string) {
  return (s || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function getIbgeNome(m: any): string {
  return String(m?.nome ?? m?.["municipio-nome"] ?? "").trim();
}
function getIbgeId(m: any): string {
  const v = m?.id ?? m?.["municipio-id"];
  return v == null ? "" : String(v).trim();
}
function getIbgeUf(m: any): string {
  const uf =
    m?.["UF-sigla"] ||
    m?.microrregiao?.mesorregiao?.UF?.sigla ||
    m?.["regiao-imediata"]?.["regiao-intermediaria"]?.UF?.sigla ||
    "";
  return String(uf || "").toUpperCase();
}

function safeNum(v: any): number | null {
  if (v === null || v === undefined || v === "") return null;
  const n = Number(String(v).replace(",", "."));
  return Number.isFinite(n) ? n : null;
}

function fmtCoord(n: number | null) {
  if (n === null) return "";
  return String(Number(n.toFixed(6)));
}

type Props = {
  editMode: ClimaEditMode;
  setEditMode: Dispatch<SetStateAction<ClimaEditMode>>;

  mode: "create" | "edit";
  editing: ClimaItem | null;

  form: ClimaFormState;
  setForm: Dispatch<SetStateAction<ClimaFormState>>;

  saving: boolean;

  onSubmit: () => void;
  onCancelEdit: () => void;

  // mantido por compatibilidade (mesmo sem botão)
  onStartCreate: () => void;

  onBuscarIbge?: (q: { uf: string; city: string }) => void;

  onSuggestStations?: (
    uf: string,
    q: string,
    limit?: number,
  ) => Promise<GeoSuggestion[]>;
};

export default function ClimaForm({
  editMode,
  setEditMode,
  mode,
  editing,
  form,
  setForm,
  saving,
  onSubmit,
  onCancelEdit,
  onStartCreate, // mantido
  onBuscarIbge,
  onSuggestStations,
}: Props) {
  const isEdit = mode === "edit" && !!editing;
  const showIbgeUi = editMode === "ibge";

  const [ibgeLoading, setIbgeLoading] = useState(false);
  const [ibgeError, setIbgeError] = useState<string | null>(null);
  const [ibgeSuggestions, setIbgeSuggestions] = useState<
    IbgeMunicipioNivelado[]
  >([]);
  const ibgeAllRef = useRef<IbgeMunicipioNivelado[] | null>(null);
  const ibgeAbortRef = useRef<AbortController | null>(null);
  const debounceRef = useRef<any>(null);

  const [geoLoading, setGeoLoading] = useState(false);
  const [geoHint, setGeoHint] = useState<string | null>(null);
  const [geoSuggestions, setGeoSuggestions] = useState<GeoSuggestion[]>([]);
  const [geoPickerOpen, setGeoPickerOpen] = useState(false);

  const isResettingRef = useRef(false);

  const ibgeHint = useMemo(() => {
    if (!showIbgeUi) return null;
    if (ibgeError) return ibgeError;
    if (ibgeLoading) return "Buscando no IBGE...";
    if (ibgeSuggestions.length > 0)
      return `Sugestões: ${ibgeSuggestions.length}`;
    return "Digite o nome da cidade (ou o IBGE ID) para preencher automaticamente.";
  }, [showIbgeUi, ibgeError, ibgeLoading, ibgeSuggestions.length]);

  function set<K extends keyof ClimaFormState>(
    key: K,
    value: ClimaFormState[K],
  ) {
    setForm((p) => ({ ...p, [key]: value }));
  }

  function clearAssist() {
    setIbgeError(null);
    setIbgeSuggestions([]);
    setGeoHint(null);
    setGeoSuggestions([]);
    setGeoPickerOpen(false);
  }

  function clearFormData() {
    isResettingRef.current = true;

    try {
      ibgeAbortRef.current?.abort();
    } catch {}
    ibgeAbortRef.current = null;

    clearAssist();

    setForm((p: any) => ({
      ...p,
      city_name: "",
      uf: "",
      slug: "",
      ibge_id: "",
      station_code: "",
      station_lat: "",
      station_lon: "",
      station_distance: "",
      mm_24h: "",
      mm_7d: "",
      source: "",
      last_update_at: "",
      // ativo mantém
    }));

    setTimeout(() => {
      isResettingRef.current = false;
    }, 0);

    // mantém compatibilidade com o fluxo existente
    // (se seu hook usa startCreate para garantir modo create)
    try {
      onStartCreate?.();
    } catch {}
  }

  async function ensureIbgeAllLoaded() {
    if (ibgeAllRef.current) return ibgeAllRef.current;

    setIbgeLoading(true);
    setIbgeError(null);

    try {
      const url =
        "https://servicodados.ibge.gov.br/api/v1/localidades/municipios?view=nivelado&orderBy=nome";
      const res = await fetch(url);
      if (!res.ok) throw new Error(`IBGE: HTTP ${res.status}`);
      const data = (await res.json()) as IbgeMunicipioNivelado[];
      ibgeAllRef.current = Array.isArray(data) ? data : [];
      return ibgeAllRef.current;
    } catch (e: any) {
      setIbgeError(e?.message || "Erro ao carregar base do IBGE.");
      ibgeAllRef.current = [];
      return [];
    } finally {
      setIbgeLoading(false);
    }
  }

  async function suggestIbgeByCityName(nome: string) {
    const q = stripAccents(nome.trim());
    if (q.length < 2) {
      setIbgeSuggestions([]);
      setIbgeError(null);
      return;
    }
    const all = await ensureIbgeAllLoaded();

    const starts: IbgeMunicipioNivelado[] = [];
    const contains: IbgeMunicipioNivelado[] = [];

    for (const m of all) {
      const n = stripAccents(getIbgeNome(m));
      if (!n) continue;
      if (n.startsWith(q)) starts.push(m);
      else if (n.includes(q)) contains.push(m);
    }

    setIbgeSuggestions([...starts, ...contains].slice(0, 10));
  }

  async function fetchIbgeMunicipioById(idRaw: string) {
    const id = idRaw.trim();
    if (!/^[0-9]{6,8}$/.test(id)) return;

    try {
      setIbgeLoading(true);
      setIbgeError(null);

      ibgeAbortRef.current?.abort();
      const controller = new AbortController();
      ibgeAbortRef.current = controller;

      const url = `https://servicodados.ibge.gov.br/api/v1/localidades/municipios/${encodeURIComponent(id)}`;
      const res = await fetch(url, { signal: controller.signal });
      if (!res.ok) throw new Error(`IBGE: HTTP ${res.status}`);

      const data = (await res.json()) as IbgeMunicipioCompleto | any;
      if (data && typeof data === "object") {
        await applyMunicipio(data);
      }
    } catch (e: any) {
      if (isAbortError(e)) return;
      setIbgeError(e?.message || "Erro ao buscar IBGE por ID.");
    } finally {
      setIbgeLoading(false);
    }
  }

  async function geocodeFlow(uf: string, city: string) {
    if (!onSuggestStations) return;

    const UF = String(uf || "")
      .trim()
      .toUpperCase();
    const CITY = String(city || "").trim();

    if (UF.length !== 2 || CITY.length < 2) {
      setGeoHint("Preencha UF (2 letras) e cidade para buscar coordenadas.");
      return;
    }

    try {
      setGeoLoading(true);
      setGeoHint(null);

      const list = await onSuggestStations(UF, CITY, 10);
      const items = Array.isArray(list) ? list : [];
      setGeoSuggestions(items);

      if (items.length === 0) {
        setGeoPickerOpen(false);
        setGeoHint(
          "Não encontrei coordenadas. Verifique cidade/UF (ex.: “Caratinga / MG”).",
        );
        return;
      }

      const hasCoords =
        String((form as any).station_lat || "").trim() &&
        String((form as any).station_lon || "").trim();

      if (hasCoords) {
        setGeoPickerOpen(true);
        setGeoHint(
          "Sugestões encontradas. Você pode trocar as coordenadas se quiser.",
        );
        return;
      }

      const best = items[0];
      const lat = safeNum(best?.lat);
      const lon = safeNum(best?.lon);

      if (lat !== null && lon !== null) {
        setForm((p: any) => ({
          ...p,
          station_lat: fmtCoord(lat),
          station_lon: fmtCoord(lon),
          station_source: "OPEN_METEO_GEOCODING",
        }));
        setGeoPickerOpen(false);
        setGeoHint(
          `Coordenadas sugeridas automaticamente: ${fmtCoord(lat)}, ${fmtCoord(lon)}`,
        );
      } else {
        setGeoPickerOpen(true);
        setGeoHint(
          "Encontrei sugestões, mas selecione manualmente para aplicar as coordenadas.",
        );
      }
    } catch {
      setGeoSuggestions([]);
      setGeoPickerOpen(false);
      setGeoHint(
        "Falha ao buscar coordenadas. Você pode preencher latitude/longitude manualmente.",
      );
    } finally {
      setGeoLoading(false);
    }
  }

  function selectGeo(s: GeoSuggestion) {
    const lat = safeNum(s?.lat);
    const lon = safeNum(s?.lon);

    if (lat === null || lon === null) {
      setGeoHint("Sugestão inválida (sem lat/lon).");
      return;
    }

    setForm((p: any) => ({
      ...p,
      station_lat: fmtCoord(lat),
      station_lon: fmtCoord(lon),
      station_source: "OPEN_METEO_GEOCODING",
    }));

    setGeoPickerOpen(false);
    setGeoHint(
      `Coordenadas selecionadas: ${fmtCoord(lat)}, ${fmtCoord(lon)} (${s.name})`,
    );
  }

  async function applyMunicipio(m: any) {
    if (isResettingRef.current) return;

    const nome = getIbgeNome(m);
    const uf = getIbgeUf(m);
    const id = getIbgeId(m);

    setForm((p: any) => ({
      ...p,
      city_name: nome || p.city_name,
      uf: (uf || p.uf || "").toUpperCase(),
      ibge_id: id || p.ibge_id,
      slug: normalizeSlug(p.slug || nome || p.city_name || ""),
    }));

    setIbgeSuggestions([]);

    if (showIbgeUi && uf && nome) {
      await geocodeFlow(uf, nome);
    }
  }

  useEffect(() => {
    if (!showIbgeUi) return;
    if (isResettingRef.current) return;

    const city = form.city_name || "";
    const id = (form as any).ibge_id || "";

    if (debounceRef.current) clearTimeout(debounceRef.current);

    debounceRef.current = setTimeout(() => {
      const idTrim = String(id).trim();

      if (/^[0-9]{6,8}$/.test(idTrim)) {
        fetchIbgeMunicipioById(idTrim);
        return;
      }

      suggestIbgeByCityName(city);
    }, 250);

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showIbgeUi, form.city_name, (form as any).ibge_id]);

  useEffect(() => {
    if (!showIbgeUi) return;
    ensureIbgeAllLoaded();
  }, [showIbgeUi]);

  useEffect(() => {
    return () => {
      try {
        ibgeAbortRef.current?.abort();
      } catch {}
      ibgeAbortRef.current = null;
    };
  }, []);

  const inputBase =
    "w-full rounded-xl border border-slate-200 bg-white px-3 py-2.5 text-sm text-slate-900 " +
    "placeholder:text-slate-400 shadow-sm " +
    "focus:outline-none focus:ring-2 focus:ring-[#EC5B20] focus:border-transparent";
  const labelBase =
    "text-xs font-semibold uppercase tracking-wide text-slate-600";

  return (
    <section className="rounded-2xl border border-slate-200 bg-white shadow-[0_8px_30px_rgba(15,23,42,0.08)] overflow-hidden">
      <header className="px-5 py-4 border-b bg-gradient-to-r from-slate-50 to-white">
        <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
          <div className="flex items-center gap-2">
            <span className="inline-flex h-9 w-9 items-center justify-center rounded-xl bg-slate-900 text-white text-sm">
              ⛅
            </span>
            <div>
              <h3 className="text-base font-semibold text-slate-900">Clima</h3>
              <p className="text-sm text-slate-500">
                {isEdit
                  ? `Editando: ${editing?.city_name ?? ""}`
                  : "Cadastrar / atualizar cidades monitoradas"}
              </p>
            </div>
          </div>

          {/* ações: removido “Adicionar cidade” */}
          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-end">
            <div className="inline-flex w-full sm:w-auto rounded-xl border border-slate-200 bg-white p-1">
              <button
                type="button"
                onClick={() => setEditMode("manual")}
                className={`px-3 py-1.5 text-sm rounded-lg transition ${
                  editMode === "manual"
                    ? "bg-slate-900 text-white"
                    : "text-slate-700 hover:bg-slate-50"
                }`}
              >
                Manual
              </button>
              <button
                type="button"
                onClick={() => setEditMode("ibge")}
                className={`px-3 py-1.5 text-sm rounded-lg transition ${
                  editMode === "ibge"
                    ? "bg-slate-900 text-white"
                    : "text-slate-700 hover:bg-slate-50"
                }`}
              >
                IBGE
              </button>
            </div>

            <button
              type="button"
              onClick={clearFormData}
              className="w-full sm:w-auto rounded-xl border border-slate-200 bg-white px-4 py-2.5 text-sm font-semibold text-slate-700 hover:bg-slate-50 transition"
            >
              Limpar dados
            </button>
          </div>
        </div>
      </header>

      <div className="p-5 space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="space-y-2">
            <label className={labelBase}>Cidade</label>
            <input
              value={form.city_name}
              onChange={(e) => {
                setGeoHint(null);
                setGeoPickerOpen(false);
                set("city_name", e.target.value);
              }}
              className={inputBase}
              placeholder="Ex: Uberlândia"
            />

            {showIbgeUi ? (
              <div className="space-y-2">
                <p className="text-xs text-slate-500">{ibgeHint}</p>

                {ibgeSuggestions.length > 0 ? (
                  <div className="rounded-xl border border-slate-200 bg-white shadow-sm overflow-hidden">
                    {ibgeSuggestions.map((m) => {
                      const uf = getIbgeUf(m);
                      const id = getIbgeId(m);
                      const nome = getIbgeNome(m);
                      return (
                        <button
                          key={`${id}-${uf}-${nome}`}
                          type="button"
                          onClick={() => applyMunicipio(m)}
                          className="w-full text-left px-3 py-2 text-sm hover:bg-slate-50 transition flex items-center justify-between"
                        >
                          <span className="font-medium text-slate-900">
                            {nome}
                          </span>
                          <span className="text-xs text-slate-500">
                            {uf ? `${uf} · ` : ""}
                            {id}
                          </span>
                        </button>
                      );
                    })}
                  </div>
                ) : null}
              </div>
            ) : null}
          </div>

          <div className="space-y-2">
            <label className={labelBase}>UF</label>
            <input
              value={form.uf}
              onChange={(e) => {
                setGeoHint(null);
                setGeoPickerOpen(false);
                set("uf", e.target.value.toUpperCase());
              }}
              className={inputBase}
              placeholder="Ex: MG"
              maxLength={2}
            />
          </div>

          <div className="space-y-2">
            <label className={labelBase}>Slug</label>
            <input
              value={form.slug}
              onChange={(e) => set("slug", e.target.value)}
              className={inputBase}
              placeholder="Ex: uberlandia"
              disabled={showIbgeUi}
            />
            <p className="text-xs text-slate-500">
              {showIbgeUi
                ? "No modo IBGE, o slug é gerado automaticamente pela cidade."
                : "Use letras minúsculas e hífen."}
            </p>
          </div>
        </div>

        <div className="rounded-2xl border border-slate-200 bg-slate-50 p-4 space-y-4">
          <div className="flex flex-col gap-2 md:flex-row md:items-center md:justify-between">
            <div className="min-w-0">
              <p className="text-sm font-semibold text-slate-900">
                Coordenadas (Open-Meteo)
              </p>
              <p className="text-xs text-slate-500">
                Chuva (mm) será sincronizada via latitude/longitude.
              </p>
              {geoHint ? (
                <p className="text-xs text-slate-600 mt-1 break-words">
                  {geoHint}
                </p>
              ) : null}
            </div>

            <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-2">
              {editMode === "ibge" && onBuscarIbge ? (
                <button
                  type="button"
                  onClick={() =>
                    onBuscarIbge({
                      uf: form.uf.trim().toUpperCase(),
                      city: form.city_name.trim(),
                    })
                  }
                  className="px-3 py-2 rounded-xl border border-slate-200 bg-white text-sm text-slate-700 hover:bg-slate-50 transition"
                >
                  Buscar no IBGE
                </button>
              ) : null}

              {onSuggestStations ? (
                <button
                  type="button"
                  disabled={geoLoading}
                  onClick={() => geocodeFlow(form.uf, form.city_name)}
                  className="px-3 py-2 rounded-xl border border-slate-200 bg-white text-sm text-slate-700 hover:bg-slate-50 transition disabled:opacity-60"
                  title="Busca coordenadas com Open-Meteo (geocoding)"
                >
                  {geoLoading ? "Buscando..." : "Buscar coordenadas"}
                </button>
              ) : null}
            </div>
          </div>

          {geoPickerOpen && geoSuggestions.length > 0 ? (
            <div className="rounded-xl border border-slate-200 bg-white shadow-sm overflow-hidden">
              <div className="px-3 py-2 text-xs font-semibold text-slate-600 bg-slate-50 border-b">
                Selecione o local (aplicará station_lat/station_lon)
              </div>
              {geoSuggestions.slice(0, 10).map((s) => {
                const lat = safeNum(s?.lat);
                const lon = safeNum(s?.lon);
                return (
                  <button
                    key={`${s.name}-${s.uf}-${lat ?? "x"}-${lon ?? "y"}`}
                    type="button"
                    onClick={() => selectGeo(s)}
                    className="w-full text-left px-3 py-2 text-sm hover:bg-slate-50 transition flex items-center justify-between gap-3"
                  >
                    <span className="font-medium text-slate-900 truncate">
                      {s.name}{" "}
                      <span className="font-normal text-slate-600">
                        — {s.uf}
                      </span>
                    </span>
                    <span className="text-xs text-slate-500 whitespace-nowrap">
                      {lat !== null && lon !== null
                        ? `${fmtCoord(lat)}, ${fmtCoord(lon)}`
                        : "—"}
                    </span>
                  </button>
                );
              })}
            </div>
          ) : null}

          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="space-y-2">
              <label className={labelBase}>Latitude</label>
              <input
                value={(form as any).station_lat ?? ""}
                onChange={(e) =>
                  setForm((p: any) => ({ ...p, station_lat: e.target.value }))
                }
                className={inputBase}
                placeholder="Ex: -18.920000"
                inputMode="decimal"
              />
            </div>

            <div className="space-y-2">
              <label className={labelBase}>Longitude</label>
              <input
                value={(form as any).station_lon ?? ""}
                onChange={(e) =>
                  setForm((p: any) => ({ ...p, station_lon: e.target.value }))
                }
                className={inputBase}
                placeholder="Ex: -48.260000"
                inputMode="decimal"
              />
            </div>

            <div className="space-y-2 md:col-span-2">
              <label className={labelBase}>IBGE ID (opcional)</label>
              <input
                value={(form as any).ibge_id ?? ""}
                onChange={(e) => {
                  setGeoHint(null);
                  setGeoPickerOpen(false);
                  setForm((p: any) => ({ ...p, ibge_id: e.target.value }));
                }}
                className={inputBase}
                placeholder="Ex: 3170206"
                inputMode="numeric"
              />
              {showIbgeUi ? (
                <p className="text-xs text-slate-500">
                  Se digitar o ID (6–8 dígitos), ele preenche automático.
                </p>
              ) : null}
