              {selectedPreset ? (
                <div className="rounded-xl border border-slate-200 bg-slate-50 px-3 py-2">
                  <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                    <div className="text-xs text-slate-600">
                      <span className="font-semibold text-slate-800">
                        Preset:
                      </span>{" "}
                      {[
                        selectedPreset.name
                          ? `nome: ${selectedPreset.name}`
                          : null,
                        selectedPreset.type
                          ? `tipo: ${selectedPreset.type}`
                          : null,
                        selectedPreset.unit
                          ? `unidade: ${selectedPreset.unit}`
                          : null,
                        selectedPreset.market
                          ? `market: ${selectedPreset.market}`
                          : null,
                        selectedPreset.source
                          ? `source: ${selectedPreset.source}`
                          : null,
                      ]
                        .filter(Boolean)
                        .join(" • ")}
                    </div>

                    <button
                      type="button"
                      onClick={forceApplySelectedPreset}
                      className="w-full sm:w-auto rounded-xl border border-slate-200 bg-white px-3 py-2 text-xs font-semibold text-slate-700 hover:bg-slate-50 transition"
                      title="Aplica o preset sobrescrevendo os campos do formulário"
                    >
                      Aplicar preset do slug
                    </button>
                  </div>
                </div>
              ) : null}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="space-y-2 md:col-span-2">
            <label className={labelBase}>Tipo</label>
            <input
              value={form.type}
