              className={inputBase}
              placeholder="Ex: cambio, graos, pecuaria, cafe..."
              list="knews-types"
            />
            <datalist id="knews-types">
              {suggestions.types.map((t) => (
                <option key={t} value={t} />
              ))}
            </datalist>
          </div>

          <div className="space-y-2">
            <label className={labelBase}>Unidade</label>
            <input
              value={form.unit}
              onChange={(e) => set("unit", e.target.value)}
              className={inputBase}
              placeholder="Ex: R$/saca, R$/@, R$"
              list="knews-units"
            />
            <datalist id="knews-units">
              {suggestions.units.map((u) => (
                <option key={u} value={u} />
              ))}
            </datalist>
          </div>

          <div className="space-y-2">
            <label className={labelBase}>Market (opcional)</label>
            <input
              value={form.market}
              onChange={(e) => set("market", e.target.value)}
              className={inputBase}
              placeholder="Ex: CEPEA, B3..."
              list="knews-markets"
            />
            <datalist id="knews-markets">
              {suggestions.markets.map((m) => (
                <option key={m} value={m} />
              ))}
            </datalist>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="space-y-2">
            <label className={labelBase}>Preço</label>
            <input
              value={form.price}
              onChange={(e) => set("price", e.target.value)}
              className={inputBase}
              placeholder="Ex: 5.12"
              inputMode="decimal"
            />
          </div>

          <div className="space-y-2">
            <label className={labelBase}>Variação dia</label>
            <input
              value={form.variation_day}
              onChange={(e) => set("variation_day", e.target.value)}
              className={inputBase}
              placeholder="Ex: 0.32"
              inputMode="decimal"
            />
          </div>

          <div className="space-y-2 md:col-span-2">
            <label className={labelBase}>Source (opcional)</label>
            <input
              value={form.source}
              onChange={(e) => set("source", e.target.value)}
              className={inputBase}
              placeholder="Ex: BCB PTAX, CEPEA, B3..."
              list="knews-sources"
            />
            <datalist id="knews-sources">
              {suggestions.sources.map((s) => (
                <option key={s} value={s} />
              ))}
            </datalist>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 items-end">
          <div className="space-y-2 md:col-span-2">
            <label className={labelBase}>Last update (opcional)</label>
            <input
              value={form.last_update_at}
              onChange={(e) => set("last_update_at", e.target.value)}
              className={inputBase}
              placeholder="YYYY-MM-DD HH:mm:ss"
            />
          </div>

          <label className="flex items-center gap-2 rounded-xl border border-slate-200 bg-white px-3 py-2.5 text-sm text-slate-700 shadow-sm">
            <input
              type="checkbox"
              checked={form.ativo}
              onChange={(e) => set("ativo", e.target.checked)}
              className="h-4 w-4 accent-[#EC5B20]"
            />
            Ativo
          </label>
        </div>

        <div className="flex flex-col sm:flex-row gap-2 sm:justify-end">
          {isEdit ? (
            <button
              type="button"
              onClick={onCancelEdit}
              className="w-full sm:w-auto rounded-xl border border-slate-200 bg-white px-4 py-2.5 text-sm font-semibold text-slate-700 hover:bg-slate-50 transition"
            >
              Cancelar edição
            </button>
          ) : null}

          <LoadingButton
            isLoading={saving}
            onClick={onSubmit}
            className="w-full sm:w-auto rounded-xl bg-slate-900 px-5 py-2.5 text-sm font-semibold text-white hover:brightness-95 transition"
          >
            {isEdit ? "Salvar alterações" : "Salvar"}
          </LoadingButton>
        </div>
      </div>
    </section>
  );
}

"use client";

import { useMemo, useState } from "react";
import { useCotacoesAdmin } from "@/hooks/useCotacoesAdmin";
import CotacoesForm from "./CotacoesForm";
import CotacoesTable from "./CotacoesTable";

export default function CotacoesSection(props: {
  apiBase: string;
  authOptions: RequestInit;
  onUnauthorized: () => void;
}) {
  const { apiBase, authOptions, onUnauthorized } = props;

  const cot = useCotacoesAdmin({ apiBase, authOptions, onUnauthorized });
  const [syncingAll, setSyncingAll] = useState(false);

  const handleReload = useMemo(
    () => async () => Promise.resolve(cot.load()),
    [cot.load],
  );

  const handleSyncAll = useMemo(() => {
    return async () => {
      if (syncingAll) return;
      setSyncingAll(true);
      try {
        await Promise.resolve(cot.syncAll());
      } finally {
        setSyncingAll(false);
      }
    };
  }, [syncingAll, cot.syncAll]);

  return (
    <div className="space-y-5">
      <CotacoesForm
        allowedSlugs={cot.allowedSlugs}
        mode={cot.mode}
        editing={cot.editing}
        form={cot.form}
        setForm={cot.setForm}
        saving={cot.saving}
        onSubmit={cot.submit}
        onCancelEdit={cot.cancelEdit}
        onStartCreate={cot.startCreate}
      />

      <CotacoesTable
        rows={cot.sorted}
        loading={cot.loading}
        errorMsg={cot.errorMsg}
        onReload={handleReload}
        onSyncAll={handleSyncAll}
        syncingAll={syncingAll}
        onEdit={cot.startEdit}
        onDelete={cot.remove}
        deletingId={cot.deletingId}
        onSync={cot.sync}
        syncingId={cot.syncingId}
      />
    </div>
  );
}

"use client";

import { useMemo, useState } from "react";
import type { CotacaoItem } from "@/types/kavita-news";
import { formatDateTimeBR, fmtNum } from "@/utils/kavita-news/cotacoes";

type Props = {
  rows: CotacaoItem[];
  loading: boolean;
  errorMsg: string | null;

  onReload: () => void | Promise<void>;
  onSyncAll?: () => void | Promise<void>;
  syncingAll?: boolean;

  onEdit: (item: CotacaoItem) => void;
  onDelete: (id: number) => void;

  onSync?: (id: number) => void;

  deletingId: number | null;
  syncingId?: number | null;
};

function badgeClass(kind: "ok" | "error" | "neutral") {
  if (kind === "ok") return "bg-emerald-50 text-emerald-700 border-emerald-200";
  if (kind === "error") return "bg-rose-50 text-rose-700 border-rose-200";
  return "bg-slate-50 text-slate-600 border-slate-200";
}

function dotClass(kind: "ok" | "error" | "neutral") {
  if (kind === "ok") return "bg-emerald-500";
  if (kind === "error") return "bg-rose-500";
  return "bg-slate-400";
}

function syncKind(r: any): "ok" | "error" | "neutral" {
  if (r?.last_sync_status === "ok") return "ok";
  if (r?.last_sync_status === "error") return "error";
  return "neutral";
}

function syncLabel(r: any) {
  const k = syncKind(r);
  if (k === "ok") return "OK";
  if (k === "error") return "Erro";
  return "—";
}

export default function CotacoesTable({
  rows,
  loading,
  errorMsg,
  onReload,
  onSyncAll,
  syncingAll = false,
  onEdit,
  onDelete,
  onSync,
  deletingId,
  syncingId,
}: Props) {
  const [q, setQ] = useState("");
  const [onlyActive, setOnlyActive] = useState(false);
  const [onlyErrors, setOnlyErrors] = useState(false);

  const handleSyncAll = async () => {
    if (onSyncAll) return Promise.resolve(onSyncAll());
    return Promise.resolve(onReload());
  };

  const filtered = useMemo(() => {
    const query = q.trim().toLowerCase();

    return (rows || []).filter((r: any) => {
      const ativo = Number(r.ativo ?? 1) === 1;
      const isErr = r?.last_sync_status === "error";

      if (onlyActive && !ativo) return false;
      if (onlyErrors && !isErr) return false;

      if (!query) return true;

      const hay =
        `${r?.name ?? ""} ${r?.slug ?? ""} ${r?.type ?? ""} ${r?.source ?? ""}`.toLowerCase();

      return hay.includes(query);
    });
  }, [rows, q, onlyActive, onlyErrors]);

  return (
    <section className="rounded-2xl border border-slate-200 bg-white shadow-[0_8px_30px_rgba(15,23,42,0.08)] overflow-hidden">
      <header className="px-5 py-4 border-b bg-gradient-to-r from-slate-50 to-white">
        <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
          <div>
            <h4 className="text-base font-semibold text-slate-900">
              Cotações cadastradas
            </h4>
            <p className="text-sm text-slate-500">
              Total:{" "}
              <span className="font-semibold text-slate-800">
                {filtered.length}
              </span>{" "}
              <span className="text-slate-400">/ {rows.length}</span>
            </p>
          </div>

          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-end">
            <div className="flex items-center gap-2">
              <input
                value={q}
                onChange={(e) => setQ(e.target.value)}
                placeholder="Buscar por nome, slug, tipo, fonte..."
                className="w-full sm:w-[340px] rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 placeholder:text-slate-400 shadow-sm focus:outline-none focus:ring-2 focus:ring-[#EC5B20] focus:border-transparent"
              />

              <button
                type="button"
                onClick={() => setQ("")}
                className="rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50 transition"
                title="Limpar busca"
              >
                Limpar
              </button>
            </div>

            <div className="flex flex-wrap items-center gap-2">
              <label className="inline-flex items-center gap-2 rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-700 shadow-sm">
                <input
                  type="checkbox"
                  checked={onlyActive}
                  onChange={(e) => setOnlyActive(e.target.checked)}
                  className="h-4 w-4 accent-[#EC5B20]"
                />
                Somente ativos
              </label>

              <label className="inline-flex items-center gap-2 rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-700 shadow-sm">
                <input
                  type="checkbox"
                  checked={onlyErrors}
                  onChange={(e) => setOnlyErrors(e.target.checked)}
                  className="h-4 w-4 accent-[#EC5B20]"
                />
                Somente com erro
              </label>

              <button
                type="button"
                onClick={handleSyncAll}
                disabled={syncingAll || rows.length === 0}
                className="px-4 py-2 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 hover:bg-slate-50 transition disabled:opacity-60"
                title="Sincroniza todas as cotações ativas de uma vez"
              >
                {syncingAll ? "Atualizando..." : "Atualizar"}
              </button>
            </div>
          </div>
        </div>

        {errorMsg ? (
          <div className="mt-3 rounded-xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-700">
            {errorMsg}
          </div>
        ) : null}
      </header>

      {/* MOBILE: cards */}
      <div className="md:hidden p-4 space-y-3">
        {loading && filtered.length === 0 ? (
          <div className="text-sm text-slate-500">Carregando...</div>
        ) : filtered.length === 0 ? (
          <div className="text-sm text-slate-500">
            Nenhuma cotação encontrada.
          </div>
        ) : (
          filtered.map((r: any) => {
            const ativo = Number(r.ativo ?? 1) === 1;
            const isSyncing = syncingId === r.id;
            const disabledRowActions = syncingAll;
            const sk = syncKind(r);

            return (
              <div
                key={r.id}
                className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm"
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0">
                    <p className="font-semibold text-slate-900 truncate">
                      {r.name}
                    </p>
                    <p className="text-xs text-slate-500">
                      {r.type} • {r.slug}
                    </p>
                    <p
                      className="mt-1 text-xs text-slate-500 truncate"
                      title={r.source || ""}
                    >
                      Fonte:{" "}
                      <span className="font-medium text-slate-700">
                        {r.source ?? "—"}
                      </span>
                    </p>
                  </div>

                  <div className="flex flex-col items-end gap-2">
                    <span
                      className={`inline-flex items-center gap-2 rounded-full px-3 py-1 text-xs font-semibold border ${
                        ativo
                          ? "bg-emerald-50 text-emerald-700 border-emerald-200"
                          : "bg-slate-50 text-slate-600 border-slate-200"
                      }`}
                    >
                      <span
                        className={`h-2 w-2 rounded-full ${ativo ? "bg-emerald-500" : "bg-slate-400"}`}
                      />
                      {ativo ? "Ativo" : "Inativo"}
                    </span>

                    <span
                      title={
                        r.last_sync_status === "error"
                          ? r.last_sync_message || "Erro ao sincronizar"
                          : "Status do Sync"
                      }
                      className={`inline-flex items-center gap-2 rounded-full px-3 py-1 text-xs font-semibold border ${badgeClass(
                        sk,
                      )}`}
                    >
                      <span
                        className={`h-2 w-2 rounded-full ${dotClass(sk)}`}
                      />
                      Sync: {syncLabel(r)}
                    </span>
                  </div>
                </div>

                <div className="mt-3 grid grid-cols-2 gap-2 text-xs">
                  <div className="rounded-xl bg-slate-50 p-2">
                    <p className="text-slate-500">Preço</p>
                    <p className="font-medium text-slate-900">
                      {fmtNum(r.price, 4)} {r.unit ? `(${r.unit})` : ""}
                    </p>
                  </div>
                  <div className="rounded-xl bg-slate-50 p-2">
                    <p className="text-slate-500">Variação</p>
                    <p className="font-medium text-slate-900">
                      {fmtNum(r.variation_day, 4)}
                    </p>
                  </div>
                  <div className="rounded-xl bg-slate-50 p-2 col-span-2">
                    <p className="text-slate-500">Atualizado</p>
                    <p className="font-medium text-slate-900">
                      {formatDateTimeBR(r.last_update_at ?? null)}
                    </p>
                  </div>
                </div>

                <div className="mt-3 flex flex-col gap-2">
                  {onSync ? (
                    <button
                      type="button"
                      onClick={() => onSync(r.id)}
                      disabled={disabledRowActions || isSyncing || !ativo}
                      className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 hover:bg-slate-50 transition disabled:opacity-60"
                      title={!ativo ? "Cotação inativa" : "Sincronizar agora"}
                    >
                      {isSyncing ? "Sincronizando..." : "Sync"}
                    </button>
                  ) : null}

                  <div className="grid grid-cols-2 gap-2">
                    <button
                      type="button"
                      onClick={() => onEdit(r)}
                      disabled={disabledRowActions}
                      className="px-3 py-2 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 hover:bg-slate-50 transition disabled:opacity-60"
                    >
                      Editar
                    </button>

                    <button
                      type="button"
                      onClick={() => onDelete(r.id)}
                      disabled={disabledRowActions || deletingId === r.id}
                      className="px-3 py-2 rounded-xl border border-rose-200 bg-white text-sm font-medium text-rose-700 hover:bg-rose-50 transition disabled:opacity-60"
                    >
                      {deletingId === r.id ? "Excluindo..." : "Excluir"}
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* DESKTOP: tabela */}
      <div className="hidden md:block overflow-auto">
        <table className="min-w-[1240px] w-full text-sm">
          <thead className="bg-white sticky top-0 z-10">
            <tr className="text-left border-b">
              <th className="px-5 py-3 font-semibold text-slate-700">Nome</th>
              <th className="px-5 py-3 font-semibold text-slate-700">Tipo</th>
              <th className="px-5 py-3 font-semibold text-slate-700">Slug</th>
              <th className="px-5 py-3 font-semibold text-slate-700">Preço</th>
              <th className="px-5 py-3 font-semibold text-slate-700">
                Unidade
              </th>
              <th className="px-5 py-3 font-semibold text-slate-700">
                Variação
              </th>
              <th className="px-5 py-3 font-semibold text-slate-700">Fonte</th>
              <th className="px-5 py-3 font-semibold text-slate-700">
                Atualizado
              </th>
              <th className="px-5 py-3 font-semibold text-slate-700">Sync</th>
              <th className="px-5 py-3 font-semibold text-slate-700 text-right">
                Ações
              </th>
            </tr>
          </thead>

          <tbody className="divide-y divide-slate-100">
            {loading && filtered.length === 0 ? (
              <tr>
                <td className="px-5 py-6 text-slate-500" colSpan={10}>
                  Carregando...
                </td>
              </tr>
            ) : filtered.length === 0 ? (
              <tr>
                <td className="px-5 py-6 text-slate-500" colSpan={10}>
                  Nenhuma cotação encontrada.
                </td>
              </tr>
            ) : (
              filtered.map((r: any) => {
                const ativo = Number(r.ativo ?? 1) === 1;
                const isSyncing = syncingId === r.id;
                const disabledRowActions = syncingAll;
                const sk = syncKind(r);

                const syncTitle =
                  r.last_sync_status === "error"
                    ? r.last_sync_message || "Erro ao sincronizar"
                    : r.last_sync_status === "ok"
                      ? "Sincronizado com sucesso"
                      : "Sem sincronização recente";

                return (
                  <tr key={r.id} className="hover:bg-slate-50/70 transition">
                    <td className="px-5 py-3 font-semibold text-slate-900">
                      {r.name}
                    </td>
                    <td className="px-5 py-3 text-slate-700">{r.type}</td>
                    <td className="px-5 py-3 text-slate-700">{r.slug}</td>
                    <td className="px-5 py-3 text-slate-700">
                      {fmtNum(r.price, 4)}
                    </td>
                    <td className="px-5 py-3 text-slate-700">
                      {r.unit ?? "—"}
                    </td>
                    <td className="px-5 py-3 text-slate-700">
                      {fmtNum(r.variation_day, 4)}
                    </td>
                    <td
                      className="px-5 py-3 text-slate-700"
                      title={r.source || ""}
                    >
                      {r.source ?? "—"}
                    </td>
                    <td className="px-5 py-3 text-slate-700">
                      {formatDateTimeBR(r.last_update_at ?? null)}
                    </td>

                    <td className="px-5 py-3">
                      <span
                        title={syncTitle}
                        className={`inline-flex items-center gap-2 rounded-full px-3 py-1 text-xs font-semibold border ${badgeClass(
                          sk,
                        )}`}
                      >
                        <span
                          className={`h-2 w-2 rounded-full ${dotClass(sk)}`}
                        />
                        {syncLabel(r)}
                      </span>
                    </td>

                    <td className="px-5 py-3">
                      <div className="flex justify-end gap-2">
                        {onSync ? (
                          <button
                            type="button"
                            onClick={() => onSync(r.id)}
                            disabled={disabledRowActions || isSyncing || !ativo}
                            className="px-3 py-2 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 hover:bg-slate-50 transition disabled:opacity-60"
                            title={
                              !ativo ? "Cotação inativa" : "Sincronizar agora"
                            }
                          >
                            {isSyncing ? "Sincronizando..." : "Sync"}
                          </button>
                        ) : null}

                        <button
                          type="button"
                          onClick={() => onEdit(r)}
                          disabled={disabledRowActions}
                          className="px-3 py-2 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 hover:bg-slate-50 transition disabled:opacity-60"
                        >
                          Editar
                        </button>

                        <button
                          type="button"
                          onClick={() => onDelete(r.id)}
                          disabled={disabledRowActions || deletingId === r.id}
                          className="px-3 py-2 rounded-xl border border-rose-200 bg-white text-sm font-medium text-rose-700 hover:bg-rose-50 transition disabled:opacity-60"
                        >
                          {deletingId === r.id ? "Excluindo..." : "Excluir"}
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </section>
  );
}

"use client";

import React, { useEffect, useMemo, useRef, useState } from "react";
import type {
  NewsPostDetail,
  NewsPostStatus,
  NewsPostUpsertInput,
} from "@/types/kavita-news";
import { uploadNewsCover } from "@/utils/kavita-news/posts";

type CoverMode = "url" | "upload";

type Props = {
  open: boolean;
  mode: "create" | "edit";
  initial?: NewsPostDetail | null;

  onClose: () => void;
  onSubmit: (payload: NewsPostUpsertInput) => Promise<void>;

  isSaving?: boolean;
};

function slugify(input: string) {
  return (input || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9\s-]/g, "")
    .trim()
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-");
}

export default function PostForm({
  open,
  mode,
  initial,
  onClose,
  onSubmit,
  isSaving,
}: Props) {
  const isEdit = mode === "edit";

  const [title, setTitle] = useState("");
  const [slug, setSlug] = useState("");
  const [manualSlug, setManualSlug] = useState(false);
  const [status, setStatus] = useState<NewsPostStatus>("draft");
  const [category, setCategory] = useState("");
  const [tagsCsv, setTagsCsv] = useState("");
  const [coverUrl, setCoverUrl] = useState("");
  const [excerpt, setExcerpt] = useState("");
  const [content, setContent] = useState("");

  // Capa: URL ou Upload
  const [coverMode, setCoverMode] = useState<CoverMode>("url");
  const [coverFileName, setCoverFileName] = useState<string>("");
  const [coverPreview, setCoverPreview] = useState<string>("");

  // Ajuste visual da imagem (cover/contain)
  const [coverFit, setCoverFit] = useState<"cover" | "contain">("cover");

  // Erro amigável no modal (para não estourar "Unhandled Runtime Error")
  const [formError, setFormError] = useState<string>("");

  // estado simples de upload (evita “salvar” antes do upload terminar)
  const [coverUploading, setCoverUploading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement | null>(null);

  const inputBase =
    "w-full rounded-lg border bg-white px-3 py-2 text-sm text-gray-900 placeholder:text-gray-400 outline-none " +
    "focus:ring-2 focus:ring-emerald-200 disabled:bg-gray-50 disabled:text-gray-700";

  const textareaBase =
    "w-full rounded-lg border bg-white px-3 py-2 text-sm text-gray-900 placeholder:text-gray-400 outline-none " +
    "focus:ring-2 focus:ring-emerald-200";

  useEffect(() => {
    if (!open) return;

    setFormError("");

    if (!isEdit) {
      setTitle("");
      setSlug("");
      setManualSlug(false);
      setStatus("draft");
      setCategory("");
      setTagsCsv("");
      setCoverUrl("");
      setExcerpt("");
      setContent("");

      setCoverMode("url");
      setCoverFileName("");
      setCoverPreview("");
      setCoverFit("cover");
      setCoverUploading(false);

      if (fileInputRef.current) fileInputRef.current.value = "";
      return;
    }

    const p = initial;

    setTitle(p?.title || "");
    setSlug(p?.slug || "");
    setManualSlug(true);
    setStatus((p?.status as NewsPostStatus) || "draft");
    setCategory(p?.category || "");
    setTagsCsv((p?.tags || [])?.join(", ") || "");
    setCoverUrl(p?.cover_url || "");
    setExcerpt(p?.excerpt || "");
    setContent(p?.content || "");

    setCoverMode("url");
    setCoverFileName("");
    setCoverPreview(p?.cover_url || "");
    setCoverFit("cover");
    setCoverUploading(false);

    if (fileInputRef.current) fileInputRef.current.value = "";
  }, [open, isEdit, initial]);

  useEffect(() => {
    if (!open) return;
    if (manualSlug) return;
    setSlug(slugify(title));
  }, [title, manualSlug, open]);

  useEffect(() => {
    if (!open) return;
    function onKeyDown(e: KeyboardEvent) {
      if (e.key === "Escape") onClose();
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [open, onClose]);

  const headerTitle = useMemo(
    () => (isEdit ? "Editar Post" : "Novo Post"),
    [isEdit],
  );

  function clearCover() {
    setFormError("");
    setCoverUrl("");
    setCoverPreview("");
    setCoverFileName("");
    setCoverUploading(false);
    if (fileInputRef.current) fileInputRef.current.value = "";
  }

  async function onPickCoverFile(file: File | null) {
    setFormError("");
    if (!file) return;

    // preview imediato (UX)
    const reader = new FileReader();
    reader.onload = () => {
      if (!reader.result) return;

      const base64 = String(reader.result);

      setCoverMode("upload");
      setCoverFileName(file.name);
      setCoverPreview(base64);
      // IMPORTANTE: não salva base64 no coverUrl (DB)
    };
    reader.readAsDataURL(file);

    // upload real
    try {
      setCoverUploading(true);
      const up = await uploadNewsCover(file);
      setCoverUrl(up.url); // ✅ URL real persistível no DB
    } catch (e: any) {
      setFormError(e?.message || "Erro ao enviar imagem.");
      // mantém preview, mas não força coverUrl inválida
      setCoverUrl("");
    } finally {
      setCoverUploading(false);
    }
  }

  async function handleSubmit(publishNow: boolean) {
    try {
      setFormError("");

      if (coverUploading) {
        throw new Error("Aguarde o upload da imagem terminar.");
      }

      // Segurança: varchar(500)
      if ((coverUrl ?? "").length > 500) {
        throw new Error("URL da capa muito grande (máx 500 caracteres).");
      }

      const payload: NewsPostUpsertInput = {
        title: (title ?? "").trim(),
        slug: (slug ?? "").trim(),
        status: publishNow ? "published" : status,
        category: (category ?? "").trim() || null,
        tags_csv: (tagsCsv ?? "").trim() || "",
        cover_url: (coverUrl ?? "").trim() || null,
        excerpt: (excerpt ?? "").trim() || null,
        content: (content ?? "").trim(),
        publish_now: publishNow,
      };

      if (!payload.title) throw new Error("Título é obrigatório.");
      if (!payload.slug) throw new Error("Slug é obrigatório.");

      await onSubmit(payload);
    } catch (err: any) {
      setFormError(err?.message || "Erro ao salvar.");
    }
  }

  if (!open) return null;

  const previewSrc = (coverPreview || coverUrl) ?? "";
  const showPreview = !!previewSrc;

  return (
    <div className="fixed inset-0 z-50">
      <button
        className="absolute inset-0 bg-black/50"
        onClick={onClose}
        aria-label="Fechar"
      />

      <div className="absolute inset-x-0 bottom-0 mx-auto w-full max-w-4xl rounded-t-2xl bg-white shadow-2xl sm:inset-y-10 sm:bottom-auto sm:rounded-2xl">
        <div className="flex items-center justify-between gap-3 border-b px-4 py-3 sm:px-6">
          <div>
            <div className="text-base font-semibold text-gray-900">
              {headerTitle}
            </div>
            <div className="text-xs text-gray-500">Kavita News • Admin</div>
          </div>

          <button
            type="button"
            onClick={onClose}
            className="rounded-lg border border-gray-200 bg-white px-3 py-1.5 text-sm font-semibold text-gray-900 hover:bg-gray-50"
          >
            Fechar
          </button>
        </div>

        <div className="max-h-[80vh] overflow-y-auto px-4 py-4 sm:max-h-[70vh] sm:px-6">
          {formError && (
            <div className="mb-4 rounded-xl border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">
              {formError}
            </div>
          )}

          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <div>
              <label className="text-xs font-semibold text-gray-700">
                Título
              </label>
              <input
                value={title ?? ""}
                onChange={(e) => setTitle(e.target.value)}
                className={inputBase}
                placeholder="Ex: Café sobe com clima seco"
              />
            </div>

            <div>
              <div className="flex items-center justify-between">
                <label className="text-xs font-semibold text-gray-700">
                  Slug
                </label>
                <label className="flex items-center gap-2 text-xs text-gray-600">
                  <input
                    type="checkbox"
                    checked={manualSlug}
                    onChange={(e) => setManualSlug(e.target.checked)}
                  />
                  Editar manualmente
                </label>
              </div>
              <input
                value={slug ?? ""}
                onChange={(e) => setSlug(e.target.value)}
                className={inputBase}
                placeholder="cafe-sobe-com-clima-seco"
                disabled={!manualSlug}
              />
            </div>

            <div>
              <label className="text-xs font-semibold text-gray-700">
                Status
              </label>
              <select
                value={status ?? "draft"}
                onChange={(e) => setStatus(e.target.value as NewsPostStatus)}
                className={inputBase}
              >
                <option value="draft">Rascunho</option>
                <option value="published">Publicado</option>
                <option value="archived">Arquivado</option>
              </select>
            </div>

            <div>
              <label className="text-xs font-semibold text-gray-700">
                Categoria
              </label>
              <input
                value={category ?? ""}
                onChange={(e) => setCategory(e.target.value)}
                className={inputBase}
                placeholder="Ex: café"
              />
            </div>

            <div className="sm:col-span-2">
              <label className="text-xs font-semibold text-gray-700">
                Tags (CSV)
              </label>
              <input
                value={tagsCsv ?? ""}
                onChange={(e) => setTagsCsv(e.target.value)}
                className={inputBase}
                placeholder="cafe, clima, mercado"
              />
            </div>

            <div className="sm:col-span-2">
              <div className="flex items-center justify-between gap-2">
                <label className="text-xs font-semibold text-gray-700">
                  Capa
                </label>

                <div className="flex items-center gap-2">
                  <button
                    type="button"
                    onClick={() => {
                      setCoverMode("url");
                      setFormError("");
                    }}
                    className={`rounded-lg border px-3 py-1.5 text-xs font-semibold ${
                      coverMode === "url"
                        ? "border-gray-900 bg-gray-900 text-white"
                        : "border-gray-200 bg-white text-gray-900 hover:bg-gray-50"
                    }`}
                  >
                    URL
                  </button>
                  <button
                    type="button"
                    onClick={() => {
                      setCoverMode("upload");
                      setFormError("");
                    }}
                    className={`rounded-lg border px-3 py-1.5 text-xs font-semibold ${
                      coverMode === "upload"
                        ? "border-gray-900 bg-gray-900 text-white"
                        : "border-gray-200 bg-white text-gray-900 hover:bg-gray-50"
                    }`}
                  >
                    Upload
                  </button>
                </div>
              </div>

              {coverMode === "url" ? (
                <div className="mt-2 flex flex-col gap-2 sm:flex-row sm:items-center">
                  <input
                    value={coverUrl ?? ""}
                    onChange={(e) => {
                      setFormError("");
                      setCoverUrl(e.target.value);
                      setCoverPreview(e.target.value);
                    }}
                    className={inputBase}
                    placeholder="https://..."
                  />
                  <button
                    type="button"
                    onClick={clearCover}
                    className="rounded-lg border border-gray-200 bg-white px-3 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-50"
                  >
                    Limpar
                  </button>
                </div>
              ) : (
                <div className="mt-2 flex flex-col gap-2 sm:flex-row sm:items-center">
                  <input
                    key={coverMode}
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={(e) =>
                      onPickCoverFile(e.target.files?.[0] || null)
                    }
                    className="w-full rounded-lg border border-gray-200 bg-white text-sm file:mr-3 file:rounded-lg file:border-0 file:bg-gray-100 file:px-3 file:py-2 file:text-sm file:font-semibold file:text-gray-900 hover:file:bg-gray-200"
                  />
                  <button
                    type="button"
                    onClick={() => fileInputRef.current?.click()}
                    className="rounded-lg bg-emerald-600 px-3 py-2 text-sm font-semibold text-white hover:bg-emerald-700 disabled:opacity-60"
                    disabled={coverUploading}
                  >
                    {coverUploading ? "Enviando..." : "Escolher imagem"}
                  </button>
                  <button
                    type="button"
                    onClick={clearCover}
                    className="rounded-lg border border-gray-200 bg-white px-3 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-50"
                    disabled={coverUploading}
                  >
                    Remover
                  </button>
                </div>
              )}

              {showPreview && (
                <div className="mt-3 overflow-hidden rounded-xl border bg-gray-50">
                  <div className="flex items-center justify-between gap-2 px-3 py-2 text-xs text-gray-600">
                    <span className="truncate">
                      {coverMode === "upload" && coverFileName
