"use client";

import React from "react";

export type ShippingRules = {
  shippingFree: boolean;
  shippingFreeFromQtyStr: string;

  // ✅ NOVO: prazo do produto (dias) — string para permitir "" (NULL) e input controlado
  shippingPrazoDiasStr: string;
};

type Props = {
  value: ShippingRules;
  onChange: (next: ShippingRules) => void;
};

function onlyDigits(v: string) {
  return (v || "").replace(/\D/g, "");
}

export default function ProductShippingSection({ value, onChange }: Props) {
  function patch(next: Partial<ShippingRules>) {
    onChange({ ...value, ...next });
  }

  const showDetails = value.shippingFree;

  return (
    <div className="rounded-2xl border border-gray-200 bg-white p-4 shadow-sm">
      <div>
        <h3 className="text-sm font-semibold text-gray-900">
          Frete do produto
        </h3>
        <p className="mt-0.5 text-[11px] text-gray-500">
          Configure regras simples de frete grátis por produto e o prazo
          específico deste item.
        </p>
      </div>

      {/* ✅ NOVO: Prazo do produto (dias) */}
      <div className="mt-4">
        <div className="flex flex-col gap-1.5">
          <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700">
            Prazo do produto (dias) — opcional
          </label>

          <input
            value={value.shippingPrazoDiasStr}
            onChange={(e) => {
              // Regras:
              // - só números
              // - "" => NULL no backend (usa zone.prazo_dias)
              // - "0" => trata como "" (para evitar prazo inválido)
              const digits = onlyDigits(e.target.value).slice(0, 4); // limite razoável (0-9999)
              const normalized = digits === "0" ? "" : digits;

              patch({ shippingPrazoDiasStr: normalized });
            }}
            placeholder="Ex.: 3"
            inputMode="numeric"
            className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 text-sm text-gray-900 outline-none focus:border-[#359293] focus:ring-2 focus:ring-[#359293]/20"
          />

          <span className="text-[11px] text-gray-500">
            Se vazio, o sistema usa o prazo da zona (UF/cidade). No checkout, o
            prazo final será o maior prazo entre os produtos do carrinho.
          </span>
        </div>
      </div>

      <div className="mt-4 flex items-center gap-2">
        <input
          id="shippingFree"
          type="checkbox"
          checked={value.shippingFree}
          onChange={(e) => {
            const nextChecked = e.target.checked;

            if (!nextChecked) {
              // Evita estado zumbi: desmarcou => zera qty e manda false
              onChange({
                ...value,
                shippingFree: false,
                shippingFreeFromQtyStr: "", // => NULL no backend
              });
              return;
            }

            // Marcou => mantém qty como está (ou vazio), mas garante boolean true
            patch({ shippingFree: true });
          }}
          className="h-4 w-4 rounded border-gray-300 text-[#359293] focus:ring-[#359293]"
        />
        <label
          htmlFor="shippingFree"
          className="text-sm font-medium text-gray-800"
        >
          Frete grátis (este produto)
        </label>
      </div>

      {showDetails && (
        <div className="mt-3">
          <div className="flex flex-col gap-1.5">
            <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700">
              Frete grátis a partir de (unidades) — opcional
            </label>

            <input
              value={value.shippingFreeFromQtyStr}
              onChange={(e) => {
                // Regras:
                // - só números
                // - "" => NULL no backend (sempre grátis)
                // - "0" => trata como "" (sempre grátis)
                const digits = onlyDigits(e.target.value).slice(0, 6); // limite razoável
                const normalized = digits === "0" ? "" : digits;

                patch({ shippingFreeFromQtyStr: normalized });
              }}
              placeholder="Ex.: 3"
              inputMode="numeric"
              className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 text-sm text-gray-900 outline-none focus:border-[#359293] focus:ring-2 focus:ring-[#359293]/20"
            />

            <span className="text-[11px] text-gray-500">
              Se vazio, o frete grátis vale para qualquer quantidade (sem
              limite).
            </span>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useMemo, useState } from "react";

export type Product = {
  id: number;
  name: string;
  description?: string | null;
  price: number | string;
  quantity: number | string;
  category_id?: number | null;
  image?: string | null; // capa vinda do banco (ex.: "/uploads/abc.jpg")
  images?: string[]; // urls adicionais (ex.: ["/uploads/1.jpg", ...])
};

type Props = {
  produto: Product;
  onEditar?: (p: Product) => void;
  onRemover?: (id: number) => Promise<void> | void;
  confirmText?: string;
  readOnly?: boolean;
  /** Permite controlar margens no grid/página (ex.: "mt-6") */
  className?: string;
};

const PLACEHOLDER = "/placeholder.png";
const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

/** Converte paths relativos ("/uploads/...") em URL absoluta do backend */
function absUrl(p?: string | null) {
  if (!p) return null;
  if (p.startsWith("http://") || p.startsWith("https://")) return p;
  return `${API_BASE}${p.startsWith("/") ? p : `/${p}`}`;
}

function toBRL(n: number) {
  try {
    return n.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
  } catch {
    return `R$ ${n.toFixed(2)}`;
  }
}

export default function ProdutoCard({
  produto,
  onEditar,
  onRemover,
  confirmText = "Tem certeza que deseja remover este produto?",
  readOnly = false,
  className = "",
}: Props) {
  const [removing, setRemoving] = useState(false);

  const price = useMemo(() => Number(produto.price) || 0, [produto.price]);
  const qty = useMemo(() => Number(produto.quantity) || 0, [produto.quantity]);

  // Monta lista de imagens (capa + extras) normalizando para URL absoluta e removendo duplicatas
  const images = useMemo(() => {
    const extras = Array.isArray(produto.images) ? produto.images : [];
    const all = [produto.image, ...extras].filter(Boolean) as string[];
    const unique = Array.from(new Set(all));
    return unique.map(absUrl).filter(Boolean) as string[]; // só strings válidas
  }, [produto.image, produto.images]);

  const cover = images[0] || PLACEHOLDER;

  async function handleRemove() {
    if (!onRemover || readOnly) return;
    if (!window.confirm(confirmText)) return;
    try {
      setRemoving(true);
      await onRemover(produto.id);
    } finally {
      setRemoving(false);
    }
  }

  return (
    <article
      className={`flex h-full flex-col overflow-hidden rounded-2xl bg-white/95 shadow-sm ring-1 ring-black/5 transition hover:-translate-y-0.5 hover:shadow-md ${className}`}
      aria-labelledby={`prod-${produto.id}-title`}
    >
      {/* Capa com ratio fixo */}
      <div className="relative w-full bg-gray-50 pb-[60%]">
        <img
          src={cover}
          alt={produto.name || "Imagem do produto"}
          className="absolute inset-0 h-full w-full object-cover"
          onError={(e) =>
            ((e.currentTarget as HTMLImageElement).src = PLACEHOLDER)
          }
          loading="lazy"
        />
        {qty <= 0 && (
          <span className="absolute left-2 top-2 rounded-full bg-red-600 px-2 py-0.5 text-xs font-semibold text-white">
            Sem estoque
          </span>
        )}
      </div>

      {/* Conteúdo */}
      <div className="flex flex-1 flex-col gap-2 p-4">
        <h3
          id={`prod-${produto.id}-title`}
          className="line-clamp-1 text-base font-semibold text-gray-900"
          title={produto.name}
        >
          {produto.name}
        </h3>

        {produto.description && (
          <p
            className="line-clamp-3 text-sm text-gray-600"
            title={produto.description || undefined}
          >
            {produto.description}
          </p>
        )}

        <div className="mt-1 flex items-center justify-between">
          <span className="text-sm font-semibold text-[#2F7E7F]">
            {toBRL(price)}
          </span>
          <span className="text-xs text-gray-500">Qtde: {qty}</span>
        </div>

        {/* Miniaturas (se houver) */}
        {images.length > 1 && (
          <div className="mt-2 flex gap-2 overflow-x-auto pb-1">
            {images.slice(1, 6).map((src, i) => (
              <img
                key={`${src}-${i}`}
                src={src}
                alt={`Miniatura ${i + 1}`}
                className="h-12 w-12 flex-shrink-0 rounded-lg bg-gray-50 object-cover ring-1 ring-black/10"
                onError={(e) =>
                  ((e.currentTarget as HTMLImageElement).src = PLACEHOLDER)
                }
                loading="lazy"
              />
            ))}
            {images.length > 6 && (
              <span className="self-center text-xs text-gray-500">
                +{images.length - 6}
              </span>
            )}
          </div>
        )}

        {/* Ações */}
        <div className="mt-3 flex flex-wrap items-center justify-end gap-2">
          <button
            type="button"
            onClick={() => onEditar?.(produto)}
            disabled={readOnly}
            className="rounded-full bg-gray-100 px-3 py-1.5 text-xs font-medium text-gray-800 transition hover:bg-gray-200 disabled:opacity-50"
          >
            Editar
          </button>
          <button
            type="button"
            onClick={handleRemove}
            disabled={readOnly || removing}
            className="rounded-full bg-red-600 px-3 py-1.5 text-xs font-semibold text-white transition hover:bg-red-700 disabled:opacity-50"
          >
            {removing ? "Removendo..." : "Remover"}
          </button>
        </div>
      </div>
    </article>
  );
}

"use client";

import React, { useEffect, useMemo, useRef, useState } from "react";
import ProductShippingSection from "./ProductShippingSection";

type Msg = { type: "success" | "error"; text: string };

type ProdutoEditado = {
  id: number;
  name: string;
  description?: string | null;
  price: number;
  quantity: number;
  category_id: number | string;
  image?: string | null;
  images?: string[];

  // frete por produto
  shipping_free?: number | boolean | null;
  shipping_free_from_qty?: number | null;

  // ✅ NOVO: prazo por produto (dias)
  shipping_prazo_dias?: number | null;
};

type Props = {
  API_BASE?: string; // ✅ deixa opcional para evitar "undefined" caso esqueça de passar
  produtoEditado?: ProdutoEditado | null;
  onProdutoAdicionado?: () => void;
  onLimparEdicao?: () => void;
};

function absUrl(API_BASE: string, p?: string | null) {
  if (!p) return null;
  if (p.startsWith("http://") || p.startsWith("https://")) return p;
  return `${API_BASE}${p.startsWith("/") ? "" : "/"}${p}`;
}

export default function ProdutoForm({
  API_BASE,
  produtoEditado,
  onProdutoAdicionado,
  onLimparEdicao,
}: Props) {
  // ✅ fallback seguro: se esquecer de passar API_BASE, não cai no Next (3000)
  const BASE =
    API_BASE || process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

  const isEditing = !!produtoEditado;

  const [msg, setMsg] = useState<Msg | null>(null);
  const [loading, setLoading] = useState(false);

  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [priceStr, setPriceStr] = useState("");
  const [quantityStr, setQuantityStr] = useState("");
  const [categoryId, setCategoryId] = useState<string | number>("");

  // imagens
  const [existingImgs, setExistingImgs] = useState<string[]>([]);
  const [removeExisting, setRemoveExisting] = useState<Set<string>>(new Set());
  const [newFiles, setNewFiles] = useState<File[]>([]);
  const [newPreviews, setNewPreviews] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement | null>(null);

  // frete por produto
  const [shippingFree, setShippingFree] = useState<boolean>(false);
  const [shippingFreeFromQtyStr, setShippingFreeFromQtyStr] =
    useState<string>("");

  // ✅ NOVO: prazo do produto (dias)
  const [shippingPrazoDiasStr, setShippingPrazoDiasStr] = useState<string>("");

  function toRel(abs: string) {
    if (!abs) return "";
    try {
      const u = new URL(abs);
      return u.pathname || "";
    } catch {
      return abs;
    }
  }

  useEffect(() => {
    if (produtoEditado) {
      setName(produtoEditado.name || "");
      setDescription(produtoEditado.description || "");
      setPriceStr(String(produtoEditado.price ?? ""));
      setQuantityStr(String(produtoEditado.quantity ?? ""));
      setCategoryId(produtoEditado.category_id || "");

      const extras = Array.isArray(produtoEditado.images)
        ? produtoEditado.images
        : [];
      const allRel = [produtoEditado.image, ...extras].filter(
        Boolean,
      ) as string[];
      const uniqueRel = Array.from(new Set(allRel));
      const urlsAbs = uniqueRel.map((p) => absUrl(BASE, p)!).filter(Boolean);

      setExistingImgs(urlsAbs);
      setRemoveExisting(new Set());
      setNewFiles([]);
      setNewPreviews([]);
      if (fileInputRef.current) fileInputRef.current.value = "";

      const freeBool =
        produtoEditado.shipping_free === true ||
        produtoEditado.shipping_free === 1 ||
        String(produtoEditado.shipping_free ?? "0") === "1";

      setShippingFree(freeBool);
      setShippingFreeFromQtyStr(
        produtoEditado.shipping_free_from_qty
          ? String(produtoEditado.shipping_free_from_qty)
          : "",
      );

      // ✅ NOVO: carrega prazo do produto (dias)
      setShippingPrazoDiasStr(
        produtoEditado.shipping_prazo_dias
          ? String(produtoEditado.shipping_prazo_dias)
          : "",
      );
    } else {
      resetForm();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [produtoEditado]);

  useEffect(() => {
    const urls = newFiles.map((f) => URL.createObjectURL(f));
    setNewPreviews(urls);
    return () => urls.forEach((u) => URL.revokeObjectURL(u));
  }, [newFiles]);

  function normalizeNumber(input: string): number {
    if (input == null) return 0;
    let s = String(input).trim();
    if (!s) return 0;
    s = s.replace(/[R$\s]/g, "");
    const lastComma = s.lastIndexOf(",");
    const lastDot = s.lastIndexOf(".");
    if (lastComma > -1 && lastDot > -1) {
      const decSep = lastComma > lastDot ? "," : ".";
      const thouSep = decSep === "," ? "." : ",";
      s = s.replace(new RegExp("\\" + thouSep, "g"), "");
      if (decSep === ",") s = s.replace(",", ".");
    } else if (lastComma > -1) {
      s = s.replace(/\./g, "").replace(",", ".");
    }
    const n = Number(s);
    return Number.isNaN(n) ? 0 : Number(n.toFixed(2));
  }

  const price = useMemo(() => normalizeNumber(priceStr), [priceStr]);
  const quantity = useMemo(
    () => Math.max(0, Math.floor(Number(quantityStr) || 0)),
    [quantityStr],
  );

  function resetForm() {
    setName("");
    setDescription("");
    setPriceStr("");
    setQuantityStr("");
    setCategoryId("");
    setExistingImgs([]);
    setRemoveExisting(new Set());
    setNewFiles([]);
    setNewPreviews([]);
    if (fileInputRef.current) fileInputRef.current.value = "";

    setShippingFree(false);
    setShippingFreeFromQtyStr("");

    // ✅ NOVO
    setShippingPrazoDiasStr("");
  }

  function validate(): string | null {
    if (!name.trim()) return "Informe o nome do produto.";
    if (!categoryId) return "Selecione uma categoria.";
    if (price <= 0) return "Informe um preço válido.";
    if (quantity < 0) return "A quantidade não pode ser negativa.";

    if (shippingFree && shippingFreeFromQtyStr.trim()) {
      const n = Number(shippingFreeFromQtyStr);
      if (!Number.isFinite(n) || n <= 0) {
        return "Frete grátis por quantidade: informe um número válido (ex: 10).";
      }
    }

    // ✅ NOVO: prazo do produto (dias) opcional, mas se preenchido deve ser inteiro > 0
    if (shippingPrazoDiasStr.trim()) {
      const n = Number(shippingPrazoDiasStr);
      if (!Number.isFinite(n) || n <= 0 || !Number.isInteger(n)) {
        return "Prazo do produto (dias): informe um número inteiro válido (ex: 3).";
      }
    }

    return null;
  }

  function onPickFiles(e: React.ChangeEvent<HTMLInputElement>) {
    const files = Array.from(e.target.files || []);
    if (!files.length) return;

    setNewFiles((prev) => {
      const next = [...prev, ...files];
      return next.slice(0, 8);
    });
  }

  function removeNewImage(index: number) {
    setNewFiles((prev) => prev.filter((_, i) => i !== index));
  }

  function toggleRemoveExisting(urlAbs: string) {
    setRemoveExisting((prev) => {
      const next = new Set(prev);
      const rel = toRel(urlAbs);
      if (next.has(rel)) next.delete(rel);
      else next.add(rel);
      return next;
    });
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setMsg(null);

    const err = validate();
    if (err) {
      setMsg({ type: "error", text: err });
      return;
    }

    const fd = new FormData();
    fd.append("name", name.trim());
    fd.append("description", (description || "").trim());
    fd.append("price", String(price));
    fd.append("quantity", String(quantity));
    fd.append("category_id", String(categoryId));

    // frete por produto (sempre enviar)
    fd.append("shippingFree", shippingFree ? "1" : "0");
    fd.append("shippingFreeFromQtyStr", shippingFreeFromQtyStr.trim());

    // ✅ NOVO: prazo do produto (dias) — sempre enviar; "" => NULL no backend
    fd.append("shippingPrazoDiasStr", shippingPrazoDiasStr.trim());

    newFiles.forEach((file) => fd.append("images", file));

    if (isEditing) {
      const kept = existingImgs
        .map((abs) => toRel(abs))
        .filter((rel) => rel && !removeExisting.has(rel));
      fd.append("keepImages", JSON.stringify(kept));
    }

    const method = isEditing ? "PUT" : "POST";
    const url = isEditing
      ? `${BASE}/api/admin/produtos/${produtoEditado!.id}`
      : `${BASE}/api/admin/produtos`;

    setLoading(true);
    try {
      const res = await fetch(url, {
        method,
        body: fd,
        credentials: "include",
      });

      if (!res.ok) {
        if (res.status === 401 || res.status === 403) {
          const txt = await safeText(res);
          throw new Error(
            txt ||
              "Você não tem permissão para salvar este produto. Faça login novamente.",
          );
        }

        const txt = await safeText(res);
        throw new Error(
          `Falha ao ${isEditing ? "atualizar" : "salvar"} (${res.status}). ${txt || ""}`,
        );
      }

      setMsg({
        type: "success",
        text: isEditing
          ? "Produto atualizado com sucesso."
          : "Produto salvo com sucesso.",
      });

      resetForm();
      onProdutoAdicionado?.();
      onLimparEdicao?.();
    } catch (e: any) {
      setMsg({ type: "error", text: e?.message || "Erro ao salvar produto." });
    } finally {
      setLoading(false);
    }
  }

  async function safeText(res: Response) {
    try {
      const ct = res.headers.get("content-type") || "";
      if (ct.includes("application/json")) {
        const j = await res.json();
        return (j as any)?.message || JSON.stringify(j);
      }
      return await res.text();
    } catch {
      return "";
    }
  }

  return (
    <form
      onSubmit={handleSubmit}
      className="flex w-full flex-col gap-5 rounded-2xl bg-white p-4 shadow-sm sm:p-6 md:p-8"
    >
      <div className="flex flex-col gap-3 border-b border-gray-100 pb-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h2 className="text-base font-semibold text-[#359293] sm:text-lg">
            {isEditing ? "Editar Produto" : "Adicionar Produto"}
          </h2>
          <p className="mt-1 text-xs text-gray-500 sm:text-sm">
            Preencha os dados abaixo para manter o catálogo sempre atualizado.
          </p>
        </div>

        {isEditing && (
          <button
            type="button"
            onClick={() => {
              resetForm();
              onLimparEdicao?.();
            }}
            className="self-start rounded-full border border-gray-300 px-3 py-1.5 text-xs font-medium text-gray-700 transition hover:bg-gray-50 sm:self-auto"
          >
            Cancelar edição
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 gap-5 md:grid-cols-2">
        <div className="flex flex-col gap-4">
          <div className="flex flex-col gap-1.5">
            <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700 sm:text-xs">
              Nome do produto
            </label>
            <input
              className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm outline-none focus:border-[#359293]"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Ex.: Ração Premium 10kg"
            />
          </div>

          <div className="flex flex-col gap-1.5">
            <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700 sm:text-xs">
              Categoria
            </label>
            <select
              className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm outline-none focus:border-[#359293]"
              value={String(categoryId)}
              onChange={(e) => setCategoryId(e.target.value)}
            >
              <option value="">Selecione...</option>
            </select>
          </div>

          <div className="flex flex-col gap-1.5">
            <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700 sm:text-xs">
              Descrição
            </label>
            <textarea
              className="min-h-[120px] w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm outline-none focus:border-[#359293]"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Detalhes do produto, recomendações de uso, etc."
            />
          </div>
        </div>

        <div className="flex flex-col gap-4">
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <div className="flex flex-col gap-1.5">
              <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700 sm:text-xs">
                Preço
              </label>
              <input
                className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm outline-none focus:border-[#359293]"
                value={priceStr}
                onChange={(e) => setPriceStr(e.target.value)}
                placeholder="Ex.: 200,00"
              />
            </div>

            <div className="flex flex-col gap-1.5">
              <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700 sm:text-xs">
                Quantidade em estoque
              </label>
              <input
                className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm outline-none focus:border-[#359293]"
                value={quantityStr}
                onChange={(e) => setQuantityStr(e.target.value)}
                placeholder="Ex.: 10"
              />
            </div>
          </div>

          <div className="flex flex-col gap-2">
            <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700 sm:text-xs">
              Imagens do produto (opcional)
            </label>

            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              multiple
              onChange={onPickFiles}
            />

            {!!newPreviews.length && (
              <div className="flex flex-wrap gap-2">
                {newPreviews.map((src, i) => (
                  <div key={src} className="relative">
                    <img
                      src={src}
                      alt={`Nova imagem ${i + 1}`}
                      className="h-16 w-16 rounded-lg object-cover ring-1 ring-black/10"
                    />
                    <button
                      type="button"
                      className="absolute -right-2 -top-2 rounded-full bg-black/70 px-2 py-0.5 text-xs text-white"
                      onClick={() => removeNewImage(i)}
                    >
                      x
                    </button>
                  </div>
                ))}
              </div>
            )}

            {!!existingImgs.length && (
              <div className="flex flex-wrap gap-2">
                {existingImgs.map((abs) => {
                  const rel = toRel(abs);
                  const willRemove = removeExisting.has(rel);
                  return (
                    <button
                      key={abs}
                      type="button"
                      onClick={() => toggleRemoveExisting(abs)}
                      className={`relative rounded-lg ring-1 ring-black/10 transition ${
                        willRemove ? "opacity-40" : "opacity-100"
                      }`}
                      title={willRemove ? "Remover" : "Manter"}
                    >
                      <img
                        src={abs}
                        alt="Imagem existente"
                        className="h-16 w-16 rounded-lg object-cover"
                      />
                      {willRemove && (
                        <span className="absolute inset-0 flex items-center justify-center text-xs font-semibold text-red-600">
                          Remover
                        </span>
                      )}
                    </button>
                  );
                })}
              </div>
            )}
          </div>

          <ProductShippingSection
            value={{
              shippingFree,
              shippingFreeFromQtyStr,
              shippingPrazoDiasStr,
            }}
            onChange={(next) => {
              setShippingFree(!!next.shippingFree);
              setShippingFreeFromQtyStr(next.shippingFreeFromQtyStr ?? "");
              setShippingPrazoDiasStr(next.shippingPrazoDiasStr ?? "");
            }}
          />
        </div>
      </div>

      {msg && (
        <div
          className={`rounded-lg px-3 py-2 text-sm ${
            msg.type === "success"
              ? "bg-emerald-50 text-emerald-700"
              : "bg-rose-50 text-rose-700"
          }`}
        >
          {msg.text}
        </div>
      )}

      <div className="flex items-center justify-end gap-3">
        <button
          type="button"
          onClick={resetForm}
          className="rounded-full border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50"
          disabled={loading}
        >
          Limpar
        </button>

        <button
          type="submit"
          className="rounded-full bg-[#2F7E7F] px-5 py-2 text-sm font-semibold text-white hover:opacity-95 disabled:opacity-60"
          disabled={loading}
        >
          {loading
            ? "Salvando..."
            : isEditing
              ? "Salvar alterações"
              : "Adicionar Produto"}
        </button>
      </div>
    </form>
  );
}

"use client";

import React, { useEffect, useMemo, useState } from "react";
import { Service } from "@/types/service";

type Props = {
  servico?: Service | null;
  onEditar?: (p: Service) => void;
  onRemover?: (id: number) => Promise<void> | void;

  /** ✅ NOVO: permite verificar/desverificar (sem quebrar quem não usa) */
  onToggleVerificado?: (id: number, novoValor: boolean) => Promise<void> | void;

  confirmText?: string;
  readOnly?: boolean;
  className?: string;
};

const PLACEHOLDER = "/placeholder.png";
const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

/** 🔗 Gera URL absoluta para imagem (caso backend envie caminho relativo) */
function absUrl(p?: string | null) {
  if (!p) return null;
  const v = String(p).trim();
  if (!v) return null;
  if (v.startsWith("http://") || v.startsWith("https://")) return v;
  return `${API_BASE}${v.startsWith("/") ? v : `/${v}`}`;
}

/** 📱 Formata telefone BR para exibição */
function formatWhatsApp(raw: string) {
  const digits = raw.replace(/\D/g, "");
  if (digits.length === 11)
    return `(${digits.slice(0, 2)}) ${digits.slice(2, 7)}-${digits.slice(7)}`;
  if (digits.length === 10)
    return `(${digits.slice(0, 2)}) ${digits.slice(2, 6)}-${digits.slice(6)}`;
  return digits || raw;
}

/** ✅ Normaliza "verificado" vindo do backend (boolean/number/string/etc) */
function normalizeVerificado(v: unknown): boolean {
  return v === true || v === 1 || v === "1" || v === "true";
}

/** ✅ Extrai imagens válidas (string[]) de qualquer formato */
function normalizeImages(v: unknown): string[] {
  if (!Array.isArray(v)) return [];
  return v.filter(
    (x): x is string => typeof x === "string" && x.trim().length > 0,
  );
}

export default function ServiceCard({
  servico,
  onEditar,
  onRemover,
  onToggleVerificado,
  confirmText = "Tem certeza que deseja remover este serviço?",
  readOnly = false,
  className = "",
}: Props) {
  // ✅ Hooks SEMPRE no topo (não pode ter return antes)
  const [removing, setRemoving] = useState(false);
  const [toggling, setToggling] = useState(false);

  // ✅ Cria lista de imagens (capa + extras) sem duplicadas
  const images = useMemo(() => {
    if (!servico) return [];

    const extras = normalizeImages(
      (servico as unknown as { images?: unknown }).images,
    );
    const capa = typeof servico.imagem === "string" ? servico.imagem : "";

    const all = [capa, ...extras].filter(Boolean) as string[];
    const unique = Array.from(new Set(all));
    return unique.map(absUrl).filter(Boolean) as string[];
  }, [servico?.imagem, servico?.images]);

  // 👁️ Estado para imagem principal exibida
  const [activeImg, setActiveImg] = useState<string>(PLACEHOLDER);

  // ✅ Mantém a imagem ativa sincronizada quando mudar o serviço/imagens
  useEffect(() => {
    setActiveImg(images[0] || PLACEHOLDER);
  }, [images]);

  // ✅ Só agora pode retornar (depois dos hooks)
  if (!servico) return null;

  const waDigits = (servico.whatsapp || "").replace(/\D/g, "");
  const waLabel = formatWhatsApp(servico.whatsapp || "");

  const verificadoRaw: unknown = (
    servico as unknown as { verificado?: unknown }
  ).verificado;
  const isVerified = normalizeVerificado(verificadoRaw);

  async function handleRemove() {
    if (!servico || !onRemover || readOnly) return;
    if (!window.confirm(confirmText)) return;

    try {
      setRemoving(true);
      await onRemover(servico.id);
    } finally {
      setRemoving(false);
    }
  }

  async function handleToggleVerificado() {
    if (!servico || !onToggleVerificado || readOnly) return;

    const novoValor = !isVerified;

    try {
      setToggling(true);
      await onToggleVerificado(servico.id, novoValor);
      // Observação: o estado visual final vem do "servico.verificado" atualizado no parent.
    } finally {
      setToggling(false);
    }
  }

  return (
    <article
      className={`flex h-full flex-col overflow-hidden rounded-3xl bg-white shadow-md ring-1 ring-black/5 transition hover:-translate-y-0.5 hover:shadow-lg ${className}`}
      aria-labelledby={`serv-${servico.id}-title`}
    >
      {/* ===== TOPO COM IMAGEM + SELOS ===== */}
      <div className="relative w-full bg-gray-100 pb-[55%]">
        <img
          src={activeImg}
          alt={servico.nome || "Imagem do serviço"}
          className="absolute inset-0 h-full w-full object-cover transition-all duration-300"
          onError={(e) =>
            ((e.currentTarget as HTMLImageElement).src = PLACEHOLDER)
          }
          loading="lazy"
        />

        {/* Gradiente */}
        <div className="pointer-events-none absolute inset-x-0 bottom-0 h-16 bg-gradient-to-t from-black/50 to-transparent" />

        {/* Selo de verificado / pendente */}
        <div
          className={`absolute left-3 top-3 flex items-center gap-1 rounded-full px-2.5 py-1 text-[11px] font-semibold text-white shadow-sm ${
            isVerified ? "bg-emerald-500/95" : "bg-amber-500/95"
          }`}
        >
          <span>{isVerified ? "✓" : "⏳"}</span>
          <span>
            {isVerified ? "Profissional verificado" : "Pendente de verificação"}
          </span>
        </div>

        {/* Contador de fotos */}
        {images.length > 1 && (
          <span className="absolute right-3 top-3 rounded-full bg-black/70 px-2 py-0.5 text-[11px] font-medium text-white">
            {images.length} foto(s)
          </span>
        )}
      </div>

      {/* ===== CONTEÚDO ===== */}
      <div className="flex flex-1 flex-col gap-2 p-4 sm:p-5">
        {/* Nome + tag de especialidade */}
        <div className="flex flex-wrap items-center justify-between gap-2">
          <h3
            id={`serv-${servico.id}-title`}
            className="line-clamp-1 text-base font-semibold text-gray-900 sm:text-lg"
            title={servico.nome || undefined}
          >
            {servico.nome}
          </h3>

          {servico.especialidade_nome && (
            <span className="inline-flex items-center rounded-full bg-emerald-50 px-3 py-1 text-[11px] font-medium text-emerald-700 ring-1 ring-emerald-100">
              {servico.especialidade_nome}
            </span>
          )}
        </div>

        {/* Cargo */}
        {servico.cargo && (
          <p className="text-sm text-gray-700">
            <span className="font-medium text-gray-800">Cargo: </span>
            <span className="line-clamp-1">{servico.cargo}</span>
          </p>
        )}

        {/* Descrição */}
        {servico.descricao && (
          <p
            className="mt-1 line-clamp-3 text-sm leading-relaxed text-gray-600"
            title={servico.descricao || undefined}
          >
            {servico.descricao}
          </p>
        )}

        {/* ===== MINIATURAS ===== */}
        {images.length > 1 && (
          <div className="mt-3 flex gap-2 overflow-x-auto pb-1">
            {images.map((src, i) => (
              <button
                key={`${src}-${i}`}
                type="button"
                onClick={() => setActiveImg(src)}
                className={`flex-shrink-0 overflow-hidden rounded-xl border-2 transition-all ${
                  activeImg === src
                    ? "border-[#2F7E7F] shadow-sm"
                    : "border-transparent hover:border-gray-300"
                }`}
                aria-label={`Selecionar imagem ${i + 1}`}
              >
                <img
                  src={src}
                  alt={`Miniatura ${i + 1}`}
                  className="h-12 w-12 object-cover sm:h-14 sm:w-14"
                  onError={(e) =>
                    ((e.currentTarget as HTMLImageElement).src = PLACEHOLDER)
                  }
                  loading="lazy"
                />
              </button>
            ))}
          </div>
        )}

        {/* ===== CONTATO ===== */}
        {waDigits && (
          <a
            href={`https://wa.me/${waDigits}`}
            target="_blank"
            rel="noreferrer"
            className="mt-3 inline-flex w-fit items-center gap-2 rounded-full bg-[#2F7E7F]/5 px-3 py-1.5 text-xs font-medium text-[#2F7E7F] ring-1 ring-[#2F7E7F]/20 transition hover:bg-[#2F7E7F]/10"
          >
            <span className="text-base">📱</span>
            <span>WhatsApp: {waLabel}</span>
          </a>
        )}

        {/* ===== AÇÕES ===== */}
        {!readOnly && (
          <div className="mt-4 flex flex-wrap items-center justify-end gap-2">
            {/* ✅ Verificar / Desverificar (só aparece se o parent passar a prop) */}
            {onToggleVerificado && (
              <button
                type="button"
                onClick={handleToggleVerificado}
                disabled={toggling}
                className={`rounded-full px-3.5 py-1.5 text-xs font-semibold shadow-sm transition disabled:opacity-50 ${
                  isVerified
                    ? "bg-amber-500 text-white hover:bg-amber-600"
                    : "bg-emerald-600 text-white hover:bg-emerald-700"
                }`}
              >
                {toggling
                  ? "Salvando..."
                  : isVerified
                    ? "Desverificar"
                    : "Verificar"}
              </button>
            )}

            <button
              type="button"
              onClick={() => onEditar?.(servico)}
              className="rounded-full bg-gray-100 px-3.5 py-1.5 text-xs font-medium text-gray-900 transition hover:bg-gray-200 disabled:opacity-50"
            >
              Editar
            </button>

            <button
              type="button"
              onClick={handleRemove}
              disabled={removing}
              className="rounded-full bg-red-600 px-3.5 py-1.5 text-xs font-semibold text-white shadow-sm transition hover:bg-red-700 disabled:opacity-50"
            >
              {removing ? "Removendo..." : "Remover"}
            </button>
          </div>
        )}
      </div>
    </article>
  );
}

"use client";

import React, { useEffect, useRef, useState } from "react";
import CustomButton from "@/components/buttons/CustomButton";
import { Service } from "@/types/service";
import FormattedInput from "@/components/layout/FormattedInput";

interface Especialidade {
  id: number;
  nome: string;
}

interface Props {
  servicoEditado?: Service | null;
  onSaved: () => void;
  onCancel: () => void;
}

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";
const API_SERVICOS = `${API_BASE}/api/admin/servicos`;
const API_ESPECIALIDADES = `${API_BASE}/api/admin/especialidades`;

// Normaliza URL absoluta → para preview
const toAbs = (p?: string | null) =>
  !p
    ? null
    : p.startsWith("http")
      ? p
      : `${API_BASE}${p.startsWith("/") ? p : `/${p}`}`;

// Converte URL absoluta → para relativa (salvar no banco)
const toRel = (u: string) =>
  u?.startsWith(API_BASE) ? u.slice(API_BASE.length) : u;

export default function ServiceFormUnificado({
  servicoEditado,
  onSaved,
  onCancel,
}: Props) {
  /* --------------------------- estados principais --------------------------- */
  const [form, setForm] = useState({
    nome: "",
    cargo: "",
    whatsapp: "",
    descricao: "",
    especialidade_id: "",
  });

  const [especialidades, setEspecialidades] = useState<Especialidade[]>([]);

  // imagens
  const [existingImgs, setExistingImgs] = useState<string[]>([]);
  const [removeExisting, setRemoveExisting] = useState<Set<string>>(new Set());
  const [newFiles, setNewFiles] = useState<File[]>([]);
  const [newPreviews, setNewPreviews] = useState<string[]>([]);

  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState<{
    type: "success" | "error";
    text: string;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const isEditing = !!servicoEditado?.id;

  /* ---------------------------- carregar dados ---------------------------- */
  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(API_ESPECIALIDADES, {
          credentials: "include", // ✅ cookie HttpOnly
        });
        if (!res.ok) {
          console.error("Falha ao buscar especialidades:", res.status);
          return;
        }
        const data = await res.json();
        setEspecialidades(Array.isArray(data) ? data : []);
      } catch (err) {
        console.error("Erro ao buscar especialidades:", err);
      }
    })();
  }, []);

  /* ---------------------------- preencher form ---------------------------- */
  useEffect(() => {
    if (servicoEditado) {
      setForm({
        nome: servicoEditado.nome || "",
        cargo: servicoEditado.cargo || "",
        whatsapp: servicoEditado.whatsapp || "",
        descricao: servicoEditado.descricao || "",
        especialidade_id: String(servicoEditado.especialidade_id ?? ""),
      });

      // imagens existentes
      const extras = Array.isArray(servicoEditado.images)
        ? (servicoEditado.images as unknown as string[])
        : [];
      const allRel = [servicoEditado.imagem, ...extras].filter(
        Boolean,
      ) as string[];
      const uniqueRel = Array.from(new Set(allRel));
      const abs = uniqueRel.map((p) => toAbs(p)!).filter(Boolean);
      setExistingImgs(abs);
      setRemoveExisting(new Set());
      setNewFiles([]);
      setNewPreviews([]);
      if (fileInputRef.current) fileInputRef.current.value = "";
    } else {
      resetForm();
    }
  }, [servicoEditado]);

  // gerar e liberar previews de novas imagens
  useEffect(() => {
    const urls = newFiles.map((f) => URL.createObjectURL(f));
    setNewPreviews(urls);
    return () => urls.forEach((u) => URL.revokeObjectURL(u));
  }, [newFiles]);

  /* ------------------------------- helpers ------------------------------- */
  function resetForm() {
    setForm({
      nome: "",
      cargo: "",
      whatsapp: "",
      descricao: "",
      especialidade_id: "",
    });
    setExistingImgs([]);
    setRemoveExisting(new Set());
    setNewFiles([]);
    setNewPreviews([]);
    if (fileInputRef.current) fileInputRef.current.value = "";
  }

  function validate(): string | null {
    if (!form.nome.trim()) return "Informe o nome do colaborador.";
    if (!form.whatsapp.trim()) return "Informe o WhatsApp.";
    if (!form.especialidade_id) return "Selecione uma especialidade.";
    return null;
  }

  async function safeText(res: Response) {
    try {
      const ct = res.headers.get("content-type") || "";
      if (ct.includes("application/json")) {
        const j = await res.json();
        return (j as any)?.message || JSON.stringify(j);
      }
      return await res.text();
    } catch {
      return "";
    }
  }

  /* ------------------------------- eventos ------------------------------- */
  function handleChange(
    e:
      | React.ChangeEvent<HTMLInputElement>
      | React.ChangeEvent<HTMLTextAreaElement>
      | React.ChangeEvent<HTMLSelectElement>,
  ) {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  }

  function onPickFiles(e: React.ChangeEvent<HTMLInputElement>) {
    const files = Array.from(e.target.files || []);
    if (!files.length) return;
    setNewFiles((prev) => [...prev, ...files].slice(0, 8)); // limite 8
  }

  function removeNewImage(index: number) {
    setNewFiles((prev) => prev.filter((_, i) => i !== index));
  }

  function toggleRemoveExisting(urlAbs: string) {
    setRemoveExisting((prev) => {
      const next = new Set(prev);
      const rel = toRel(urlAbs);
      if (next.has(rel)) next.delete(rel);
      else next.add(rel);
      return next;
    });
  }

  /* ---------------------------- submit form ---------------------------- */
  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setMsg(null);

    const err = validate();
    if (err) {
      setMsg({ type: "error", text: err });
      return;
    }

    const fd = new FormData();
    fd.append("nome", form.nome.trim());
    fd.append("cargo", form.cargo.trim());
    fd.append("whatsapp", form.whatsapp.trim());
    fd.append("descricao", form.descricao.trim());
    fd.append("especialidade_id", form.especialidade_id);

    // imagens novas
    newFiles.forEach((f) => fd.append("images", f));

    if (isEditing) {
      const kept = existingImgs
        .map((abs) => toRel(abs))
        .filter((rel) => rel && !removeExisting.has(rel));
      fd.append("keepImages", JSON.stringify(kept));
    }

    const method = isEditing ? "PUT" : "POST";
    const url = isEditing
      ? `${API_SERVICOS}/${servicoEditado!.id}`
      : API_SERVICOS;

    setLoading(true);
    try {
      const res = await fetch(url, {
        method,
        body: fd,
        credentials: "include", // ✅ cookie HttpOnly
      });

      if (!res.ok) {
        const txt = await safeText(res);
        const msg =
          txt ||
          (res.status === 401 || res.status === 403
            ? "Você não tem permissão para salvar serviço. Faça login novamente."
            : "Falha ao salvar serviço.");
        throw new Error(msg);
      }

      setMsg({
        type: "success",
        text: isEditing
          ? "Serviço atualizado com sucesso!"
          : "Serviço cadastrado com sucesso!",
      });

      resetForm();
      onSaved();
      onCancel();
    } catch (err: any) {
      console.error("Erro ao salvar:", err);
      setMsg({
        type: "error",
        text: err.message || "Erro ao salvar serviço.",
      });
    } finally {
      setLoading(false);
    }
  }

  /* ----------------------------- interface ----------------------------- */
  return (
    <form
      onSubmit={handleSubmit}
      className="flex w-full max-w-4xl flex-col gap-5 rounded-2xl bg-white p-4 shadow-sm sm:p-6 md:p-8"
    >
      {/* Cabeçalho */}
      <div className="flex flex-col gap-3 border-b border-gray-100 pb-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h2 className="text-base font-semibold text-[#2F7E7F] sm:text-lg">
            {isEditing ? "Editar Serviço" : "Adicionar Serviço e Colaborador"}
          </h2>
          <p className="mt-1 text-xs text-gray-500 sm:text-sm">
            Cadastre colaboradores e serviços oferecidos na fazenda.
          </p>
        </div>

        {isEditing && (
          <button
            type="button"
            onClick={() => {
              resetForm();
              onCancel();
            }}
            className="self-start rounded-full border border-gray-300 px-3 py-1.5 text-xs font-medium text-gray-700 transition hover:bg-gray-50 sm:self-auto"
          >
            Cancelar edição
          </button>
        )}
      </div>

      {/* Campos em grid */}
      <div className="grid grid-cols-1 gap-5 md:grid-cols-2">
        {/* Coluna esquerda */}
        <div className="flex flex-col gap-4">
          {/* Nome */}
          <FormattedInput
            label="Nome do colaborador"
            name="nome"
            value={form.nome}
            onChange={handleChange}
            placeholder="Nome completo"
            required
          />

          {/* Cargo */}
          <FormattedInput
            label="Cargo ou função"
            name="cargo"
            value={form.cargo}
            onChange={handleChange}
            placeholder="Ex.: Veterinário, Aplicador de defensivo…"
          />

          {/* WhatsApp com máscara */}
          <FormattedInput
            label="WhatsApp"
            name="whatsapp"
            value={form.whatsapp}
            onChange={handleChange}
            placeholder="(00) 90000-0000"
            mask="telefone"
            required
          />
        </div>

        {/* Coluna direita */}
        <div className="flex flex-col gap-4">
          <div className="flex flex-col gap-1.5">
            <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700 sm:text-xs">
              Especialidade
            </label>
            <select
              name="especialidade_id"
              className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 text-sm text-gray-900 outline-none ring-0 transition focus:border-[#2F7E7F] focus:ring-2 focus:ring-[#2F7E7F]/20"
              value={form.especialidade_id}
              onChange={handleChange}
            >
              <option value="">Selecione a especialidade…</option>
              {especialidades.map((e) => (
                <option key={e.id} value={e.id}>
                  {e.nome}
                </option>
              ))}
            </select>
          </div>

          <div className="flex flex-col gap-1.5">
            <label className="text-[11px] font-semibold uppercase tracking-wide text-gray-700 sm:text-xs">
              Descrição do serviço
            </label>
            <textarea
              name="descricao"
              className="min-h-[96px] w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 text-sm text-gray-900 outline-none placeholder:text-gray-400 ring-0 transition focus:border-[#2F7E7F] focus:ring-2 focus:ring-[#2F7E7F]/20"
              placeholder="Como esse colaborador atua, quais serviços presta, região de atendimento…"
              value={form.descricao}
              onChange={handleChange}
            />
          </div>
        </div>
      </div>

      {/* Imagens existentes */}
      {isEditing && existingImgs.length > 0 && (
        <div className="flex flex-col gap-2">
          <label className="text-xs font-medium uppercase tracking-wide text-gray-600">
            Imagens atuais
          </label>
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
            {existingImgs.map((u) => {
              const rel = toRel(u);
              const marked = removeExisting.has(rel);
              return (
                <button
                  key={u}
                  type="button"
                  onClick={() => toggleRemoveExisting(u)}
                  className={`relative overflow-hidden rounded-lg border text-left shadow-sm transition ${
                    marked
                      ? "ring-2 ring-red-500"
                      : "ring-1 ring-black/5 hover:ring-[#2F7E7F]"
                  }`}
                  title={marked ? "Remover imagem" : "Manter imagem"}
                >
                  <img
                    src={u}
                    alt="img existente"
                    className="h-28 w-full object-cover"
                  />
                  <span
                    className={`absolute right-1 top-1 rounded-full px-2 py-0.5 text-[10px] font-medium ${
                      marked
                        ? "bg-red-600 text-white"
                        : "bg-black/60 text-white"
                    }`}
                  >
                    {marked ? "remover" : "manter"}
                  </span>
                </button>
              );
            })}
          </div>
        </div>
      )}

      {/* upload novas imagens */}
      <div className="flex flex-col gap-2">
        <label className="text-xs font-medium uppercase tracking-wide text-gray-600">
          Adicionar novas imagens (opcional)
        </label>
        <input
          ref={fileInputRef}
          type="file"
          multiple
          accept="image/*"
          onChange={onPickFiles}
          className="block w-full text-xs text-gray-600 file:mr-3 file:cursor-pointer file:rounded-full file:border-0 file:bg-[#2F7E7F] file:px-3 file:py-1.5 file:text-xs file:font-medium file:text-white hover:file:bg-[#256466]"
        />

        {newPreviews.length > 0 && (
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
            {newPreviews.map((src, i) => (
              <div
                key={`${src}-${i}`}
                className="relative overflow-hidden rounded-lg border border-gray-200 shadow-sm"
              >
                <img
                  src={src}
                  alt={`preview-${i}`}
                  className="h-28 w-full object-cover"
                />
                <button
                  type="button"
                  onClick={() => removeNewImage(i)}
                  className="absolute right-1 top-1 rounded-full bg-black/70 px-2 py-0.5 text-[10px] text-white"
                >
                  remover
                </button>
              </div>
            ))}
          </div>
        )}
      </div>

      {msg && (
        <div
          className={`rounded-lg px-3 py-2 text-sm ${
            msg.type === "success"
              ? "bg-green-50 text-green-700"
              : "bg-red-50 text-red-700"
          }`}
        >
          {msg.text}
        </div>
      )}

      {/* Ações */}
      <div className="flex flex-col gap-3 pt-2 sm:flex-row sm:justify-end">
        <button
          type="button"
          onClick={() => {
            resetForm();
            onCancel();
          }}
          disabled={loading}
          className="w-full rounded-full border border-gray-300 px-4 py-2.5 text-sm font-medium text-gray-700 transition hover:bg-gray-50 disabled:opacity-50 sm:w-auto"
        >
          Limpar
        </button>
        <CustomButton
          type="submit"
          label={
            loading
              ? isEditing
                ? "Atualizando..."
                : "Salvando..."
              : isEditing
                ? "Atualizar Serviço"
                : "Adicionar Serviço"
          }
          variant="primary"
          size="medium"
          isLoading={loading}
          className="w-full sm:w-auto"
        />
      </div>
    </form>
  );
}

"use client";

import { Product } from "@/types/product";
import { useCart } from "@/context/CartContext";
import { useState } from "react";
import { resolveStockValue } from "../../utils/stock";

interface AddToCartButtonProps {
  product: Product;
  qty?: number; // 👈 NOVO: quantidade
  className?: string;
  disabled?: boolean;
}

const AddToCartButton: React.FC<AddToCartButtonProps> = ({
  product,
  qty = 1,
  className,
  disabled,
}) => {
  const { addToCart, openCart } = useCart();
  const [loading, setLoading] = useState(false);

  const stock = resolveStockValue(
    (product as any).quantity,
    (product as any).estoque,
    (product as any).stock,
  );
  const hasStockFlag = typeof stock === "number";
  const isOut = hasStockFlag ? stock <= 0 : false;

  const handleAddToCart = async (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (loading || disabled || isOut) return;
    setLoading(true);
    try {
      const res = addToCart(product, qty); // 👈 passa a QTD escolhida
      // Abra o carrinho SEMPRE que clicar (mesmo se já existia e só atualizou)
      if (res.ok) openCart();
      // Em caso de LIMIT_REACHED/OUT_OF_STOCK, o contexto já faz toast
    } finally {
      setLoading(false);
    }
  };

  return (
    <button
      onClick={handleAddToCart}
      disabled={loading || disabled || isOut}
      className={`w-full py-3 rounded-xl text-white font-semibold transition ${
        isOut
          ? "bg-gray-400 cursor-not-allowed"
          : "bg-green-600 hover:bg-green-700 active:bg-green-800"
      } disabled:opacity-60 ${className ?? ""}`}
      aria-busy={loading}
      title={isOut ? "Esgotado" : "Adicionar ao Carrinho"}
      aria-disabled={loading || disabled || isOut || undefined}
    >
      {loading
        ? "Adicionando..."
        : isOut
          ? "Esgotado"
          : "Adicionar ao Carrinho"}
    </button>
  );
};

export default AddToCartButton;

"use client";

import React, { useMemo, useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import axios from "axios";
import { useCart } from "../../context/CartContext";
import { useAuth } from "../../context/AuthContext";
import CartItemCard from "./CartItemCard";
import CustomButton from "../buttons/CustomButton";
import CloseButton from "../buttons/CloseButton";
import toast from "react-hot-toast";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

interface CouponPreviewResponse {
  success: boolean;
  message?: string;
  desconto?: number;
  total_original?: number;
  total_com_desconto?: number;
  cupom?: {
    id: number;
    codigo: string;
    tipo: string;
    valor: number;
  };
}

const money = (v: number) =>
  `R$ ${Number(v || 0)
    .toFixed(2)
    .replace(".", ",")}`;

// Promoção normalizada para o carrinho
type Promotion = {
  originalPrice: number;
  finalPrice: number;
  discountPercent?: number;
};

const CartCar: React.FC<{ isCartOpen: boolean; closeCart: () => void }> = ({
  isCartOpen,
  closeCart,
}) => {
  const { cartItems } = useCart();
  const auth = useAuth() as any;
  const router = useRouter();

  const [logged, setLogged] = useState(false);

  // CUPOM
  const [coupon, setCoupon] = useState("");
  const [couponLoading, setCouponLoading] = useState(false);
  const [couponMessage, setCouponMessage] = useState<string | null>(null);
  const [couponError, setCouponError] = useState<string | null>(null);
  const [discount, setDiscount] = useState(0);

  const isEmpty = cartItems.length === 0;

  // ============================
  // 🔐 Verifica se está logado
  // ============================
  useEffect(() => {
    const authenticated =
      Boolean(auth?.user?.id) || Boolean(auth?.isAuthenticated);
    setLogged(authenticated);
  }, [auth?.user?.id, auth?.isAuthenticated]);

  // ============================
  // ✅ FECHAR AUTOMATICAMENTE
  // quando o carrinho ficar vazio
  // ============================
  useEffect(() => {
    if (isCartOpen && isEmpty) {
      closeCart();
    }
  }, [isCartOpen, isEmpty, closeCart]);

  // ============================
  // 🔥 Promoções por produto
  // ============================
  const [promotions, setPromotions] = useState<
    Record<number, Promotion | null>
  >({});

  useEffect(() => {
    if (!cartItems.length) {
      setPromotions({});
      return;
    }

    const uniqueIds = Array.from(
      new Set(cartItems.map((it) => Number(it.id))),
    ).filter(Boolean);

    (async () => {
      try {
        const results = await Promise.all(
          uniqueIds.map(async (id) => {
            try {
              const res = await fetch(`${API_BASE}/api/public/promocoes/${id}`);

              if (!res.ok) {
                return { id, promo: null };
              }

              const data = await res.json();

              const original = Number(data.original_price ?? data.price ?? 0);
              const final = Number(
                data.final_price ?? data.promo_price ?? data.price ?? original,
              );

              const discountPercent =
                data.discount_percent != null
                  ? Number(data.discount_percent)
                  : undefined;

              return {
                id,
                promo: {
                  originalPrice: original,
                  finalPrice: final,
                  discountPercent,
                } as Promotion,
              };
            } catch {
              return { id, promo: null };
            }
          }),
        );

        setPromotions((prev) => {
          const next: Record<number, Promotion | null> = { ...prev };
          for (const { id, promo } of results) {
            next[id] = promo;
          }
          return next;
        });
      } catch {
        // Sem log no console para manter padrão profissional
      }
    })();
  }, [cartItems]);

  // ============================
  // ⚠️ Warnings de estoque
  // ============================
  const warnings = useMemo(() => {
    return (cartItems as any[])
      .filter(
        (i) =>
          typeof i._stock === "number" &&
          i._stock > 0 &&
          i.quantity >= i._stock,
      )
      .map((i) => `“${i.name}” atingiu o limite de estoque (${i._stock}).`);
  }, [cartItems]);

  // ============================
  // 💰 Subtotal (usando promo)
  // ============================
  const subtotal = useMemo(
    () =>
      cartItems.reduce((acc, it) => {
        const basePrice = Number((it as any).price) || 0;
        const qty = Number(it.quantity || 1);
        const promo = promotions[it.id];

        const finalPricePerUnit = promo ? promo.finalPrice : basePrice;

        return acc + finalPricePerUnit * qty;
      }, 0),
    [cartItems, promotions],
  );

  const total = useMemo(
    () => Math.max(subtotal - discount, 0),
    [subtotal, discount],
  );

  // sempre que carrinho mudar (itens ou promoções), limpa estado de cupom
  useEffect(() => {
    setDiscount(0);
    setCouponMessage(null);
    setCouponError(null);
  }, [cartItems, promotions]);

  // ============================
  // 🎫 Aplicar cupom
  // ============================
  const applyDiscount = async () => {
    const code = coupon.trim().toUpperCase();

    if (!code) {
      toast.error("Informe um cupom.");
      return;
    }

    if (!logged) {
      toast.error("Você precisa estar logado para aplicar um cupom.");
      router.push("/login");
      return;
    }

    if (!subtotal || subtotal <= 0) {
      toast.error("Seu carrinho está vazio.");
      return;
    }

    try {
      setCouponLoading(true);
      setCouponError(null);
      setCouponMessage(null);

      const { data } = await axios.post<CouponPreviewResponse>(
        `${API_BASE}/api/checkout/preview-cupom`,
        { codigo: code, total: subtotal },
        { withCredentials: true },
      );

      if (!data?.success) {
        const msg = data?.message || "Não foi possível aplicar este cupom.";
        setDiscount(0);
        setCouponError(msg);
        toast.error(msg);
        return;
      }

      const desconto = Number(data.desconto || 0);
      setDiscount(desconto > 0 ? desconto : 0);

      const msg = data.message || "Cupom aplicado com sucesso!";
      setCouponMessage(msg);
      setCouponError(null);
      toast.success(msg);

      if (typeof window !== "undefined") {
        localStorage.setItem("kavita_current_coupon", code);
      }
    } catch (err: any) {
      const msgBackend = err?.response?.data?.message;
      const msg = msgBackend || "Não foi possível aplicar este cupom.";
      setDiscount(0);
      setCouponError(msg);
      toast.error(msg);
    } finally {
      setCouponLoading(false);
    }
  };

  // ============================
  // 🧾 Ir para checkout
  // ============================
  const handleCheckout = () => {
    if (isEmpty) {
      toast.error("Seu carrinho está vazio!");
      return;
    }
    if (!logged) {
      toast("Faça login para continuar.");
      router.push("/login");
      return;
    }
    router.push("/checkout");
  };

  return (
    <div
      className={`fixed inset-y-0 right-0 left-0 sm:left-auto bg-white shadow-xl z-[70] flex flex-col
                  transition-transform duration-300
                  w-full sm:w-[90vw] md:w-[26rem] lg:w-[28rem]
                  ${isCartOpen ? "translate-x-0" : "translate-x-full"}`}
      role="dialog"
      aria-label="Carrinho de compras"
      aria-hidden={!isCartOpen}
    >
      {/* Header */}
      <header className="sticky top-0 z-10 bg-white/95 backdrop-blur border-b px-4 sm:px-5 py-3">
        <div className="relative flex items-center justify-center">
          <h2 className="text-base sm:text-lg font-semibold">
            Carrinho de compras
          </h2>
          <CloseButton
            onClose={closeCart}
            className="absolute right-0 top-1/2 -translate-y-1/2"
          />
        </div>
      </header>

      {/* Lista de itens */}
      <div className="flex-1 overflow-y-auto px-3 sm:px-5 py-3 space-y-3">
        {isEmpty ? (
          <p className="text-sm sm:text-base text-gray-500 text-center py-10">
            🛒 Seu carrinho está vazio!
          </p>
        ) : (
          <ul className="space-y-3">
            {cartItems.map((item) => (
              <CartItemCard key={item.id} item={item} />
            ))}
          </ul>
        )}
      </div>

      {/* Footer */}
      {!isEmpty && (
        <footer className="sticky bottom-0 z-10 border-t bg-white px-4 sm:px-5 py-3">
          {warnings.length > 0 && (
            <div className="mb-2 text-xs text-orange-600 space-y-1">
              {warnings.map((w, idx) => (
                <p key={idx}>⚠️ {w}</p>
              ))}
            </div>
          )}

          <div className="space-y-1 text-sm">
            <div className="flex items-center justify-between text-gray-700">
              <span>Subtotal</span>
              <span>{money(subtotal)}</span>
            </div>

            {discount > 0 && (
              <div className="flex items-center justify-between text-emerald-700">
                <span>Desconto (cupom)</span>
                <span>- {money(discount)}</span>
              </div>
            )}

            <div className="flex items-center justify-between font-semibold pt-1 border-t border-gray-100 mt-1">
              <span>Total</span>
              <span className="text-lg font-extrabold text-green-600">
                {money(total)}
              </span>
            </div>
          </div>

          {couponMessage && (
            <p className="mt-1 text-xs text-emerald-600">{couponMessage}</p>
          )}
          {couponError && (
            <p className="mt-1 text-xs text-red-600">{couponError}</p>
          )}

          <div className="mt-3 flex gap-2">
            <input
              type="text"
              value={coupon}
              onChange={(e) => {
                setCoupon(e.target.value.toUpperCase());
                setCouponMessage(null);
                setCouponError(null);
              }}
              placeholder="Cupom de desconto"
              className="flex-1 rounded-lg border border-gray-300 bg-white px-3 py-2 min-h-[44px] text-sm
                         focus:border-[#359293] focus:ring-2 focus:ring-[#359293]/20 outline-none"
            />
            <CustomButton
              label={couponLoading ? "Aplicando..." : "Aplicar"}
              onClick={applyDiscount}
              variant="primary"
              isLoading={couponLoading}
              size="medium"
              className="min-w-[96px] min-h-[44px]"
            />
          </div>

          <CustomButton
            label="Finalizar Compra"
            onClick={handleCheckout}
            variant="primary"
            className="mt-3 w-full min-h-[48px]"
            isLoading={false}
            size="medium"
          />
        </footer>
      )}
    </div>
  );
};

