"use client";

import Image from "next/image";
import React, { useEffect, useState } from "react";
import { CartItem } from "../../types/CartCarProps";
import { useCart } from "../../context/CartContext";
import CustomButton from "../buttons/CustomButton";

const API = process.env.NEXT_PUBLIC_API_URL || "";
const PLACEHOLDER = "/placeholder.png";

/* Helpers de preço/imagem */
function normalizePrice(price: unknown): number {
  if (typeof price === "number" && !Number.isNaN(price)) return price;
  if (typeof price === "string") {
    const cleaned = price.replace(/[^\d,.-]/g, "").replace(",", ".");
    const n = parseFloat(cleaned);
    return Number.isFinite(n) ? n : 0;
  }
  return 0;
}

function formatPriceBRL(n: number): string {
  return n.toFixed(2).replace(".", ",");
}

function resolveImage(raw: any): string {
  if (!raw) return PLACEHOLDER;
  if (typeof raw === "object") {
    const candidate = raw.url || raw.path || raw.src || raw.image;
    if (candidate) return resolveImage(candidate);
    return PLACEHOLDER;
  }
  const src = String(raw).trim().replace(/\\/g, "/");
  if (!src) return PLACEHOLDER;
  if (/^https?:\/\//i.test(src)) return src;
  if (src.startsWith("/uploads")) return `${API}${src}`;
  if (src.startsWith("uploads")) return `${API}/${src}`;
  return `${API}/uploads/${src}`;
}

const quantityButtonClasses =
  "min-w-[36px] h-9 rounded-lg border border-gray-300 bg-white text-gray-700 text-sm font-semibold transition hover:bg-gray-100 disabled:opacity-50";

/**
 * Estrutura normalizada de promoção dentro do carrinho.
 * Aqui NÃO usamos null, só number ou undefined para ficar fácil pro TS.
 */
type Promotion = {
  originalPrice: number;
  finalPrice: number;
  discountPercent?: number;
};

export default function CartItemCard({ item }: { item: CartItem }) {
  const { removeFromCart, updateQuantity } = useCart();

  const unitFromCart = normalizePrice(item.price); // preço que veio do addToCart
  const qty = typeof item.quantity === "number" ? item.quantity : 1;

  const rawImage =
    (item as any).image ||
    (Array.isArray((item as any).images) ? (item as any).images[0] : null);
  const imageSrc = resolveImage(rawImage);

  const stock = Number((item as any)._stock);
  const hasStock = Number.isFinite(stock) && stock >= 0;
  const atMax = hasStock && stock > 0 && qty >= stock;
  const canDecrease = qty > 1;
  const canIncrease = !atMax;

  // ========================
  // 🔥 BUSCAR PROMOÇÃO DO PRODUTO
  // ========================
  const [promo, setPromo] = useState<Promotion | null>(null);

  useEffect(() => {
    let ignore = false;

    (async () => {
      try {
        const res = await fetch(`${API}/api/public/promocoes/${item.id}`);
        if (!res.ok) return; // 404 = sem promo, só ignora

        const data = await res.json();

        // normaliza para sempre ter number (sem null)
        const original = Number(
          data.original_price ?? data.price ?? unitFromCart ?? 0,
        );
        const final = Number(
          data.final_price ??
            data.promo_price ??
            data.price ??
            unitFromCart ??
            0,
        );

        const discountPercent =
          data.discount_percent != null
            ? Number(data.discount_percent)
            : undefined;

        if (!ignore) {
          setPromo({
            originalPrice: original,
            finalPrice: final,
            discountPercent,
          });
        }
      } catch (err) {
        console.warn("[CartItemCard] erro ao buscar promoção:", err);
      }
    })();

    return () => {
      ignore = true;
    };
  }, [item.id, unitFromCart]);

  // ========================
  // 🔥 CÁLCULO DE PREÇO
  // ========================

  // se tiver promoção, usamos o finalPrice; senão, o preço que está no carrinho
  const finalUnit = promo ? promo.finalPrice : unitFromCart;
  const originalUnit = promo ? promo.originalPrice : unitFromCart;

  const hasDiscount = !!promo && promo.finalPrice < promo.originalPrice;

  const lineTotal = finalUnit * qty;
  const lineOriginalTotal = originalUnit * qty;

  return (
    <li
      className="rounded-xl border border-gray-200 bg-white p-3 sm:p-4 shadow-sm
                 grid grid-cols-[64px_1fr] sm:grid-cols-[64px_1fr_auto] gap-3 sm:gap-4 items-start"
    >
      {/* imagem */}
      <Image
        src={imageSrc}
        alt={item.name}
        className="w-16 h-16 object-cover rounded-md"
        width={64}
        height={64}
        sizes="64px"
      />

      {/* infos */}
      <div className="min-w-0">
        <h3 className="text-sm font-semibold line-clamp-2">{item.name}</h3>

        {/* 🔥 PREÇO UNITÁRIO COM DESCONTO */}
        {hasDiscount ? (
          <div className="mt-1">
            <p className="text-[11px] text-gray-400 line-through">
              R$ {formatPriceBRL(originalUnit)}
            </p>
            <p className="text-green-600 font-bold text-sm">
              R$ {formatPriceBRL(finalUnit)}
            </p>
            <span className="inline-block mt-1 text-[10px] px-2 py-1 bg-red-500 text-white rounded-full font-semibold">
              -{promo.discountPercent?.toFixed(0)}% OFF
            </span>
          </div>
        ) : (
          <p className="mt-1 text-gray-700 text-sm">
            R$ {formatPriceBRL(unitFromCart)}
          </p>
        )}

        {/* quantidade */}
        <div className="mt-2 flex items-center gap-2" aria-live="polite">
          <button
            type="button"
            onClick={() =>
              canDecrease && updateQuantity(item.id, Math.max(1, qty - 1))
            }
            className={quantityButtonClasses}
            disabled={!canDecrease}
            aria-label={`Diminuir quantidade de ${item.name}`}
          >
            -
          </button>
          <span
            className="w-8 text-center text-sm"
            aria-label={`Quantidade de ${item.name}`}
          >
            {qty}
          </span>
          <button
            type="button"
            onClick={() => canIncrease && updateQuantity(item.id, qty + 1)}
            className={quantityButtonClasses}
            disabled={!canIncrease}
            aria-label={`Aumentar quantidade de ${item.name}`}
          >
            +
          </button>
        </div>

        {hasStock && (
          <p className="text-xs text-gray-500 mt-1">
            {stock === 0
              ? "Sem estoque"
              : atMax
                ? "Limite de estoque atingido"
                : `Em estoque: ${Math.max(0, stock - qty)}`}
          </p>
        )}
      </div>

      {/* ações / total */}
      <div className="col-span-2 sm:col-span-1 sm:pl-2 flex items-center justify-between sm:block sm:justify-end gap-2">
        {/* total com “de/por” */}
        <div className="text-right mb-1 sm:mb-2">
          {hasDiscount && (
            <p className="text-[11px] text-gray-400 line-through">
              R$ {formatPriceBRL(lineOriginalTotal)}
            </p>
          )}
          <p className="text-green-600 font-bold text-sm sm:text-base">
            R$ {formatPriceBRL(lineTotal)}
          </p>
        </div>

        <CustomButton
          label="Remover"
          onClick={() => removeFromCart(item.id)}
          variant="primary"
          isLoading={false}
          size="small"
          className="min-h-[36px] sm:mt-6 w-auto"
        />
      </div>
    </li>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { CheckoutFormChangeHandler, Endereco } from "@/hooks/useCheckoutForm";
import { ESTADOS_BR } from "@/utils/brasil";

type AddressFormProps = {
  endereco: Endereco;
  onChange: CheckoutFormChangeHandler;
};

// máscara simples 00000-000
function formatCep(value: string): string {
  const digits = value.replace(/\D/g, "").slice(0, 8);
  if (digits.length <= 5) return digits;
  return `${digits.slice(0, 5)}-${digits.slice(5)}`;
}

function normalizeTipoLocalidade(v: any): "URBANA" | "RURAL" {
  const t = String(v || "URBANA").toUpperCase();
  return t === "RURAL" ? "RURAL" : "URBANA";
}

export function AddressForm({ endereco, onChange }: AddressFormProps) {
  const [cepLoading, setCepLoading] = useState(false);
  const [cities, setCities] = useState<string[]>([]);

  const cepValue = endereco.cep ?? "";
  const estadoValue = (endereco.estado ?? "").toUpperCase();

  const tipoLocalidade = useMemo(
    () => normalizeTipoLocalidade((endereco as any)?.tipo_localidade),
    [endereco],
  );

  const isRural = tipoLocalidade === "RURAL";

  // CEP → ViaCEP (auto preenche cidade/estado e, se URBANA, rua/bairro)
  useEffect(() => {
    const digits = cepValue.replace(/\D/g, "");
    if (digits.length !== 8) return;

    let aborted = false;

    (async () => {
      try {
        setCepLoading(true);
        const res = await fetch(`https://viacep.com.br/ws/${digits}/json/`);
        if (!res.ok) return;
        const data = await res.json();
        if (aborted || data.erro) return;

        // Sempre preenche cidade/estado (serve tanto urbano quanto rural)
        onChange("endereco.cidade", data.localidade || "");
        onChange("endereco.estado", data.uf || "");

        // Só preenche rua/bairro quando for URBANA
        if (!isRural) {
          onChange("endereco.logradouro", data.logradouro || "");
          onChange("endereco.bairro", data.bairro || "");
        }
      } catch {
        // se falhar, o usuário ainda consegue digitar manualmente
      } finally {
        if (!aborted) setCepLoading(false);
      }
    })();

    return () => {
      aborted = true;
    };
  }, [cepValue, onChange, isRural]);

  // Estado → carrega cidades (IBGE) e usa datalist como sugestão
  useEffect(() => {
    const uf = estadoValue;
    if (!uf) {
      setCities([]);
      return;
    }

    let aborted = false;

    (async () => {
      try {
        const res = await fetch(
          `https://servicodados.ibge.gov.br/api/v1/localidades/estados/${uf}/municipios`,
        );
        if (!res.ok) return;
        const data = await res.json();
        if (aborted || !Array.isArray(data)) return;

        const names = data.map((m: any) => m.nome).sort();
        setCities(names);
      } catch {
        // se falhar, deixa o usuário digitar normalmente
      }
    })();

    return () => {
      aborted = true;
    };
  }, [estadoValue]);

  const handleCepChange: React.ChangeEventHandler<HTMLInputElement> = (e) => {
    const masked = formatCep(e.target.value);
    onChange("endereco.cep", masked);
  };

  const handleFieldChange =
    (
      field: keyof Endereco | string,
    ): React.ChangeEventHandler<HTMLInputElement> =>
    (e) => {
      onChange(`endereco.${field}` as any, e.target.value);
    };

  const handleEstadoChange: React.ChangeEventHandler<HTMLSelectElement> = (
    e,
  ) => {
    const value = e.target.value;
    onChange("endereco.estado", value);
    // limpamos cidade quando troca estado
    onChange("endereco.cidade", "");
  };

  const handleCidadeChange: React.ChangeEventHandler<HTMLInputElement> = (
    e,
  ) => {
    onChange("endereco.cidade", e.target.value);
  };

  const setTipo = (tipo: "URBANA" | "RURAL") => {
    onChange("endereco.tipo_localidade" as any, tipo);

    // Quando troca para RURAL, não apagamos nada automaticamente para evitar fricção.
    // Porém, se quiser deixar “mais limpo”, pode limpar bairro/logradouro aqui.
    // Mantive conservador para não quebrar a lógica existente.
  };

  return (
    <div className="space-y-4 sm:space-y-5">
      {/* Tipo de localidade */}
      <div>
        <span className="block text-sm font-medium text-gray-700">
          Tipo de localidade
        </span>

        <div className="mt-1 inline-flex w-full rounded-xl border border-gray-300 bg-white p-1">
          <button
            type="button"
            onClick={() => setTipo("URBANA")}
            aria-pressed={!isRural}
            className={[
              "w-1/2 rounded-lg px-3 py-2 text-sm font-medium transition min-h-[44px]",
              !isRural
                ? "bg-[#EC5B20] text-white"
                : "text-gray-700 hover:bg-gray-50",
            ].join(" ")}
          >
            Zona urbana
          </button>

          <button
            type="button"
            onClick={() => setTipo("RURAL")}
            aria-pressed={isRural}
            className={[
              "w-1/2 rounded-lg px-3 py-2 text-sm font-medium transition min-h-[44px]",
              isRural
                ? "bg-[#EC5B20] text-white"
                : "text-gray-700 hover:bg-gray-50",
            ].join(" ")}
          >
            Zona rural
          </button>
        </div>

        <p className="mt-1 text-[11px] text-gray-500">
          {isRural
            ? "Para zona rural, informe a comunidade/córrego e a descrição de acesso."
            : "Para zona urbana, informe rua/avenida, bairro e número."}
        </p>

        {/* AVISO (apenas quando RURAL) */}
        {isRural && (
          <div className="mt-3 rounded-xl border border-amber-200 bg-amber-50 px-3 py-2.5">
            <p className="text-sm font-semibold text-amber-900">
              Aviso importante
            </p>
            <p className="mt-1 text-[13px] leading-relaxed text-amber-900/90">
              Em área rural, podem ocorrer chuvas e estradas muito precárias.
              Isso pode dificultar nossa entrega e, eventualmente, não
              conseguiremos entregar dentro do prazo informado.
            </p>
          </div>
        )}
      </div>

      {/* CEP */}
      <div>
        <label
          htmlFor="checkout-cep"
          className="block text-sm font-medium text-gray-700"
        >
          CEP
        </label>
        <div className="mt-1 flex items-center gap-2">
          <input
            id="checkout-cep"
            name="cep"
            value={cepValue}
            onChange={handleCepChange}
            autoComplete="postal-code"
            inputMode="numeric"
            placeholder="00000-000"
            className="w-full px-3 sm:px-4 py-2.5 sm:py-3 text-sm sm:text-base text-gray-800 border border-gray-300 rounded-xl min-h-[44px] focus:outline-none focus:ring-2 focus:ring-[#EC5B20] transition"
          />
          {cepLoading && (
            <span className="text-xs text-gray-500 whitespace-nowrap">
              Buscando CEP...
            </span>
          )}
        </div>

        <p className="mt-1 text-[11px] text-gray-500">
          {isRural
            ? "Digite o CEP para sugerir cidade e estado automaticamente."
            : "Digite o CEP para preencher rua, bairro, cidade e estado automaticamente."}
        </p>
      </div>

      {/* Estado + Cidade */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
        <div>
          <label
            htmlFor="checkout-estado"
            className="block text-sm font-medium text-gray-700"
          >
            Estado
          </label>
          <select
            id="checkout-estado"
            value={estadoValue}
            onChange={handleEstadoChange}
            className="mt-1 w-full px-3 sm:px-4 py-2.5 sm:py-3 text-sm sm:text-base text-gray-800 border border-gray-300 rounded-xl min-h-[44px] focus:outline-none focus:ring-2 focus:ring-[#EC5B20] transition bg-white"
          >
            <option value="">Selecione o estado</option>
            {ESTADOS_BR.map((uf) => (
              <option key={uf.sigla} value={uf.sigla}>
                {uf.sigla} - {uf.nome}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label
            htmlFor="checkout-cidade"
            className="block text-sm font-medium text-gray-700"
          >
            Cidade
          </label>
          <input
            id="checkout-cidade"
