"use client";

import { useMemo, useState } from "react";
import ProductCard from "@/components/products/ProductCard";
import { useFetchProducts } from "@/hooks/useFetchProducts";
import type { Product } from "@/types/product";

type Props = {
  categoria: string;
  title?: string;
};

function asProductList(payload: unknown): Product[] {
  if (Array.isArray(payload)) return payload as Product[];
  if (
    payload &&
    typeof payload === "object" &&
    "data" in (payload as any) &&
    Array.isArray((payload as any).data)
  ) {
    return (payload as any).data as Product[];
  }
  return [];
}

export default function CategoryPage({ categoria, title }: Props) {
  const { data, loading, error } = useFetchProducts({
    categorySlug: categoria,
  });
  const products: Product[] = asProductList(data);
  const [selected, setSelected] = useState<string>("");

  const subcategorias = useMemo(() => {
    const set = new Set(
      products.map((p) => p.third_category).filter(Boolean) as string[],
    );
    return Array.from(set);
  }, [products]);

  const filtered = useMemo(() => {
    if (!selected) return products;
    return products.filter((p) => p.third_category === selected);
  }, [products, selected]);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[50vh] px-4">
        <div className="flex flex-col items-center text-center">
          <div className="animate-spin rounded-full h-10 w-10 sm:h-12 sm:w-12 border-b-2 border-emerald-500 mb-3" />
          <p className="text-gray-600 text-sm sm:text-base font-medium">
            Carregando produtos...
          </p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[50vh] text-center px-4">
        <p className="text-red-600 font-semibold mb-1 sm:mb-2">
          Erro ao carregar produtos
        </p>
        <p className="text-gray-500 text-xs sm:text-sm">{String(error)}</p>
      </div>
    );
  }

  return (
    <section className="container mx-auto px-4 sm:px-6 lg:px-10 py-8 sm:py-10">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 sm:gap-4 mb-6 sm:mb-8">
        <h1 className="text-2xl sm:text-4xl font-bold text-emerald-700 tracking-tight">
          {title ?? categoria}
        </h1>

        {subcategorias.length > 0 && (
          <select
            className="w-full sm:w-auto border border-gray-300 rounded-lg px-3 py-2 text-sm shadow-sm focus:ring-2 focus:ring-emerald-500 transition"
            value={selected}
            onChange={(e) => setSelected(e.target.value)}
          >
            <option value="">Todas as Subcategorias</option>
            {subcategorias.map((sc) => (
              <option key={sc} value={sc}>
                {sc}
              </option>
            ))}
          </select>
        )}
      </div>

      {filtered.length === 0 ? (
        <div className="text-center text-gray-500 py-12 sm:py-16">
          <p className="text-base sm:text-lg font-medium">
            Nenhum item encontrado.
          </p>
          <p className="text-xs sm:text-sm text-gray-400 mt-1">
            Tente outra subcategoria ou volte mais tarde.
          </p>
        </div>
      ) : (
        <div className="grid gap-4 sm:gap-6 grid-cols-2 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4">
          {filtered.map((product) => (
            <ProductCard key={product.id} product={product} />
          ))}
        </div>
      )}
    </section>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import Image from "next/image";
import { Product } from "@/types/product";
import { api } from "@/lib/api";

type PromoProduct = Product & {
  image?: string | null;
  original_price?: number | string | null;
  final_price?: number | string | null;
  discount_percent?: number | string | null;
  promo_price?: number | string | null;
  ends_at?: string | null;
};

const SLIDE_INTERVAL = 6000; // 6s
const API_BASE = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:5000";
const PLACEHOLDER =
  "https://via.placeholder.com/600x400?text=Produto+sem+imagem";

// mesma ideia que usamos no admin
function getImageUrl(raw?: string | null): string {
  if (!raw) return PLACEHOLDER;

  let p = String(raw).trim().replace(/\\/g, "/");

  // já é URL completa
  if (/^https?:\/\//i.test(p)) return p;

  // remove barras iniciais duplicadas
  p = p.replace(/^\/+/, "");

  // se vier só "uploads/..." já funciona
  return `${API_BASE}/${p}`;
}

export default function PromocoesHero() {
  const [promocoes, setPromocoes] = useState<PromoProduct[]>([]);
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    const fetchPromocoes = async () => {
      try {
        const data = await api("/api/public/promocoes");
        const list = Array.isArray(data) ? data : [];

        const mapped: PromoProduct[] = list.map((item: any) => {
          const originalNum = Number(item.original_price ?? item.price ?? 0);
          const finalNum = Number(
            item.final_price ??
              item.promo_price ??
              item.price ??
              item.original_price ??
              0,
          );

          const discountNum =
            item.discount_percent != null
              ? Number(item.discount_percent)
              : originalNum > 0
                ? ((originalNum - finalNum) / originalNum) * 100
                : 0;

          return {
            ...(item as Product),
            image: item.image ?? item.main_image ?? item.foto ?? null,
            price: finalNum,
            preco: finalNum,
            original_price: originalNum,
            final_price: finalNum,
            discount_percent: discountNum > 0 ? discountNum : null,
            promo_price:
              item.promo_price != null ? Number(item.promo_price) : null,
            ends_at: item.ends_at ?? null,
          };
        });

        setPromocoes(mapped);
        setCurrent(0);
      } catch (err) {
        console.error("Erro ao buscar promoções:", err);
      }
    };

    fetchPromocoes();
  }, []);

  // autoplay
  useEffect(() => {
    if (promocoes.length <= 1) return;

    const id = setInterval(
      () => setCurrent((prev) => (prev + 1 >= promocoes.length ? 0 : prev + 1)),
      SLIDE_INTERVAL,
    );

    return () => clearInterval(id);
  }, [promocoes.length]);

  if (promocoes.length === 0) return null;

  const produto = promocoes[current];

  const original = Number(produto.original_price ?? produto.price ?? 0);
  const final = Number(produto.final_price ?? produto.price ?? 0);

  const desconto =
    produto.discount_percent != null
      ? Number(produto.discount_percent)
      : original > 0
        ? ((original - final) / original) * 100
        : 0;

  const endsAt = produto.ends_at;
  const imageUrl = getImageUrl(produto.image as string | null);

  return (
    <section className="mb-10 px-4 sm:px-6 lg:px-10">
      <div className="relative overflow-hidden rounded-3xl bg-emerald-700/95 px-4 py-6 text-white shadow-lg sm:px-8 sm:py-8 lg:px-10 lg:py-10">
        {/* fundo decorativo */}
        <div className="pointer-events-none absolute inset-0 opacity-40">
          <div className="absolute -left-10 -top-10 h-40 w-40 rounded-full bg-emerald-500 blur-3xl" />
          <div className="absolute bottom-0 right-0 h-48 w-48 rounded-full bg-amber-400 blur-3xl" />
        </div>

        <div className="relative z-10 flex flex-col gap-6 lg:flex-row lg:items-center lg:justify-between">
          {/* Texto da oferta */}
          <div className="max-w-xl">
            <span className="text-[11px] font-semibold uppercase tracking-[0.16em] text-amber-200">
              Ofertas especiais
            </span>
            <h2 className="mt-1 text-2xl font-extrabold leading-tight sm:text-3xl lg:text-4xl">
              Produtos em Promoção
            </h2>
            <p className="mt-2 text-sm text-emerald-50/90 sm:text-base">
              Descontos selecionados com carinho para o produtor rural.
              Aproveite preços especiais por tempo limitado nas principais
              soluções do Kavita.
            </p>

            <div className="mt-4 rounded-2xl bg-emerald-900/40 p-3 text-sm sm:p-4">
              <p className="text-xs font-semibold uppercase tracking-wide text-emerald-200">
                Oferta em destaque
              </p>
              <p className="mt-1 text-lg font-semibold">{produto.name}</p>

              {produto.description && (
                <p className="mt-1 line-clamp-2 text-xs text-emerald-100/90 sm:text-sm">
                  {produto.description}
                </p>
              )}

              <div className="mt-3 flex flex-wrap items-baseline gap-2 text-sm">
                {original > final && (
                  <span className="text-xs text-emerald-200 line-through">
                    R$ {original.toFixed(2)}
                  </span>
                )}
                <span className="text-xl font-extrabold text-amber-200">
                  R$ {final.toFixed(2)}
                </span>
                {desconto > 0 && (
                  <span className="rounded-full bg-amber-300/90 px-2 py-0.5 text-[11px] font-bold text-emerald-900">
                    -{desconto.toFixed(0)}% OFF
                  </span>
                )}
              </div>

              {endsAt && (
                <p className="mt-1 text-[11px] text-amber-100">
                  Válido até{" "}
                  {new Date(endsAt).toLocaleDateString("pt-BR", {
                    day: "2-digit",
                    month: "2-digit",
                  })}
                  , ou enquanto durarem os estoques.
                </p>
              )}

              <div className="mt-4 flex flex-wrap gap-3">
                <Link
                  href={`/produtos/${produto.id}`}
                  className="inline-flex items-center justify-center rounded-full bg-amber-300 px-5 py-2 text-sm font-semibold text-emerald-900 shadow-md transition hover:bg-amber-200"
                >
                  Ver oferta
                </Link>
              </div>
            </div>
          </div>

          {/* Imagem grande do produto */}
          <div className="mx-auto w-full max-w-xs sm:max-w-sm lg:max-w-md">
            <div className="relative overflow-hidden rounded-3xl bg-white/95 shadow-xl">
              <div className="relative h-56 w-full sm:h-64 lg:h-72">
                <Image
                  src={imageUrl}
                  alt={produto.name}
                  fill
                  className="object-cover"
                  sizes="(max-width:768px) 100vw, (max-width:1024px) 50vw, 40vw"
                />
              </div>

              <div className="border-t border-emerald-100/60 px-4 py-3 text-xs text-emerald-900/90 sm:px-5 sm:py-4">
                <p className="line-clamp-1 font-semibold">{produto.name}</p>
              </div>

              {desconto > 0 && (
                <span className="absolute left-3 top-3 rounded-full bg-red-500 px-2 py-0.5 text-xs font-bold text-white shadow-md">
                  -{desconto.toFixed(0)}%
                </span>
              )}
            </div>
          </div>
        </div>

        {/* Bolinhas de navegação */}
        {promocoes.length > 1 && (
          <div className="relative z-10 mt-5 flex justify-center gap-2">
            {promocoes.map((_, index) => (
              <button
                key={index}
                type="button"
                onClick={() => setCurrent(index)}
                className={`h-2.5 rounded-full transition ${
                  index === current
                    ? "w-6 bg-amber-300"
                    : "w-2 bg-emerald-200/60 hover:bg-amber-200"
                }`}
                aria-label={`Ir para promoção ${index + 1}`}
              />
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

"use client";

import React, { useMemo, useState, useEffect, useCallback } from "react";
import Link from "next/link";
import Image from "next/image";
import { Heart } from "lucide-react";
import AddToCartButton from "@/components/buttons/AddToCartButton";
import type { Product } from "@/types/product";
import { resolveStockValue } from "../../utils/stock";
import { useAuth } from "@/context/AuthContext";

type Props = {
  product: Product;
  images?: string[];
  className?: string;
  initialIsFavorite?: boolean;
};

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";
const PLACEHOLDER = "/placeholder.png";

/** normaliza URL de imagem */
function absUrl(raw?: string | null): string | null {
  if (!raw) return null;
  const src = String(raw).trim().replace(/\\/g, "/");
  if (/^https?:\/\//i.test(src)) return src;
  if (src.startsWith("/uploads")) return `${API_BASE}${src}`;
  if (src.startsWith("uploads")) return `${API_BASE}/${src}`;
  if (!src.startsWith("/")) return `${API_BASE}/uploads/${src}`;
  return `${API_BASE}${src}`;
}

/** formatador BRL determinístico */
function formatBRL(value: unknown): string {
  const n = Number(value ?? 0);
  const [int, dec] = n.toFixed(2).split(".");
  const mil = int.replace(/\B(?=(\d{3})+(?!\d))/g, ".");
  return `R$ ${mil},${dec}`;
}

// Promoção vinda da rota pública
type ProductPromotion = {
  id: number;
  product_id?: number;
  title?: string | null;
  original_price?: number | string | null;
  final_price?: number | string | null;
  discount_percent?: number | string | null;
  promo_price?: number | string | null;
  ends_at?: string | null;
};

export default function ProductCard({
  product,
  images: externalImages,
  className = "",
  initialIsFavorite,
}: Props) {
  const { user } = useAuth(); // pega user + token do contexto

  // === Imagens ===
  const images = useMemo(() => {
    if (externalImages?.length) {
      const norm = externalImages.map(absUrl).filter(Boolean) as string[];
      return norm.length ? norm : [PLACEHOLDER];
    }
    const extras: string[] = Array.isArray(product.images)
      ? (product.images as unknown as string[])
      : [];
    const all = [product.image, ...extras].filter(Boolean) as string[];
    const uniq = Array.from(new Set(all))
      .map(absUrl)
      .filter(Boolean) as string[];
    return uniq.length ? uniq : [PLACEHOLDER];
  }, [externalImages, product.image, product.images]);

  const cover = images[0] ?? PLACEHOLDER;

  // === Estoque ===
  const stock = resolveStockValue(
    (product as any).quantity,
    (product as any).estoque,
    (product as any).stock,
  );
  const outOfStock = typeof stock === "number" ? stock <= 0 : false;

  // === Frete grátis (badge) ===
  // Regra de negócio:
  // shipping_free = 1 => produto tem frete grátis
  // shipping_free_from_qty null => sempre grátis
  // shipping_free_from_qty número => grátis a partir daquela quantidade
  const shippingFree = Boolean((product as any).shipping_free);
  const shippingFreeFromQty =
    (product as any).shipping_free_from_qty != null
      ? Number((product as any).shipping_free_from_qty)
      : null;

  // === Avaliação (⭐) ===
  const ratingAvgRaw = (product as any).rating_avg;
  const ratingCountRaw = (product as any).rating_count;

  const ratingAvg =
    ratingAvgRaw !== null && ratingAvgRaw !== undefined
      ? Number(ratingAvgRaw)
      : NaN;
  const ratingCount =
    ratingCountRaw !== null && ratingCountRaw !== undefined
      ? Number(ratingCountRaw)
      : 0;

  const hasRating =
    !Number.isNaN(ratingAvg) && ratingAvg > 0 && ratingCount > 0;

  // === Promoção / desconto ===
  const [promotion, setPromotion] = useState<ProductPromotion | null>(null);

  useEffect(() => {
    let ignore = false;

    async function fetchPromotion() {
      try {
        if (!product?.id) return;

        const res = await fetch(
          `${API_BASE}/api/public/promocoes/${product.id}`,
        );

        if (!res.ok) {
          // 404 = não tem promo pra esse produto, só ignora
          return;
        }

        const data = await res.json();
        if (!ignore) {
          setPromotion(data as ProductPromotion);
        }
      } catch (err) {
        console.error("[ProductCard] erro ao buscar promoção:", err);
      }
    }

    fetchPromotion();

    return () => {
      ignore = true;
    };
  }, [product?.id]);

  // === Cálculo de preço final (mesma lógica do produto) ===
  const precoBase = Number(product.price ?? 0);

  const originalFromPromo =
    promotion?.original_price != null ? Number(promotion.original_price) : null;
  const finalFromPromo =
    promotion?.final_price != null
      ? Number(promotion.final_price)
      : promotion?.promo_price != null
        ? Number(promotion.promo_price)
        : null;

  const originalPrice =
    originalFromPromo !== null ? originalFromPromo : precoBase || 0;

  let finalPrice = finalFromPromo !== null ? finalFromPromo : originalPrice;

  let discountPercent: number | null = null;

  if (promotion) {
    const explicitDiscount =
      promotion.discount_percent != null
        ? Number(promotion.discount_percent)
        : NaN;

    // se veio só % de desconto sem final_price calculado
    if (
      finalFromPromo === null &&
      !Number.isNaN(explicitDiscount) &&
      explicitDiscount > 0 &&
      originalPrice > 0
    ) {
      finalPrice = originalPrice * (1 - explicitDiscount / 100);
    }

    // calcula % real
    if (originalPrice > 0 && finalPrice < originalPrice) {
      discountPercent = ((originalPrice - finalPrice) / originalPrice) * 100;
    } else if (!Number.isNaN(explicitDiscount) && explicitDiscount > 0) {
      discountPercent = explicitDiscount;
    }
  }

  const hasDiscount =
    discountPercent !== null &&
    discountPercent > 0 &&
    finalPrice < originalPrice;

  // produto que vai para o carrinho com o PREÇO FINAL
  const productForCart: Product = {
    ...product,
    price: finalPrice,
  };

  // === Favoritos ===
  const [isFavorite, setIsFavorite] = useState<boolean>(false);
  const [favLoading, setFavLoading] = useState(false);

  useEffect(() => {
    if (initialIsFavorite) setIsFavorite(true);
  }, [initialIsFavorite]);

  const handleToggleFavorite = useCallback(async () => {
    // se não tiver user, manda pra login
    if (!user) {
      if (typeof window !== "undefined") {
        window.location.href = "/login";
      }
      return;
    }

    const token = (user as any).token;
    if (!token) {
      console.warn("Usuário logado mas sem token. Faça login novamente.");
      return;
    }

    if (favLoading) return;

    const wasFavorite = isFavorite;
    setIsFavorite(!wasFavorite);
    setFavLoading(true);

    try {
      const url = wasFavorite
        ? `${API_BASE}/api/favorites/${product.id}`
        : `${API_BASE}/api/favorites`;

      const options: RequestInit = {
        method: wasFavorite ? "DELETE" : "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
      };

      if (!wasFavorite) {
        options.body = JSON.stringify({ productId: product.id });
      }

      const res = await fetch(url, options);

      if (!res.ok) {
        // desfaz se der erro
        setIsFavorite(wasFavorite);
        console.error("Falha ao atualizar favorito");
      }
    } catch (err) {
      console.error("Erro ao chamar /api/favorites:", err);
      setIsFavorite(wasFavorite);
    } finally {
      setFavLoading(false);
    }
  }, [user, isFavorite, favLoading, product.id]);

  return (
    <article
      className={[
        "group relative flex h-full flex-col rounded-2xl border border-gray-200 bg-white",
        "shadow-sm hover:shadow-md transition-shadow",
        "ring-1 ring-gray-100 hover:ring-emerald-200/70",
        "p-3 sm:p-4",
        className,
      ].join(" ")}
    >
      {/* Botão de favorito */}
      <button
        type="button"
        onClick={handleToggleFavorite}
        aria-pressed={isFavorite}
        disabled={favLoading}
        className="
          absolute right-3 top-3 z-20
          inline-flex h-9 w-9 items-center justify-center
          rounded-full bg-white/95
          border border-gray-200
          shadow-sm
          hover:bg-white hover:border-rose-300 hover:text-rose-500
          transition
        "
      >
        <Heart
          className="h-4 w-4"
          fill={isFavorite ? "currentColor" : "none"}
        />
      </button>

      {/* Imagem */}
      <Link
        href={`/produtos/${product.id}`}
        aria-label={`Ver detalhes de ${product.name}`}
        prefetch={false}
        className="relative block w-full overflow-hidden rounded-xl bg-gray-50"
      >
        <div className="relative w-full aspect-[4/3] sm:aspect-[16/11]">
          <Image
            src={cover}
            alt={product.name}
            fill
            className="object-cover transition-transform duration-300 group-hover:scale-[1.02]"
            sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 33vw"
          />
        </div>

        {/* Badges */}
        <div className="absolute left-2 top-2 z-10 flex flex-col gap-1">
          {outOfStock && (
            <span className="rounded-full bg-red-600 px-2.5 py-1 text-[10px] font-semibold uppercase tracking-wide text-white shadow-sm">
              Esgotado
            </span>
          )}

          {hasDiscount && !outOfStock && (
            <span className="rounded-full bg-red-500 px-2.5 py-1 text-[10px] font-semibold uppercase tracking-wide text-white shadow-sm">
              -{discountPercent!.toFixed(0)}% OFF
            </span>
          )}

          {shippingFree && !outOfStock && (
            <span className="rounded-full bg-emerald-600 px-2.5 py-1 text-[10px] font-semibold uppercase tracking-wide text-white shadow-sm">
              {shippingFreeFromQty
                ? `Frete grátis a partir de ${shippingFreeFromQty} un.`
                : "Frete grátis"}
            </span>
          )}
        </div>
      </Link>

      {/* Conteúdo */}
      <div className="mt-3 flex flex-1 flex-col">
        <Link
          href={`/produtos/${product.id}`}
          prefetch={false}
          className="min-h-[44px] line-clamp-2 text-sm sm:text-[15px] font-semibold text-gray-900 hover:underline underline-offset-2"
        >
          {product.name}
        </Link>

        {/* ⭐ Avaliação resumida */}
        {hasRating && (
          <div className="mt-1 flex items-center gap-1 text-xs text-amber-600">
            <span>⭐ {ratingAvg.toFixed(1)}</span>
            <span className="text-[11px] text-gray-500">
              ({ratingCount} avaliação{ratingCount > 1 ? "s" : ""})
            </span>
          </div>
        )}

        {product.description && (
          <p className="mt-1 min-h-[36px] line-clamp-2 text-xs sm:text-sm text-gray-600">
            {product.description}
          </p>
        )}

        {/* Preço + desconto */}
        <div className="mt-3 space-y-0.5">
          {hasDiscount && (
            <div className="text-xs text-gray-400 line-through">
              {formatBRL(originalPrice)}
            </div>
          )}
          <span className="text-lg sm:text-xl font-extrabold text-emerald-600">
            {formatBRL(finalPrice)}
          </span>
        </div>

        <div className="mt-auto pt-4 flex flex-col gap-2">
          <div className="w-full">
            <AddToCartButton product={productForCart} disabled={outOfStock} />
          </div>

          <Link
            href={`/produtos/${product.id}`}
            prefetch={false}
            className="w-full inline-flex items-center justify-center rounded-lg border border-gray-300 px-3 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50"
          >
            Ver detalhes
          </Link>
        </div>
      </div>
    </article>
  );
}

"use client";

import Link from "next/link";

type UiProduct = {
  id: number;
  name: string;
  description?: string;
  image: string;
  original_price: number | null;
  final_price: number | null;
  discount_percent: number | null;
  isPromo: boolean;
};

type Props = {
  loading: boolean;
  products: UiProduct[];
  empty: React.ReactNode;
};

function formatBRL(n: number) {
  return n.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

export function ProductGrid({ loading, products, empty }: Props) {
  if (loading) {
    return (
      <div className="grid grid-cols-2 gap-3 md:grid-cols-3 lg:grid-cols-4">
        {Array.from({ length: 12 }).map((_, i) => (
          <div
            key={i}
            className="h-56 rounded-xl border border-zinc-200 bg-white shadow-sm"
          >
            <div className="h-32 w-full animate-pulse rounded-t-xl bg-zinc-100" />
            <div className="space-y-2 p-3">
              <div className="h-4 w-3/4 animate-pulse rounded bg-zinc-100" />
              <div className="h-4 w-1/2 animate-pulse rounded bg-zinc-100" />
              <div className="h-4 w-2/5 animate-pulse rounded bg-zinc-100" />
            </div>
          </div>
        ))}
      </div>
    );
  }

  if (!products || products.length === 0) return <>{empty}</>;

  return (
    <div className="grid grid-cols-2 gap-3 md:grid-cols-3 lg:grid-cols-4">
      {products.map((p) => {
        const hasDiscount =
          p.original_price != null &&
          p.final_price != null &&
          p.final_price < p.original_price;

        return (
          <Link
            key={p.id}
            href={`/produto/${p.id}`}
            className="group overflow-hidden rounded-xl border border-zinc-200 bg-white shadow-sm transition hover:shadow-md"
          >
            <div className="relative h-40 w-full bg-zinc-50">
              <img
                src={p.image}
                alt={p.name}
                className="h-full w-full object-contain p-3 transition group-hover:scale-[1.02]"
                loading="lazy"
              />
              {p.isPromo || hasDiscount ? (
                <span className="absolute left-2 top-2 rounded-full bg-emerald-600 px-2 py-1 text-xs font-semibold text-white">
                  Promo
                </span>
              ) : null}
            </div>

            <div className="p-3">
              <h3 className="line-clamp-2 text-sm font-semibold text-zinc-900">
                {p.name}
              </h3>

              <div className="mt-2">
                {hasDiscount ? (
                  <div className="flex items-baseline gap-2">
                    <span className="text-sm font-bold text-emerald-700">
                      {formatBRL(p.final_price!)}
                    </span>
                    <span className="text-xs text-zinc-500 line-through">
                      {formatBRL(p.original_price!)}
                    </span>
                  </div>
                ) : p.final_price != null ? (
                  <span className="text-sm font-bold text-zinc-900">
                    {formatBRL(p.final_price)}
                  </span>
                ) : null}

                {p.discount_percent != null && p.discount_percent > 0 ? (
                  <p className="mt-1 text-xs font-medium text-emerald-700">
                    {p.discount_percent}% OFF
                  </p>
                ) : null}
              </div>
            </div>
          </Link>
        );
      })}
    </div>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import ProductCard from "./ProductCard";
import type { Product } from "@/types/product";

type Props = { categoria: string; limit?: number };

const API = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:5000";

function normalizeProducts(payload: any): Product[] {
  if (!payload) return [];
  if (Array.isArray(payload)) return payload;
  const cands = [
    "items",
    "data",
    "results",
    "rows",
    "products",
    "list",
    "content",
  ] as const;
  for (const key of cands) {
    if (Array.isArray(payload?.[key])) return payload[key] as Product[];
    if (Array.isArray(payload?.data?.[key]))
      return payload.data[key] as Product[];
  }
  return [];
}

export default function ProdutosPorCategoria({ categoria, limit = 12 }: Props) {
  const [list, setList] = useState<Product[]>([]);
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const wrapRef = useRef<HTMLDivElement>(null);
  const [hasOverflow, setHasOverflow] = useState(false);

  useEffect(() => {
    const el = wrapRef.current;
    if (!el) return;
    const check = () => setHasOverflow(el.scrollWidth > el.clientWidth + 8);
    check();
    const obs = new ResizeObserver(check);
    obs.observe(el);
    return () => obs.disconnect();
  }, [list.length]);

  useEffect(() => {
    const ctrl = new AbortController();
    (async () => {
      try {
        setLoading(true);
        setErrorMsg(null);
        setList([]);

        const url = `${API}/api/products?category=${encodeURIComponent(
          categoria,
        )}`;
        const res = await fetch(url, {
          signal: ctrl.signal,
          cache: "no-store",
        });
        const text = await res.text();

        if (!res.ok) throw new Error(text || res.statusText);

        const json = text ? JSON.parse(text) : [];
        const arr = normalizeProducts(json).slice(0, limit);
        setList(arr);
      } catch (e: any) {
        if (e?.name !== "AbortError")
          setErrorMsg("Não foi possível carregar produtos.");
        console.warn("ProdutosPorCategoria:", e);
      } finally {
        setLoading(false);
      }
    })();
    return () => ctrl.abort();
  }, [categoria, limit]);

  const skeletons = useMemo(
    () => new Array(Math.min(5, limit)).fill(0),
    [limit],
  );

  const handleScroll = (direction: "left" | "right") => {
    const el = wrapRef.current;
    if (!el) return;
    const amount = el.clientWidth * 0.8;
    el.scrollBy({
      left: direction === "left" ? -amount : amount,
      behavior: "smooth",
    });
  };

  return (
    <div className="relative">
      <div className="rounded-3xl border border-emerald-50 bg-emerald-50/50 px-2 py-3 shadow-sm sm:px-3 lg:px-4">
        <div className="relative group">
          {hasOverflow && (
            <>
              <div className="pointer-events-none absolute left-0 top-0 h-full w-10 rounded-l-3xl bg-gradient-to-r from-emerald-50 via-emerald-50/70 to-transparent" />
              <div className="pointer-events-none absolute right-0 top-0 h-full w-10 rounded-r-3xl bg-gradient-to-l from-emerald-50 via-emerald-50/70 to-transparent" />
            </>
          )}

          {/* SETAS – um pouco para fora e com visual melhor */}
          {hasOverflow && !loading && list.length > 0 && (
            <>
              <button
                type="button"
                onClick={() => handleScroll("left")}
                className="hidden md:flex absolute -left-4 top-1/2 z-30 h-10 w-10 -translate-y-1/2 items-center justify-center rounded-full bg-white text-emerald-700 shadow-lg ring-1 ring-emerald-200 hover:bg-emerald-50 hover:text-emerald-800 focus:outline-none focus:ring-2 focus:ring-emerald-400"
                aria-label="Voltar produtos"
              >
                <span className="text-xl leading-none">&lsaquo;</span>
              </button>

              <button
                type="button"
                onClick={() => handleScroll("right")}
                className="hidden md:flex absolute -right-4 top-1/2 z-30 h-10 w-10 -translate-y-1/2 items-center justify-center rounded-full bg-white text-emerald-700 shadow-lg ring-1 ring-emerald-200 hover:bg-emerald-50 hover:text-emerald-800 focus:outline-none focus:ring-2 focus:ring-emerald-400"
                aria-label="Avançar produtos"
              >
                <span className="text-xl leading-none">&rsaquo;</span>
              </button>
            </>
          )}

          <div
            ref={wrapRef}
            className="no-scrollbar flex snap-x snap-mandatory scroll-smooth gap-4 overflow-x-auto py-1 pl-1 pr-6 sm:gap-5 sm:py-2 sm:pl-1 sm:pr-8 lg:gap-6 lg:py-3 lg:pl-1 lg:pr-10 [-ms-overflow-style:none] [scrollbar-width:none]"
            style={{ WebkitOverflowScrolling: "touch" }}
          >
            <style>{`.no-scrollbar::-webkit-scrollbar{display:none}`}</style>

            {loading &&
              skeletons.map((_, i) => (
                <div
                  key={i}
                  className="min-w-[220px] max-w-[220px] snap-start rounded-2xl bg-white/90 p-3 shadow-sm ring-1 ring-emerald-100 sm:min-w-[240px] sm:max-w-[240px] lg:min-w-[250px] lg:max-w-[250px]"
                >
                  <div className="h-40 w-full animate-pulse rounded-xl bg-emerald-100/80 sm:h-44" />
                  <div className="mt-3 h-4 w-3/4 animate-pulse rounded-full bg-emerald-100/80" />
                  <div className="mt-2 h-4 w-1/2 animate-pulse rounded-full bg-emerald-100/70" />
                  <div className="mt-4 h-10 w-full animate-pulse rounded-full bg-emerald-100/80" />
                </div>
              ))}

            {!loading && errorMsg && (
              <div className="py-6 text-sm font-medium text-red-600">
                {errorMsg}
              </div>
            )}

            {!loading && !errorMsg && list.length === 0 && (
              <div className="py-6 text-sm text-emerald-900/80">
                Sem produtos nessa categoria.
              </div>
            )}

            {!loading &&
              !errorMsg &&
              list.map((p) => (
                <div
                  key={p.id}
                  className="min-w-[220px] max-w-[220px] snap-start sm:min-w-[240px] sm:max-w-[240px] lg:min-w-[250px] lg:max-w-[250px]"
                >
                  <ProductCard product={p as any} />
                </div>
              ))}
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";

type Produto = {
  id: number;
  name: string;
  price?: number;
  image?: string | null;
  images?: string[] | null;
};

type Props = {
  placeholder?: string;
  className?: string;
  /** chamado quando o usuário escolhe um produto (clique ou Enter) */
  onPick: (produto: Produto) => void;
  /** base do backend; opcional (usa env/localhost por padrão) */
  apiBase?: string;
};

// Se tiver um arquivo em public/placeholder.png, pode trocar por "/placeholder.png"
const PLACEHOLDER = "https://via.placeholder.com/80?text=Img";
const API_DEFAULT =
  process.env.NEXT_PUBLIC_API_BASE ||
  process.env.NEXT_PUBLIC_API_URL ||
  "http://localhost:5000";

/* ------------------------- Utils de normalização ------------------------- */

function toArray(json: any): any[] {
  if (Array.isArray(json)) return json;
  if (json && Array.isArray(json.data)) return json.data;
  if (json && Array.isArray(json.rows)) return json.rows;
  if (json && Array.isArray(json.items)) return json.items;
  if (json && Array.isArray(json.products)) return json.products;
  return [];
}

function toImageUrl(apiBase: string, raw?: string | null) {
  if (!raw) return PLACEHOLDER;
  const p = String(raw).trim().replace(/\\/g, "/");
  if (/^https?:\/\//i.test(p)) return p;
  const clean = p.replace(/^\/+/, "");
  if (clean.startsWith("uploads/")) return `${apiBase}/${clean}`;
  if (clean.startsWith("public/")) return `${apiBase}/${clean}`;
  return `${apiBase}/uploads/${clean}`;
}

/* --------------------------------- Componente -------------------------------- */

export default function SearchInputProdutos({
  placeholder = "Buscar produto…",
  className = "",
  onPick,
  apiBase = API_DEFAULT,
}: Props) {
  const [all, setAll] = useState<Produto[]>([]);
  const [q, setQ] = useState("");
  const [open, setOpen] = useState(false);
  const [cursor, setCursor] = useState(-1);
  const [loading, setLoading] = useState(false);

  // Carrega os produtos uma vez (endpoint público)
  useEffect(() => {
    (async () => {
      setLoading(true);
      try {
        const res = await fetch(
          `${apiBase}/api/products?category=all&limit=1000&sort=name&order=asc`,
          { cache: "no-store" },
        );
        if (!res.ok) {
          const txt = await res.text().catch(() => "");
          throw new Error(`Falha ao listar produtos (${res.status}): ${txt}`);
        }
        const json = await res.json();
        const arr = toArray(json);

        const list: Produto[] = arr.map((p: any) => ({
          id: Number(p.id ?? p.product_id ?? 0),
          name: String(p.name ?? p.nome ?? ""),
          price: Number(p.price ?? p.preco ?? 0),
          image:
            p.image ??
            (Array.isArray(p.images) && p.images.length > 0
              ? p.images[0]
              : null),
          images: Array.isArray(p.images) ? p.images : null,
        }));

        setAll(list);
      } catch (err) {
        console.warn("[SearchInput] Erro ao carregar produtos:", err);
        setAll([]); // evita quebrar o UI
      } finally {
        setLoading(false);
      }
    })();
  }, [apiBase]);

  // Debounce do termo
  const [debounced, setDebounced] = useState(q);
  useEffect(() => {
    const t = setTimeout(() => setDebounced(q), 300);
    return () => clearTimeout(t);
  }, [q]);

  // Filtro local
  const results = useMemo(() => {
    const term = debounced.trim().toLowerCase();
    if (!term) return [];
    return all;
    return all.filter((p) => p.name.toLowerCase().includes(term));
  }, [debounced, all]);

  function choose(item: Produto) {
    onPick(item);
    setOpen(false);
    setQ("");
    setCursor(-1);
  }

  return (
    <div className={`relative ${className}`}>
      <div className="flex shadow rounded overflow-hidden bg-white">
        <input
          type="text"
          value={q}
          placeholder={placeholder}
          onChange={(e) => setQ(e.target.value)}
          onFocus={() => setOpen(true)}
          onBlur={() => setTimeout(() => setOpen(false), 150)}
          onKeyDown={(e) => {
            if (!results.length) return;
            if (e.key === "ArrowDown")
              setCursor((v) => Math.min(v + 1, results.length - 1));
            if (e.key === "ArrowUp") setCursor((v) => Math.max(v - 1, 0));
            if (e.key === "Enter" && cursor >= 0) choose(results[cursor]!);
          }}
          className="w-full px-4 py-2 text-sm text-gray-700 focus:outline-none"
        />
        <button
          type="button"
          className="px-3 border-l border-gray-200 bg-white"
          title="Pesquisar"
          aria-label="Pesquisar"
          onMouseDown={(e) => e.preventDefault()}
        >
          {/* Lupa laranja */}
          <svg
            xmlns="http://www.w3.org/2000/svg"
            width="18"
            height="18"
            viewBox="0 0 24 24"
            fill="none"
            stroke="#FF7A00"
            strokeWidth="2"
          >
            <circle cx="11" cy="11" r="8"></circle>
            <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
          </svg>
        </button>
      </div>

      {open && (
        <ul className="absolute z-20 w-full mt-1 max-h-64 overflow-y-auto border border-gray-200 bg-white rounded-md shadow">
          {loading ? (
            <li className="px-4 py-2 text-sm text-gray-500 italic">
              Carregando…
            </li>
          ) : results.length ? (
            results.map((p, i) => {
              const img = toImageUrl(apiBase, p.image);
              return (
                <li
                  key={p.id}
                  onMouseDown={() => choose(p)}
                  className={`flex items-center gap-3 px-4 py-2 cursor-pointer ${
                    i === cursor ? "bg-gray-100" : "hover:bg-gray-50"
                  }`}
                >
                  <img
                    src={img}
                    alt={p.name}
                    className="w-10 h-10 object-cover rounded"
                    onError={(e) =>
                      ((e.currentTarget as HTMLImageElement).src = PLACEHOLDER)
                    }
                  />
                  <div className="min-w-0">
                    <p className="text-sm font-medium text-gray-800 truncate">
                      {p.name}
                    </p>
                    {!!p.price && (
                      <p className="text-xs text-green-700">
                        R$ {Number(p.price).toFixed(2)}
                      </p>
                    )}
                  </div>
                </li>
              );
            })
          ) : debounced.trim() ? (
            <li className="px-4 py-2 text-sm text-gray-500 italic">
              Nenhum produto encontrado
            </li>
          ) : (
            <li className="px-4 py-2 text-sm text-gray-500 italic">
              Digite para buscar…
            </li>
          )}
        </ul>
      )}
    </div>
  );
}

"use client";

import { useMemo } from "react";

type Category = {
  id: number;
  name: string;
  slug?: string;
  total_products?: number;
};

export type FiltersState = {
  q: string;
  categories: number[];
  minPrice: number | null;
  maxPrice: number | null;
  promo: boolean;
};

type Props = {
  categories: Category[];
  categoriesLoading?: boolean;
  value: FiltersState;
  onChange: (patch: Partial<FiltersState>) => void;
  onClear: () => void;
  onApply?: () => void;
  stickyActions?: boolean;
  applyLabel?: string;
};

function safeNumberOrNull(v: string): number | null {
  const s = v.trim();
  if (!s) return null;
  const n = Number(s.replace(",", "."));
  return Number.isFinite(n) ? n : null;
}

export function FiltersPanel({
  categories,
  categoriesLoading,
  value,
  onChange,
  onClear,
  onApply,
  stickyActions = false,
  applyLabel = "Aplicar filtros",
}: Props) {
  const selectedCount = useMemo(() => {
    let c = 0;
    if (value.q?.trim()) c++;
    if (value.categories?.length) c++;
    if (value.minPrice != null || value.maxPrice != null) c++;
    if (value.promo) c++;
    return c;
  }, [value]);

  const minStr = value.minPrice == null ? "" : String(value.minPrice);
  const maxStr = value.maxPrice == null ? "" : String(value.maxPrice);

  const hasCategories = (categories || []).length > 0;

  const selectedCategoryId = value.categories?.[0] ?? 0;

