"use client";

import React, { useEffect, useMemo, useRef, useState } from "react";
import { useRouter } from "next/navigation";
import { FaSearch, FaCartPlus } from "react-icons/fa";
import { useCart } from "@/context/CartContext";

type ResultItem =
  | {
      type: "produto";
      id: number;
      name: string;
      price: number;
      image?: string;
      images?: string[];
    }
  | {
      type: "servico";
      id: number;
      name: string;
      price: number;
      image?: string;
      images?: string[];
    };

type CartItem = Parameters<ReturnType<typeof useCart>["addToCart"]>[0];

const PLACEHOLDER = "/placeholder.png";
const ORANGE = "#FF7A00";

/** Blindado: nunca gera /api/api */
function getApiBase(): string {
  const raw =
    process.env.NEXT_PUBLIC_API_BASE_URL ||
    process.env.NEXT_PUBLIC_API_URL ||
    "http://localhost:5000";
  const base = raw.replace(/\/+$/, "");
  return base.endsWith("/api") ? base : `${base}/api`;
}

const API_BASE = getApiBase();

function safeNumber(v: unknown, fallback = 0): number {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function toArray<T = any>(data: any): T[] {
  if (Array.isArray(data)) return data as T[];
  if (data?.products && Array.isArray(data.products))
    return data.products as T[];
  if (data?.data && Array.isArray(data.data)) return data.data as T[];
  if (data?.items && Array.isArray(data.items)) return data.items as T[];
  if (data?.results && Array.isArray(data.results)) return data.results as T[];
  return [];
}

function resolveImage(raw?: unknown): string {
  if (!raw) return PLACEHOLDER;

  if (typeof raw === "object" && raw !== null) {
    const anyRaw = raw as any;
    const candidate =
      anyRaw.url || anyRaw.path || anyRaw.src || anyRaw.image || anyRaw.imagem;
    return candidate ? resolveImage(candidate) : PLACEHOLDER;
  }

  const src = String(raw).trim().replace(/\\/g, "/");
  if (!src) return PLACEHOLDER;

  if (/^https?:\/\//i.test(src)) return src;

  const serverBase = API_BASE.replace(/\/api$/, "");

  if (src.startsWith("/uploads")) return `${serverBase}${src}`;
  if (src.startsWith("uploads")) return `${serverBase}/${src}`;

  return `${serverBase}/uploads/${src}`;
}

function formatPrice(v: unknown): string {
  const n = parseFloat(
    String(v ?? "")
      .replace(/[^0-9,.-]/g, "")
      .replace(",", "."),
  );
  return Number.isFinite(n) ? n.toFixed(2) : "0,00";
}

export default function SearchBar() {
  const router = useRouter();
  const { addToCart } = useCart();

  const [query, setQuery] = useState("");
  const [results, setResults] = useState<ResultItem[]>([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [cursor, setCursor] = useState(-1);

  const abortRef = useRef<AbortController | null>(null);

  // debounce
  useEffect(() => {
    const t = setTimeout(() => {
      const q = query.trim();
      if (q.length >= 1) doSearch(q);
      else {
        abortRef.current?.abort();
        setResults([]);
        setCursor(-1);
        setLoading(false);
      }
    }, 350);

    return () => clearTimeout(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [query]);

  // ✅ mappers tipados (resolve o erro do "type: string")
  const mapProduto = (p: any): ResultItem => {
    const price =
      p.final_price != null
        ? safeNumber(p.final_price, 0)
        : p.original_price != null
          ? safeNumber(p.original_price, 0)
          : safeNumber(p.price ?? p.preco, 0);

    const images = Array.isArray(p.images) ? p.images : [];
    const image = images?.[0] ?? p.image ?? null;

    return {
      type: "produto",
      id: Number(p.id),
      name: p.name ?? p.nome ?? "Produto",
      price,
      image: image || undefined,
      images,
    };
  };

  const mapServico = (s: any): ResultItem => {
    const images = Array.isArray(s.images) ? s.images : [];
    const image = s.imagem ?? s.image ?? images?.[0] ?? null;

    return {
      type: "servico",
      id: Number(s.id),
      name: s.nome ?? s.name ?? "Serviço",
      price: safeNumber(s.preco ?? s.price, 0),
      image: image || undefined,
      images,
    };
  };

  const doSearch = async (q: string) => {
    abortRef.current?.abort();
    const ctrl = new AbortController();
    abortRef.current = ctrl;

    setLoading(true);

    try {
      const produtosUrl = `${API_BASE}/products/search?q=${encodeURIComponent(q)}&page=1&limit=6&sort=newest`;
      const servicosUrl = `${API_BASE}/public/servicos?busca=${encodeURIComponent(q)}&page=1&limit=6&sort=id&order=desc`;

      const [prodRes, servRes] = await Promise.all([
        fetch(produtosUrl, { signal: ctrl.signal, credentials: "include" }),
        fetch(servicosUrl, { signal: ctrl.signal, credentials: "include" }),
      ]);

      const produtosJson = prodRes.ok ? await prodRes.json() : null;
      const servicosJson = servRes.ok ? await servRes.json() : null;

      const produtosRaw = toArray<any>(produtosJson);
      const servicosRaw = toArray<any>(servicosJson);

      const produtos: ResultItem[] = produtosRaw.map(mapProduto);
      const servicos: ResultItem[] = servicosRaw.map(mapServico);

      // ✅ agora TS entende que é ResultItem[]
      setResults([...produtos, ...servicos].slice(0, 12));
      setCursor(-1);
      setOpen(true);
    } catch (e: any) {
      if (e?.name === "AbortError") return;
      console.error("Search error:", e);
      setResults([]);
      setCursor(-1);
    } finally {
      setLoading(false);
    }
  };

  const goTo = (item: ResultItem) => {
    router.push(
      item.type === "produto" ? `/produtos/${item.id}` : `/servicos/${item.id}`,
    );
    setOpen(false);
    setQuery("");
    setResults([]);
    setCursor(-1);
  };

  const onKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "ArrowDown")
      setCursor((v) => Math.min(v + 1, results.length - 1));
    else if (e.key === "ArrowUp") setCursor((v) => Math.max(v - 1, 0));
    else if (e.key === "Escape") {
      setOpen(false);
      setCursor(-1);
    } else if (e.key === "Enter") {
      if (cursor >= 0 && results[cursor]) goTo(results[cursor]);
      else {
        const q = query.trim();
        if (q.length > 0) {
          setOpen(false);
          router.push(`/busca?q=${encodeURIComponent(q)}`);
        }
      }
    }
  };

  const onSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (cursor >= 0 && results[cursor]) return goTo(results[cursor]);

    const q = query.trim();
    if (q.length > 0) {
      setOpen(false);
      router.push(`/busca?q=${encodeURIComponent(q)}`);
    }
  };

  const ORANGE_ICON = useMemo(() => ({ color: ORANGE, fontSize: 16 }), []);

  return (
    <div className="relative w-full max-w-xl mx-auto">
      <form
        onSubmit={onSubmit}
        className="flex shadow rounded overflow-hidden bg-white"
      >
        <input
          type="text"
          placeholder="Buscar produto ou serviço..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onKeyDown={onKeyDown}
          onFocus={() => setOpen(true)}
          onBlur={() => setTimeout(() => setOpen(false), 150)}
          className="w-full px-4 py-2 text-sm text-gray-700 focus:outline-none"
          aria-label="Buscar"
          autoComplete="off"
        />
        <button
          type="submit"
          className="px-4 py-2 border-l border-gray-200 hover:bg-gray-50 transition"
          aria-label="Pesquisar"
          title="Pesquisar"
        >
          <FaSearch style={ORANGE_ICON} />
        </button>
      </form>

      {open && (
        <ul className="absolute w-full mt-1 z-20 max-h-64 overflow-y-auto border border-gray-200 bg-white rounded-md shadow">
          {loading ? (
            <li className="px-4 py-2 text-sm text-gray-500 italic">
              Carregando...
            </li>
          ) : results.length ? (
            results.map((item, i) => {
              const img = resolveImage(item.image || item.images?.[0]);

              return (
                <li
                  key={`${item.type}-${item.id}`}
                  onMouseDown={() => goTo(item)}
                  className={`flex justify-between items-center gap-3 px-4 py-3 cursor-pointer ${
                    i === cursor ? "bg-gray-100" : "hover:bg-gray-50"
                  }`}
                >
                  <div className="flex items-center gap-3">
                    {/* eslint-disable-next-line @next/next/no-img-element */}
                    <img
                      src={img}
                      alt={item.name}
                      className="w-12 h-12 object-cover rounded"
                    />
                    <div>
                      <p className="text-sm font-semibold text-gray-800">
                        {item.name}
                      </p>
                      <p className="text-xs text-gray-500">
                        {item.type === "produto" ? "Produto" : "Serviço"}
                      </p>
                      <p className="text-xs text-green-600 font-semibold">
                        R$ {formatPrice(item.price)}
                      </p>
                    </div>
                  </div>

                  {item.type === "produto" && (
                    <button
                      type="button"
                      onClick={(e) => {
                        e.stopPropagation();
                        const prod: CartItem = {
                          id: item.id,
                          name: item.name,
                          price: item.price,
                          image: item.image,
                          quantity: 1 as any,
                        } as CartItem;
                        addToCart(prod);
                      }}
                      className="hover:opacity-80"
                      title="Adicionar ao carrinho"
                      aria-label="Adicionar ao carrinho"
                    >
                      <FaCartPlus style={{ color: ORANGE, fontSize: 18 }} />
                    </button>
                  )}
                </li>
              );
            })
          ) : (
            <li className="px-4 py-2 text-sm text-gray-500 italic">
              Nenhum resultado encontrado
            </li>
          )}
        </ul>
      )}
    </div>
  );
}

"use client";

import React, {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  ReactNode,
} from "react";
import { api } from "@/lib/api";

// --------------------------------------------------
// Tipos
// --------------------------------------------------
export type AuthUser = {
  id: number;
  nome: string;
  email: string;
};

export type RegisterPayload = {
  nome: string;
  email: string;
  senha: string;
  cpf?: string; // <-- para não quebrar o /register
};

type AuthContextValue = {
  user: AuthUser | null;
  loading: boolean;

  login: (
    email: string,
    senha: string,
  ) => Promise<{ ok: boolean; message?: string }>;

  register: (
    payload: RegisterPayload,
  ) => Promise<{ ok: boolean; message?: string }>;

  logout: () => Promise<void>;
  refreshUser: () => Promise<void>;
};

const AuthContext = createContext<AuthContextValue | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [loading, setLoading] = useState(true);

  // -----------------------------
  // Carrega usuário pelo cookie
  // -----------------------------
  const refreshUser = async () => {
    try {
      const data = await api<AuthUser>("/api/users/me");
      setUser(data);
    } catch {
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    refreshUser();
  }, []);

  // -----------------------------
  // LOGIN (consistente e silencioso)
  // -----------------------------
  const login = async (email: string, senha: string) => {
    const invalidMsg = "Credenciais inválidas.";

    try {
      const data = await api<any>("/api/login", {
        method: "POST",
        body: JSON.stringify({ email, senha }),
      });

      const rawUser = data?.user ?? data;

      if (!rawUser?.id) {
        setUser(null);
        return { ok: false, message: invalidMsg };
      }

      const finalUser: AuthUser = {
        id: Number(rawUser.id),
        nome: rawUser.nome ?? "",
        email: rawUser.email ?? email,
      };

      setUser(finalUser);
      return { ok: true };
    } catch {
      setUser(null);
      return { ok: false, message: invalidMsg };
    }
  };

  // -----------------------------
  // REGISTER
  // -----------------------------
  const register = async (payload: RegisterPayload) => {
    const fallbackMsg = "Não foi possível criar sua conta.";

    try {
      await api<any>("/api/users/register", {
        method: "POST",
        body: JSON.stringify(payload),
      });

      // Se sua API já loga e seta cookie ao registrar, descomente:
      // await refreshUser();

      return { ok: true };
    } catch (err: any) {
      const msg =
        err?.message ||
        err?.response?.data?.message ||
        err?.data?.message ||
        fallbackMsg;

      return { ok: false, message: msg };
    }
  };

  // -----------------------------
  // LOGOUT
  // -----------------------------
  const logout = async () => {
    try {
      await api("/api/logout", { method: "POST" });
    } catch {
      // silencioso
    }
    setUser(null);
  };

  const value: AuthContextValue = useMemo(
    () => ({
      user,
      loading,
      login,
      register,
      logout,
      refreshUser,
    }),
    [user, loading],
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth deve ser usado dentro de <AuthProvider>");
  return ctx;
};

"use client";

import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { usePathname } from "next/navigation";
import { Product, CartItem } from "@/types/CartCarProps";
import { useAuth } from "@/context/AuthContext";
import { handleApiError } from "@/lib/handleApiError";

/* Config API */
const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

/* ===== Tipos de resposta da API ===== */
type CartApiItem = {
  item_id?: number;
  produto_id: number;
  nome?: string;
  valor_unitario?: number | string;
  quantidade?: number | string;
  image?: string | null;
  stock?: number | string; // ✅ novo (retornado do backend)
};

type CartGetResponse = {
  success?: boolean;
  items?: CartApiItem[];
  carrinho_id?: number | null;
};

/* Helpers */
const toNum = (v: any, fallback = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
};

const knownStock = (item: Partial<CartItem>) =>
  typeof item._stock === "number" && item._stock >= 0 ? item._stock : undefined;

const clampByStock = (item: Partial<CartItem>, desired: number) => {
  const s = knownStock(item);
  if (s !== undefined) {
    if (s <= 0) return 0;
    return Math.max(1, Math.min(s, desired));
  }
  return Math.max(1, desired);
};

type AddResult =
  | { ok: true }
  | { ok: false; reason: "OUT_OF_STOCK" | "LIMIT_REACHED" };

type AfterFn = () => void;

interface CartContextProps {
  cartItems: CartItem[];
  addToCart: (product: Product, qty?: number) => AddResult;
  updateQuantity: (id: number, quantity: number) => void;
  removeFromCart: (id: number) => void;
  syncStock: (productId: number, newStock: number) => void;
  clearCart: () => void;
  cartTotal: number;
  isCartOpen: boolean;
  openCart: () => void;
  closeCart: () => void;
}

const CartContext = createContext<CartContextProps | undefined>(undefined);

const makeCartKey = (userId: number | null | undefined) =>
  userId ? `cartItems_${userId}` : "cartItems_guest";

function normalizeApiItems(itemsFromApi: CartApiItem[]): CartItem[] {
  return itemsFromApi.map((it) => {
    const stockNum = toNum((it as any).stock, NaN);
    const stock =
      Number.isFinite(stockNum) && stockNum >= 0 ? stockNum : undefined;

    return {
      id: Number(it.produto_id),
      name: it.nome ?? `Produto #${it.produto_id}`,
      price: toNum(it.valor_unitario, 0),
      image: it.image ?? null,
      quantity: Math.max(1, toNum(it.quantidade, 1)),
      _stock: stock, // ✅ agora vem do backend
    };
  });
}

export const CartProvider = ({ children }: { children: React.ReactNode }) => {
  const { user } = useAuth();
  const pathname = usePathname();

  const userId: number | null = user?.id ? Number(user.id) : null;

  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [cartKey, setCartKey] = useState<string | null>(null);

  // evita “vazar” itens para a chave nova quando troca user/guest
  const lastCartKeyRef = useRef<string | null>(null);
  const lastUserIdRef = useRef<number | null>(userId);

  const openCart = () => setIsCartOpen(true);
  const closeCart = () => setIsCartOpen(false);

  /**
   * 1) Quando muda de usuário (login/logout/troca), zera o estado local imediatamente.
   * Isso impede o carrinho do usuário logado aparecer no modo visitante.
   */
  useEffect(() => {
    if (lastUserIdRef.current !== userId) {
      lastUserIdRef.current = userId;
      setCartItems([]);
      setIsCartOpen(false);
    }
  }, [userId]);

  /**
   * 2) Atualiza chave do carrinho
   */
  useEffect(() => {
    setCartKey(makeCartKey(userId));
  }, [userId]);

  const loadFromLocal = (key: string) => {
    if (typeof window === "undefined") return;
    try {
      const raw = localStorage.getItem(key);
      setCartItems(raw ? JSON.parse(raw) : []);
    } catch {
      setCartItems([]);
    }
  };

  /**
   * 3) Carregamento:
   * - /admin: não chama API
   * - visitante: localStorage
   * - logado: servidor é fonte da verdade (inclusive vazio)
   */
  useEffect(() => {
    if (!cartKey || typeof window === "undefined") return;

    if (pathname.startsWith("/admin")) {
      loadFromLocal(cartKey);
      return;
    }

    if (!userId) {
      loadFromLocal(cartKey);
      return;
    }

    (async () => {
      try {
        const res = await axios.get<CartGetResponse>(`${API_BASE}/api/cart`, {
          withCredentials: true,
        });

        const data = res.data;
        const itemsFromApi = Array.isArray(data.items) ? data.items : [];
        const normalized = normalizeApiItems(itemsFromApi);

        // logado: reflete servidor sempre (mesmo vazio)
        setCartItems(normalized);

        // cache local (opcional)
        try {
          localStorage.setItem(cartKey, JSON.stringify(normalized));
        } catch {
          // ignore
        }
      } catch (e: unknown) {
        handleApiError(e, {
          fallbackMessage: "Erro ao sincronizar o carrinho com o servidor.",
        });
        // fallback de UX: tenta cache local
        loadFromLocal(cartKey);
      }
    })();
  }, [cartKey, userId, pathname]);

  /**
   * 4) Persistência local:
   * Se o cartKey mudou agora, não persiste ainda (evita gravar estado antigo na chave nova).
   */
  useEffect(() => {
    if (!cartKey || typeof window === "undefined") return;

    if (lastCartKeyRef.current !== cartKey) {
      lastCartKeyRef.current = cartKey;
      return;
    }

    try {
      localStorage.setItem(cartKey, JSON.stringify(cartItems));
    } catch {
      // ignore
    }
  }, [cartItems, cartKey]);

  /**
   * 5) Fechar automaticamente quando carrinho ficar vazio
   */
  useEffect(() => {
    if (isCartOpen && cartItems.length === 0) {
      setIsCartOpen(false);
    }
  }, [isCartOpen, cartItems.length]);

  /* ========== Helpers de re-sync ========== */
  const refetchServerCart = async () => {
    if (!userId) return;
    try {
      const res = await axios.get<CartGetResponse>(`${API_BASE}/api/cart`, {
        withCredentials: true,
      });
      const itemsFromApi = Array.isArray(res.data.items) ? res.data.items : [];
      setCartItems(normalizeApiItems(itemsFromApi));
    } catch {
      // ignore
    }
  };

  /* ========== Ações ========== */

  const addToCart = (product: Product, qty = 1): AddResult => {
    const stockFromApi =
      typeof (product as any).quantity === "number"
        ? (product as any).quantity
        : typeof (product as any).estoque === "number"
          ? (product as any).estoque
          : typeof (product as any).stock === "number"
            ? (product as any).stock
            : undefined;

    let result: AddResult = { ok: true };
    const after: AfterFn[] = [];
    const increment = Math.max(1, toNum(qty, 1));

    // otimista no estado local
    setCartItems((prev) => {
      const found = prev.find((i) => i.id === product.id);

      if (found) {
        const stock = stockFromApi ?? knownStock(found);
        const desired = toNum(found.quantity, 1) + increment;
        const clamped = clampByStock({ ...found, _stock: stock }, desired);

        if (clamped === 0) {
          result = { ok: false, reason: "OUT_OF_STOCK" };
          after.push(() => toast.error("Produto esgotado."));
          return prev;
        }

        if (clamped <= found.quantity) {
          result = { ok: false, reason: "LIMIT_REACHED" };
          after.push(() =>
            typeof stock === "number"
              ? toast.error(`Limite de estoque atingido (máx. ${stock}).`)
              : toast.error("Quantidade máxima atingida."),
          );
          return prev;
        }

        after.push(() => toast.success("Quantidade atualizada no carrinho."));
        return prev.map((i) =>
          i.id === product.id
            ? { ...found, quantity: clamped, _stock: stock }
            : i,
        );
      }

      const stock = stockFromApi;
      const firstQty = clampByStock({ _stock: stock }, increment);

      if (firstQty === 0) {
        result = { ok: false, reason: "OUT_OF_STOCK" };
        after.push(() => toast.error("Produto esgotado."));
        return prev;
      }

      after.push(() => {
        openCart();
        toast.success("Adicionado ao carrinho!");
      });

      const newItem: CartItem = {
        id: product.id,
        name: product.name,
        price: toNum((product as any).price, 0),
        image: (product as any).image ?? null,
        quantity: firstQty,
        _stock: stock,
      };

      return [...prev, newItem];
    });

    // logado: sincroniza no servidor
    if (userId) {
      axios
        .post(
          `${API_BASE}/api/cart/items`,
          { produto_id: product.id, quantidade: increment },
          { withCredentials: true },
        )
        .catch((err) => {
          // Tratamento específico para STOCK_LIMIT (409)
          const status = err?.response?.status;
          const code =
            err?.response?.data?.code || err?.response?.data?.error?.code;

          if (status === 409 && code === "STOCK_LIMIT") {
            toast.error("Limite de estoque atingido.");
            refetchServerCart();
            return;
          }

          handleApiError(err, {
            fallbackMessage: "Erro ao salvar item no carrinho no servidor.",
          });

          // reconciliar com servidor (fallback)
          refetchServerCart();
        });
    }

    after.forEach((fn) => fn());
    return result;
  };

  const updateQuantity = (id: number, quantity: number) => {
    let finalQty: number | null = null;
    const after: AfterFn[] = [];

    setCartItems((prev) => {
      const found = prev.find((i) => i.id === id);
      if (!found) return prev;

      const desired = toNum(quantity, 1);
      const clamped = clampByStock(found, desired);
      finalQty = clamped;

      if (clamped === 0) {
        after.push(() =>
          toast.error("Produto esgotado. Removemos do carrinho."),
        );
        return prev.filter((i) => i.id !== id);
      }

      if (clamped !== desired) {
        after.push(() =>
          toast.error(`Ajustamos para ${clamped} por limite de estoque.`),
        );
      }

      return prev.map((i) => (i.id === id ? { ...i, quantity: clamped } : i));
    });

    if (userId && finalQty !== null) {
      if (finalQty <= 0) {
        axios
          .delete(`${API_BASE}/api/cart/items/${id}`, { withCredentials: true })
          .catch((err) =>
            handleApiError(err, {
              fallbackMessage: "Erro ao remover item do carrinho no servidor.",
            }),
          );
      } else {
        axios
          .patch(
            `${API_BASE}/api/cart/items`,
            { produto_id: id, quantidade: finalQty },
            { withCredentials: true },
          )
          .catch((err) => {
            const status = err?.response?.status;
            const code =
              err?.response?.data?.code || err?.response?.data?.error?.code;

            if (status === 409 && code === "STOCK_LIMIT") {
              toast.error("Limite de estoque atingido.");
              refetchServerCart();
              return;
            }

            handleApiError(err, {
              fallbackMessage: "Erro ao atualizar quantidade no servidor.",
            });
          });
      }
    }

    after.forEach((fn) => fn());
  };

  const removeFromCart = (id: number) => {
    setCartItems((prev) => prev.filter((i) => i.id !== id));

    if (userId) {
      axios
        .delete(`${API_BASE}/api/cart/items/${id}`, { withCredentials: true })
        .catch((err) =>
          handleApiError(err, {
            fallbackMessage: "Erro ao remover item do carrinho no servidor.",
          }),
        );
    }

    toast("Item removido do carrinho.");
  };

  const syncStock = (productId: number, newStock: number) => {
    const after: AfterFn[] = [];

    setCartItems(
      (prev) =>
        prev
          .map((it) => {
            if (it.id !== productId) return it;
            const stock = Math.max(0, toNum(newStock, 0));
            const clamped = clampByStock({ ...it, _stock: stock }, it.quantity);

            if (stock === 0) {
              after.push(() =>
                toast.error("Um item esgotou e foi removido do carrinho."),
              );
              return null;
            }

            if (clamped !== it.quantity) {
              after.push(() =>
                toast.error(`Estoque atualizado. Ajustamos para ${clamped}.`),
              );
            }

            return { ...it, _stock: stock, quantity: clamped };
          })
          .filter(Boolean) as CartItem[],
    );

    after.forEach((fn) => fn());
  };

  const clearCart = () => {
    setCartItems([]);
    closeCart();

    if (typeof window !== "undefined" && cartKey) {
      try {
        localStorage.removeItem(cartKey);
      } catch {
        // ignore
      }
    }

    if (userId) {
      axios
        .delete(`${API_BASE}/api/cart`, { withCredentials: true })
        .catch((err) =>
          handleApiError(err, {
            fallbackMessage: "Erro ao limpar o carrinho no servidor.",
          }),
        );
    }

    toast("Carrinho limpo.");
  };

  const cartTotal = useMemo(
    () =>
      cartItems.reduce(
        (sum, it) => sum + toNum(it.price, 0) * toNum(it.quantity, 1),
        0,
      ),
    [cartItems],
  );

  const value: CartContextProps = {
    cartItems,
    addToCart,
    updateQuantity,
    removeFromCart,
    syncStock,
    clearCart,
    cartTotal,
    isCartOpen,
    openCart,
    closeCart,
  };

  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
};

export const useCart = () => {
  const ctx = useContext(CartContext);
  if (!ctx) throw new Error("useCart deve ser usado dentro de CartProvider");
  return ctx;
};

"use client";

import { useCallback, useState } from "react";

/** -----------------------------
 * Tipos do formulário de checkout
 * ----------------------------- */

export type TipoLocalidade = "URBANA" | "RURAL";

export type Endereco = {
  cep: string;
  estado: string;
  cidade: string;

  // Urbano (no rural podem ficar vazios, validação é “inteligente” no submit)
  bairro: string;
  logradouro: string;

  // pode ser "S/N"
  numero: string;

  // ✅ Separação correta
  complemento?: string; // apto/bloco/casa
  referencia?: string; // ponto de referência

  // ✅ Novo: urbano/rural
  tipo_localidade?: TipoLocalidade;

  // ✅ Novo: rural
  comunidade?: string;
  observacoes_acesso?: string;
};

export type CheckoutFormData = {
  nome: string;
  cpf: string;
  email: string;
  telefone?: string;
  endereco: Endereco;
  formaPagamento: "Pix" | "Boleto" | "Prazo" | string;
};

/**
 * ✅ O AddressForm e outros formulários podem importar isso
 * Mesma assinatura do updateForm (evento | "campo" | objeto) + arg2 opcional
 */
export type CheckoutFormChangeHandler = (
  arg1:
    | React.ChangeEvent<
        HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement
      >
    | string
    | Record<string, any>,
  arg2?: any,
) => void;

/** Estado inicial seguro */
const INITIAL_STATE: CheckoutFormData = {
  nome: "",
  cpf: "",
  email: "",
  telefone: "",
  endereco: {
    cep: "",
    estado: "",
    cidade: "",
    bairro: "",
    logradouro: "",
    numero: "",
    complemento: "",
    referencia: "",

    tipo_localidade: "URBANA",
    comunidade: "",
    observacoes_acesso: "",
  },
  formaPagamento: "Pix",
};

/** -----------------------------
 * Hook
 * ----------------------------- */
export function useCheckoutForm() {
  const [formData, setFormData] = useState<CheckoutFormData>(INITIAL_STATE);

  /** Atualiza campo aninhado de endereço (estável) */
  const updateEndereco = useCallback((key: keyof Endereco, value: any) => {
    setFormData((prev) => ({
      ...prev,
      endereco: { ...prev.endereco, [key]: value },
    }));
  }, []);

  /**
   * ✅ updateForm ESTÁVEL (useCallback) — resolve “Maximum update depth exceeded”
   *
   * Aceita:
   *   - updateForm(e)
   *   - updateForm("campo", valor)
   *   - updateForm({ patch })
   * Suporta campos "endereco.*"
   */
  const updateForm: CheckoutFormChangeHandler = useCallback(
    (arg1, arg2) => {
      // Caso 1: evento
      if (arg1 && typeof arg1 === "object" && "target" in arg1) {
        const e = arg1 as React.ChangeEvent<
          HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement
        >;

        const name = String(e.target.name || "").trim();
        if (!name) return;

        const isCheckbox = (e.target as HTMLInputElement).type === "checkbox";
        const value = isCheckbox
          ? (e.target as HTMLInputElement).checked
          : e.target.value;

        if (name.startsWith("endereco.")) {
          const key = name.replace("endereco.", "") as keyof Endereco;
          updateEndereco(key, value);
          return;
        }

        setFormData((prev) => ({ ...prev, [name]: value }));
        return;
      }

      // Caso 2: patch objeto
      if (arg1 && typeof arg1 === "object") {
        const patch = arg1 as Record<string, any>;
        setFormData((prev) => ({ ...prev, ...patch }));
        return;
      }

      // Caso 3: (field, value)
      const field = String(arg1 || "").trim();
      const value = arg2;

      if (!field) return;

      if (field.startsWith("endereco.")) {
        const key = field.replace("endereco.", "") as keyof Endereco;
        updateEndereco(key, value);
        return;
      }

      setFormData((prev) => ({ ...prev, [field]: value }));
    },
    [updateEndereco],
  );

  /** Helpers opcionais */
  const setField = useCallback((field: keyof CheckoutFormData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  }, []);

  const bulkUpdate = useCallback((patch: Partial<CheckoutFormData>) => {
    setFormData((prev) => ({ ...prev, ...patch }));
  }, []);

  const resetForm = useCallback(() => setFormData(INITIAL_STATE), []);

  return {
    formData,
    updateForm,
    setField,
    bulkUpdate,
    resetForm,
  };
}

"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { ClimaFormState, ClimaItem, NewsOk } from "@/types/kavita-news";
import {
  normalizeSlug,
  toNumberOrNull,
  parseIbgeId,
  parseStationCode,
} from "@/utils/kavita-news/clima";

type Params = {
  apiBase: string;
  authOptions: RequestInit;
  onUnauthorized: () => void;
};

type ApiErrorShape = {
  ok?: boolean;
  code?: string;
  message?: string;
  mensagem?: string;
  details?: any;
};

export type InmetStation = {
  // Mantemos o tipo/export para compatibilidade com o front atual.
  // Agora estes itens representam sugestões de geocoding (Open-Meteo), não "estações INMET".
  // Campos relevantes para o formulário: name/uf/lat/lon.
  code?: string;
  name: string;
  uf: string;
  status?: string;
  lat?: string | number | null;
  lon?: string | number | null;
  country?: string;
  admin1?: string;
  admin2?: string;
  timezone?: string;
};

function pickMessage(payload: any, fallback: string) {
  return payload?.message || payload?.mensagem || payload?.error || fallback;
}

function mergeHeaders(a?: HeadersInit, b?: HeadersInit): HeadersInit {
  return { ...(a || {}), ...(b || {}) };
}

function isAbortError(e: any) {
  const msg = String(e?.message || e || "").toLowerCase();
  return (
    e?.name === "AbortError" || msg.includes("aborted") || msg.includes("abort")
  );
}

function toUpperUF(v: string) {
  return (v || "").trim().toUpperCase();
}

export function useClimaAdmin({
  apiBase,
  authOptions,
  onUnauthorized,
}: Params) {
  const [rows, setRows] = useState<ClimaItem[]>([]);
  const [loading, setLoading] = useState(false);

  const [saving, setSaving] = useState(false);
  const [deletingId, setDeletingId] = useState<number | null>(null);
  const [syncingId, setSyncingId] = useState<number | null>(null);

  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const [editing, setEditing] = useState<ClimaItem | null>(null);
  const [mode, setMode] = useState<"create" | "edit">("create");

  const [form, setForm] = useState<ClimaFormState>({
    city_name: "",
    slug: "",
    uf: "",
    ibge_id: "",
    station_code: "",
    // Open-Meteo: coordenadas
    station_lat: "" as any,
    station_lon: "" as any,
    station_distance: "" as any,
    mm_24h: "",
    mm_7d: "",
    source: "",
    last_update_at: "",
    ativo: true,
  });

  // Abort só para requests “in flight” no unmount do hook.
  const abortAllRef = useRef<AbortController | null>(null);

  const request = useCallback(
    async <T>(path: string, init?: RequestInit): Promise<T> => {
      // controlador geral do hook (para abort no unmount)
      if (!abortAllRef.current) abortAllRef.current = new AbortController();

      // controlador por request (para poder cancelar somente ela se necessário)
      const localController = new AbortController();

      // se o hook for abortado, aborta a request local também
      const parent = abortAllRef.current;
      const onAbort = () => {
        try {
          localController.abort();
        } catch {}
      };
      parent.signal.addEventListener("abort", onAbort, { once: true });

      const url = `${apiBase}${path}`;

      // garante envio de cookies (sessão/adminToken) por padrão.
      const credentials =
        (init?.credentials as RequestCredentials | undefined) ??
        (authOptions?.credentials as RequestCredentials | undefined) ??
        ("include" as RequestCredentials);

      const res = await fetch(url, {
        ...authOptions,
        ...init,
        credentials,
        headers: mergeHeaders(authOptions.headers, init?.headers),
        signal: localController.signal,
      });

      if (res.status === 401) {
        onUnauthorized();
        throw new Error("UNAUTHORIZED");
      }

      let payload: any = null;
      try {
        payload = await res.json();
      } catch {
        payload = null;
      }

      if (!res.ok) {
        const msg = pickMessage(payload, `HTTP ${res.status}`);
        throw new Error(msg);
      }

      // padrão: { ok: true, data: ... }
      if (payload && typeof payload === "object" && "ok" in payload) {
        if (payload.ok === false) {
          const msg = pickMessage(
            payload as ApiErrorShape,
            "Erro na operação.",
          );
          throw new Error(msg);
        }
        return (payload as NewsOk<T>).data as T;
      }

      // tolerância: endpoint retornando direto
      return payload as T;
    },
    [apiBase, authOptions, onUnauthorized],
  );

  const resetForm = useCallback(() => {
    setForm({
      city_name: "",
      slug: "",
      uf: "",
      ibge_id: "",
      station_code: "",
      station_lat: "" as any,
      station_lon: "" as any,
      station_distance: "" as any,
      mm_24h: "",
      mm_7d: "",
      source: "",
      last_update_at: "",
      ativo: true,
    });
  }, []);

  const startCreate = useCallback(() => {
    setMode("create");
    setEditing(null);
    setErrorMsg(null);
    resetForm();
  }, [resetForm]);

  const startEdit = useCallback((item: ClimaItem) => {
    setMode("edit");
    setEditing(item);
    setErrorMsg(null);

    setForm({
      city_name: item.city_name || "",
      slug: item.slug || "",
      uf: item.uf || "",
      ibge_id: item.ibge_id == null ? "" : String(item.ibge_id),
      station_code: item.station_code ?? "",
      station_lat:
        (item as any).station_lat == null
          ? ("" as any)
          : (String((item as any).station_lat) as any),
      station_lon:
        (item as any).station_lon == null
          ? ("" as any)
          : (String((item as any).station_lon) as any),
      station_distance:
        (item as any).station_distance == null
          ? ("" as any)
          : (String((item as any).station_distance) as any),
      mm_24h: item.mm_24h == null ? "" : String(item.mm_24h),
      mm_7d: item.mm_7d == null ? "" : String(item.mm_7d),
      source: item.source ?? "",
      last_update_at: item.last_update_at ?? "",
      ativo: Number(item.ativo ?? 1) === 1,
    });
  }, []);

  const cancelEdit = useCallback(() => startCreate(), [startCreate]);

  const load = useCallback(async () => {
    try {
      setLoading(true);
      setErrorMsg(null);

      const data = await request<ClimaItem[]>("/api/admin/news/clima", {
        method: "GET",
      });
      setRows(Array.isArray(data) ? data : []);
    } catch (e: any) {
      if (isAbortError(e)) return;
      if (String(e?.message) !== "UNAUTHORIZED")
        setErrorMsg(e?.message || "Erro ao listar clima.");
    } finally {
      setLoading(false);
    }
  }, [request]);

  useEffect(() => {
    load();
    return () => {
      try {
        abortAllRef.current?.abort();
      } catch {}
      abortAllRef.current = null;
    };
  }, [load]);

  const submit = useCallback(async () => {
    try {
      setSaving(true);
      setErrorMsg(null);

      const city_name = form.city_name.trim();
      const uf = toUpperUF(form.uf);
      const slug = normalizeSlug(form.slug);

      if (!city_name) return setErrorMsg("Preencha o nome da cidade.");
      if (!uf || uf.length !== 2)
        return setErrorMsg("UF inválida (use 2 letras).");
      if (!slug) return setErrorMsg("Slug inválido.");

      const ibge_id = parseIbgeId(form.ibge_id);

      // station_code fica legado/optional (Open-Meteo não depende disso)
      const station_code =
        parseStationCode(form.station_code) ??
        (form.station_code.trim()
          ? form.station_code.trim().toUpperCase()
          : null);

      // Open-Meteo: coordenadas
      const station_lat = toNumberOrNull((form as any).station_lat);
      const station_lon = toNumberOrNull((form as any).station_lon);
      const station_distance = toNumberOrNull((form as any).station_distance);

      // validação: se o usuário preencher apenas um lado, bloqueia para evitar sync inconsistente
      const latRaw = String((form as any).station_lat ?? "").trim();
      const lonRaw = String((form as any).station_lon ?? "").trim();
      if ((latRaw && !lonRaw) || (!latRaw && lonRaw)) {
        return setErrorMsg(
          "Preencha station_lat e station_lon (ambos) ou deixe ambos vazios para geocoding automático.",
        );
      }

      const payload = {
        city_name,
        slug,
        uf,
        ibge_id,
        station_code,
        station_lat,
        station_lon,
        station_distance,
        mm_24h: toNumberOrNull(form.mm_24h),
        mm_7d: toNumberOrNull(form.mm_7d),
        source: form.source.trim() ? form.source.trim() : null,
        last_update_at: form.last_update_at.trim()
          ? form.last_update_at.trim()
          : null,
        ativo: form.ativo ? 1 : 0,
      };

      const isEdit = mode === "edit" && editing?.id;
      const path = isEdit
        ? `/api/admin/news/clima/${editing!.id}`
        : `/api/admin/news/clima`;

      await request<any>(path, {
        method: isEdit ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      await load();
      startCreate();
    } catch (e: any) {
      if (isAbortError(e)) return;
      if (String(e?.message) !== "UNAUTHORIZED")
        setErrorMsg(e?.message || "Erro ao salvar clima.");
    } finally {
      setSaving(false);
    }
  }, [editing, form, load, mode, request, startCreate]);

  const remove = useCallback(
    async (id: number) => {
      const yes = confirm("Excluir este clima?");
      if (!yes) return;

      try {
        setDeletingId(id);
        setErrorMsg(null);

        await request<any>(`/api/admin/news/clima/${id}`, { method: "DELETE" });
        await load();
      } catch (e: any) {
        if (isAbortError(e)) return;
        if (String(e?.message) !== "UNAUTHORIZED")
          setErrorMsg(e?.message || "Erro ao excluir clima.");
      } finally {
        setDeletingId(null);
      }
    },
    [load, request],
  );

  const sync = useCallback(
    async (id: number) => {
      try {
        setSyncingId(id);
        setErrorMsg(null);

        await request<ClimaItem>(`/api/admin/news/clima/${id}/sync`, {
          method: "POST",
        });
        await load();
      } catch (e: any) {
        if (isAbortError(e)) return;
        if (String(e?.message) !== "UNAUTHORIZED")
          setErrorMsg(e?.message || "Erro ao sincronizar clima.");
      } finally {
        setSyncingId(null);
      }
    },
    [load, request],
  );

  /**
   * Sugere coordenadas (Open-Meteo Geocoding) via backend
   * GET /api/admin/news/clima/stations?uf=MG&q=Manhuaçu&limit=10
   */
  const suggestStations = useCallback(
    async (uf: string, q: string, limit = 10): Promise<InmetStation[]> => {
      try {
        const UF = toUpperUF(uf);
        const Q = String(q || "").trim();
        if (UF.length !== 2 || Q.length < 2) return [];

        const data = await request<InmetStation[]>(
          `/api/admin/news/clima/stations?uf=${encodeURIComponent(UF)}&q=${encodeURIComponent(Q)}&limit=${encodeURIComponent(
            String(limit),
          )}`,
          { method: "GET" },
        );

        return Array.isArray(data) ? data : [];
      } catch (e: any) {
        // não estoura erro para não “quebrar” UX do formulário; só ignora
        if (isAbortError(e)) return [];
        if (String(e?.message) === "UNAUTHORIZED") return [];
        return [];
      }
    },
    [request],
  );

  const sorted = useMemo(() => {
    return [...rows].sort((a, b) =>
      a.city_name.localeCompare(b.city_name, "pt-BR"),
    );
  }, [rows]);

  return {
    rows,
    sorted,

    loading,
    saving,
    deletingId,
    syncingId,
    errorMsg,

    mode,
    editing,
    form,
    setForm,

    load,
    submit,
    remove,
    sync,

    suggestStations,

    startEdit,
    startCreate,
    resetForm,
    cancelEdit,
  };
}

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import toast from "react-hot-toast";
import type {
  CotacaoFormState,
  CotacaoItem,
  CotacaoSlug,
} from "@/types/kavita-news";
import { ALLOWED_SLUGS } from "@/utils/kavita-news/cotacoes";

type Props = {
  apiBase: string;
  authOptions: RequestInit;
  onUnauthorized: () => void;
};

function isUnauthorized(res: Response) {
  return res.status === 401 || res.status === 403;
}

function toStr(v: any) {
  return v == null ? "" : String(v);
}

function toNumString(v: any) {
  if (v === null || v === undefined) return "";
  const s = String(v);
  return s;
}

export function useCotacoesAdmin({
  apiBase,
  authOptions,
  onUnauthorized,
}: Props) {
  const [rows, setRows] = useState<CotacaoItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const [mode, setMode] = useState<"create" | "edit">("create");
  const [editing, setEditing] = useState<CotacaoItem | null>(null);

  const [allowedSlugs, setAllowedSlugs] = useState<string[]>([
    ...ALLOWED_SLUGS,
  ]);

  const [deletingId, setDeletingId] = useState<number | null>(null);
  const [syncingId, setSyncingId] = useState<number | null>(null);

  const [form, setForm] = useState<CotacaoFormState>({
    name: "",
    slug: "" as CotacaoSlug | "",
    type: "",
    price: "",
    unit: "",
    variation_day: "",
    market: "",
    source: "",
    last_update_at: "",
    ativo: true,
  });

  const fetchJson = useCallback(
    async (path: string, init?: RequestInit) => {
      const res = await fetch(`${apiBase}${path}`, {
        ...authOptions,
        ...(init || {}),
        headers: {
          "Content-Type": "application/json",
          ...(init?.headers || {}),
        },
      });

      if (isUnauthorized(res)) {
        onUnauthorized();
        throw new Error("Não autorizado.");
      }

      let data: any = null;
      try {
        data = await res.json();
      } catch {}

      if (!res.ok) {
        const msg = data?.message || data?.mensagem || `HTTP ${res.status}`;
        throw new Error(msg);
      }

      return data;
    },
    [apiBase, authOptions, onUnauthorized],
  );

  const load = useCallback(async () => {
    setLoading(true);
    setErrorMsg(null);
    try {
      const j = await fetchJson("/api/admin/news/cotacoes");
      const list = (j?.data || j) as CotacaoItem[];
      setRows(Array.isArray(list) ? list : []);

      const metaSlugs = j?.meta?.allowed_slugs;
      if (Array.isArray(metaSlugs) && metaSlugs.length > 0)
        setAllowedSlugs(metaSlugs);
    } catch (e: any) {
      setErrorMsg(e?.message || "Erro ao carregar cotações.");
    } finally {
      setLoading(false);
    }
  }, [fetchJson]);

  useEffect(() => {
    load();
  }, [load]);

  const sorted = useMemo(() => {
    const list = Array.isArray(rows) ? [...rows] : [];
    // ativos primeiro, depois por type/name
    return list.sort((a, b) => {
      const aa = Number(a?.ativo ?? 1);
      const bb = Number(b?.ativo ?? 1);
      if (aa !== bb) return bb - aa;
      return (
        String(a?.type || "").localeCompare(String(b?.type || "")) ||
        String(a?.name || "").localeCompare(String(b?.name || ""))
      );
    });
  }, [rows]);

  const startCreate = useCallback(() => {
    setMode("create");
    setEditing(null);
    setForm({
      name: "",
      slug: "" as any,
      type: "",
      price: "",
      unit: "",
      variation_day: "",
      market: "",
      source: "",
      last_update_at: "",
      ativo: true,
    });
  }, []);

  const startEdit = useCallback((item: CotacaoItem) => {
    setMode("edit");
    setEditing(item);
    setForm({
      name: toStr(item?.name),
      slug: (toStr(item?.slug) as any) || ("" as any),
      type: toStr(item?.type),
      price: toNumString(item?.price),
      unit: toStr(item?.unit),
      variation_day: toNumString(item?.variation_day),
      market: toStr(item?.market),
      source: toStr(item?.source),
      last_update_at: toStr(item?.last_update_at),
      ativo: Number(item?.ativo ?? 1) === 1,
    });
  }, []);

  const cancelEdit = useCallback(() => {
    startCreate();
  }, [startCreate]);

  const submit = useCallback(async () => {
    setSaving(true);
    setErrorMsg(null);

    try {
      const payload: any = {
        name: form.name?.trim(),
        slug: form.slug || null,
        type: form.type?.trim(),
        price: form.price === "" ? null : form.price,
        unit: form.unit?.trim() || null,
        variation_day: form.variation_day === "" ? null : form.variation_day,
        market: form.market?.trim() || null,
        source: form.source?.trim() || null,
        last_update_at: form.last_update_at?.trim() || null,
        ativo: form.ativo ? 1 : 0,
      };

      if (!payload.name) throw new Error("Preencha o nome.");
      if (!payload.slug) throw new Error("Selecione o slug.");
      if (!payload.type) throw new Error("Preencha o tipo.");

      if (mode === "edit" && editing?.id) {
        await fetchJson(`/api/admin/news/cotacoes/${editing.id}`, {
          method: "PUT",
          body: JSON.stringify(payload),
        });
        toast.success("Cotação atualizada.");
      } else {
        await fetchJson(`/api/admin/news/cotacoes`, {
          method: "POST",
          body: JSON.stringify(payload),
        });
        toast.success("Cotação criada.");
      }

      await load();
      startCreate();
    } catch (e: any) {
      const msg = e?.message || "Erro ao salvar.";
      setErrorMsg(msg);
      toast.error(msg);
    } finally {
      setSaving(false);
    }
  }, [form, mode, editing?.id, fetchJson, load, startCreate]);

  const remove = useCallback(
    async (id: number) => {
      setDeletingId(id);
      setErrorMsg(null);
      try {
        await fetchJson(`/api/admin/news/cotacoes/${id}`, { method: "DELETE" });
        toast.success("Cotação removida.");
        await load();
      } catch (e: any) {
        const msg = e?.message || "Erro ao remover.";
        setErrorMsg(msg);
        toast.error(msg);
      } finally {
        setDeletingId(null);
      }
    },
    [fetchJson, load],
  );

  const sync = useCallback(
    async (id: number) => {
      setSyncingId(id);
      setErrorMsg(null);
      try {
        await fetchJson(`/api/admin/news/cotacoes/${id}/sync`, {
          method: "POST",
        });
        toast.success("Sync concluído.");
        await load();
      } catch (e: any) {
        const msg = e?.message || "Erro no sync.";
        setErrorMsg(msg);
        toast.error(msg);
      } finally {
        setSyncingId(null);
      }
    },
    [fetchJson, load],
  );

  const syncAll = useCallback(async () => {
    setErrorMsg(null);
    try {
      await fetchJson(`/api/admin/news/cotacoes/sync-all`, { method: "POST" });
      toast.success("Atualização em lote concluída.");
      await load();
    } catch (e: any) {
      const msg = e?.message || "Erro ao atualizar tudo.";
      setErrorMsg(msg);
      toast.error(msg);
    }
  }, [fetchJson, load]);

  return {
    rows,
    sorted,
    loading,
    saving,
    errorMsg,

    mode,
    editing,
    form,
    setForm,

    allowedSlugs,

    load,
    startCreate,
    startEdit,
    cancelEdit,
    submit,
    remove,
    deletingId,

    sync,
    syncAll,
    syncingId,
  };
}

// src/hooks/useFetchDronesPage.ts
"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type {
  DroneGalleryItem,
  DroneRepresentative,
  DronePageSettings,
  DroneComment,
} from "@/types/drones";

/**
 * =========================================================
 * CONFIG
 * =========================================================
 */
const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

/**
 * =========================================================
 * TYPES / ERRORS
 * =========================================================
 */
export type ApiErrorPayload = {
  status?: number;
  code?: string;
  message?: string;
  details?: any;
};

class ApiError extends Error {
  status: number;
  code?: string;
  details?: any;

  constructor(message: string, status = 500, code?: string, details?: any) {
    super(message);
    this.name = "ApiError";
    this.status = status;
    this.code = code;
    this.details = details;
  }
}

export type ModelKey = string;

export type DroneModel = {
  key: string;
  label: string;
  is_active?: boolean | number;
  sort_order?: number;

  // ids escolhidos no admin (para card/destaque)
  current_hero_media_id?: number | null;
  current_card_media_id?: number | null;
};

type AnyJson = Record<string, any> | any[] | string | number | boolean | null;

/**
 * Resposta REAL do backend:
 * - getRoot: { landing, model, model_data, gallery, comments }
 * - getModelAggregate: { landing, model, model_data, gallery, comments }
 */
export type PublicDronesRootResponse = {
  landing?: DronePageSettings | null;
  model?: any;
  model_data?: any;
  gallery?: { items?: DroneGalleryItem[] } | DroneGalleryItem[];
  comments?: { items?: DroneComment[] } | DroneComment[] | any;
};

export type PublicDronesModelAggregateResponse = PublicDronesRootResponse;

/**
 * =========================================================
 * UTILS
 * =========================================================
 */

function isValidModelKey(modelKey: string) {
  return /^[a-z0-9_]{2,20}$/.test(
    String(modelKey || "")
      .trim()
      .toLowerCase(),
  );
}

function extractItemsArray<T>(payload: AnyJson): T[] {
  if (Array.isArray(payload)) return payload as T[];
  if (payload && typeof payload === "object") {
    const obj = payload as any;
    if (Array.isArray(obj.items)) return obj.items as T[];
    if (Array.isArray(obj.data)) return obj.data as T[];
  }
  return [];
}

async function readJsonSafely(
  res: Response,
): Promise<{ text: string; json: AnyJson }> {
  const text = await res.text();
  try {
    return { text, json: JSON.parse(text) as AnyJson };
  } catch {
    return { text, json: null };
  }
}

function pickErrorMessage(json: AnyJson, fallback: string) {
  if (json && typeof json === "object") {
    const msg = (json as any).message;
    if (typeof msg === "string" && msg.trim()) return msg.trim();
  }
  return fallback;
}

/**
 * fetchJsonOrThrow:
 * - suporta AbortController via init.signal
 * - aplica cache: "no-store" por padrão (você pode sobrescrever)
 * - captura payload padrão do backend (status/code/message/details)
 */
async function fetchJsonOrThrow<T>(
  url: string,
  init: RequestInit = {},
): Promise<T> {
  const res = await fetch(url, {
    cache: "no-store",
    ...init,
  });

  const { json } = await readJsonSafely(res);

  if (!res.ok) {
    const payload = (
      json && typeof json === "object" ? (json as any) : {}
    ) as ApiErrorPayload;
    throw new ApiError(
      pickErrorMessage(json, "Falha na requisição."),
      res.status,
      payload.code,
      payload.details,
    );
  }

  return json as T;
}

/**
 * ✅ Normaliza modelos para o formato do front (key/label + ids)
 * Observação: os ids current_* normalmente ficam em models_json[modelKey],
 * mas deixo suporte aqui caso você devolva isso diretamente no endpoint /models.
 */
function normalizeModels(raw: any): DroneModel[] {
  const arr = extractItemsArray<any>(raw);
  return arr
    .map((m) => {
      const key = String(m.key || m.model_key || "")
        .trim()
        .toLowerCase();
      const label = String(m.label || m.name || "").trim();

      return {
        key,
        label,
        is_active: m.is_active,
        sort_order: m.sort_order,
        current_hero_media_id:
          m.current_hero_media_id === undefined
            ? null
            : (m.current_hero_media_id ?? null),
        current_card_media_id:
          m.current_card_media_id === undefined
            ? null
            : (m.current_card_media_id ?? null),
      } as DroneModel;
    })
    .filter((m) => m.key && m.label);
}

function resolvePageFromRoot(root: any): DronePageSettings | null {
  if (!root || typeof root !== "object") return null;
  if ("landing" in root) return (root.landing ?? null) as any;
  if ("page" in root) return (root.page ?? null) as any;
  return null;
}

/**
 * =========================================================
 * HOOK
 * =========================================================
 */
export function useFetchDronesPage(modelKey?: ModelKey) {
  const normalizedModelKey = useMemo(() => {
    const mk = String(modelKey || "")
      .trim()
      .toLowerCase();
    return mk && isValidModelKey(mk) ? mk : undefined;
  }, [modelKey]);

  const abortRef = useRef<AbortController | null>(null);

  const [page, setPage] = useState<DronePageSettings | null>(null);
  const [models, setModels] = useState<DroneModel[]>([]);
  const [gallery, setGallery] = useState<DroneGalleryItem[]>([]);
  const [representatives, setRepresentatives] = useState<DroneRepresentative[]>(
    [],
  );
  const [comments, setComments] = useState<DroneComment[]>([]);
  const [model, setModel] = useState<any | null>(null); // model_data (models_json[modelKey])

  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const hardResetState = useCallback(() => {
    setPage(null);
    setModels([]);
    setGallery([]);
    setRepresentatives([]);
    setComments([]);
    setModel(null);
  }, []);

  const reload = useCallback(async () => {
    abortRef.current?.abort();
    const ac = new AbortController();
    abortRef.current = ac;

    setLoading(true);
    setError(null);

    const fetchInit: RequestInit = {
      cache: "no-store",
      signal: ac.signal,
    };

    try {
      /**
       * Sempre buscamos:
       * - modelos (abas/carrossel)
       * - representantes (legado)
       *
       * E buscamos em paralelo com:
       * - root agregado (sem modelKey) OU aggregate do modelo (com modelKey)
       */
      const modelsPromise = fetchJsonOrThrow<any>(
        `${API_BASE}/api/public/drones/models`,
        fetchInit,
      );

      const repsPromise = fetchJsonOrThrow<any>(
        `${API_BASE}/api/public/drones/representantes?page=1&limit=12`,
        fetchInit,
      );

      if (normalizedModelKey) {
        const aggPromise = fetchJsonOrThrow<PublicDronesModelAggregateResponse>(
          `${API_BASE}/api/public/drones/models/${normalizedModelKey}`,
          fetchInit,
        );

        const [modelsRes, repsRes, agg] = await Promise.all([
          modelsPromise,
          repsPromise,
          aggPromise,
        ]);

        setModels(normalizeModels(modelsRes));
        setRepresentatives(extractItemsArray<DroneRepresentative>(repsRes));

        setPage(resolvePageFromRoot(agg));
        setModel((agg as any)?.model_data ?? null);
        setGallery(extractItemsArray<DroneGalleryItem>((agg as any)?.gallery));
        setComments(extractItemsArray<DroneComment>((agg as any)?.comments));

        return;
      }

      // sem modelKey: root agregado
      const rootPromise = fetchJsonOrThrow<PublicDronesRootResponse>(
        `${API_BASE}/api/public/drones`,
        fetchInit,
      );

      const [modelsRes, repsRes, root] = await Promise.all([
        modelsPromise,
        repsPromise,
        rootPromise,
      ]);

      setModels(normalizeModels(modelsRes));
      setRepresentatives(extractItemsArray<DroneRepresentative>(repsRes));

      const pageResolved = resolvePageFromRoot(root);
      const modelResolved = (root as any)?.model_data ?? null;

      const galleryResolved = extractItemsArray<DroneGalleryItem>(
        (root as any)?.gallery,
      );
      const commentsResolved = extractItemsArray<DroneComment>(
        (root as any)?.comments,
      );

      setPage(pageResolved);
      setModel(modelResolved);
      setGallery(galleryResolved);
      setComments(commentsResolved);

      /**
       * Fallback legado:
       * - só chama se o root veio vazio
       * - mantém compatibilidade com backend antigo
       */
      const needLegacyGallery = galleryResolved.length === 0;
      const needLegacyComments = commentsResolved.length === 0;

      const legacyReqs: Promise<void>[] = [];

      if (needLegacyGallery) {
        legacyReqs.push(
          (async () => {
            const gal = await fetchJsonOrThrow<any>(
              `${API_BASE}/api/public/drones/galeria`,
              fetchInit,
            );
            setGallery(extractItemsArray<DroneGalleryItem>(gal));
          })(),
        );
      }

      if (needLegacyComments) {
        legacyReqs.push(
          (async () => {
            const com = await fetchJsonOrThrow<any>(
              `${API_BASE}/api/public/drones/comentarios?page=1&limit=10`,
              fetchInit,
            );
            setComments(extractItemsArray<DroneComment>(com));
          })(),
        );
      }

      if (legacyReqs.length) await Promise.all(legacyReqs);
    } catch (e: any) {
      if (e?.name === "AbortError") return;

      setError(e?.message || "Erro ao carregar Kavita Drones.");
      hardResetState();
    } finally {
      setLoading(false);
    }
  }, [normalizedModelKey, hardResetState]);

  useEffect(() => {
    reload();
    return () => abortRef.current?.abort();
  }, [reload]);

  return {
    page,
    models,
    model, // model_data (models_json[modelKey])
    gallery,
    representatives,
    comments,
    loading,
    error,
    reload,
  };
}

"use client";

import { useEffect, useRef, useState } from "react";
import type { Product } from "@/types/product";
export type { Product } from "@/types/product";

import { getProducts, type GetProductsParams } from "@/services/products";
import { handleApiError } from "@/lib/handleApiError";

/**
 * Opções do hook.
 * - Mantém compatibilidade com a versão antiga via `categorySlug`.
 * - `enabled` permite pausar o fetch (útil para páginas que ainda não têm categoria definida).
 */
type Opts = GetProductsParams & {
  categorySlug?: string; // compatível com versão antiga
  enabled?: boolean;
  search?: number | string;
};

export function useFetchProducts(opts: Opts = {}) {
  const {
    // compatibilidade: alguns lugares ainda passam categorySlug
    category,
    categorySlug,
    subcategory,
    search,
    page,
    limit,
    sort,
    order,
    enabled = true,
  } = opts;

  const effectiveCategory = category ?? categorySlug;

  const [data, setData] = useState<Product[]>([]);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  // Mantém a lógica atual de refetch via incremento em ref + rerender por setLoading(true)
  const trigger = useRef<number>(0);

  useEffect(() => {
    if (!enabled) return;

    let alive = true;
    setLoading(true);
    setError(null);

    async function run() {
      try {
        const res = await getProducts({
          category: effectiveCategory,
          subcategory,
          search,
          page,
          limit,
          sort,
          order,
        } as GetProductsParams);

        // getProducts pode retornar:
        // - array direto
        // - { products: [...] }
        // - { data: [...] }
        const list: unknown =
          (res as any)?.products ?? (res as any)?.data ?? res;

        if (alive) {
          setData(Array.isArray(list) ? (list as Product[]) : []);
        }
      } catch (e) {
        const ui = handleApiError(e, {
          silent: true,
          fallback: "Não foi possível carregar os produtos.",
        });

        // handleApiError pode retornar objeto (UiError) ou string.
        // Normalizamos para string para manter error: string | null
        const msg =
          typeof ui === "string"
            ? ui
            : ((ui as any)?.message ??
              (ui as any)?.fallback ??
              "Não foi possível carregar os produtos.");

        if (alive) setError(msg);
      } finally {
        if (alive) setLoading(false);
      }
    }

    run();

    return () => {
      alive = false;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    effectiveCategory,
    subcategory,
    search,
    page,
    limit,
    sort,
    order,
    enabled,
    trigger.current,
  ]);

  const refetch = () => {
    trigger.current += 1;
    setLoading(true);
  };

  // `products` é alias para não quebrar código antigo
  return { data, products: data, loading, error, refetch };
}

// src/hooks/useFetchServicos.ts
"use client";

import useSWR from "swr";
import { apiFetch } from "@/lib/apiClient";
import { handleApiError } from "@/lib/handleApiError";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

type Params = {
  q?: string;
  especialidade?: string | number | null;
  page?: number;
  limit?: number;
  sort?: string;
  order?: "asc" | "desc";
};

type AnyObj = Record<string, any>;

type ApiListResponse<T> = {
  data?: T[];
  items?: T[];
  results?: T[];
  servicos?: T[];
  rows?: T[];
  total?: number;
  totalPages?: number;
  page?: number;
  meta?: {
    total?: number;
    totalPages?: number;
    page?: number;
    [k: string]: any;
  };
  [k: string]: any;
};

function pickList<T>(payload: any): T[] {
  if (!payload) return [];
  if (Array.isArray(payload)) return payload as T[];

  const p = payload as AnyObj;

  const directKeys = ["data", "items", "results", "servicos", "rows"];
  for (const k of directKeys) {
    if (Array.isArray(p?.[k])) return p[k] as T[];
  }

  // casos tipo { data: { items: [...] } } etc.
  if (p?.data && typeof p.data === "object") {
    for (const k of directKeys) {
      if (Array.isArray(p.data?.[k])) return p.data[k] as T[];
    }
  }

  return [];
}

function pickMeta(payload: any, fallbackPage: number) {
  const p = (payload || {}) as AnyObj;

  const metaFromMeta = p?.meta || p?.data?.meta;
  const total =
    Number(metaFromMeta?.total ?? p?.total ?? p?.data?.total ?? 0) || 0;

  const totalPages =
    Number(
      metaFromMeta?.totalPages ?? p?.totalPages ?? p?.data?.totalPages ?? 1,
    ) || 1;

  const page =
    Number(metaFromMeta?.page ?? p?.page ?? p?.data?.page ?? fallbackPage) ||
    fallbackPage;

  return { total, totalPages, page };
}

const fetcher = async (url: string) => {
  return apiFetch(url);
};

export function useFetchServicos({
  q,
  especialidade,
  page = 1,
  limit = 12,
  sort = "id",
  order = "desc",
}: Params = {}) {
  // ✅ ROTA PÚBLICA (coerente com ServicosSection)
  const url = new URL("/api/public/servicos", API_BASE);

  if (q && String(q).trim().length > 0) url.searchParams.set("q", String(q));

  if (
    especialidade !== undefined &&
    especialidade !== null &&
    String(especialidade).length > 0
  ) {
    url.searchParams.set("especialidade", String(especialidade));
  }

  url.searchParams.set("page", String(page));
  url.searchParams.set("limit", String(limit));
  url.searchParams.set("sort", String(sort));
  url.searchParams.set("order", order);

  const { data, error, isLoading } = useSWR<ApiListResponse<any>>(
    url.toString(),
    fetcher,
  );

  const list = pickList<any>(data);
  const meta = pickMeta(data, page);

  const errorMessage = error
    ? handleApiError(error, {
        silent: true,
        fallback: "Não foi possível carregar os serviços.",
      })
    : null;

  return {
    data: list,
    meta,
    loading: isLoading,
    error: errorMessage,
  };
}

"use client";

import { useCallback, useEffect, useState } from "react";
import toast from "react-hot-toast";
import { apiClient } from "@/lib/apiClient";
import { ENDPOINTS } from "@/services/api/endpoints";

export type UserAddress = {
  id: number;
  apelido: string | null;
  cep: string;
  endereco: string;
  numero: string;
  bairro: string;
  cidade: string;
  estado: string;
  complemento: string | null;
  ponto_referencia: string | null;
  telefone: string | null;
  // no banco provavelmente é TINYINT(1), então aceitamos 0/1 ou boolean
  is_default: 0 | 1 | boolean;
};

export type UserAddressPayload = {
  apelido?: string;
  cep: string;
  endereco: string;
  numero: string;
  bairro: string;
  cidade: string;
  estado: string;
  complemento?: string;
  ponto_referencia?: string;
  telefone?: string;
  is_default?: boolean;
};

type UseUserAddressesResult = {
  addresses: UserAddress[];
  loading: boolean;
  createAddress: (payload: UserAddressPayload) => Promise<void>;
  updateAddress: (id: number, payload: UserAddressPayload) => Promise<void>;
  deleteAddress: (id: number) => Promise<void>;
  reload: () => Promise<void>;
};

export function useUserAddresses(): UseUserAddressesResult {
  const [addresses, setAddresses] = useState<UserAddress[]>([]);
  const [loading, setLoading] = useState<boolean>(true);

  const fetchAddresses = useCallback(async () => {
    try {
      setLoading(true);
      const data = await apiClient.get<UserAddress[]>(
        ENDPOINTS.USERS.ADDRESSES,
      );
      setAddresses(data || []);
    } catch (err: any) {
      console.error("[useUserAddresses] erro ao carregar endereços:", err);
      const msg = err?.message || "Não foi possível carregar seus endereços.";
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAddresses();
  }, [fetchAddresses]);

  const createAddress = useCallback(async (payload: UserAddressPayload) => {
    try {
      const created = await apiClient.post<UserAddress>(
        ENDPOINTS.USERS.ADDRESSES,
        payload,
      );
      setAddresses((prev) => [...prev, created]);
      toast.success("Endereço salvo com sucesso! ✅");
    } catch (err: any) {
      console.error("[useUserAddresses] erro ao criar endereço:", err);
      const msg = err?.message || "Não foi possível salvar o endereço.";
      toast.error(msg);
      throw err;
    }
  }, []);

  const updateAddress = useCallback(
    async (id: number, payload: UserAddressPayload) => {
      try {
        const updated = await apiClient.put<UserAddress>(
          ENDPOINTS.USERS.ADDRESS(id),
          payload,
        );
        setAddresses((prev) =>
          prev.map((addr) => (addr.id === id ? updated : addr)),
        );
        toast.success("Endereço atualizado com sucesso! ✅");
      } catch (err: any) {
        console.error("[useUserAddresses] erro ao atualizar endereço:", err);
        const msg = err?.message || "Não foi possível atualizar o endereço.";
        toast.error(msg);
        throw err;
      }
    },
    [],
  );

  const deleteAddress = useCallback(async (id: number) => {
    try {
      await apiClient.del(ENDPOINTS.USERS.ADDRESS(id));
      setAddresses((prev) => prev.filter((addr) => addr.id !== id));
      toast.success("Endereço excluído com sucesso.");
    } catch (err: any) {
      console.error("[useUserAddresses] erro ao excluir endereço:", err);
      const msg = err?.message || "Não foi possível excluir o endereço.";
      toast.error(msg);
      throw err;
    }
  }, []);

  return {
    addresses,
    loading,
    createAddress,
    updateAddress,
    deleteAddress,
    reload: fetchAddresses,
  };
}

